// ===============================
// ARTIST DOWNLOADS MANAGEMENT SYSTEM
// ===============================

/**
 * Register a new artist download for bubble management
 */
function registerArtistDownload(artist, album, virtualPlaylistId, albumType) {
    console.log(`📝 Registering artist download: ${artist.name} - ${album.name}`);

    const artistId = artist.id;

    // Initialize artist bubble if it doesn't exist
    if (!artistDownloadBubbles[artistId]) {
        artistDownloadBubbles[artistId] = {
            artist: artist,
            downloads: [],
            element: null,
            hasCompletedDownloads: false
        };
    }

    // Add this download to the artist's downloads
    const downloadInfo = {
        virtualPlaylistId: virtualPlaylistId,
        album: album,
        albumType: albumType,
        status: 'in_progress', // 'in_progress', 'completed', 'view_results'
        startTime: new Date()
    };

    artistDownloadBubbles[artistId].downloads.push(downloadInfo);

    // Show/update the artist downloads section
    updateArtistDownloadsSection();

    // Save snapshot of current state
    saveArtistBubbleSnapshot();

    // Monitor this download for completion
    monitorArtistDownload(artistId, virtualPlaylistId);
}

/**
 * Debounced update for artist downloads section to prevent rapid updates
 */
function updateArtistDownloadsSection() {
    if (downloadsUpdateTimeout) {
        clearTimeout(downloadsUpdateTimeout);
    }
    downloadsUpdateTimeout = setTimeout(() => {
        showArtistDownloadsSection();
        showLibraryDownloadsSection();
        showBeatportDownloadsSection();
        updateDashboardDownloads();
    }, 300); // 300ms debounce
}

// --- Artist Bubble Snapshot System ---

let snapshotSaveTimeout = null; // Debounce snapshot saves

async function saveArtistBubbleSnapshot() {
    /**
     * Saves current artistDownloadBubbles state to backend for persistence.
     * Debounced to prevent excessive backend calls.
     */

    // Clear any existing timeout
    if (snapshotSaveTimeout) {
        clearTimeout(snapshotSaveTimeout);
    }

    // Debounce the actual save
    snapshotSaveTimeout = setTimeout(async () => {
        try {
            const bubbleCount = Object.keys(artistDownloadBubbles).length;

            // Don't save empty state
            if (bubbleCount === 0) {
                console.log('📸 Skipping snapshot save - no artist bubbles to save');
                return;
            }

            console.log(`📸 Saving artist bubble snapshot: ${bubbleCount} artists`);

            // Prepare snapshot data (clean up DOM references)
            const cleanBubbles = {};
            for (const [artistId, bubbleData] of Object.entries(artistDownloadBubbles)) {
                cleanBubbles[artistId] = {
                    artist: bubbleData.artist,
                    downloads: bubbleData.downloads.map(download => ({
                        virtualPlaylistId: download.virtualPlaylistId,
                        album: download.album,
                        albumType: download.albumType,
                        status: download.status,
                        startTime: download.startTime instanceof Date ? download.startTime.toISOString() : download.startTime
                    })),
                    hasCompletedDownloads: bubbleData.hasCompletedDownloads
                };
            }

            const response = await fetch('/api/artist_bubbles/snapshot', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    bubbles: cleanBubbles
                })
            });

            const data = await response.json();

            if (data.success) {
                console.log(`✅ Artist bubble snapshot saved: ${bubbleCount} artists`);
            } else {
                console.error('❌ Failed to save artist bubble snapshot:', data.error);
            }

        } catch (error) {
            console.error('❌ Error saving artist bubble snapshot:', error);
        }
    }, 1000); // 1 second debounce
}

async function hydrateArtistBubblesFromSnapshot() {
    /**
     * Hydrates artist download bubbles from backend snapshot with live status.
     * Called on page load to restore bubble state.
     */
    try {
        console.log('🔄 Loading artist bubble snapshot from backend...');

        const response = await fetch('/api/artist_bubbles/hydrate');
        const data = await response.json();

        if (!data.success) {
            console.error('❌ Failed to load artist bubble snapshot:', data.error);
            return;
        }

        const bubbles = data.bubbles || {};
        const stats = data.stats || {};

        console.log(`🔄 Loaded bubble snapshot: ${stats.total_artists || 0} artists, ${stats.active_downloads || 0} active, ${stats.completed_downloads || 0} completed`);

        if (Object.keys(bubbles).length === 0) {
            console.log('ℹ️ No artist bubbles to hydrate');
            return;
        }

        // Clear existing state
        artistDownloadBubbles = {};

        // Restore artistDownloadBubbles with hydrated data
        for (const [artistId, bubbleData] of Object.entries(bubbles)) {
            artistDownloadBubbles[artistId] = {
                artist: bubbleData.artist,
                downloads: bubbleData.downloads.map(download => ({
                    virtualPlaylistId: download.virtualPlaylistId,
                    album: download.album,
                    albumType: download.albumType,
                    status: download.status, // Live status from backend
                    startTime: new Date(download.startTime)
                })),
                element: null, // Will be created when UI updates
                hasCompletedDownloads: bubbleData.hasCompletedDownloads
            };

            console.log(`🔄 Hydrated artist: ${bubbleData.artist.name} (${bubbleData.downloads.length} downloads)`);

            // Start monitoring for any in-progress downloads
            for (const download of bubbleData.downloads) {
                if (download.status === 'in_progress') {
                    console.log(`📡 Starting monitoring for: ${download.album.name}`);
                    monitorArtistDownload(artistId, download.virtualPlaylistId);
                }
            }
        }

        // Update UI to show hydrated bubbles
        updateArtistDownloadsSection();

        const totalArtists = Object.keys(artistDownloadBubbles).length;
        console.log(`✅ Successfully hydrated ${totalArtists} artist download bubbles`);

    } catch (error) {
        console.error('❌ Error hydrating artist bubbles from snapshot:', error);
    }
}

// --- Search Bubble Snapshot System ---

async function saveSearchBubbleSnapshot() {
    /**
     * Saves current searchDownloadBubbles state to backend for persistence.
     */
    try {
        // Rate limit saves to avoid spamming backend
        if (saveSearchBubbleSnapshot.lastSaveTime) {
            const timeSinceLastSave = Date.now() - saveSearchBubbleSnapshot.lastSaveTime;
            if (timeSinceLastSave < 2000) {
                console.log('⏱️ Skipping search bubble snapshot save (rate limited)');
                return;
            }
        }

        const bubbleCount = Object.keys(searchDownloadBubbles).length;

        if (bubbleCount === 0) {
            console.log('📸 Skipping snapshot save - no search bubbles to save');
            return;
        }

        console.log(`📸 Saving search bubble snapshot: ${bubbleCount} artists`);

        // Convert search bubbles to plain objects for serialization
        const bubblesToSave = {};
        for (const [artistName, bubbleData] of Object.entries(searchDownloadBubbles)) {
            bubblesToSave[artistName] = {
                artist: bubbleData.artist,
                downloads: bubbleData.downloads.map(d => ({
                    virtualPlaylistId: d.virtualPlaylistId,
                    item: d.item,
                    type: d.type,
                    status: d.status,
                    startTime: d.startTime
                }))
            };
        }

        const response = await fetch('/api/search_bubbles/snapshot', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ bubbles: bubblesToSave })
        });

        const data = await response.json();

        if (data.success) {
            console.log(`✅ Search bubble snapshot saved: ${bubbleCount} artists`);
            saveSearchBubbleSnapshot.lastSaveTime = Date.now();
        } else {
            console.error('❌ Failed to save search bubble snapshot:', data.error);
        }

    } catch (error) {
        console.error('❌ Error saving search bubble snapshot:', error);
    }
}

async function hydrateSearchBubblesFromSnapshot() {
    /**
     * Hydrates search download bubbles from backend snapshot with live status.
     */
    try {
        console.log('🔄 Loading search bubble snapshot from backend...');

        const response = await fetch('/api/search_bubbles/hydrate');
        const data = await response.json();

        if (!data.success) {
            console.error('❌ Failed to load search bubble snapshot:', data.error);
            return;
        }

        const bubbles = data.bubbles || {};
        const stats = data.stats || {};

        if (Object.keys(bubbles).length === 0) {
            console.log('ℹ️ No search bubbles to hydrate');
            return;
        }

        // Clear and restore search bubbles
        searchDownloadBubbles = {};

        for (const [artistName, bubbleData] of Object.entries(bubbles)) {
            searchDownloadBubbles[artistName] = {
                artist: bubbleData.artist,
                downloads: bubbleData.downloads || []
            };

            console.log(`🔄 Hydrated artist: ${artistName} (${bubbleData.downloads.length} downloads)`);

            // Setup monitoring for each download
            for (const download of bubbleData.downloads) {
                if (download.status === 'in_progress') {
                    monitorSearchDownload(artistName, download.virtualPlaylistId);
                }
            }
        }

        const totalArtists = Object.keys(searchDownloadBubbles).length;
        console.log(`✅ Successfully hydrated ${totalArtists} search download bubbles`);

        // Refresh display
        showSearchDownloadBubbles();

    } catch (error) {
        console.error('❌ Error hydrating search bubbles from snapshot:', error);
    }
}

/**
 * Register a new search download for bubble management (grouped by artist)
 */
function registerSearchDownload(item, type, virtualPlaylistId, artistName) {
    console.log(`📝 [REGISTER] Registering search download: ${item.name} (${type}) by ${artistName}`);

    // Initialize artist bubble if it doesn't exist
    if (!searchDownloadBubbles[artistName]) {
        searchDownloadBubbles[artistName] = {
            artist: {
                name: artistName,
                image_url: item.image_url || (item.images && item.images[0]?.url) || null
            },
            downloads: []
        };
    }

    // Add this download to the artist's downloads
    const downloadInfo = {
        virtualPlaylistId: virtualPlaylistId,
        item: item,
        type: type, // 'album' or 'track'
        status: 'in_progress',
        startTime: new Date().toISOString()
    };

    searchDownloadBubbles[artistName].downloads.push(downloadInfo);

    console.log(`✅ [REGISTER] Registered search download for ${artistName} - ${item.name}`);

    // Save snapshot
    saveSearchBubbleSnapshot();

    // Setup monitoring
    monitorSearchDownload(artistName, virtualPlaylistId);

    // Refresh display
    updateSearchDownloadsSection();
}

/**
 * Debounced update for search downloads section
 */
function updateSearchDownloadsSection() {
    if (window.searchUpdateTimeout) {
        clearTimeout(window.searchUpdateTimeout);
    }
    window.searchUpdateTimeout = setTimeout(() => {
        showSearchDownloadBubbles();
        updateDashboardDownloads();
    }, 300);
}

/**
 * Monitor a search download for completion status changes
 */
function monitorSearchDownload(artistName, virtualPlaylistId) {
    const checkCompletion = setInterval(() => {
        const process = activeDownloadProcesses[virtualPlaylistId];

        if (!process || !searchDownloadBubbles[artistName]) {
            clearInterval(checkCompletion);
            return;
        }

        // Find the download in the artist's downloads
        const download = searchDownloadBubbles[artistName].downloads.find(
            d => d.virtualPlaylistId === virtualPlaylistId
        );

        if (!download) {
            clearInterval(checkCompletion);
            return;
        }

        // Update status
        const newStatus = process.status === 'complete' || process.status === 'view_results'
            ? 'view_results'
            : 'in_progress';

        if (download.status !== newStatus) {
            console.log(`🔄 [MONITOR] Status changed for ${download.item.name}: ${download.status} -> ${newStatus}`);
            download.status = newStatus;

            // Save snapshot and refresh
            saveSearchBubbleSnapshot();
            updateSearchDownloadsSection();
        }
    }, 2000);
}

/**
 * Show or update the search downloads bubble section
 */
function showSearchDownloadBubbles() {
    console.log(`🔄 [SHOW] showSearchDownloadBubbles() called`);

    const resultsArea = document.getElementById('enhanced-main-results-area');
    if (!resultsArea) {
        console.log(`⏭️ [SHOW] Skipping - no enhanced-main-results-area found`);
        return;
    }

    // Count active artists (those with downloads)
    const activeArtists = Object.keys(searchDownloadBubbles).filter(artistName =>
        searchDownloadBubbles[artistName].downloads.length > 0
    );

    if (activeArtists.length === 0) {
        // Show placeholder
        resultsArea.innerHTML = `
            <div class="search-results-placeholder">
                <p>Search results will appear here when you select an album or track.</p>
            </div>
        `;
        return;
    }

    // Create bubbles display
    const bubblesHTML = activeArtists.map(artistName =>
        createSearchBubbleCard(searchDownloadBubbles[artistName])
    ).join('');

    resultsArea.innerHTML = `
        <div class="search-bubble-section">
            <div class="search-bubble-header">
                <h3 class="search-bubble-title">Active Downloads</h3>
                <span class="search-bubble-count">${activeArtists.length}</span>
            </div>
            <div class="search-bubble-container" id="search-bubble-container">
                ${bubblesHTML}
            </div>
        </div>
    `;

    console.log(`✅ [SHOW] Displayed ${activeArtists.length} search bubbles`);
}

/**
 * Create HTML for a search bubble card (grouped by artist)
 */
function createSearchBubbleCard(artistBubbleData) {
    const { artist, downloads } = artistBubbleData;
    const activeCount = downloads.filter(d => d.status === 'in_progress').length;
    const completedCount = downloads.filter(d => d.status === 'view_results').length;
    const allCompleted = activeCount === 0 && completedCount > 0;

    console.log(`🔵 [BUBBLE] Creating bubble for ${artist.name}:`, {
        totalDownloads: downloads.length,
        activeCount,
        completedCount,
        allCompleted
    });

    const imageUrl = artist.image_url || '';
    const backgroundStyle = imageUrl ?
        `background-image: url('${escapeHtml(imageUrl)}');` :
        `background: linear-gradient(135deg, rgba(29, 185, 84, 0.3) 0%, rgba(24, 156, 71, 0.2) 100%);`;

    return `
        <div class="search-bubble-card ${allCompleted ? 'all-completed' : ''}"
             data-artist-name="${escapeHtml(artist.name)}"
             onclick="openSearchDownloadModal('${escapeForInlineJs(artist.name)}')"
             title="Click to manage downloads for ${escapeHtml(artist.name)}">
            <div class="search-bubble-image" style="${backgroundStyle}"></div>
            <div class="search-bubble-overlay"></div>
            <div class="search-bubble-content">
                <div class="search-bubble-name">${escapeHtml(artist.name)}</div>
                <div class="search-bubble-status">
                    ${activeCount > 0 ? `${activeCount} active` : ''}
                    ${completedCount > 0 ? `${completedCount} completed` : ''}
                </div>
            </div>
            ${allCompleted ? `
                <div class="bulk-complete-indicator"
                     onclick="event.stopPropagation(); bulkCompleteSearchDownloads('${escapeForInlineJs(artist.name)}')"
                     title="Complete all downloads">
                    <span class="bulk-complete-icon">✅</span>
                </div>
            ` : ''}
        </div>
    `;
}

/**
 * Open modal showing all downloads for an artist
 */
async function openSearchDownloadModal(artistName) {
    const artistBubbleData = searchDownloadBubbles[artistName];
    if (!artistBubbleData || searchDownloadModalOpen) return;

    console.log(`🎵 [MODAL OPEN] Opening search download modal for: ${artistBubbleData.artist.name}`);

    searchDownloadModalOpen = true;

    const modal = document.createElement('div');
    modal.id = 'search-download-management-modal';
    modal.className = 'artist-download-management-modal';
    modal.innerHTML = `
        <div class="artist-download-modal-content">
            <div class="artist-download-modal-hero">
                <div class="artist-download-modal-hero-bg" ${artistBubbleData.artist.image_url ? `style="background-image: url('${escapeHtml(artistBubbleData.artist.image_url)}')"` : ''}></div>
                <div class="artist-download-modal-hero-overlay">
                    <div class="artist-download-modal-hero-content">
                        <div class="artist-download-modal-hero-avatar">
                            ${artistBubbleData.artist.image_url
            ? `<img src="${escapeHtml(artistBubbleData.artist.image_url)}" alt="${escapeHtml(artistBubbleData.artist.name)}" class="artist-download-modal-hero-image" loading="lazy">`
            : '<div class="artist-download-modal-hero-fallback">🎵</div>'
        }
                        </div>
                        <div class="artist-download-modal-hero-info">
                            <h2 class="artist-download-modal-hero-title">${escapeHtml(artistBubbleData.artist.name)}</h2>
                            <p class="artist-download-modal-hero-subtitle">${artistBubbleData.downloads.length} active download${artistBubbleData.downloads.length !== 1 ? 's' : ''}</p>
                        </div>
                    </div>
                    <span class="artist-download-modal-close" onclick="closeSearchDownloadModal()">&times;</span>
                </div>
            </div>

            <div class="artist-download-modal-body">
                <div class="artist-download-items" id="search-download-items">
                    ${artistBubbleData.downloads.map((download, index) => createSearchDownloadItem(download, index)).join('')}
                </div>
            </div>
        </div>
        <div class="artist-download-modal-overlay" onclick="closeSearchDownloadModal()"></div>
    `;

    document.body.appendChild(modal);
    modal.style.display = 'flex';

    // Start monitoring for status changes
    // Start monitoring for status changes
    monitorSearchDownloadModal(artistName);

    // Lazy load artist image if missing (common for iTunes)
    if (!artistBubbleData.artist.image_url) {
        console.log(`🖼️ Lazy loading modal image for ${artistBubbleData.artist.name} (${artistBubbleData.artist.id})`);
        fetch(`/api/artist/${artistBubbleData.artist.id}/image`)
            .then(response => response.json())
            .then(data => {
                if (data.success && data.image_url) {
                    // Update header background
                    const headerBg = modal.querySelector('.artist-download-modal-hero-bg');
                    if (headerBg) {
                        headerBg.style.backgroundImage = `url('${data.image_url}')`;
                    }

                    // Update avatar
                    const avatarContainer = modal.querySelector('.artist-download-modal-hero-avatar');
                    if (avatarContainer) {
                        avatarContainer.innerHTML = `<img src="${data.image_url}" alt="${artistBubbleData.artist.name}" class="artist-download-modal-hero-image" loading="lazy">`;
                    }

                    // Update artist object in memory
                    artistBubbleData.artist.image_url = data.image_url;
                }
            })
            .catch(err => console.error('❌ Failed to load modal image:', err));
    }
}

/**
 * Create HTML for a download item in the search modal
 */
function createSearchDownloadItem(download, index) {
    const { item, type, status, virtualPlaylistId } = download;
    const buttonText = status === 'view_results' ? 'View Results' : 'View Progress';
    const buttonClass = status === 'view_results' ? 'completed' : 'active';
    const typeLabel = type === 'album' ? 'Album' : type === 'single' ? 'Single' : 'Track';

    return `
        <div class="artist-download-item" data-playlist-id="${virtualPlaylistId}">
            <div class="download-item-artwork">
                ${item.image_url
            ? `<img src="${escapeHtml(item.image_url)}" alt="${escapeHtml(item.name)}" class="download-item-image" loading="lazy">`
            : `<div class="download-item-fallback">
                         ${type === 'album' ? '💿' : '🎵'}
                       </div>`
        }
            </div>
            <div class="download-item-info">
                <div class="download-item-name">${escapeHtml(item.name)}</div>
                <div class="download-item-type">${typeLabel}</div>
            </div>
            <div class="download-item-actions">
                <button class="download-item-btn ${buttonClass}"
                        onclick="reopenDownloadModal('${virtualPlaylistId}')">
                    ${buttonText}
                </button>
            </div>
        </div>
    `;
}

/**
 * Reopen an individual download modal from the artist modal
 */
async function reopenDownloadModal(virtualPlaylistId) {
    const process = activeDownloadProcesses[virtualPlaylistId];

    // If process exists, show the existing modal
    if (process && process.modalElement) {
        console.log(`✅ [REOPEN] Showing existing modal for ${virtualPlaylistId}`);
        closeSearchDownloadModal();
        setTimeout(() => {
            process.modalElement.style.display = 'flex';
        }, 100);
        return;
    }

    // Process doesn't exist (after page refresh) - recreate it
    console.log(`🔄 [REOPEN] Modal not found, recreating for ${virtualPlaylistId}`);

    // Find the download in searchDownloadBubbles
    let downloadData = null;
    for (const artistName in searchDownloadBubbles) {
        const bubble = searchDownloadBubbles[artistName];
        const download = bubble.downloads.find(d => d.virtualPlaylistId === virtualPlaylistId);
        if (download) {
            downloadData = download;
            break;
        }
    }

    if (!downloadData) {
        console.warn(`⚠️ No download data found for ${virtualPlaylistId}`);
        return;
    }

    // Close search modal first
    closeSearchDownloadModal();

    // Recreate the modal based on type
    const { item, type } = downloadData;

    if (type === 'album') {
        // For albums, we need to fetch the tracks
        console.log(`📥 [REOPEN] Recreating album modal for: ${item.name}`);

        // Fetch album tracks (pass name/artist for Hydrabase support)
        showLoadingOverlay(`Loading ${item.name}...`);

        try {
            const _sap2 = new URLSearchParams({ name: item.name || '', artist: item.artist || '' });
            const response = await fetch(`/api/spotify/album/${item.id}?${_sap2}`);
            if (!response.ok) {
                throw new Error('Failed to fetch album tracks');
            }

            const albumData = await response.json();
            if (!albumData.tracks || albumData.tracks.length === 0) {
                throw new Error('No tracks found in album');
            }

            const spotifyTracks = albumData.tracks.map(track => ({
                id: track.id,
                name: track.name,
                artists: track.artists || [{ name: item.artists?.[0]?.name || item.artist || 'Unknown Artist' }],
                album: {
                    name: item.name,
                    images: item.image_url ? [{ url: item.image_url }] : []
                },
                duration_ms: track.duration_ms || 0
            }));

            hideLoadingOverlay();

            // Open the modal
            await openDownloadMissingModalForArtistAlbum(
                virtualPlaylistId,
                item.name,
                spotifyTracks,
                item,
                { name: item.artists?.[0]?.name || item.artist || 'Unknown Artist' },
                false // Don't show loading overlay again
            );

            // Sync with backend to check for active batch process
            const process = activeDownloadProcesses[virtualPlaylistId];
            if (process) {
                try {
                    const processResponse = await fetch('/api/active-processes');
                    if (processResponse.ok) {
                        const processData = await processResponse.json();
                        const activeProcess = processData.active_processes?.find(p => p.playlist_id === virtualPlaylistId);

                        if (activeProcess) {
                            console.log(`📡 [REOPEN] Found active batch for album: ${activeProcess.batch_id}`);
                            process.status = 'running';
                            process.batchId = activeProcess.batch_id;

                            // Update UI to show running state
                            const beginBtn = document.getElementById(`begin-analysis-btn-${virtualPlaylistId}`);
                            const cancelBtn = document.getElementById(`cancel-all-btn-${virtualPlaylistId}`);
                            if (beginBtn) beginBtn.style.display = 'none';
                            if (cancelBtn) cancelBtn.style.display = 'inline-block';

                            // Start polling for live updates
                            startModalDownloadPolling(virtualPlaylistId);
                        }
                    }
                } catch (err) {
                    console.warn('Could not check for active processes:', err);
                }
            }

        } catch (error) {
            hideLoadingOverlay();
            showToast(`Failed to load album: ${error.message}`, 'error');
            console.error('Error loading album:', error);
        }

    } else {
        // For tracks, create enriched track and open modal
        console.log(`🎵 [REOPEN] Recreating track modal for: ${item.name}`);

        const enrichedTrack = {
            id: item.id,
            name: item.name,
            artists: item.artists || [{ name: item.artist || 'Unknown Artist' }],
            album: item.album || {
                name: item.album?.name || 'Unknown Album',
                images: item.image_url ? [{ url: item.image_url }] : []
            },
            duration_ms: item.duration_ms || 0
        };

        await openDownloadMissingModalForYouTube(
            virtualPlaylistId,
            `${enrichedTrack.name} - ${enrichedTrack.artists[0].name || enrichedTrack.artists[0]}`,
            [enrichedTrack]
        );

        // Sync with backend to check for active batch process
        const process = activeDownloadProcesses[virtualPlaylistId];
        if (process) {
            try {
                const processResponse = await fetch('/api/active-processes');
                if (processResponse.ok) {
                    const processData = await processResponse.json();
                    const activeProcess = processData.active_processes?.find(p => p.playlist_id === virtualPlaylistId);

                    if (activeProcess) {
                        console.log(`📡 [REOPEN] Found active batch for track: ${activeProcess.batch_id}`);
                        process.status = 'running';
                        process.batchId = activeProcess.batch_id;

                        // Update UI to show running state
                        const beginBtn = document.getElementById(`begin-analysis-btn-${virtualPlaylistId}`);
                        const cancelBtn = document.getElementById(`cancel-all-btn-${virtualPlaylistId}`);
                        if (beginBtn) beginBtn.style.display = 'none';
                        if (cancelBtn) cancelBtn.style.display = 'inline-block';

                        // Start polling for live updates
                        startModalDownloadPolling(virtualPlaylistId);
                    }
                }
            } catch (err) {
                console.warn('Could not check for active processes:', err);
            }
        }
    }
}

/**
 * Monitor search download modal for status changes
 */
function monitorSearchDownloadModal(artistName) {
    const updateModal = () => {
        if (!searchDownloadModalOpen) return;

        const modal = document.getElementById('search-download-management-modal');
        const itemsContainer = document.getElementById('search-download-items');

        if (!modal || !itemsContainer || !searchDownloadBubbles[artistName]) return;

        const downloads = searchDownloadBubbles[artistName].downloads;

        // If no downloads at all, close modal
        if (downloads.length === 0) {
            closeSearchDownloadModal();
            return;
        }

        // Update modal content and sync status with active processes
        let statusChanged = false;
        itemsContainer.innerHTML = downloads.map((download, index) => {
            const process = activeDownloadProcesses[download.virtualPlaylistId];

            // Only update status if process exists (otherwise keep current status)
            if (process) {
                const newStatus = process.status === 'complete' || process.status === 'view_results'
                    ? 'view_results'
                    : 'in_progress';

                if (download.status !== newStatus) {
                    console.log(`🔄 [MODAL MONITOR] Status changed: ${download.item.name} ${download.status} -> ${newStatus}`);
                    download.status = newStatus;
                    statusChanged = true;
                }
            }

            return createSearchDownloadItem(download, index);
        }).join('');

        // If status changed, refresh bubble display and save
        if (statusChanged) {
            updateSearchDownloadsSection();
            saveSearchBubbleSnapshot();
        }

        // Continue monitoring
        setTimeout(updateModal, 2000);
    };

    setTimeout(updateModal, 1000);
}

/**
 * Close the search download modal
 */
function closeSearchDownloadModal() {
    const modal = document.getElementById('search-download-management-modal');
    if (modal) {
        modal.style.display = 'none';
        if (modal.parentElement) {
            modal.parentElement.removeChild(modal);
        }
    }
    searchDownloadModalOpen = false;
}

/**
 * Bulk complete all downloads for an artist (called when user clicks green checkmark)
 */
function bulkCompleteSearchDownloads(artistName) {
    console.log(`🎯 Bulk completing downloads for artist: ${artistName}`);

    const artistBubbleData = searchDownloadBubbles[artistName];
    if (!artistBubbleData) {
        console.warn(`❌ No artist bubble data found for ${artistName}`);
        return;
    }

    // Find all completed downloads
    const completedDownloads = artistBubbleData.downloads.filter(d => d.status === 'view_results');
    console.log(`📋 Found ${completedDownloads.length} completed downloads to close:`,
        completedDownloads.map(d => d.item.name));

    if (completedDownloads.length === 0) {
        console.warn(`⚠️ No completed downloads found for bulk close`);
        showToast('No completed downloads to close', 'info');
        return;
    }

    // Close all completed modals
    completedDownloads.forEach(download => {
        const process = activeDownloadProcesses[download.virtualPlaylistId];
        if (process && process.modalElement) {
            console.log(`🗑️ Closing modal for: ${download.item.name}`);
            closeDownloadMissingModal(download.virtualPlaylistId);
        } else {
            // No modal open — clean up the bubble entry directly
            console.log(`🧹 Direct cleanup (no modal) for: ${download.item.name}`);
            cleanupSearchDownload(download.virtualPlaylistId);
        }
    });

    showToast(`Completed ${completedDownloads.length} downloads for ${artistBubbleData.artist.name}`, 'success');
}

/**
 * Cleanup search download when modal is closed
 */
function cleanupSearchDownload(virtualPlaylistId) {
    console.log(`🔍 [CLEANUP] Looking for search download to cleanup: ${virtualPlaylistId}`);

    // Find which artist this download belongs to
    for (const artistName in searchDownloadBubbles) {
        const downloads = searchDownloadBubbles[artistName].downloads;
        const downloadIndex = downloads.findIndex(d => d.virtualPlaylistId === virtualPlaylistId);

        if (downloadIndex !== -1) {
            console.log(`🧹 [CLEANUP] Found download in artist ${artistName}: ${downloads[downloadIndex].item.name}`);

            // Remove this download
            downloads.splice(downloadIndex, 1);
            console.log(`🗑️ [CLEANUP] Removed download from ${artistName}'s bubble`);

            // If no more downloads for this artist, remove the bubble
            if (downloads.length === 0) {
                delete searchDownloadBubbles[artistName];
                console.log(`🧹 [CLEANUP] No more downloads - removed artist bubble: ${artistName}`);
            }

            // Save snapshot and refresh
            saveSearchBubbleSnapshot();
            updateSearchDownloadsSection();

            return;
        }
    }

    console.log(`⚠️ [CLEANUP] No matching search download found for: ${virtualPlaylistId}`);
}

/**
 * Show or update the artist downloads section in search state
 */
function showArtistDownloadsSection() {
    console.log(`🔄 [SHOW] showArtistDownloadsSection() called - refreshing artist bubbles`);
    console.log(`🔄 [SHOW] Current view: ${artistsPageState.currentView}, artistDownloadBubbles count: ${Object.keys(artistDownloadBubbles).length}`);

    // Only show in search state
    if (artistsPageState.currentView !== 'search') {
        console.log(`⏭️ [SHOW] Skipping - not in search state (current: ${artistsPageState.currentView})`);
        return;
    }

    const artistsSearchState = document.getElementById('artists-search-state');
    if (!artistsSearchState) {
        console.log(`⏭️ [SHOW] Skipping - no artists-search-state element found`);
        return;
    }

    let downloadsSection = document.getElementById('artist-downloads-section');

    // Create section if it doesn't exist
    if (!downloadsSection) {
        downloadsSection = document.createElement('div');
        downloadsSection.id = 'artist-downloads-section';
        downloadsSection.className = 'artist-downloads-section';

        // Insert after the search container
        const searchContainer = artistsSearchState.querySelector('.artists-search-container');
        if (searchContainer) {
            searchContainer.insertAdjacentElement('afterend', downloadsSection);
        }
    }

    // Count active artists (those with downloads)
    const activeArtists = Object.keys(artistDownloadBubbles).filter(artistId =>
        artistDownloadBubbles[artistId].downloads.length > 0
    );

    if (activeArtists.length === 0) {
        downloadsSection.style.display = 'none';
        return;
    }

    // Show and populate the section
    downloadsSection.style.display = 'block';
    downloadsSection.innerHTML = `
        <div class="artist-downloads-header">
            <h3 class="artist-downloads-title">Current Downloads</h3>
            <p class="artist-downloads-subtitle">Active download processes</p>
        </div>
        <div class="artist-bubble-container" id="artist-bubble-container">
            ${activeArtists.map(artistId => createArtistBubbleCard(artistDownloadBubbles[artistId])).join('')}
        </div>
    `;

    // Add event listeners to bubble cards
    activeArtists.forEach(artistId => {
        const bubbleCard = downloadsSection.querySelector(`[data-artist-id="${artistId}"]`);
        if (bubbleCard) {
            bubbleCard.addEventListener('click', () => openArtistDownloadModal(artistId));

            // Add dynamic glow effect
            const artist = artistDownloadBubbles[artistId].artist;
            if (artist.image_url) {
                extractImageColors(artist.image_url, (colors) => {
                    applyDynamicGlow(bubbleCard, colors);
                });
            }
        }
    });
}

/**
 * Show download bubbles on the Library page (mirrors showArtistDownloadsSection)
 */
function showLibraryDownloadsSection() {
    const libraryContent = document.querySelector('.library-content');
    if (!libraryContent) return;

    let downloadsSection = document.getElementById('library-downloads-section');

    // Create section if it doesn't exist
    if (!downloadsSection) {
        downloadsSection = document.createElement('div');
        downloadsSection.id = 'library-downloads-section';
        downloadsSection.className = 'artist-downloads-section';

        // Insert before the artist grid
        const artistGrid = document.getElementById('library-artists-grid');
        if (artistGrid) {
            libraryContent.insertBefore(downloadsSection, artistGrid);
        }
    }

    // Count active artists (reuses artistDownloadBubbles state)
    const activeArtists = Object.keys(artistDownloadBubbles).filter(artistId =>
        artistDownloadBubbles[artistId].downloads.length > 0
    );

    if (activeArtists.length === 0) {
        downloadsSection.style.display = 'none';
        return;
    }

    downloadsSection.style.display = 'block';
    downloadsSection.innerHTML = `
        <div class="artist-downloads-header">
            <h3 class="artist-downloads-title">Current Downloads</h3>
            <p class="artist-downloads-subtitle">Active download processes</p>
        </div>
        <div class="artist-bubble-container">
            ${activeArtists.map(artistId => createArtistBubbleCard(artistDownloadBubbles[artistId])).join('')}
        </div>
    `;

    // Add click handlers + glow effects
    activeArtists.forEach(artistId => {
        const bubbleCard = downloadsSection.querySelector(`[data-artist-id="${artistId}"]`);
        if (bubbleCard) {
            bubbleCard.addEventListener('click', () => openArtistDownloadModal(artistId));
            const artist = artistDownloadBubbles[artistId].artist;
            if (artist.image_url) {
                extractImageColors(artist.image_url, (colors) => {
                    applyDynamicGlow(bubbleCard, colors);
                });
            }
        }
    });
}

/**
 * Create HTML for an artist bubble card
 */
function createArtistBubbleCard(artistBubbleData) {
    const { artist, downloads } = artistBubbleData;
    const activeCount = downloads.filter(d => d.status === 'in_progress').length;
    const completedCount = downloads.filter(d => d.status === 'view_results').length;
    const allCompleted = activeCount === 0 && completedCount > 0;

    // Enhanced debug logging for bubble card creation and green checkmark detection
    console.log(`🔵 [BUBBLE] Creating bubble for ${artist.name}:`, {
        totalDownloads: downloads.length,
        activeCount,
        completedCount,
        allCompleted,
        downloadStatuses: downloads.map(d => `${d.album.name}: ${d.status}`)
    });

    // CRITICAL: Green checkmark detection logging
    if (allCompleted) {
        console.log(`🟢 [BUBBLE] GREEN CHECKMARK DETECTED for ${artist.name} - all ${downloads.length} downloads completed`);
        console.log(`✅ [BUBBLE] This bubble will have 'all-completed' class and green checkmark`);
    } else if (activeCount === 0 && completedCount === 0) {
        console.log(`⭕ [BUBBLE] No active or completed downloads for ${artist.name} - this shouldn't happen`);
    } else {
        console.log(`⏳ [BUBBLE] Still waiting for completion: ${activeCount} active, ${completedCount} completed`);
    }

    const imageUrl = artist.image_url || '';
    const backgroundStyle = imageUrl ?
        `background-image: url('${imageUrl}');` :
        `background: linear-gradient(135deg, rgba(29, 185, 84, 0.3) 0%, rgba(24, 156, 71, 0.2) 100%);`;

    return `
        <div class="artist-bubble-card ${allCompleted ? 'all-completed' : ''}" 
             data-artist-id="${artist.id}"
             title="Click to manage downloads for ${escapeHtml(artist.name)}">
            <div class="artist-bubble-image" style="${backgroundStyle}"></div>
            <div class="artist-bubble-overlay"></div>
            <div class="artist-bubble-content">
                <div class="artist-bubble-name">${escapeHtml(artist.name)}</div>
                <div class="artist-bubble-status">
                    ${activeCount > 0 ? `${activeCount} active` : ''}
                    ${completedCount > 0 ? `${completedCount} completed` : ''}
                </div>
            </div>
            ${allCompleted ? `
                <div class="bulk-complete-indicator" 
                     onclick="event.stopPropagation(); bulkCompleteArtistDownloads('${artist.id}')"
                     title="Complete all downloads">
                    <span class="bulk-complete-icon">✅</span>
                </div>
            ` : ''}
        </div>
    `;
}

/**
 * Monitor an artist download for completion status changes
 */
function monitorArtistDownload(artistId, virtualPlaylistId) {
    // Check if the download process exists and monitor its status
    const checkStatus = () => {
        const process = activeDownloadProcesses[virtualPlaylistId];
        if (!process || !artistDownloadBubbles[artistId]) {
            return; // Process or artist bubble no longer exists
        }

        // Find this download in the artist's downloads
        const download = artistDownloadBubbles[artistId].downloads.find(d => d.virtualPlaylistId === virtualPlaylistId);
        if (!download) return;

        // Update download status based on process status
        if (process.status === 'complete' && download.status === 'in_progress') {
            download.status = 'view_results';
            console.log(`✅ Download completed for ${artistDownloadBubbles[artistId].artist.name} - ${download.album.name}`);
            console.log(`📊 Artist ${artistId} downloads status:`, artistDownloadBubbles[artistId].downloads.map(d => `${d.album.name}: ${d.status}`));

            // Update the downloads section
            updateArtistDownloadsSection();

            // Save snapshot of updated state
            saveArtistBubbleSnapshot();

            // Check if all downloads for this artist are now completed
            const artistDownloads = artistDownloadBubbles[artistId].downloads;
            const allCompleted = artistDownloads.every(d => d.status === 'view_results');
            if (allCompleted) {
                console.log(`🟢 All downloads completed for ${artistDownloadBubbles[artistId].artist.name} - green checkmark should appear`);
                console.log(`🎯 [STATUS DEBUG] Green checkmark trigger - forcing bubble refresh`);
                // Force immediate bubble refresh to show green checkmark
                setTimeout(updateArtistDownloadsSection, 100);
            }
        }

        // Continue monitoring if still active
        if (process.status !== 'complete') {
            setTimeout(checkStatus, 2000); // Check every 2 seconds
        }
    };

    // Start monitoring after a brief delay
    setTimeout(checkStatus, 1000);
}

/**
 * Open the artist download management modal
 */
function openArtistDownloadModal(artistId) {
    const artistBubbleData = artistDownloadBubbles[artistId];
    if (!artistBubbleData || artistDownloadModalOpen) return;

    console.log(`🎵 [MODAL OPEN] Opening artist download modal for: ${artistBubbleData.artist.name}`);
    console.log(`📊 [MODAL OPEN] Current download statuses:`, artistBubbleData.downloads.map(d => `${d.album.name}: ${d.status}`));
    artistDownloadModalOpen = true;

    const modal = document.createElement('div');
    modal.id = 'artist-download-management-modal';
    modal.className = 'artist-download-management-modal';
    modal.innerHTML = `
        <div class="artist-download-modal-content">
            <div class="artist-download-modal-hero">
                <div class="artist-download-modal-hero-bg" ${artistBubbleData.artist.image_url ? `style="background-image: url('${escapeHtml(artistBubbleData.artist.image_url)}')"` : ''}></div>
                <div class="artist-download-modal-hero-overlay">
                    <div class="artist-download-modal-hero-content">
                        <div class="artist-download-modal-hero-avatar">
                            ${artistBubbleData.artist.image_url
            ? `<img src="${escapeHtml(artistBubbleData.artist.image_url)}" alt="${escapeHtml(artistBubbleData.artist.name)}" class="artist-download-modal-hero-image" loading="lazy">`
            : '<div class="artist-download-modal-hero-fallback"><i class="fas fa-user-music"></i></div>'
        }
                        </div>
                        <div class="artist-download-modal-hero-info">
                            <h2 class="artist-download-modal-hero-title">${escapeHtml(artistBubbleData.artist.name)}</h2>
                            <p class="artist-download-modal-hero-subtitle">${artistBubbleData.downloads.length} active download${artistBubbleData.downloads.length !== 1 ? 's' : ''}</p>
                        </div>
                    </div>
                    <span class="artist-download-modal-close" onclick="closeArtistDownloadModal()">&times;</span>
                </div>
            </div>

            <div class="artist-download-modal-body">
                <div class="artist-download-items" id="artist-download-items-${artistId}">
                    ${artistBubbleData.downloads.map((download, index) => createArtistDownloadItem(download, index)).join('')}
                </div>
            </div>
        </div>
        <div class="artist-download-modal-overlay" onclick="closeArtistDownloadModal()"></div>
    `;

    document.body.appendChild(modal);
    modal.style.display = 'flex';

    // Monitor for real-time updates
    startArtistDownloadModalMonitoring(artistId);
}

/**
 * Create HTML for an individual download item in the artist modal
 */
function createArtistDownloadItem(download, index) {
    const { album, albumType, status, virtualPlaylistId } = download;
    const buttonText = status === 'view_results' ? 'View Results' : 'View Progress';
    const buttonClass = status === 'view_results' ? 'completed' : 'active';

    // Enhanced debugging for button text generation
    console.log(`🎯 [BUTTON] Creating item for ${album.name}: status='${status}' → buttonText='${buttonText}'`);

    return `
        <div class="artist-download-item" data-playlist-id="${virtualPlaylistId}">
            <div class="download-item-artwork">
                ${album.image_url
            ? `<img src="${escapeHtml(album.image_url)}" alt="${escapeHtml(album.name)}" class="download-item-image" loading="lazy">`
            : `<div class="download-item-fallback">
                         <i class="fas fa-${albumType === 'album' ? 'compact-disc' : albumType === 'single' ? 'music' : 'record-vinyl'}"></i>
                       </div>`
        }
            </div>
            <div class="download-item-info">
                <div class="download-item-name">${escapeHtml(album.name)}</div>
                <div class="download-item-type">${albumType === 'album' ? 'Album' : albumType === 'single' ? 'Single' : 'EP'}</div>
            </div>
            <div class="download-item-actions">
                <button class="download-item-btn ${buttonClass}"
                        onclick="openArtistDownloadProcess('${virtualPlaylistId}')">
                    ${buttonText}
                </button>
            </div>
        </div>
    `;
}

/**
 * Monitor artist download modal for real-time updates
 */
function startArtistDownloadModalMonitoring(artistId) {
    if (!artistDownloadModalOpen) return;

    const updateModal = () => {
        const modal = document.getElementById('artist-download-management-modal');
        const itemsContainer = document.getElementById(`artist-download-items-${artistId}`);

        if (!modal || !itemsContainer || !artistDownloadBubbles[artistId]) return;

        // Check for completed downloads that need to be removed
        const activeDownloads = artistDownloadBubbles[artistId].downloads.filter(download => {
            const process = activeDownloadProcesses[download.virtualPlaylistId];
            // Keep if process exists or if it's completed but not yet cleaned up
            return process !== undefined;
        });

        // Update the downloads array
        artistDownloadBubbles[artistId].downloads = activeDownloads;

        // If no downloads left, close modal
        if (activeDownloads.length === 0) {
            closeArtistDownloadModal();
            return;
        }

        // Update modal content and synchronize with bubble state
        let statusChanged = false;
        itemsContainer.innerHTML = activeDownloads.map((download, index) => {
            const process = activeDownloadProcesses[download.virtualPlaylistId];
            if (process) {
                const newStatus = process.status === 'complete' ? 'view_results' : 'in_progress';
                if (download.status !== newStatus) {
                    console.log(`🔄 [ARTIST MODAL] Updating ${download.album.name} status from ${download.status} to ${newStatus}`);
                    download.status = newStatus;
                    statusChanged = true;
                }
            }
            return createArtistDownloadItem(download, index);
        }).join('');

        // CRITICAL: If any status changed, immediately refresh artist bubble to show green checkmarks
        if (statusChanged) {
            console.log(`🎯 [SYNC] Status change detected in artist modal - refreshing bubble display`);
            updateArtistDownloadsSection();

            // Check if all downloads for this artist are now completed
            const artistDownloads = artistDownloadBubbles[artistId].downloads;
            const allCompleted = artistDownloads.every(d => d.status === 'view_results');
            if (allCompleted) {
                console.log(`🟢 [ARTIST MODAL] All downloads completed for artist ${artistId} - triggering green checkmark`);
                // Force additional refresh after a brief delay to ensure UI updates
                setTimeout(() => {
                    console.log(`✨ [ARTIST MODAL] Forcing final refresh for green checkmark`);
                    updateArtistDownloadsSection();
                }, 200);
            }
        }

        // Continue monitoring
        setTimeout(updateModal, 2000);
    };

    setTimeout(updateModal, 1000);
}

/**
 * Open a specific artist download process modal
 */
function openArtistDownloadProcess(virtualPlaylistId) {
    const process = activeDownloadProcesses[virtualPlaylistId];
    if (process && process.modalElement) {
        // Close artist management modal first
        closeArtistDownloadModal();

        // Show the download process modal
        process.modalElement.style.display = 'flex';

        if (process.status === 'complete') {
            showToast('Review download results and click "Close" to finish.', 'info');
        }
    }
}

/**
 * Close the artist download management modal
 */
function closeArtistDownloadModal() {
    const modal = document.getElementById('artist-download-management-modal');
    if (modal) {
        modal.remove();
    }
    artistDownloadModalOpen = false;
}

/**
 * Bulk complete all downloads for an artist (when all are in 'view_results' state)
 */
function bulkCompleteArtistDownloads(artistId) {
    console.log(`🎯 Bulk completing downloads for artist: ${artistId}`);

    const artistBubbleData = artistDownloadBubbles[artistId];
    if (!artistBubbleData) {
        console.warn(`❌ No artist bubble data found for ${artistId}`);
        return;
    }

    // Find all downloads in 'view_results' state
    const completedDownloads = artistBubbleData.downloads.filter(d => d.status === 'view_results');
    console.log(`📋 Found ${completedDownloads.length} completed downloads to close:`,
        completedDownloads.map(d => d.album.name));

    if (completedDownloads.length === 0) {
        console.warn(`⚠️ No completed downloads found for bulk close`);
        showToast('No completed downloads to close', 'info');
        return;
    }

    // Programmatically close all completed modals
    completedDownloads.forEach(download => {
        const process = activeDownloadProcesses[download.virtualPlaylistId];
        if (process && process.modalElement) {
            console.log(`🗑️ Closing modal for: ${download.album.name}`);
            // Trigger the close function which handles cleanup
            closeDownloadMissingModal(download.virtualPlaylistId);
        } else {
            // No modal open — clean up the bubble entry directly
            console.log(`🧹 Direct cleanup (no modal) for: ${download.album.name}`);
            cleanupArtistDownload(download.virtualPlaylistId);
        }
    });

    showToast(`Completed ${completedDownloads.length} downloads for ${artistBubbleData.artist.name}`, 'success');
}

// ========================================
// Beatport Download Bubbles
// ========================================

/**
 * Register a new Beatport chart download for bubble management
 */
function registerBeatportDownload(chartName, chartImage, virtualPlaylistId) {
    console.log(`📝 Registering Beatport download: ${chartName}`);

    // Use chart name as key (sanitised)
    const chartKey = chartName.replace(/[^a-zA-Z0-9]/g, '_').toLowerCase();

    if (!beatportDownloadBubbles[chartKey]) {
        beatportDownloadBubbles[chartKey] = {
            chart: { name: chartName, image: chartImage || '' },
            downloads: []
        };
    }

    beatportDownloadBubbles[chartKey].downloads.push({
        virtualPlaylistId: virtualPlaylistId,
        status: 'in_progress',
        startTime: new Date()
    });

    updateBeatportDownloadsSection();
    saveBeatportBubbleSnapshot();
    monitorBeatportDownload(chartKey, virtualPlaylistId);
}

/**
 * Debounced update for Beatport downloads section
 */
function updateBeatportDownloadsSection() {
    if (beatportDownloadsUpdateTimeout) {
        clearTimeout(beatportDownloadsUpdateTimeout);
    }
    beatportDownloadsUpdateTimeout = setTimeout(() => {
        showBeatportDownloadsSection();
        updateDashboardDownloads();
    }, 300);
}

/**
 * Render Beatport download bubbles on the Beatport page
 */
function showBeatportDownloadsSection() {
    const downloadsSection = document.getElementById('beatport-downloads-section');
    if (!downloadsSection) return;

    const activeCharts = Object.keys(beatportDownloadBubbles).filter(key =>
        beatportDownloadBubbles[key].downloads.length > 0
    );

    if (activeCharts.length === 0) {
        downloadsSection.style.display = 'none';
        return;
    }

    downloadsSection.style.display = 'block';
    downloadsSection.innerHTML = `
        <div class="artist-downloads-header">
            <h3 class="artist-downloads-title">Beatport Downloads</h3>
            <p class="artist-downloads-subtitle">Active chart download processes</p>
        </div>
        <div class="artist-bubble-container" id="beatport-bubble-container">
            ${activeCharts.map(key => createBeatportBubbleCard(beatportDownloadBubbles[key])).join('')}
        </div>
    `;

    // Attach click handlers + glow
    activeCharts.forEach(chartKey => {
        const card = downloadsSection.querySelector(`[data-chart-key="${chartKey}"]`);
        if (card) {
            card.addEventListener('click', () => openBeatportBubbleModal(chartKey));
            const chartImage = beatportDownloadBubbles[chartKey].chart.image;
            if (chartImage) {
                extractImageColors(chartImage, (colors) => {
                    applyDynamicGlow(card, colors);
                });
            }
        }
    });
}

/**
 * Create HTML for a Beatport bubble card (reuses artist bubble CSS)
 */
function createBeatportBubbleCard(bubbleData) {
    const { chart, downloads } = bubbleData;
    const chartKey = chart.name.replace(/[^a-zA-Z0-9]/g, '_').toLowerCase();
    const activeCount = downloads.filter(d => d.status === 'in_progress').length;
    const completedCount = downloads.filter(d => d.status === 'view_results').length;
    const allCompleted = activeCount === 0 && completedCount > 0;

    const backgroundStyle = chart.image
        ? `background-image: url('${chart.image}');`
        : `background: linear-gradient(135deg, rgba(0, 210, 120, 0.3) 0%, rgba(0, 170, 100, 0.2) 100%);`;

    return `
        <div class="artist-bubble-card ${allCompleted ? 'all-completed' : ''}"
             data-chart-key="${chartKey}"
             title="Click to manage downloads for ${escapeHtml(chart.name)}">
            <div class="artist-bubble-image" style="${backgroundStyle}"></div>
            <div class="artist-bubble-overlay"></div>
            <div class="artist-bubble-content">
                <div class="artist-bubble-name">${escapeHtml(chart.name)}</div>
                <div class="artist-bubble-status">
                    ${activeCount > 0 ? `${activeCount} active` : ''}
                    ${completedCount > 0 ? `${completedCount} completed` : ''}
                </div>
            </div>
            ${allCompleted ? `
                <div class="bulk-complete-indicator"
                     onclick="event.stopPropagation(); bulkCompleteBeatportDownloads('${chartKey}')"
                     title="Complete all downloads">
                    <span class="bulk-complete-icon">✅</span>
                </div>
            ` : ''}
        </div>
    `;
}

/**
 * Monitor a Beatport download for completion
 */
function monitorBeatportDownload(chartKey, virtualPlaylistId) {
    const checkStatus = () => {
        const process = activeDownloadProcesses[virtualPlaylistId];
        if (!process || !beatportDownloadBubbles[chartKey]) return;

        const download = beatportDownloadBubbles[chartKey].downloads.find(d => d.virtualPlaylistId === virtualPlaylistId);
        if (!download) return;

        if (process.status === 'complete' && download.status === 'in_progress') {
            download.status = 'view_results';
            console.log(`✅ Beatport download completed for ${beatportDownloadBubbles[chartKey].chart.name}`);

            updateBeatportDownloadsSection();
            saveBeatportBubbleSnapshot();

            const allCompleted = beatportDownloadBubbles[chartKey].downloads.every(d => d.status === 'view_results');
            if (allCompleted) {
                console.log(`🟢 All Beatport downloads completed for ${beatportDownloadBubbles[chartKey].chart.name}`);
                setTimeout(updateBeatportDownloadsSection, 100);
            }
        }

        if (process.status !== 'complete') {
            setTimeout(checkStatus, 2000);
        }
    };

    setTimeout(checkStatus, 1000);
}

/**
 * Open the download modal for a Beatport chart bubble
 */
function openBeatportBubbleModal(chartKey) {
    const bubbleData = beatportDownloadBubbles[chartKey];
    if (!bubbleData) return;

    // Find the first download with an active modal
    for (const download of bubbleData.downloads) {
        const process = activeDownloadProcesses[download.virtualPlaylistId];
        if (process && process.modalElement) {
            process.modalElement.style.display = 'flex';
            if (process.status === 'complete') {
                showToast('Review download results and click "Close" to finish.', 'info');
            }
            return;
        }
    }

    showToast('No active download modal found for this chart', 'info');
}

/**
 * Bulk complete all downloads for a Beatport chart
 */
function bulkCompleteBeatportDownloads(chartKey) {
    console.log(`🎯 Bulk completing Beatport downloads for chart: ${chartKey}`);

    const bubbleData = beatportDownloadBubbles[chartKey];
    if (!bubbleData) return;

    const completedDownloads = bubbleData.downloads.filter(d => d.status === 'view_results');
    if (completedDownloads.length === 0) {
        showToast('No completed downloads to close', 'info');
        return;
    }

    completedDownloads.forEach(download => {
        const process = activeDownloadProcesses[download.virtualPlaylistId];
        if (process && process.modalElement) {
            closeDownloadMissingModal(download.virtualPlaylistId);
        } else {
            cleanupBeatportDownload(download.virtualPlaylistId);
        }
    });

    showToast(`Completed ${completedDownloads.length} downloads for ${bubbleData.chart.name}`, 'success');
}

/**
 * Clean up a Beatport download when its modal is closed
 */
function cleanupBeatportDownload(virtualPlaylistId) {
    console.log(`🔍 [CLEANUP] Looking for Beatport download to cleanup: ${virtualPlaylistId}`);

    for (const chartKey in beatportDownloadBubbles) {
        const downloads = beatportDownloadBubbles[chartKey].downloads;
        const downloadIndex = downloads.findIndex(d => d.virtualPlaylistId === virtualPlaylistId);

        if (downloadIndex !== -1) {
            downloads.splice(downloadIndex, 1);
            console.log(`🧹 [CLEANUP] Removed Beatport download from ${chartKey}. Remaining: ${downloads.length}`);

            if (downloads.length === 0) {
                delete beatportDownloadBubbles[chartKey];
                console.log(`🧹 [CLEANUP] No more downloads - removed Beatport bubble: ${chartKey}`);
            }

            updateBeatportDownloadsSection();
            saveBeatportBubbleSnapshot();
            return;
        }
    }
}

// --- Beatport Bubble Snapshot System ---

let beatportSnapshotSaveTimeout = null;

async function saveBeatportBubbleSnapshot() {
    if (beatportSnapshotSaveTimeout) {
        clearTimeout(beatportSnapshotSaveTimeout);
    }

    beatportSnapshotSaveTimeout = setTimeout(async () => {
        try {
            const bubbleCount = Object.keys(beatportDownloadBubbles).length;
            if (bubbleCount === 0) return;

            const cleanBubbles = {};
            for (const [chartKey, bubbleData] of Object.entries(beatportDownloadBubbles)) {
                cleanBubbles[chartKey] = {
                    chart: bubbleData.chart,
                    downloads: bubbleData.downloads.map(d => ({
                        virtualPlaylistId: d.virtualPlaylistId,
                        status: d.status,
                        startTime: d.startTime instanceof Date ? d.startTime.toISOString() : d.startTime
                    }))
                };
            }

            const response = await fetch('/api/beatport_bubbles/snapshot', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ bubbles: cleanBubbles })
            });

            const data = await response.json();
            if (data.success) {
                console.log(`✅ Beatport bubble snapshot saved: ${bubbleCount} charts`);
            }
        } catch (error) {
            console.error('❌ Error saving Beatport bubble snapshot:', error);
        }
    }, 1000);
}

async function hydrateBeatportBubblesFromSnapshot() {
    try {
        console.log('🔄 Loading Beatport bubble snapshot from backend...');

        const response = await fetch('/api/beatport_bubbles/hydrate');
        const data = await response.json();

        if (!data.success) {
            console.error('❌ Failed to load Beatport bubble snapshot:', data.error);
            return;
        }

        const bubbles = data.bubbles || {};
        if (Object.keys(bubbles).length === 0) {
            console.log('ℹ️ No Beatport bubbles to hydrate');
            return;
        }

        beatportDownloadBubbles = {};

        for (const [chartKey, bubbleData] of Object.entries(bubbles)) {
            beatportDownloadBubbles[chartKey] = {
                chart: bubbleData.chart,
                downloads: bubbleData.downloads.map(d => ({
                    virtualPlaylistId: d.virtualPlaylistId,
                    status: d.status,
                    startTime: new Date(d.startTime)
                }))
            };

            for (const download of bubbleData.downloads) {
                if (download.status === 'in_progress') {
                    monitorBeatportDownload(chartKey, download.virtualPlaylistId);
                }
            }
        }

        updateBeatportDownloadsSection();
        console.log(`✅ Hydrated ${Object.keys(beatportDownloadBubbles).length} Beatport download bubbles`);
    } catch (error) {
        console.error('❌ Error hydrating Beatport bubbles:', error);
    }
}

/**
 * Clean up artist download when a modal is closed
 */
function cleanupArtistDownload(virtualPlaylistId) {
    console.log(`🔍 [CLEANUP] Looking for download to cleanup: ${virtualPlaylistId}`);
    console.log(`🔍 [CLEANUP] Current artist bubbles:`, Object.keys(artistDownloadBubbles));

    // Find which artist this download belongs to
    for (const artistId in artistDownloadBubbles) {
        const downloads = artistDownloadBubbles[artistId].downloads;
        const downloadIndex = downloads.findIndex(d => d.virtualPlaylistId === virtualPlaylistId);

        console.log(`🔍 [CLEANUP] Checking artist ${artistId}: ${downloads.length} downloads`);
        downloads.forEach(d => console.log(`  - ${d.album.name} (${d.virtualPlaylistId}): ${d.status}`));

        if (downloadIndex !== -1) {
            const downloadToRemove = downloads[downloadIndex];
            console.log(`🧹 [CLEANUP] Found download to cleanup: ${downloadToRemove.album.name} (status: ${downloadToRemove.status})`);

            // Remove this download from the artist's downloads
            downloads.splice(downloadIndex, 1);
            console.log(`✅ [CLEANUP] Removed download from artist ${artistId}. Remaining: ${downloads.length}`);

            // If no more downloads for this artist, remove the bubble
            if (downloads.length === 0) {
                delete artistDownloadBubbles[artistId];
                console.log(`🧹 [CLEANUP] No more downloads - removed artist bubble: ${artistId}`);
            } else {
                console.log(`📊 [CLEANUP] Artist ${artistId} still has ${downloads.length} downloads remaining`);
            }

            // Update the downloads section
            console.log(`🔄 [CLEANUP] Updating artist downloads section...`);
            updateArtistDownloadsSection();

            // Save snapshot of updated state
            saveArtistBubbleSnapshot();
            break;
        }
    }
    console.log(`✅ [CLEANUP] Cleanup process completed for ${virtualPlaylistId}`);
}

/**
 * Force refresh all artist download statuses (useful for debugging)
 */
function refreshAllArtistDownloadStatuses() {
    console.log('🔄 Force refreshing all artist download statuses...');

    for (const artistId in artistDownloadBubbles) {
        const artistData = artistDownloadBubbles[artistId];
        let hasChanges = false;

        artistData.downloads.forEach(download => {
            const process = activeDownloadProcesses[download.virtualPlaylistId];
            if (process) {
                const expectedStatus = process.status === 'complete' ? 'view_results' : 'in_progress';
                if (download.status !== expectedStatus) {
                    console.log(`🔧 Fixing status for ${download.album.name}: ${download.status} → ${expectedStatus}`);
                    download.status = expectedStatus;
                    hasChanges = true;
                }
            }
        });

        if (hasChanges) {
            console.log(`✅ Updated statuses for ${artistData.artist.name}`);
        }
    }

    // Force update the downloads section
    showArtistDownloadsSection();
}

/**
 * Extract dominant colors from an image for dynamic glow effects
 */
async function extractImageColors(imageUrl, callback) {
    if (!imageUrl) {
        callback(getAccentFallbackColors()); // Fallback to Spotify green
        return;
    }

    // Check cache first for performance
    if (artistsPageState.cache.colors[imageUrl]) {
        callback(artistsPageState.cache.colors[imageUrl]);
        return;
    }

    try {
        // Create a canvas to analyze the image
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        const img = new Image();

        img.crossOrigin = 'anonymous';

        img.onload = function () {
            // Resize to small dimensions for faster processing
            const size = 50;
            canvas.width = size;
            canvas.height = size;

            // Draw image to canvas
            ctx.drawImage(img, 0, 0, size, size);

            try {
                // Get image data
                const imageData = ctx.getImageData(0, 0, size, size);
                const data = imageData.data;

                // Extract colors (sample every few pixels for performance)
                const colors = [];
                for (let i = 0; i < data.length; i += 16) { // Sample every 4th pixel
                    const r = data[i];
                    const g = data[i + 1];
                    const b = data[i + 2];
                    const alpha = data[i + 3];

                    // Skip transparent or very dark pixels
                    if (alpha > 128 && (r + g + b) > 150) {
                        colors.push({ r, g, b });
                    }
                }

                if (colors.length === 0) {
                    callback(getAccentFallbackColors()); // Fallback
                    return;
                }

                // Find dominant colors using a simple clustering approach
                const dominantColors = findDominantColors(colors, 2);

                // Convert to CSS hex colors
                const hexColors = dominantColors.map(color =>
                    `#${((1 << 24) + (color.r << 16) + (color.g << 8) + color.b).toString(16).slice(1)}`
                );

                // Cache the colors for future use
                artistsPageState.cache.colors[imageUrl] = hexColors;

                callback(hexColors);

            } catch (e) {
                console.warn('Color extraction failed, using fallback colors:', e);
                callback(getAccentFallbackColors());
            }
        };

        img.onerror = function () {
            callback(getAccentFallbackColors()); // Fallback on error
        };

        img.src = imageUrl;

    } catch (error) {
        console.warn('Image color extraction error:', error);
        callback(getAccentFallbackColors());
    }
}

/**
 * Simple color clustering to find dominant colors
 */
function findDominantColors(colors, numColors = 2) {
    if (colors.length === 0) return [{ r: 29, g: 185, b: 84 }];

    // Simple k-means clustering
    let centroids = [];

    // Initialize centroids randomly
    for (let i = 0; i < numColors; i++) {
        centroids.push(colors[Math.floor(Math.random() * colors.length)]);
    }

    // Run a few iterations of k-means
    for (let iteration = 0; iteration < 5; iteration++) {
        const clusters = Array(numColors).fill().map(() => []);

        // Assign each color to nearest centroid
        colors.forEach(color => {
            let minDistance = Infinity;
            let nearestCluster = 0;

            centroids.forEach((centroid, i) => {
                const distance = Math.sqrt(
                    Math.pow(color.r - centroid.r, 2) +
                    Math.pow(color.g - centroid.g, 2) +
                    Math.pow(color.b - centroid.b, 2)
                );

                if (distance < minDistance) {
                    minDistance = distance;
                    nearestCluster = i;
                }
            });

            clusters[nearestCluster].push(color);
        });

        // Update centroids
        centroids = clusters.map(cluster => {
            if (cluster.length === 0) return centroids[0]; // Fallback

            const avgR = cluster.reduce((sum, c) => sum + c.r, 0) / cluster.length;
            const avgG = cluster.reduce((sum, c) => sum + c.g, 0) / cluster.length;
            const avgB = cluster.reduce((sum, c) => sum + c.b, 0) / cluster.length;

            return { r: Math.round(avgR), g: Math.round(avgG), b: Math.round(avgB) };
        });
    }

    // Ensure we have vibrant colors by boosting saturation
    return centroids.map(color => {
        const max = Math.max(color.r, color.g, color.b);
        const min = Math.min(color.r, color.g, color.b);
        const saturation = max === 0 ? 0 : (max - min) / max;

        // Boost low saturation colors
        if (saturation < 0.4) {
            const factor = 1.3;
            return {
                r: Math.min(255, Math.round(color.r * factor)),
                g: Math.min(255, Math.round(color.g * factor)),
                b: Math.min(255, Math.round(color.b * factor))
            };
        }

        return color;
    });
}

/**
 * Apply dynamic glow effect to a card element
 */
function applyDynamicGlow(cardElement, colors) {
    if (!cardElement || colors.length < 2) return;

    const color1 = colors[0];
    const color2 = colors[1];

    // Add a small delay to make the effect feel more natural
    setTimeout(() => {
        // Create CSS custom properties for the dynamic colors
        cardElement.style.setProperty('--glow-color-1', color1);
        cardElement.style.setProperty('--glow-color-2', color2);
        cardElement.classList.add('has-dynamic-glow');

        console.log(`🎨 Applied dynamic glow: ${color1}, ${color2}`);
    }, Math.random() * 200 + 100); // Random delay between 100-300ms
}

/**
 * Utility function to escape HTML
 */
function escapeHtml(text) {
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

// --- Service Status and System Stats Functions ---

async function _forceServiceStatusRefresh() {
    // Force an immediate status refresh (bypasses WebSocket check) — used after settings save
    try {
        const response = await fetch('/status');
        if (!response.ok) return;
        const data = await response.json();
        handleServiceStatusUpdate(data);
    } catch (error) {
        console.warn('Could not force service status refresh:', error);
    }
}

async function fetchAndUpdateServiceStatus() {
    if (document.hidden) return; // Skip polling when tab is not visible
    if (socketConnected) return; // WebSocket is pushing updates — skip HTTP poll
    try {
        const response = await fetch('/status');
        if (!response.ok) return;

        const data = await response.json();

        // Update service status indicators and text (dashboard)
        updateServiceStatus('spotify', data.spotify);
        updateServiceStatus('media-server', data.media_server);
        updateServiceStatus('soulseek', data.soulseek);

        // Update sidebar service status indicators
        updateSidebarServiceStatus('spotify', data.spotify);
        updateSidebarServiceStatus('media-server', data.media_server);
        updateSidebarServiceStatus('soulseek', data.soulseek);

        // Update downloads nav badge
        if (data.active_downloads !== undefined) _updateDlNavBadge(data.active_downloads);

        // Update enrichment service cards
        if (data.enrichment) renderEnrichmentCards(data.enrichment);

        // Check for Spotify rate limit
        if (data.spotify && data.spotify.rate_limited && data.spotify.rate_limit) {
            handleSpotifyRateLimit(data.spotify.rate_limit);
        } else if (_spotifyRateLimitShown) {
            handleSpotifyRateLimit(null);
        }

    } catch (error) {
        console.warn('Could not fetch service status:', error);
    }
}

function updateServiceStatus(service, statusData) {
    const indicator = document.getElementById(`${service}-status-indicator`);
    const statusText = document.getElementById(`${service}-status-text`);

    if (indicator && statusText) {
        if (service === 'spotify' && (statusData.rate_limited || statusData.post_ban_cooldown)) {
            indicator.className = 'service-card-indicator rate-limited';
            const remaining = statusData.rate_limited
                ? formatRateLimitDuration(statusData.rate_limit?.remaining_seconds || 0)
                : formatRateLimitDuration(statusData.post_ban_cooldown);
            const phase = statusData.rate_limited ? 'paused' : 'recovering';
            const fallbackLabel = statusData.source === 'deezer' ? 'Deezer' : 'iTunes';
            statusText.textContent = `${fallbackLabel} (Spotify ${phase} \u2014 ${remaining})`;
            statusText.className = 'service-card-status-text rate-limited';
        } else if (statusData.connected) {
            indicator.className = 'service-card-indicator connected';
            statusText.textContent = `Connected (${statusData.response_time}ms)`;
            statusText.className = 'service-card-status-text connected';
        } else {
            indicator.className = 'service-card-indicator disconnected';
            statusText.textContent = 'Disconnected';
            statusText.className = 'service-card-status-text disconnected';
        }
    }

    // Update music source title based on active source
    if (service === 'spotify' && statusData.source) {
        const musicSourceTitleElement = document.getElementById('music-source-title');
        if (musicSourceTitleElement) {
            const sourceName = statusData.source === 'spotify' ? 'Spotify' : statusData.source === 'deezer' ? 'Deezer' : statusData.source === 'discogs' ? 'Discogs' : 'iTunes';
            musicSourceTitleElement.textContent = sourceName;
            currentMusicSourceName = sourceName;
        }

        // Show/hide Spotify disconnect button based on connection state
        const disconnectBtn = document.getElementById('spotify-disconnect-btn');
        if (disconnectBtn) {
            disconnectBtn.style.display = statusData.source === 'spotify' ? '' : 'none';
        }
    }

    // Update download source title on dashboard card
    if (service === 'soulseek' && statusData.source) {
        const sourceNames = { soulseek: 'Soulseek', youtube: 'YouTube', tidal: 'Tidal', qobuz: 'Qobuz', hifi: 'HiFi', deezer_dl: 'Deezer', hybrid: 'Hybrid' };
        const displayName = sourceNames[statusData.source] || 'Soulseek';
        const titleEl = document.getElementById('download-source-title');
        if (titleEl) titleEl.textContent = displayName;
    }
}

function updateSidebarServiceStatus(service, statusData) {
    const indicator = document.getElementById(`${service}-indicator`);
    if (indicator) {
        const dot = indicator.querySelector('.status-dot');
        const nameElement = indicator.querySelector('.status-name');

        if (dot) {
            if (service === 'spotify' && (statusData.rate_limited || statusData.post_ban_cooldown)) {
                dot.className = 'status-dot rate-limited';
                dot.title = statusData.rate_limited
                    ? `Spotify paused \u2014 ${formatRateLimitDuration(statusData.rate_limit?.remaining_seconds || 0)} remaining`
                    : `Spotify recovering \u2014 ${formatRateLimitDuration(statusData.post_ban_cooldown)} cooldown`;
            } else if (statusData.connected) {
                dot.className = 'status-dot connected';
                dot.title = '';
            } else {
                dot.className = 'status-dot disconnected';
                dot.title = '';
            }
        }

        // Update media server name if it's the media server indicator
        if (service === 'media-server' && statusData.type) {
            const mediaServerNameElement = document.getElementById('media-server-name');
            if (mediaServerNameElement) {
                const serverName = statusData.type.charAt(0).toUpperCase() + statusData.type.slice(1);
                mediaServerNameElement.textContent = serverName;
            }
        }

        // Update music source name in sidebar based on active source
        if (service === 'spotify' && statusData.source) {
            const musicSourceNameElement = document.getElementById('music-source-name');
            if (musicSourceNameElement) {
                const sourceName = statusData.source === 'spotify' ? 'Spotify' : statusData.source === 'deezer' ? 'Deezer' : statusData.source === 'discogs' ? 'Discogs' : 'iTunes';
                musicSourceNameElement.textContent = sourceName;
            }
        }

        // Update download source name based on configured mode
        if (service === 'soulseek' && statusData.source) {
            const sourceNames = { soulseek: 'Soulseek', youtube: 'YouTube', tidal: 'Tidal', qobuz: 'Qobuz', hifi: 'HiFi', deezer_dl: 'Deezer', hybrid: 'Hybrid' };
            const displayName = sourceNames[statusData.source] || 'Soulseek';
            const sidebarName = document.getElementById('download-source-name');
            if (sidebarName) sidebarName.textContent = displayName;
        }
    }
}

function renderEnrichmentCards(enrichment) {
    const grid = document.getElementById('enrichment-status-grid');
    if (!grid || !enrichment) return;

    // Service display order
    const serviceOrder = [
        'musicbrainz', 'spotify_enrichment', 'itunes_enrichment', 'deezer_enrichment',
        'tidal_enrichment', 'qobuz_enrichment', 'lastfm', 'genius', 'audiodb',
        'acoustid', 'listenbrainz'
    ];

    // Map service keys to their settings page selector for click-to-configure
    const settingsSelectors = {
        'spotify_enrichment': '.spotify-title',
        'tidal_enrichment': '.tidal-title',
        'qobuz_enrichment': '.qobuz-title',
        'lastfm': '.lastfm-title',
        'genius': '.genius-title',
        'acoustid': '.acoustid-title',
        'listenbrainz': '.listenbrainz-title',
    };

    const chips = [];
    for (const key of serviceOrder) {
        const svc = enrichment[key];
        if (!svc) continue;

        // Determine status class and text
        let statusClass, statusLabel;
        if ('running' in svc) {
            if (!svc.configured) {
                statusClass = 'not-configured';
                statusLabel = 'Set up';
            } else if (svc.paused) {
                statusClass = 'paused';
                statusLabel = svc.yield_reason === 'downloads' ? 'Yielding' : 'Paused';
            } else if (svc.running) {
                statusClass = svc.idle ? 'idle' : 'running';
                statusLabel = svc.idle ? 'Idle' : 'Running';
            } else {
                statusClass = 'stopped';
                statusLabel = 'Stopped';
            }
        } else {
            statusClass = svc.configured ? 'running' : 'not-configured';
            statusLabel = svc.configured ? 'Ready' : 'Set up';
        }

        const selector = settingsSelectors[key];
        const clickAttr = selector
            ? `onclick="navigateToPage('settings'); setTimeout(() => { switchSettingsTab('connections'); setTimeout(() => { const el = document.querySelector('${selector}'); if (el) el.scrollIntoView({ behavior: 'smooth', block: 'center' }); }, 100); }, 50);"`
            : '';

        // Build activity display — human-readable, not cryptic numbers
        let activityHtml = '';
        let metaHtml = '';
        const isSpotify = key === 'spotify_enrichment';

        if ('running' in svc && svc.configured) {
            const c1h = svc.calls_1h || 0;
            const c24h = svc.calls_24h || 0;

            if (isSpotify && svc.daily_budget) {
                // Spotify: show budget usage prominently
                const b = svc.daily_budget;
                const pct = Math.min(100, Math.round((b.used / b.limit) * 100));
                const barClass = b.exhausted ? 'exhausted' : pct > 80 ? 'high' : '';
                activityHtml = `<span class="enrichment-chip-activity">${b.used.toLocaleString()} / ${b.limit.toLocaleString()}</span>`;
                metaHtml = `<div class="enrichment-chip-budget">
                    <div class="enrichment-chip-budget-bar ${barClass}" style="width: ${pct}%"></div>
                </div>`;
            } else if (c24h > 0) {
                // Other services: show 24h count
                activityHtml = `<span class="enrichment-chip-activity">${c24h.toLocaleString()} / 24h</span>`;
            }
        }

        // Tooltip: full details including 1h breakdown
        let tooltipLines = [svc.name + ' — ' + statusLabel];
        if ('running' in svc && svc.configured) {
            const c1h = svc.calls_1h || 0;
            const c24h = svc.calls_24h || 0;
            if (c24h > 0 || c1h > 0) tooltipLines.push('Last hour: ' + c1h + ' · Last 24h: ' + c24h);
        }
        if (isSpotify && svc.daily_budget) {
            const b = svc.daily_budget;
            tooltipLines.push('Daily budget: ' + b.used + ' / ' + b.limit + (b.exhausted ? ' (exhausted)' : ''));
        }
        if (selector && statusClass === 'not-configured') {
            tooltipLines = ['Click to configure in Settings'];
        }

        const statusDisplay = statusClass === 'not-configured' && selector ? 'Configure →' : statusLabel;

        chips.push(`
            <div class="enrichment-chip status-${statusClass}" ${clickAttr} title="${tooltipLines.join('\n')}">
                <span class="enrichment-chip-dot"></span>
                <span class="enrichment-chip-name">${svc.name}</span>
                ${activityHtml}
                <span class="enrichment-chip-status">${statusDisplay}</span>
                ${metaHtml}
            </div>
        `);
    }

    grid.innerHTML = chips.join('');
}

// ===============================
// == API RATE MONITOR GAUGES   ==
// ===============================

const _rateMonitorState = {};
const _RATE_GAUGE_SERVICES = [
    'spotify', 'itunes', 'deezer', 'lastfm', 'genius',
    'musicbrainz', 'audiodb', 'tidal', 'qobuz', 'discogs',
];
const _RATE_GAUGE_LABELS = {
    spotify: 'Spotify', itunes: 'Apple Music', deezer: 'Deezer',
    lastfm: 'Last.fm', genius: 'Genius', musicbrainz: 'MusicBrainz',
    audiodb: 'AudioDB', tidal: 'Tidal', qobuz: 'Qobuz', discogs: 'Discogs',
};
const _RATE_GAUGE_COLORS = {
    spotify: '#1DB954', itunes: '#FC3C44', deezer: '#A238FF',
    lastfm: '#D51007', genius: '#FFFF64', musicbrainz: '#BA478F',
    audiodb: '#00BCD4', tidal: '#00FFFF', qobuz: '#FF6B35', discogs: '#D4A574',
};

// SVG constants — 240° arc, gap at bottom
const _G = { size: 160, cx: 80, cy: 84, r: 56, stroke: 8, startAngle: 240, totalArc: 240 };

function _gPt(angle, radius) {
    const rad = (angle - 90) * Math.PI / 180;
    const r = radius || _G.r;
    return { x: _G.cx + r * Math.cos(rad), y: _G.cy + r * Math.sin(rad) };
}

function _gArc(startDeg, endDeg, radius) {
    const r = radius || _G.r;
    const s = _gPt(startDeg, r), e = _gPt(endDeg, r);
    const sweep = ((endDeg - startDeg + 360) % 360);
    const large = sweep > 180 ? 1 : 0;
    return `M${s.x},${s.y} A${r},${r} 0 ${large} 1 ${e.x},${e.y}`;
}

function _handleRateMonitorUpdate(data) {
    const grid = document.getElementById('rate-monitor-grid');
    if (!grid) return;

    if (!grid.children.length) {
        for (const svc of _RATE_GAUGE_SERVICES) {
            const div = document.createElement('div');
            div.className = 'rate-gauge-card';
            div.id = `rate-gauge-${svc}`;
            div.onclick = () => _openRateModal(svc);
            grid.appendChild(div);
        }
    }

    for (const svc of _RATE_GAUGE_SERVICES) {
        const d = data[svc];
        if (!d) continue;
        _rateMonitorState[svc] = d;
        const container = document.getElementById(`rate-gauge-${svc}`);
        if (!container) continue;

        const value = d.cpm || 0;
        const max = d.limit || 60;
        const pct = Math.min(value / max, 1);
        const accent = _RATE_GAUGE_COLORS[svc] || '#888';
        const label = _RATE_GAUGE_LABELS[svc] || svc;
        const worker = d.worker || {};
        const wStatus = worker.status || 'stopped';
        const isRateLimited = d.rate_limited === true;

        // Build or update the card content
        let gaugeWrap = container.querySelector('.gauge-arc-wrap');
        if (!gaugeWrap) {
            // Full rebuild
            container.innerHTML = `
                <div class="gauge-card-header">
                    <span class="gauge-card-dot" style="background:${accent}"></span>
                    <span class="gauge-card-name">${label}</span>
                    <span class="gauge-card-status" data-status="${wStatus}">${_workerStatusLabel(wStatus, worker)}</span>
                </div>
                <div class="gauge-arc-wrap">${_buildGaugeSVG(svc, value, max)}</div>
                <div class="gauge-card-stats">
                    <div class="gauge-card-stat"><span class="gauge-card-stat-val">${value.toFixed(0)}</span><span class="gauge-card-stat-label">calls/min</span></div>
                    <div class="gauge-card-stat"><span class="gauge-card-stat-val">${worker.calls_1h || 0}</span><span class="gauge-card-stat-label">last hour</span></div>
                    <div class="gauge-card-stat"><span class="gauge-card-stat-val">${(worker.calls_24h || 0).toLocaleString()}</span><span class="gauge-card-stat-label">24h</span></div>
                </div>
                ${svc === 'spotify' && worker.daily_budget ? _buildBudgetBar(worker.daily_budget) : ''}
                ${isRateLimited ? _buildRateLimitBadge(d) : ''}
            `;
        } else {
            // Fast update — only change values
            _updateGauge(gaugeWrap, value, max, svc);

            // Update status
            const statusEl = container.querySelector('.gauge-card-status');
            if (statusEl) {
                statusEl.dataset.status = wStatus;
                statusEl.textContent = _workerStatusLabel(wStatus, worker);
            }

            // Update stats
            const statVals = container.querySelectorAll('.gauge-card-stat-val');
            if (statVals[0]) statVals[0].textContent = value.toFixed(0);
            if (statVals[1]) statVals[1].textContent = worker.calls_1h || 0;
            if (statVals[2]) statVals[2].textContent = (worker.calls_24h || 0).toLocaleString();

            // Budget bar (Spotify)
            if (svc === 'spotify' && worker.daily_budget) {
                let budgetEl = container.querySelector('.gauge-budget-bar');
                if (!budgetEl) {
                    const div = document.createElement('div');
                    div.innerHTML = _buildBudgetBar(worker.daily_budget);
                    const statsEl = container.querySelector('.gauge-card-stats');
                    if (statsEl) statsEl.after(div.firstElementChild);
                } else {
                    const b = worker.daily_budget;
                    const pctB = Math.min(100, Math.round((b.used / b.limit) * 100));
                    const fill = budgetEl.querySelector('.gauge-budget-fill');
                    if (fill) { fill.style.width = pctB + '%'; }
                    const label = budgetEl.querySelector('.gauge-budget-label');
                    if (label) label.textContent = `${b.used.toLocaleString()} / ${b.limit.toLocaleString()} daily`;
                }
            }

            // Rate limit badge
            let badge = container.querySelector('.gauge-rl-badge');
            if (isRateLimited) {
                if (!badge) {
                    const div = document.createElement('div');
                    div.innerHTML = _buildRateLimitBadge(d);
                    container.appendChild(div.firstElementChild);
                } else {
                    const mins = Math.ceil((d.rl_remaining || 0) / 60);
                    const timeEl = badge.querySelector('.gauge-rl-time');
                    if (timeEl) timeEl.textContent = mins > 60 ? `${Math.floor(mins / 60)}h ${mins % 60}m` : `${mins}m`;
                }
            } else if (badge) {
                badge.remove();
            }
        }

        container.classList.toggle('danger', pct > 0.8 || isRateLimited);
        container.classList.toggle('active', value > 0 || wStatus === 'running');
        container.classList.toggle('rate-limited', isRateLimited);
    }
}

function _workerStatusLabel(status, worker) {
    if (status === 'not_configured') return 'Not configured';
    if (status === 'paused') return worker.yield_reason === 'downloads' ? 'Yielding' : 'Paused';
    if (status === 'idle') return 'Idle';
    if (status === 'running') return 'Running';
    return 'Stopped';
}

function _buildBudgetBar(budget) {
    const pct = Math.min(100, Math.round((budget.used / budget.limit) * 100));
    const cls = budget.exhausted ? 'exhausted' : pct > 80 ? 'high' : '';
    return `<div class="gauge-budget-bar ${cls}">
        <div class="gauge-budget-fill" style="width:${pct}%"></div>
        <span class="gauge-budget-label">${budget.used.toLocaleString()} / ${budget.limit.toLocaleString()} daily</span>
    </div>`;
}

function _buildRateLimitBadge(d) {
    const mins = Math.ceil((d.rl_remaining || 0) / 60);
    const text = mins > 60 ? `${Math.floor(mins / 60)}h ${mins % 60}m` : `${mins}m`;
    return `<div class="gauge-rl-badge"><span class="gauge-rl-dot"></span>RATE LIMITED<span class="gauge-rl-time">${text}</span></div>`;
}

function _buildGaugeSVG(svc, value, max) {
    const { size, cx, cy, r, stroke, startAngle, totalArc } = _G;
    const label = _RATE_GAUGE_LABELS[svc] || svc;
    const accent = _RATE_GAUGE_COLORS[svc] || '#888';
    const pct = Math.min(value / max, 1);
    const endAngle = startAngle + pct * totalArc;
    const arcEnd = startAngle + totalArc;
    const glowId = `glow-${svc}`;

    // Endpoint dot position
    const dot = pct > 0 ? _gPt(endAngle, r) : null;

    // Gradient ID for the colored arc
    const gradId = `grad-${svc}`;

    const color = pct > 0.8 ? '#ef4444' : pct > 0.6 ? '#eab308' : accent;

    return `
        <svg viewBox="0 0 ${size} ${size}" class="rate-gauge-svg">
            <!-- Background track -->
            <path d="${_gArc(startAngle, arcEnd)}" fill="none" stroke="rgba(255,255,255,0.05)" stroke-width="${stroke}" stroke-linecap="round"/>

            <!-- Danger zone marker (last 20% of arc, subtle) -->
            <path d="${_gArc(startAngle + totalArc * 0.8, arcEnd)}" fill="none" stroke="rgba(239,68,68,0.1)" stroke-width="${stroke}" stroke-linecap="round"/>

            <!-- Active arc (CSS handles glow via drop-shadow) -->
            ${pct > 0 ? `<path class="gauge-active-arc" data-color="${color}" d="${_gArc(startAngle, endAngle)}" fill="none" stroke="${color}" stroke-width="${stroke}" stroke-linecap="round" style="filter:drop-shadow(0 0 6px ${color}60)"/>` : ''}

            <!-- Endpoint dot -->
            ${dot ? `<circle class="gauge-dot" cx="${dot.x}" cy="${dot.y}" r="5" fill="${color}" style="filter:drop-shadow(0 0 4px ${color}80)"/><circle cx="${dot.x}" cy="${dot.y}" r="2.5" fill="#fff" opacity="0.9"/>` : ''}

            <!-- Scale labels: 0 and max -->
            <text x="${_gPt(startAngle, r + 16).x}" y="${_gPt(startAngle, r + 16).y}" text-anchor="middle" dominant-baseline="middle" fill="rgba(255,255,255,0.2)" font-size="9" font-family="-apple-system,sans-serif">0</text>
            <text x="${_gPt(arcEnd, r + 16).x}" y="${_gPt(arcEnd, r + 16).y}" text-anchor="middle" dominant-baseline="middle" fill="rgba(255,255,255,0.2)" font-size="9" font-family="-apple-system,sans-serif">${max}</text>

            <!-- Center content -->
            <text class="gauge-value" x="${cx}" y="${cy - 12}" text-anchor="middle" dominant-baseline="middle">${Math.round(value)}</text>
            <text class="gauge-unit" x="${cx}" y="${cy + 6}" text-anchor="middle">/min</text>

            <!-- Service label -->
            <text class="gauge-label" x="${cx}" y="${cy + 28}" text-anchor="middle">${label}</text>
        </svg>
    `;
}

function _updateGauge(container, value, max, svc) {
    const { r, stroke, startAngle, totalArc } = _G;
    const accent = _RATE_GAUGE_COLORS[svc] || '#888';
    const pct = Math.min(value / max, 1);
    const endAngle = startAngle + pct * totalArc;
    const color = pct > 0.8 ? '#ef4444' : pct > 0.6 ? '#eab308' : accent;

    // Update center value
    const valText = container.querySelector('.gauge-value');
    if (valText) valText.textContent = Math.round(value);

    // Update active arc
    const activeArc = container.querySelector('.gauge-active-arc');
    if (pct > 0) {
        const d = _gArc(startAngle, endAngle);
        if (activeArc) {
            activeArc.setAttribute('d', d);
            activeArc.setAttribute('stroke', color);
            activeArc.style.filter = `drop-shadow(0 0 6px ${color}60)`;
        } else {
            // Rebuild the whole gauge when transitioning from 0 to active
            container.innerHTML = _buildGaugeSVG(svc, value, max);
            return;
        }
    } else if (activeArc) {
        activeArc.remove();
        // Also remove dots
        container.querySelectorAll('.gauge-dot').forEach(d => d.remove());
        const innerDot = container.querySelector('.gauge-dot + circle');
        if (innerDot) innerDot.remove();
        return;
    }

    // Update endpoint dot
    const gaugeDot = container.querySelector('.gauge-dot');
    if (pct > 0 && gaugeDot) {
        const dot = _gPt(endAngle, r);
        gaugeDot.setAttribute('cx', dot.x);
        gaugeDot.setAttribute('cy', dot.y);
        gaugeDot.setAttribute('fill', color);
        gaugeDot.style.filter = `drop-shadow(0 0 4px ${color}80)`;
        const inner = gaugeDot.nextElementSibling;
        if (inner && inner.tagName === 'circle') {
            inner.setAttribute('cx', dot.x);
            inner.setAttribute('cy', dot.y);
        }
    }
}

// ── Rate Monitor Detail Modal ──

let _rateModalService = null;
let _rateModalInterval = null;

function _openRateModal(serviceKey) {
    _rateModalService = serviceKey;
    const label = _RATE_GAUGE_LABELS[serviceKey] || serviceKey;
    const accent = _RATE_GAUGE_COLORS[serviceKey] || '#888';

    let overlay = document.getElementById('rate-modal-overlay');
    if (overlay) overlay.remove();

    overlay = document.createElement('div');
    overlay.id = 'rate-modal-overlay';
    overlay.className = 'modal-overlay';
    overlay.onclick = (e) => { if (e.target === overlay) _closeRateModal(); };

    const isSpotify = serviceKey === 'spotify';
    const currentData = _rateMonitorState[serviceKey] || {};

    overlay.innerHTML = `
        <div class="rate-modal">
            <div class="rate-modal-header">
                <div class="rate-modal-header-info">
                    <div class="rate-modal-header-dot" style="background:${accent}"></div>
                    <div>
                        <h3>${label}</h3>
                        <span class="rate-modal-header-sub">${currentData.cpm || 0} calls/min — limit ${currentData.limit || '?'}/min</span>
                    </div>
                </div>
                <button class="watch-all-close" onclick="_closeRateModal()">&times;</button>
            </div>
            <div class="rate-modal-body">
                <div class="rate-modal-section-title">24-Hour Call History</div>
                <div class="rate-modal-chart-wrap">
                    <canvas id="rate-modal-chart" width="700" height="280"></canvas>
                    <div class="rate-modal-chart-legend" id="rate-modal-chart-legend"></div>
                </div>
                ${isSpotify ? '<div class="rate-modal-section-title">Per-Endpoint Breakdown</div><div class="rate-modal-endpoints" id="rate-modal-endpoints"></div>' : ''}
            </div>
        </div>
    `;
    document.body.appendChild(overlay);

    // Fetch main history + per-endpoint histories for Spotify
    const historyPromises = [
        fetch(`/api/rate-monitor/history/${serviceKey}`).then(r => r.json())
    ];
    if (isSpotify) {
        const activeEps = Object.keys(_rateMonitorState.spotify?.endpoints || {});
        for (const ep of activeEps) {
            historyPromises.push(
                fetch(`/api/rate-monitor/history/spotify:${ep}`).then(r => r.json()).catch(() => null)
            );
        }
    }
    Promise.all(historyPromises).then(results => {
        const main = results[0];
        const epHistories = isSpotify ? results.slice(1).filter(Boolean) : [];
        _renderRateChart(main.history || [], main.rate_limit || 60, accent, epHistories);
    }).catch(() => {});

    if (isSpotify) {
        _updateSpotifyEndpoints();
        _rateModalInterval = setInterval(_updateSpotifyEndpoints, 1000);
    }
}

function _closeRateModal() {
    const overlay = document.getElementById('rate-modal-overlay');
    if (overlay) overlay.remove();
    if (_rateModalInterval) { clearInterval(_rateModalInterval); _rateModalInterval = null; }
    _rateModalService = null;
}

function _renderRateChart(history, rateLimit, accent, epHistories = []) {
    const canvas = document.getElementById('rate-modal-chart');
    if (!canvas) return;

    // HiDPI support
    const dpr = window.devicePixelRatio || 1;
    const W = 700, H = 280;
    canvas.width = W * dpr;
    canvas.height = H * dpr;
    canvas.style.width = W + 'px';
    canvas.style.height = H + 'px';
    const ctx = canvas.getContext('2d');
    ctx.scale(dpr, dpr);

    const pad = { top: 24, right: 24, bottom: 36, left: 50 };
    const plotW = W - pad.left - pad.right;
    const plotH = H - pad.top - pad.bottom;

    ctx.clearRect(0, 0, W, H);

    // Build data points
    const now = Math.floor(Date.now() / 1000);
    const start = now - 86400;
    const points = [];

    if (history.length > 0) {
        const histMap = new Map(history.map(h => [h[0], h[1]]));
        for (let t = start; t <= now; t += 300) {
            const bucket = Math.floor(t / 60) * 60;
            let sum = 0;
            for (let m = bucket; m < bucket + 300; m += 60) sum += histMap.get(m) || 0;
            points.push({ t, v: sum / 5 });
        }
    }

    const maxVal = Math.max(rateLimit * 1.15, ...points.map(p => p.v), 1);

    // Grid lines (horizontal)
    ctx.strokeStyle = 'rgba(255,255,255,0.04)';
    ctx.lineWidth = 1;
    for (let i = 1; i <= 4; i++) {
        const y = pad.top + plotH * (1 - i / 4);
        ctx.beginPath();
        ctx.moveTo(pad.left, y);
        ctx.lineTo(pad.left + plotW, y);
        ctx.stroke();
    }

    // Danger zone band
    const dangerY = pad.top + plotH * (1 - rateLimit / maxVal);
    const grad = ctx.createLinearGradient(0, pad.top, 0, dangerY);
    grad.addColorStop(0, 'rgba(239, 68, 68, 0.08)');
    grad.addColorStop(1, 'rgba(239, 68, 68, 0.02)');
    ctx.fillStyle = grad;
    ctx.fillRect(pad.left, pad.top, plotW, dangerY - pad.top);

    // Rate limit line
    ctx.strokeStyle = 'rgba(239, 68, 68, 0.5)';
    ctx.setLineDash([8, 5]);
    ctx.lineWidth = 1.5;
    ctx.beginPath();
    ctx.moveTo(pad.left, dangerY);
    ctx.lineTo(pad.left + plotW, dangerY);
    ctx.stroke();
    ctx.setLineDash([]);

    ctx.fillStyle = 'rgba(239, 68, 68, 0.6)';
    ctx.font = '10px -apple-system, sans-serif';
    ctx.textAlign = 'left';
    ctx.fillText(`Rate limit: ${rateLimit}/min`, pad.left + 6, dangerY - 6);

    // Draw area fill + line
    if (points.length > 1) {
        // Area gradient fill
        const areaGrad = ctx.createLinearGradient(0, pad.top, 0, pad.top + plotH);
        // Parse accent to rgba
        areaGrad.addColorStop(0, accent + '30');
        areaGrad.addColorStop(1, accent + '05');

        ctx.beginPath();
        points.forEach((p, i) => {
            const x = pad.left + (i / (points.length - 1)) * plotW;
            const y = pad.top + plotH * (1 - p.v / maxVal);
            if (i === 0) ctx.moveTo(x, y);
            else ctx.lineTo(x, y);
        });
        ctx.lineTo(pad.left + plotW, pad.top + plotH);
        ctx.lineTo(pad.left, pad.top + plotH);
        ctx.closePath();
        ctx.fillStyle = areaGrad;
        ctx.fill();

        // Line
        ctx.beginPath();
        points.forEach((p, i) => {
            const x = pad.left + (i / (points.length - 1)) * plotW;
            const y = pad.top + plotH * (1 - p.v / maxVal);
            if (i === 0) ctx.moveTo(x, y);
            else ctx.lineTo(x, y);
        });
        ctx.strokeStyle = accent;
        ctx.lineWidth = 2;
        ctx.lineJoin = 'round';
        ctx.stroke();

        // Glow effect
        ctx.shadowColor = accent;
        ctx.shadowBlur = 8;
        ctx.stroke();
        ctx.shadowBlur = 0;
    }

    // Per-endpoint lines (Spotify breakdown)
    const legendEl = document.getElementById('rate-modal-chart-legend');
    if (epHistories.length > 0) {
        const epColors = ['#1DB954', '#FF6B6B', '#4ECDC4', '#FFE66D', '#A78BFA', '#F97316', '#06B6D4', '#EC4899', '#F472B6', '#34D399'];
        const legendItems = [];

        epHistories.forEach((epData, idx) => {
            if (!epData || !epData.history || epData.history.length === 0) return;
            const epName = (epData.service || '').replace('spotify:', '').replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
            const color = epColors[idx % epColors.length];
            legendItems.push({ name: epName, color });

            const histMap = new Map(epData.history.map(h => [h[0], h[1]]));
            const epPoints = [];
            for (let t = start; t <= now; t += 300) {
                const bucket = Math.floor(t / 60) * 60;
                let sum = 0;
                for (let m = bucket; m < bucket + 300; m += 60) sum += histMap.get(m) || 0;
                epPoints.push({ t, v: sum / 5 });
            }

            if (epPoints.length > 1) {
                ctx.beginPath();
                epPoints.forEach((p, i) => {
                    const x = pad.left + (i / (epPoints.length - 1)) * plotW;
                    const y = pad.top + plotH * (1 - p.v / maxVal);
                    if (i === 0) ctx.moveTo(x, y);
                    else ctx.lineTo(x, y);
                });
                ctx.strokeStyle = color + 'BB';
                ctx.lineWidth = 1.5;
                ctx.lineJoin = 'round';
                ctx.stroke();
            }
        });

        // HTML legend below chart
        if (legendEl && legendItems.length > 0) {
            legendEl.innerHTML = legendItems.map(item =>
                `<span class="rate-chart-legend-item"><span class="rate-chart-legend-dot" style="background:${item.color}"></span>${item.name}</span>`
            ).join('');
        }
    } else if (legendEl) {
        legendEl.innerHTML = '';
    }

    // X-axis labels
    ctx.fillStyle = 'rgba(255,255,255,0.3)';
    ctx.font = '10px -apple-system, sans-serif';
    ctx.textAlign = 'center';
    for (let i = 0; i <= 6; i++) {
        const t = start + (86400 * i / 6);
        const x = pad.left + (i / 6) * plotW;
        const d = new Date(t * 1000);
        const hr = d.getHours();
        const label = hr === 0 ? '12am' : hr < 12 ? `${hr}am` : hr === 12 ? '12pm' : `${hr - 12}pm`;
        ctx.fillText(label, x, H - 10);
        // Subtle vertical grid
        ctx.strokeStyle = 'rgba(255,255,255,0.03)';
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.moveTo(x, pad.top);
        ctx.lineTo(x, pad.top + plotH);
        ctx.stroke();
    }

    // Y-axis labels
    ctx.fillStyle = 'rgba(255,255,255,0.3)';
    ctx.textAlign = 'right';
    ctx.font = '10px -apple-system, sans-serif';
    for (let i = 0; i <= 4; i++) {
        const v = maxVal * i / 4;
        const y = pad.top + plotH * (1 - i / 4);
        ctx.fillText(Math.round(v), pad.left - 8, y + 4);
    }

    // Empty state
    if (points.length === 0) {
        ctx.fillStyle = 'rgba(255,255,255,0.15)';
        ctx.font = '13px -apple-system, sans-serif';
        ctx.textAlign = 'center';
        ctx.fillText('No call history yet — data populates as API calls are made', W / 2, H / 2);
    }
}

function _updateSpotifyEndpoints() {
    const container = document.getElementById('rate-modal-endpoints');
    if (!container) return;
    const endpoints = _rateMonitorState.spotify?.endpoints || {};
    const entries = Object.entries(endpoints).sort((a, b) => b[1] - a[1]);

    if (entries.length === 0) {
        container.innerHTML = '<div class="rate-modal-ep-empty">No active Spotify endpoints — start an enrichment worker or search to see activity</div>';
        return;
    }

    const limit = _rateMonitorState.spotify?.limit || 171;
    container.innerHTML = entries.map(([ep, cpm]) => {
        const pct = Math.min(cpm / limit * 100, 100);
        const name = ep.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
        const color = pct > 80 ? '#ef4444' : pct > 60 ? '#eab308' : '#1DB954';
        return `<div class="rate-modal-ep">
            <span class="rate-modal-ep-name">${name}</span>
            <div class="rate-modal-ep-bar"><div class="rate-modal-ep-fill" style="width:${pct}%;background:${color}"></div></div>
            <span class="rate-modal-ep-value">${Math.round(cpm)}/min</span>
        </div>`;
    }).join('');
}

async function fetchAndUpdateSystemStats() {
    if (socketConnected) return; // WebSocket handles this
    if (document.hidden) return; // Skip polling when tab is not visible
    try {
        const response = await fetch('/api/system/stats');
        if (!response.ok) return;

        const data = await response.json();

        // Update all stat cards
        updateStatCard('active-downloads-card', data.active_downloads, 'Currently downloading');
        updateStatCard('finished-downloads-card', data.finished_downloads, 'Completed this session');
        updateStatCard('download-speed-card', data.download_speed, 'Combined speed');
        updateStatCard('active-syncs-card', data.active_syncs, 'Playlists syncing');
        updateStatCard('uptime-card', data.uptime, 'Application runtime');
        updateStatCard('memory-card', data.memory_usage, 'Current usage');

    } catch (error) {
        console.warn('Could not fetch system stats:', error);
    }
}

function updateStatCard(cardId, value, subtitle) {
    const card = document.getElementById(cardId);
    if (card) {
        const valueElement = card.querySelector('.stat-card-value');
        const subtitleElement = card.querySelector('.stat-card-subtitle');

        if (valueElement) {
            valueElement.textContent = value;
        }
        if (subtitleElement) {
            subtitleElement.textContent = subtitle;
        }
    }
}

async function fetchAndUpdateActivityFeed() {
    if (socketConnected) return; // WebSocket handles this
    if (document.hidden) return; // Skip polling when tab is not visible
    try {
        const response = await fetch('/api/activity/feed');
        if (!response.ok) {
            console.warn('Activity feed response not ok:', response.status, response.statusText);
            return;
        }

        const data = await response.json();
        console.log('Activity feed data received:', data);
        updateActivityFeed(data.activities || []);

    } catch (error) {
        console.warn('Could not fetch activity feed:', error);
    }
}

// Cache last feed signature to avoid unnecessary DOM rebuilds (prevents blink)
let _lastActivityFeedSig = '';

function updateActivityFeed(activities) {
    const feedContainer = document.getElementById('dashboard-activity-feed');
    if (!feedContainer) return;

    if (activities.length === 0) {
        if (_lastActivityFeedSig === 'empty') return;
        _lastActivityFeedSig = 'empty';
        feedContainer.innerHTML = `
            <div class="activity-item">
                <span class="activity-icon">📊</span>
                <div class="activity-text-content">
                    <p class="activity-title">System Started</p>
                    <p class="activity-subtitle">Dashboard initialized successfully</p>
                </div>
                <p class="activity-time">Just now</p>
            </div>
        `;
        return;
    }

    const items = activities.slice(0, 5);
    // Build signature from titles+subtitles to detect actual changes
    const sig = items.map(a => a.title + a.subtitle).join('|');
    const feedChanged = sig !== _lastActivityFeedSig;
    _lastActivityFeedSig = sig;

    if (!feedChanged) {
        // Just update timestamps without rebuilding DOM
        const timeEls = feedContainer.querySelectorAll('.activity-time');
        items.forEach((activity, i) => {
            if (timeEls[i]) timeEls[i].textContent = timeAgo(activity.time);
        });
        return;
    }

    // Full rebuild only when feed content actually changed
    feedContainer.innerHTML = '';
    items.forEach((activity, index) => {
        const activityElement = document.createElement('div');
        activityElement.className = 'activity-item';
        activityElement.innerHTML = `
            <span class="activity-icon">${escapeHtml(activity.icon)}</span>
            <div class="activity-text-content">
                <p class="activity-title">${escapeHtml(activity.title)}</p>
                <p class="activity-subtitle">${escapeHtml(activity.subtitle)}</p>
            </div>
            <p class="activity-time">${timeAgo(activity.time)}</p>
        `;
        feedContainer.appendChild(activityElement);

        if (index < items.length - 1) {
            const separator = document.createElement('div');
            separator.className = 'activity-separator';
            feedContainer.appendChild(separator);
        }
    });
}

async function checkForActivityToasts() {
    if (socketConnected) return; // WebSocket handles this (instant push)
    if (document.hidden) return; // Skip polling when tab is not visible
    try {
        const response = await fetch('/api/activity/toasts');
        if (!response.ok) return;

        const data = await response.json();
        const toasts = data.toasts || [];

        toasts.forEach(activity => {
            // Convert activity to toast type based on icon/title
            let toastType = 'info';
            if (activity.icon === '✅' || activity.title.includes('Complete')) {
                toastType = 'success';
            } else if (activity.icon === '❌' || activity.title.includes('Failed') || activity.title.includes('Error')) {
                toastType = 'error';
            } else if (activity.icon === '🚫' || activity.title.includes('Cancelled')) {
                toastType = 'warning';
            }

            // Show toast with activity info
            showToast(`${activity.title}: ${activity.subtitle}`, toastType);
        });

    } catch (error) {
        // Silently fail for toast checking to avoid spam
    }
}

// --- Watchlist Functions ---

/**
 * Toggle an artist's watchlist status
 */
async function toggleWatchlist(event, artistId, artistName) {
    // Prevent event bubbling to parent card
    event.stopPropagation();

    const button = event.currentTarget;
    const icon = button.querySelector('.watchlist-icon');
    const text = button.querySelector('.watchlist-text');

    // Show loading state
    const originalText = text.textContent;
    text.textContent = 'Loading...';
    button.disabled = true;

    try {
        // Check current status
        const checkResponse = await fetch('/api/watchlist/check', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ artist_id: artistId })
        });

        const checkData = await checkResponse.json();
        if (!checkData.success) {
            throw new Error(checkData.error || 'Failed to check watchlist status');
        }

        const isWatching = checkData.is_watching;

        // Toggle watchlist status
        const endpoint = isWatching ? '/api/watchlist/remove' : '/api/watchlist/add';
        const payload = isWatching ?
            { artist_id: artistId } :
            { artist_id: artistId, artist_name: artistName };

        const response = await fetch(endpoint, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload)
        });

        const data = await response.json();
        if (!data.success) {
            throw new Error(data.error || 'Failed to update watchlist');
        }

        // Update button appearance
        const gearBtn = button.parentElement?.querySelector('.watchlist-settings-btn');
        if (isWatching) {
            // Was watching, now removed
            icon.textContent = '👁️';
            text.textContent = 'Add to Watchlist';
            button.classList.remove('watching');
            if (gearBtn) gearBtn.classList.add('hidden');
            console.log(`❌ Removed ${artistName} from watchlist`);
        } else {
            // Was not watching, now added
            icon.textContent = '👁️';
            text.textContent = 'Watching...';
            button.classList.add('watching');
            if (gearBtn) gearBtn.classList.remove('hidden');
            console.log(`✅ Added ${artistName} to watchlist`);
        }

        // Update dashboard watchlist count
        updateWatchlistButtonCount();

    } catch (error) {
        console.error('Error toggling watchlist:', error);
        text.textContent = originalText;

        // Show error feedback
        const originalBackground = button.style.background;
        button.style.background = 'rgba(255, 59, 48, 0.3)';
        setTimeout(() => {
            button.style.background = originalBackground;
        }, 2000);
    } finally {
        button.disabled = false;
    }
}

/**
 * Update the watchlist button count on dashboard
 */
async function updateWatchlistButtonCount() {
    if (document.hidden) return; // Skip polling when tab is not visible
    if (socketConnected) return; // WebSocket is pushing updates — skip HTTP poll
    try {
        const response = await fetch('/api/watchlist/count');
        const data = await response.json();

        if (data.success) {
            _updateHeroBtnCount('watchlist-button', 'watchlist-badge', data.count);
            const watchlistButton = document.getElementById('watchlist-button');
            if (watchlistButton) {
                const countdownText = data.next_run_in_seconds ? formatCountdownTime(data.next_run_in_seconds) : '';
                if (countdownText) {
                    watchlistButton.title = `Next auto-scan in ${countdownText}`;
                }
            }
        }
    } catch (error) {
        console.error('Error updating watchlist count:', error);
    }
}

/**
 * Check and update watchlist status for all visible artist cards
 */
async function updateArtistCardWatchlistStatus() {
    const artistCards = document.querySelectorAll('.artist-card');
    const artistIds = [];
    for (const card of artistCards) {
        const artistId = card.dataset.artistId;
        if (artistId) artistIds.push(artistId);
    }
    if (!artistIds.length) return;

    try {
        const response = await fetch('/api/watchlist/check-batch', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ artist_ids: artistIds })
        });

        const data = await response.json();
        if (data.success && data.results) {
            for (const card of artistCards) {
                const artistId = card.dataset.artistId;
                if (!artistId) continue;

                const button = card.querySelector('.watchlist-toggle-btn');
                if (!button) continue;
                const icon = button.querySelector('.watchlist-icon');
                const text = button.querySelector('.watchlist-text');

                const gearBtn = button.parentElement?.querySelector('.watchlist-settings-btn');
                if (data.results[artistId]) {
                    if (icon) icon.textContent = '👁️';
                    if (text) text.textContent = 'Watching...';
                    button.classList.add('watching');
                    if (gearBtn) gearBtn.classList.remove('hidden');
                } else {
                    if (icon) icon.textContent = '👁️';
                    if (text) text.textContent = 'Add to Watchlist';
                    button.classList.remove('watching');
                    if (gearBtn) gearBtn.classList.add('hidden');
                }
            }
        }
    } catch (error) {
        console.error('Error batch checking watchlist status:', error);
    }
}

/**
 * Show watchlist modal
 */
async function showWatchlistModal() {
    try {
        // Check if watchlist has any artists
        const countResponse = await fetch('/api/watchlist/count');
        const countData = await countResponse.json();

        if (!countData.success) {
            console.error('Error getting watchlist count:', countData.error);
            return;
        }

        if (countData.count === 0) {
            // Show empty state message
            alert('Your watchlist is empty!\n\nAdd artists to your watchlist from the Artists page to monitor them for new releases.');
            return;
        }

        // Get watchlist artists
        const artistsResponse = await fetch('/api/watchlist/artists');
        const artistsData = await artistsResponse.json();

        if (!artistsData.success) {
            console.error('Error getting watchlist artists:', artistsData.error);
            return;
        }

        // Create modal if it doesn't exist
        let modal = document.getElementById('watchlist-modal');
        if (!modal) {
            modal = document.createElement('div');
            modal.id = 'watchlist-modal';
            modal.className = 'modal-overlay';
            document.body.appendChild(modal);
        }

        // Get scan status and global config
        const statusResponse = await fetch('/api/watchlist/scan/status');
        const statusData = await statusResponse.json();
        const scanStatus = statusData.success ? statusData.status : 'idle';

        let globalOverrideActive = false;
        try {
            const globalConfigResponse = await fetch('/api/watchlist/global-config');
            const globalConfigData = await globalConfigResponse.json();
            globalOverrideActive = globalConfigData.success && globalConfigData.config.global_override_enabled;
        } catch (e) {
            console.debug('Could not fetch global config:', e);
        }

        // Format countdown timer
        const nextRunSeconds = countData.next_run_in_seconds || 0;
        const countdownText = formatCountdownTime(nextRunSeconds);

        // Build modal content
        modal.innerHTML = `
            <div class="modal-container playlist-modal watchlist-fullscreen">
                <div class="playlist-modal-header">
                    <div class="playlist-header-content" style="width: 100%;">
                        <h2><svg class="watchlist-header-icon" width="24" height="24" viewBox="0 0 24 24" fill="rgb(var(--accent-rgb))"><path d="M12 4.5C7 4.5 2.73 7.61 1 12c1.73 4.39 6 7.5 11 7.5s9.27-3.11 11-7.5c-1.73-4.39-6-7.5-11-7.5zM12 17c-2.76 0-5-2.24-5-5s2.24-5 5-5 5 2.24 5 5-2.24 5-5 5zm0-8c-1.66 0-3 1.34-3 3s1.34 3 3 3 3-1.34 3-3-1.34-3-3-3z"/></svg> Watchlist</h2>
                        <div class="playlist-quick-info">
                            <span class="playlist-track-count">${countData.count} artist${countData.count !== 1 ? 's' : ''}</span>
                            <span class="playlist-owner" id="watchlist-next-auto-timer">Next Auto${countdownText ? ': ' + countdownText : ''}</span>
                        </div>
                        <div class="playlist-modal-sync-status" id="watchlist-scan-status" style="display: ${scanStatus !== 'idle' ? 'flex' : 'none'}; flex-direction: column; align-items: center;">
                            <!-- Live Visual Activity Display -->
                            <div id="watchlist-live-activity" class="watchlist-live-activity" style="display: ${scanStatus === 'scanning' ? 'flex' : 'none'};">
                                <!-- Artist Photo -->
                                <div class="watchlist-live-activity-col">
                                    <img id="watchlist-artist-img" class="watchlist-live-activity-artist-img" src="" alt="Artist" onerror="this.style.display='none';" />
                                    <div id="watchlist-artist-name" class="watchlist-live-activity-label">Waiting...</div>
                                </div>

                                <!-- Album Cover -->
                                <div class="watchlist-live-activity-col">
                                    <img id="watchlist-album-img" class="watchlist-live-activity-album-img" src="" alt="Album" onerror="this.style.display='none';" />
                                    <div id="watchlist-album-name" class="watchlist-live-activity-label">Waiting...</div>
                                </div>

                                <!-- Track and Wishlist Feed -->
                                <div class="watchlist-live-activity-feed">
                                    <div class="watchlist-live-activity-feed-label">Current Track:</div>
                                    <div id="watchlist-track-name" class="watchlist-live-activity-track">Waiting...</div>

                                    <div class="watchlist-live-activity-feed-label-orange">✨ Recently Added:</div>
                                    <div id="watchlist-additions-feed" style="max-height: 80px; overflow-y: auto; display: flex; flex-direction: column; gap: 4px; font-size: 10px;">
                                        <!-- Populated by JavaScript -->
                                    </div>
                                </div>
                            </div>

                            ${statusData.summary ? `
                                <div class="scan-status-summary" style="margin-top: 8px; font-size: 13px; opacity: 0.8;">
                                    <span class="sync-stat">Artists: ${statusData.summary.total_artists || 0}</span>
                                    <span class="sync-separator"> • </span>
                                    <span class="sync-stat">New tracks: ${statusData.summary.new_tracks_found || 0}</span>
                                    <span class="sync-separator"> • </span>
                                    <span class="sync-stat">Added to wishlist: ${statusData.summary.tracks_added_to_wishlist || 0}</span>
                                </div>
                            ` : ''}
                        </div>
                    </div>
                    <span class="playlist-modal-close" onclick="closeWatchlistModal()">&times;</span>
                </div>

                <div class="playlist-modal-body">
                    <div class="watchlist-actions" style="margin-bottom: 16px; display: flex; gap: 12px; align-items: center; padding: 12px 32px; flex-wrap: wrap;">
                        <button class="playlist-modal-btn playlist-modal-btn-primary watchlist-btn-scan ${scanStatus === 'scanning' ? 'btn-processing' : ''}"
                                id="scan-watchlist-btn"
                                onclick="startWatchlistScan()"
                                ${scanStatus === 'scanning' ? 'disabled' : ''}>
                            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>
                            ${scanStatus === 'scanning' ? 'Scanning...' : 'Scan for New Releases'}
                        </button>
                        <button class="playlist-modal-btn playlist-modal-btn-secondary watchlist-btn-cancel"
                                id="cancel-watchlist-scan-btn"
                                onclick="cancelWatchlistScan()"
                                style="display: ${scanStatus === 'scanning' ? '' : 'none'};">
                            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/></svg>
                            Cancel Scan
                        </button>
                        <button class="playlist-modal-btn playlist-modal-btn-secondary watchlist-btn-similar"
                                id="update-similar-artists-btn"
                                onclick="updateSimilarArtists()"
                                ${scanStatus === 'scanning' ? 'disabled' : ''}>
                            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>
                            Update Similar Artists
                        </button>
                        <button class="playlist-modal-btn playlist-modal-btn-secondary watchlist-btn-settings ${globalOverrideActive ? 'watchlist-global-settings-active' : ''}"
                                id="watchlist-global-settings-btn"
                                onclick="openWatchlistGlobalSettingsModal()">
                            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1 0 2.83 2 2 0 0 1-2.83 0l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-2 2 2 2 0 0 1-2-2v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83 0 2 2 0 0 1 0-2.83l.06-.06A1.65 1.65 0 0 0 4.68 15a1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1-2-2 2 2 0 0 1 2-2h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 0-2.83 2 2 0 0 1 2.83 0l.06.06A1.65 1.65 0 0 0 9 4.68a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 2-2 2 2 0 0 1 2 2v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 0 2 2 0 0 1 0 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82V9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 2 2 2 2 0 0 1-2 2h-.09a1.65 1.65 0 0 0-1.51 1z"/></svg>
                            ${globalOverrideActive ? 'Global Override ON' : 'Global Settings'}
                        </button>
                    </div>

                    ${globalOverrideActive ? `
                    <div class="watchlist-global-override-banner" style="margin: 0 32px 12px;">
                        <span>⚠️</span>
                        <span>Global override is active — per-artist settings are being ignored during scans.</span>
                    </div>
                    ` : ''}

                    <!-- Search Bar -->
                    <div class="watchlist-search-container" style="margin-bottom: 12px;">
                        <svg class="watchlist-search-icon" width="16" height="16" viewBox="0 0 24 24" fill="rgba(255,255,255,0.35)"><path d="M15.5 14h-.79l-.28-.27A6.471 6.471 0 0016 9.5 6.5 6.5 0 109.5 16c1.61 0 3.09-.59 4.23-1.57l.27.28v.79l5 4.99L20.49 19l-4.99-5zm-6 0C7.01 14 5 11.99 5 9.5S7.01 5 9.5 5 14 7.01 14 9.5 11.99 14 9.5 14z"/></svg>
                        <input type="text"
                               id="watchlist-search-input"
                               class="watchlist-search-input"
                               placeholder="Search watchlist..."
                               oninput="filterWatchlistArtists()">
                    </div>

                    <!-- Batch action bar -->
                    <div class="watchlist-batch-bar" id="watchlist-batch-bar">
                        <label class="watchlist-select-all-label" onclick="event.stopPropagation();">
                            <input type="checkbox" id="watchlist-select-all-cb" onchange="toggleWatchlistSelectAll(this.checked)">
                            <span>Select All</span>
                        </label>
                        <span class="watchlist-batch-count" id="watchlist-batch-count"></span>
                        <button class="playlist-modal-btn playlist-modal-btn-secondary watchlist-batch-remove-btn"
                                id="watchlist-batch-remove-btn"
                                onclick="batchRemoveFromWatchlist()"
                                style="display: none;">
                            Remove Selected
                        </button>
                    </div>

                    <div class="watchlist-artists-grid" id="watchlist-artists-list">
                        ${artistsData.artists.map(artist => {
                            const pills = [];
                            if (artist.include_albums) pills.push('<span class="watchlist-pill watchlist-pill-active">Albums</span>');
                            if (artist.include_eps) pills.push('<span class="watchlist-pill watchlist-pill-active">EPs</span>');
                            if (artist.include_singles) pills.push('<span class="watchlist-pill watchlist-pill-active">Singles</span>');
                            if (artist.include_live) pills.push('<span class="watchlist-pill watchlist-pill-filter">Live</span>');
                            if (artist.include_remixes) pills.push('<span class="watchlist-pill watchlist-pill-filter">Remixes</span>');
                            if (artist.include_acoustic) pills.push('<span class="watchlist-pill watchlist-pill-filter">Acoustic</span>');
                            if (artist.include_compilations) pills.push('<span class="watchlist-pill watchlist-pill-filter">Compilations</span>');
                            const sourceBadges = [];
                            if (artist.spotify_artist_id) sourceBadges.push('<span class="watchlist-source-badge watchlist-source-spotify">Spotify</span>');
                            if (artist.itunes_artist_id) sourceBadges.push('<span class="watchlist-source-badge watchlist-source-itunes">iTunes</span>');
                            if (artist.deezer_artist_id) sourceBadges.push('<span class="watchlist-source-badge watchlist-source-deezer">Deezer</span>');
                            if (artist.discogs_artist_id) sourceBadges.push('<span class="watchlist-source-badge watchlist-source-discogs">Discogs</span>');
                            const artistPrimaryId = artist.spotify_artist_id || artist.itunes_artist_id || artist.deezer_artist_id || artist.discogs_artist_id;
                            return `
                            <div class="watchlist-artist-card"
                                 data-artist-name="${artist.artist_name.toLowerCase().replace(/"/g, '&quot;')}"
                                 data-artist-id="${artistPrimaryId}">

                                <label class="watchlist-card-checkbox" onclick="event.stopPropagation();">
                                    <input type="checkbox" class="watchlist-select-cb"
                                           data-artist-id="${artistPrimaryId}"
                                           data-artist-name="${escapeHtml(artist.artist_name)}"
                                           onchange="updateWatchlistBatchBar()">
                                    <span class="watchlist-checkbox-custom"></span>
                                </label>

                                <button class="watchlist-card-gear"
                                        data-artist-id="${artistPrimaryId}"
                                        data-artist-name="${escapeHtml(artist.artist_name)}"
                                        onclick="event.stopPropagation();"
                                        title="Artist settings">
                                    <svg viewBox="0 0 24 24"><path d="M19.14 12.94c.04-.3.06-.61.06-.94 0-.32-.02-.64-.07-.94l2.03-1.58a.49.49 0 00.12-.61l-1.92-3.32a.49.49 0 00-.59-.22l-2.39.96c-.5-.38-1.03-.7-1.62-.94l-.36-2.54a.48.48 0 00-.48-.41h-3.84a.48.48 0 00-.48.41l-.36 2.54c-.59.24-1.13.57-1.62.94l-2.39-.96a.49.49 0 00-.59.22L2.74 8.87a.48.48 0 00.12.61l2.03 1.58c-.05.3-.07.62-.07.94s.02.64.07.94l-2.03 1.58a.49.49 0 00-.12.61l1.92 3.32c.12.22.37.29.59.22l2.39-.96c.5.38 1.03.7 1.62.94l.36 2.54c.05.24.26.41.48.41h3.84c.24 0 .44-.17.48-.41l.36-2.54c.59-.24 1.13-.56 1.62-.94l2.39.96c.22.08.47 0 .59-.22l1.92-3.32c.12-.22.07-.47-.12-.61l-2.01-1.58zM12 15.6A3.6 3.6 0 1115.6 12 3.6 3.6 0 0112 15.6z"/></svg>
                                </button>

                                <div class="watchlist-card-image">
                                    ${artist.image_url ? `
                                        <img src="${artist.image_url}"
                                             alt="${escapeHtml(artist.artist_name)}"
                                             loading="lazy"
                                             onerror="this.parentElement.innerHTML='<div class=\\'watchlist-card-image-fallback\\'>🎤</div>';">
                                    ` : `
                                        <div class="watchlist-card-image-fallback">🎤</div>
                                    `}
                                </div>

                                <div class="watchlist-card-info">
                                    <span class="watchlist-card-name">${escapeHtml(artist.artist_name)}</span>
                                    <span class="watchlist-card-meta">${formatRelativeScanTime(artist.last_scan_timestamp)}</span>
                                </div>
                                ${sourceBadges.length > 0 ? `<div class="watchlist-card-sources">${sourceBadges.join('')}</div>` : ''}
                                ${pills.length > 0 ? `<div class="watchlist-card-pills">${pills.join('')}</div>` : ''}
                            </div>
                        `}).join('')}
                    </div>
                </div>
            </div>
        `;

        // Add event listeners for gear buttons
        modal.querySelectorAll('.watchlist-card-gear').forEach(button => {
            button.addEventListener('click', () => {
                const artistId = button.getAttribute('data-artist-id');
                const artistName = button.getAttribute('data-artist-name');
                openWatchlistArtistConfigModal(artistId, artistName);
            });
        });

        // Add click handlers to artist cards (except for gear button or checkbox)
        modal.querySelectorAll('.watchlist-artist-card').forEach(item => {
            item.addEventListener('click', (e) => {
                if (e.target.closest('.watchlist-card-gear') || e.target.closest('.watchlist-card-checkbox')) {
                    return;
                }

                const artistId = item.getAttribute('data-artist-id');
                const artistName = item.querySelector('.watchlist-card-name').textContent;

                console.log(`🎵 Artist card clicked: ${artistName} (${artistId})`);
                openWatchlistArtistDetailView(artistId, artistName);
            });
        });

        // Show modal
        modal.style.display = 'flex';

        // Start countdown timer update interval
        startWatchlistCountdownTimer(nextRunSeconds);

        // Start polling for scan status if scanning
        if (scanStatus === 'scanning') {
            pollWatchlistScanStatus();
        }

    } catch (error) {
        console.error('Error showing watchlist modal:', error);
    }
}

function startWatchlistCountdownTimer(initialSeconds) {
    // Clear any existing interval
    if (watchlistCountdownInterval) {
        clearInterval(watchlistCountdownInterval);
    }

    let remainingSeconds = initialSeconds;

    watchlistCountdownInterval = setInterval(async () => {
        remainingSeconds--;

        if (remainingSeconds <= 0) {
            // Timer expired, fetch fresh data
            try {
                const response = await fetch('/api/watchlist/count');
                const data = await response.json();
                remainingSeconds = data.next_run_in_seconds || 0;

                const timerElement = document.getElementById('watchlist-next-auto-timer');
                if (timerElement) {
                    const countdownText = formatCountdownTime(remainingSeconds);
                    timerElement.textContent = `Next Auto${countdownText ? ': ' + countdownText : ''}`;
                }
            } catch (error) {
                console.debug('Error updating watchlist countdown:', error);
            }
        } else {
            // Update the display
            const timerElement = document.getElementById('watchlist-next-auto-timer');
            if (timerElement) {
                const countdownText = formatCountdownTime(remainingSeconds);
                timerElement.textContent = `Next Auto${countdownText ? ': ' + countdownText : ''}`;
            }
        }
    }, 1000); // Update every second
}

/**
 * Close watchlist modal
 */
function closeWatchlistModal() {
    // Stop countdown timer
    if (watchlistCountdownInterval) {
        clearInterval(watchlistCountdownInterval);
        watchlistCountdownInterval = null;
    }

    const modal = document.getElementById('watchlist-modal');
    if (modal) {
        modal.style.display = 'none';
    }
}

/**
 * Populate the linked provider section in the watchlist config modal.
 * Shows which Spotify/iTunes/Deezer artist is linked and allows changing it.
 */
function _populateLinkedProviderSection(artistId, artistName, spotifyId, itunesId, artistInfo, deezerId, discogsId) {
    const section = document.getElementById('watchlist-linked-provider-section');
    const content = document.getElementById('watchlist-linked-provider-content');
    if (!section || !content) return;

    section.style.display = '';

    const sources = [
        { key: 'spotify', label: 'Spotify', icon: '🟢', id: spotifyId || '', color: '#1db954' },
        { key: 'itunes', label: 'Apple Music', icon: '🔴', id: itunesId || '', color: '#fc3c44' },
        { key: 'deezer', label: 'Deezer', icon: '🟣', id: deezerId || '', color: '#a238ff' },
        { key: 'discogs', label: 'Discogs', icon: '🟤', id: discogsId || '', color: '#b08968' },
    ];

    let html = '<div class="wl-linked-sources">';
    for (const src of sources) {
        const matched = !!src.id;
        const shortId = src.id ? (src.id.length > 16 ? src.id.substring(0, 14) + '...' : src.id) : '';
        html += `
            <div class="wl-linked-row ${matched ? 'matched' : 'unmatched'}" data-source="${src.key}">
                <span class="wl-linked-icon">${src.icon}</span>
                <span class="wl-linked-label">${src.label}</span>
                <span class="wl-linked-status">${matched
                    ? `<span class="wl-linked-id" title="${escapeHtml(src.id)}">${shortId}</span>`
                    : '<span class="wl-linked-none">Not matched</span>'
                }</span>
                <button class="wl-linked-fix-btn" onclick="_openSourceSearch('${src.key}', '${escapeForInlineJs(artistId)}', '${escapeForInlineJs(artistName)}')">${matched ? 'Fix' : 'Match'}</button>
                ${matched ? `<button class="wl-linked-clear-btn" onclick="_clearSourceMatch('${src.key}', '${escapeForInlineJs(artistId)}', '${escapeForInlineJs(artistName)}')" title="Clear this match">&times;</button>` : ''}
            </div>`;
    }
    html += '</div>';

    // Per-source search panel (hidden, populated on Fix/Match click)
    html += `<div class="wl-linked-search-panel" id="wl-linked-search-panel" style="display:none">
        <div class="wl-linked-search-header">
            <span id="wl-linked-search-title">Search</span>
            <button class="wl-linked-search-close" onclick="document.getElementById('wl-linked-search-panel').style.display='none'">&times;</button>
        </div>
        <div class="wl-linked-search-input-row">
            <input type="text" id="wl-linked-search-input" class="watchlist-linked-search-input"
                   placeholder="Search..." value="${escapeHtml(artistName)}">
            <button class="watchlist-linked-search-btn" id="wl-linked-search-go">Search</button>
        </div>
        <div class="wl-linked-search-results" id="wl-linked-search-results"></div>
    </div>`;

    content.innerHTML = html;
}

/**
 * Open per-source search panel for fixing a specific provider match.
 */
function _openSourceSearch(sourceKey, artistId, artistName) {
    const panel = document.getElementById('wl-linked-search-panel');
    if (!panel) return;
    const labels = { spotify: 'Spotify', itunes: 'Apple Music', deezer: 'Deezer', discogs: 'Discogs' };
    document.getElementById('wl-linked-search-title').textContent = `Search ${labels[sourceKey] || sourceKey}`;
    const input = document.getElementById('wl-linked-search-input');
    input.value = artistName;
    document.getElementById('wl-linked-search-results').innerHTML = '';
    panel.style.display = '';
    panel.dataset.source = sourceKey;
    panel.dataset.artistId = artistId;
    panel.dataset.artistName = artistName;
    input.focus();
    input.select();

    const doSearch = () => _searchSourceArtists(sourceKey, artistId);
    document.getElementById('wl-linked-search-go').onclick = doSearch;
    input.onkeydown = (e) => { if (e.key === 'Enter') doSearch(); };
}

async function _searchSourceArtists(sourceKey, watchlistArtistId) {
    const input = document.getElementById('wl-linked-search-input');
    const container = document.getElementById('wl-linked-search-results');
    const query = input?.value?.trim();
    if (!query || !container) return;

    container.innerHTML = '<div style="padding:12px;color:#888;text-align:center">Searching...</div>';

    try {
        const response = await fetch('/api/library/search-service', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ service: sourceKey, entity_type: 'artist', query })
        });
        const data = await response.json();
        if (!data.success) throw new Error(data.error);

        const results = data.results || [];
        if (!results.length) {
            container.innerHTML = '<div style="padding:12px;color:#888;text-align:center">No artists found</div>';
            return;
        }

        let html = '';
        for (const r of results) {
            html += `<div class="watchlist-linked-search-result" data-id="${escapeHtml(r.id)}" data-name="${escapeHtml(r.name)}">
                ${r.image ? `<img src="${r.image}" alt="" class="watchlist-linked-result-img">` :
                    `<div class="watchlist-linked-result-img-placeholder">🎵</div>`}
                <div class="watchlist-linked-result-info">
                    <div class="watchlist-linked-result-name">${escapeHtml(r.name)}</div>
                    <div class="watchlist-linked-result-meta">${escapeHtml(r.extra || '')}</div>
                </div>
                <button class="watchlist-linked-select-btn">Select</button>
            </div>`;
        }
        container.innerHTML = html;

        container.querySelectorAll('.watchlist-linked-search-result').forEach(el => {
            el.querySelector('.watchlist-linked-select-btn').onclick = async (e) => {
                e.stopPropagation();
                await _linkSourceArtist(sourceKey, watchlistArtistId, el.dataset.id, el.dataset.name);
            };
        });
    } catch (err) {
        console.error(`Error searching ${sourceKey}:`, err);
        container.innerHTML = '<div style="padding:12px;color:#f44;text-align:center">Search error</div>';
    }
}

async function _linkSourceArtist(sourceKey, watchlistArtistId, newId, newName) {
    try {
        const response = await fetch(`/api/watchlist/artist/${watchlistArtistId}/link-provider`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ provider_id: newId, provider: sourceKey })
        });
        const data = await response.json();
        if (!data.success) {
            showToast(`Failed to link: ${data.error}`, 'error');
            return;
        }
        showToast(`Linked to "${newName}" on ${sourceKey}`, 'success');
        // Refresh the modal
        const panel = document.getElementById('wl-linked-search-panel');
        const artistName = panel?.dataset?.artistName || newName;
        closeWatchlistArtistConfigModal();
        setTimeout(() => openWatchlistArtistConfigModal(watchlistArtistId, artistName), 300);
    } catch (err) {
        showToast('Failed to link artist', 'error');
    }
}

async function _clearSourceMatch(sourceKey, watchlistArtistId, artistName) {
    try {
        const response = await fetch(`/api/watchlist/artist/${watchlistArtistId}/link-provider`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ provider_id: '', provider: sourceKey })
        });
        const data = await response.json();
        if (!data.success) {
            showToast(`Failed to clear: ${data.error}`, 'error');
            return;
        }
        showToast(`Cleared ${sourceKey} match`, 'success');
        closeWatchlistArtistConfigModal();
        setTimeout(() => openWatchlistArtistConfigModal(watchlistArtistId, artistName), 300);
    } catch (err) {
        showToast('Failed to clear match', 'error');
    }
}

/**
 * Open watchlist artist configuration modal
 * @param {string} artistId - Spotify artist ID
 * @param {string} artistName - Artist name
 */
async function openWatchlistArtistConfigModal(artistId, artistName) {
    try {
        console.log(`🎨 Opening config modal for artist: ${artistName} (${artistId})`);

        // Fetch artist config and info
        const response = await fetch(`/api/watchlist/artist/${artistId}/config`);
        const data = await response.json();

        if (!data.success) {
            console.error('Error loading artist config:', data.error);
            showToast(`Error loading artist configuration: ${data.error}`, 'error');
            return;
        }

        const { config, artist, spotify_artist_id, itunes_artist_id, deezer_artist_id, discogs_artist_id, watchlist_name } = data;

        // Populate linked provider section (use DB watchlist_name for mismatch comparison)
        _populateLinkedProviderSection(artistId, watchlist_name || artistName, spotify_artist_id, itunes_artist_id, artist, deezer_artist_id, discogs_artist_id);

        // Check if global override is active
        let globalOverrideActive = false;
        try {
            const globalResponse = await fetch('/api/watchlist/global-config');
            const globalData = await globalResponse.json();
            globalOverrideActive = globalData.success && globalData.config.global_override_enabled;
        } catch (e) {
            console.debug('Could not check global config:', e);
        }

        // Generate hero section
        const heroHTML = `
            ${artist.image_url ? `
                <img src="${artist.image_url}"
                     alt="${escapeHtml(artist.name)}"
                     class="watchlist-artist-config-hero-image"
                     loading="lazy">
            ` : ''}
            <div class="watchlist-artist-config-hero-info">
                <h2 class="watchlist-artist-config-hero-name">${escapeHtml(artist.name)}</h2>
                <div class="watchlist-artist-config-hero-stats">
                    <div class="watchlist-artist-config-stat">
                        <span class="watchlist-artist-config-stat-value">${formatNumber(artist.followers)}</span>
                        <span class="watchlist-artist-config-stat-label">Followers</span>
                    </div>
                    <div class="watchlist-artist-config-stat">
                        <span class="watchlist-artist-config-stat-value">${artist.popularity}/100</span>
                        <span class="watchlist-artist-config-stat-label">Popularity</span>
                    </div>
                </div>
                ${artist.genres && artist.genres.length > 0 ? `
                    <div class="watchlist-artist-config-hero-genres">
                        ${artist.genres.slice(0, 3).map(genre =>
            `<span class="watchlist-artist-config-genre-tag">${escapeHtml(genre)}</span>`
        ).join('')}
                    </div>
                ` : ''}
            </div>
        `;

        // Populate hero section
        const heroContainer = document.getElementById('watchlist-artist-config-hero');
        if (heroContainer) {
            heroContainer.innerHTML = heroHTML;
        }

        // Set checkbox states
        document.getElementById('config-include-albums').checked = config.include_albums;
        document.getElementById('config-include-eps').checked = config.include_eps;
        document.getElementById('config-include-singles').checked = config.include_singles;
        document.getElementById('config-include-live').checked = config.include_live || false;
        document.getElementById('config-include-remixes').checked = config.include_remixes || false;
        document.getElementById('config-include-acoustic').checked = config.include_acoustic || false;
        document.getElementById('config-include-compilations').checked = config.include_compilations || false;
        document.getElementById('config-include-instrumentals').checked = config.include_instrumentals || false;
        document.getElementById('config-lookback-days').value = config.lookback_days != null ? String(config.lookback_days) : '';

        // Show global override notice if active
        const existingNotice = document.querySelector('.global-override-notice');
        if (existingNotice) existingNotice.remove();

        if (globalOverrideActive) {
            const notice = document.createElement('div');
            notice.className = 'global-override-notice watchlist-global-override-banner';
            notice.innerHTML = '<span>⚠️</span><span>Global override is active — these per-artist settings are currently ignored during scans.</span>';
            const configBody = document.querySelector('.watchlist-artist-config-body');
            if (configBody) configBody.insertBefore(notice, configBody.firstChild);
        }

        // Store artist ID for saving
        const modal = document.getElementById('watchlist-artist-config-modal');
        if (modal) {
            modal.setAttribute('data-artist-id', artistId);
        }

        // Show modal
        const overlay = document.getElementById('watchlist-artist-config-modal-overlay');
        if (overlay) {
            overlay.classList.remove('hidden');
        }

        // Add save button handler
        const saveBtn = document.getElementById('save-artist-config-btn');
        if (saveBtn) {
            // Remove old listeners
            const newSaveBtn = saveBtn.cloneNode(true);
            saveBtn.parentNode.replaceChild(newSaveBtn, saveBtn);

            // Add new listener
            newSaveBtn.addEventListener('click', () => saveWatchlistArtistConfig(artistId));
        }

    } catch (error) {
        console.error('Error opening watchlist artist config modal:', error);
        showToast(`Error: ${error.message}`, 'error');
    }
}

/**
 * Close watchlist artist configuration modal
 */
function closeWatchlistArtistConfigModal() {
    const overlay = document.getElementById('watchlist-artist-config-modal-overlay');
    if (overlay) {
        overlay.classList.add('hidden');
    }

    // Clear hero content
    const heroContainer = document.getElementById('watchlist-artist-config-hero');
    if (heroContainer) {
        heroContainer.innerHTML = '';
    }

    // Clear linked provider section
    const linkedContent = document.getElementById('watchlist-linked-provider-content');
    if (linkedContent) linkedContent.innerHTML = '';
    const linkedSection = document.getElementById('watchlist-linked-provider-section');
    if (linkedSection) linkedSection.style.display = 'none';
}

/**
 * Open watchlist artist detail view (slides in from right)
 */
async function openWatchlistArtistDetailView(artistId, artistName) {
    try {
        const response = await fetch(`/api/watchlist/artist/${artistId}/config`);
        const data = await response.json();

        if (!data.success) {
            showToast(`Error loading artist info: ${data.error}`, 'error');
            return;
        }

        const { config, artist, recent_releases, spotify_artist_id, itunes_artist_id, deezer_artist_id, discogs_artist_id } = data;

        // Remove existing overlay if any
        const existing = document.querySelector('.watchlist-artist-detail-overlay');
        if (existing) existing.remove();

        const overlay = document.createElement('div');
        overlay.className = 'watchlist-artist-detail-overlay';

        // Build pills
        const pills = [];
        if (config.include_albums) pills.push('<span class="watchlist-pill watchlist-pill-active">Albums</span>');
        if (config.include_eps) pills.push('<span class="watchlist-pill watchlist-pill-active">EPs</span>');
        if (config.include_singles) pills.push('<span class="watchlist-pill watchlist-pill-active">Singles</span>');
        if (config.include_live) pills.push('<span class="watchlist-pill watchlist-pill-filter">Live</span>');
        if (config.include_remixes) pills.push('<span class="watchlist-pill watchlist-pill-filter">Remixes</span>');
        if (config.include_acoustic) pills.push('<span class="watchlist-pill watchlist-pill-filter">Acoustic</span>');
        if (config.include_compilations) pills.push('<span class="watchlist-pill watchlist-pill-filter">Compilations</span>');

        // Build scan info
        const scanTimeText = config.last_scan_timestamp ? formatRelativeScanTime(config.last_scan_timestamp) : 'Never scanned';
        const dateAddedText = config.date_added ? `Added ${new Date(config.date_added).toLocaleDateString()}` : '';

        // Build metadata tags (style, mood, label)
        const metaTags = [];
        if (artist.style) metaTags.push(`<span class="watchlist-detail-genre-tag">${escapeHtml(artist.style)}</span>`);
        if (artist.mood) metaTags.push(`<span class="watchlist-detail-genre-tag">${escapeHtml(artist.mood)}</span>`);
        if (artist.label) metaTags.push(`<span class="watchlist-detail-genre-tag">${escapeHtml(artist.label)}</span>`);

        overlay.innerHTML = `
            ${artist.banner_url ? `
                <div class="watchlist-detail-banner">
                    <img src="${artist.banner_url}" alt="" onerror="this.parentElement.remove();">
                    <div class="watchlist-detail-banner-fade"></div>
                </div>
            ` : ''}

            <div class="watchlist-detail-content ${artist.banner_url ? 'has-banner' : ''}">
                <button class="watchlist-detail-back watchlist-detail-back-btn">
                    ← Back to Watchlist
                </button>

                <div class="watchlist-detail-hero">
                    ${artist.image_url ? `<img src="${artist.image_url}" alt="${escapeHtml(artist.name)}" onerror="this.style.display='none';">` : ''}
                    <div class="watchlist-detail-hero-info">
                        <h2 class="watchlist-detail-hero-name">${escapeHtml(artist.name)}</h2>
                        ${artist.followers || artist.popularity ? `
                        <div class="watchlist-detail-hero-stats">
                            ${artist.followers ? `
                            <div class="watchlist-detail-stat">
                                <span class="watchlist-detail-stat-value">${formatNumber(artist.followers)}</span>
                                <span class="watchlist-detail-stat-label">Followers</span>
                            </div>` : ''}
                            ${artist.popularity ? `
                            <div class="watchlist-detail-stat">
                                <span class="watchlist-detail-stat-value">${artist.popularity}/100</span>
                                <span class="watchlist-detail-stat-label">Popularity</span>
                            </div>` : ''}
                        </div>
                        ` : ''}
                        ${artist.genres && artist.genres.length > 0 ? `
                            <div class="watchlist-detail-hero-genres">
                                ${artist.genres.map(g => `<span class="watchlist-detail-genre-tag">${escapeHtml(g)}</span>`).join('')}
                            </div>
                        ` : ''}
                    </div>
                </div>

                ${artist.summary ? `
                <div class="watchlist-detail-section">
                    <div class="watchlist-detail-section-title">About</div>
                    <p class="watchlist-detail-bio">${escapeHtml(artist.summary)}</p>
                </div>
                ` : ''}

                ${metaTags.length > 0 ? `
                <div class="watchlist-detail-section">
                    <div class="watchlist-detail-section-title">Info</div>
                    <div class="watchlist-detail-hero-genres">${metaTags.join('')}</div>
                </div>
                ` : ''}

                ${recent_releases && recent_releases.length > 0 ? `
                <div class="watchlist-detail-section">
                    <div class="watchlist-detail-section-title">Recent Releases</div>
                    <div class="watchlist-detail-releases">
                        ${recent_releases.map(r => `
                            <div class="watchlist-detail-release">
                                ${r.album_cover_url ? `<img src="${r.album_cover_url}" alt="" onerror="this.style.display='none';">` : ''}
                                <div class="watchlist-detail-release-info">
                                    <span class="watchlist-detail-release-name">${escapeHtml(r.album_name)}</span>
                                    <span class="watchlist-detail-release-meta">${r.release_date}${r.track_count ? ` · ${r.track_count} tracks` : ''}</span>
                                </div>
                            </div>
                        `).join('')}
                    </div>
                </div>
                ` : ''}

                <div class="watchlist-detail-section">
                    <div class="watchlist-detail-section-title">Watchlist</div>
                    <div class="watchlist-detail-watchlist-info">
                        <span class="watchlist-card-meta">${scanTimeText}</span>
                        ${dateAddedText ? `<span class="watchlist-detail-info-sep">·</span><span class="watchlist-card-meta">${dateAddedText}</span>` : ''}
                    </div>
                    <div class="watchlist-card-pills" style="padding: 0; margin-top: 8px;">
                        ${pills.length > 0 ? pills.join('') : '<span class="watchlist-card-meta">No release types enabled</span>'}
                    </div>
                </div>

                <div class="watchlist-detail-actions">
                    <button class="watchlist-detail-discog-btn watchlist-detail-discog-action">View Discography</button>
                    <button class="watchlist-detail-settings-btn watchlist-detail-settings-action">Settings</button>
                    <button class="watchlist-detail-remove-btn watchlist-detail-remove-action">Remove from Watchlist</button>
                </div>
            </div>
        `;

        // Wire up event listeners (avoids inline onclick escaping issues)
        overlay.querySelector('.watchlist-detail-back-btn').addEventListener('click', () => {
            closeWatchlistArtistDetailView();
        });

        overlay.querySelector('.watchlist-detail-discog-action').addEventListener('click', () => {
            // Use the ID matching the active metadata source
            let discogId, source;
            const activeSrc = (currentMusicSourceName || '').toLowerCase();
            if (activeSrc.includes('spotify') && spotify_artist_id) {
                discogId = spotify_artist_id; source = 'spotify';
            } else if (activeSrc.includes('discogs') && discogs_artist_id) {
                discogId = discogs_artist_id; source = 'discogs';
            } else if (activeSrc.includes('deezer') && deezer_artist_id) {
                discogId = deezer_artist_id; source = 'deezer';
            } else if (itunes_artist_id) {
                discogId = itunes_artist_id; source = 'itunes';
            } else {
                discogId = spotify_artist_id || discogs_artist_id || deezer_artist_id || itunes_artist_id;
                source = spotify_artist_id ? 'spotify' : discogs_artist_id ? 'discogs' : deezer_artist_id ? 'deezer' : 'itunes';
            }
            if (discogId) {
                // Close watchlist modal + detail overlay
                closeWatchlistArtistDetailView();
                closeWatchlistModal();
                // Navigate to Artists page and load discography
                navigateToPage('artists');
                setTimeout(() => {
                    selectArtistForDetail(
                        { id: discogId, name: artistName, image_url: artist.image_url || '' },
                        { source: source }
                    );
                }, 200);
            }
        });

        overlay.querySelector('.watchlist-detail-settings-action').addEventListener('click', () => {
            // Remove overlay immediately so it doesn't block the config modal
            const detailOverlay = document.querySelector('.watchlist-artist-detail-overlay');
            if (detailOverlay) detailOverlay.remove();
            openWatchlistArtistConfigModal(artistId, artistName);
        });

        overlay.querySelector('.watchlist-detail-remove-action').addEventListener('click', () => {
            removeFromWatchlistModal(artistId, artistName);
        });

        // Append to the modal container
        const container = document.querySelector('.watchlist-fullscreen');
        if (container) {
            container.appendChild(overlay);
            // Trigger slide-in animation
            requestAnimationFrame(() => overlay.classList.add('visible'));
        }

    } catch (error) {
        console.error('Error opening artist detail view:', error);
        showToast(`Error: ${error.message}`, 'error');
    }
}

/**
 * Close watchlist artist detail view (slides out)
 */
function closeWatchlistArtistDetailView() {
    const overlay = document.querySelector('.watchlist-artist-detail-overlay');
    if (overlay) {
        overlay.classList.remove('visible');
        overlay.addEventListener('transitionend', () => overlay.remove(), { once: true });
    }
}

/**
 * Open global watchlist settings modal
 */
async function openWatchlistGlobalSettingsModal() {
    try {
        const response = await fetch('/api/watchlist/global-config');
        const data = await response.json();

        if (!data.success) {
            showToast(`Error loading global settings: ${data.error}`, 'error');
            return;
        }

        const config = data.config;

        // Populate checkboxes
        document.getElementById('global-override-enabled').checked = config.global_override_enabled;
        document.getElementById('global-include-albums').checked = config.include_albums;
        document.getElementById('global-include-eps').checked = config.include_eps;
        document.getElementById('global-include-singles').checked = config.include_singles;
        document.getElementById('global-include-live').checked = config.include_live;
        document.getElementById('global-include-remixes').checked = config.include_remixes;
        document.getElementById('global-include-acoustic').checked = config.include_acoustic;
        document.getElementById('global-include-compilations').checked = config.include_compilations;
        document.getElementById('global-include-instrumentals').checked = config.include_instrumentals;
        document.getElementById('global-exclude-terms').value = config.exclude_terms || '';

        // Sync "Include Everything" checkbox
        syncGlobalIncludeAllCheckbox();

        // Update options visibility based on toggle state
        toggleGlobalOverrideOptions();

        // Update toggle label border
        const toggleLabel = document.getElementById('global-override-toggle-label');
        if (toggleLabel) {
            toggleLabel.style.border = config.global_override_enabled
                ? '2px solid rgba(29, 185, 84, 0.5)'
                : '2px solid rgba(255, 255, 255, 0.1)';
        }

        // Show modal
        const overlay = document.getElementById('watchlist-global-config-modal-overlay');
        if (overlay) overlay.classList.remove('hidden');

    } catch (error) {
        console.error('Error opening global watchlist settings:', error);
        showToast(`Error: ${error.message}`, 'error');
    }
}

/**
 * Close global watchlist settings modal
 */
function closeWatchlistGlobalSettingsModal() {
    const overlay = document.getElementById('watchlist-global-config-modal-overlay');
    if (overlay) overlay.classList.add('hidden');
}

/**
 * Toggle global override options visibility
 */
function toggleGlobalOverrideOptions() {
    const enabled = document.getElementById('global-override-enabled').checked;
    const options = document.getElementById('global-override-options');
    if (options) {
        options.style.opacity = enabled ? '1' : '0.4';
        options.style.pointerEvents = enabled ? 'auto' : 'none';
    }

    // Update toggle label border
    const toggleLabel = document.getElementById('global-override-toggle-label');
    if (toggleLabel) {
        toggleLabel.style.border = enabled
            ? '2px solid rgba(29, 185, 84, 0.5)'
            : '2px solid rgba(255, 255, 255, 0.1)';
    }
}

/**
 * Toggle all global include checkboxes
 */
function toggleGlobalIncludeAll() {
    const checked = document.getElementById('global-include-all').checked;
    ['global-include-albums', 'global-include-eps', 'global-include-singles',
     'global-include-live', 'global-include-remixes', 'global-include-acoustic',
     'global-include-compilations', 'global-include-instrumentals'].forEach(id => {
        const el = document.getElementById(id);
        if (el) el.checked = checked;
    });
}

/**
 * Sync the "Include Everything" checkbox based on individual checkbox states
 */
function syncGlobalIncludeAllCheckbox() {
    const allIds = ['global-include-albums', 'global-include-eps', 'global-include-singles',
        'global-include-live', 'global-include-remixes', 'global-include-acoustic',
        'global-include-compilations', 'global-include-instrumentals'];
    const allChecked = allIds.every(id => {
        const el = document.getElementById(id);
        return el && el.checked;
    });
    const includeAllEl = document.getElementById('global-include-all');
    if (includeAllEl) includeAllEl.checked = allChecked;
}

/**
 * Save global watchlist configuration
 */
async function saveWatchlistGlobalConfig() {
    try {
        const globalOverrideEnabled = document.getElementById('global-override-enabled').checked;
        const includeAlbums = document.getElementById('global-include-albums').checked;
        const includeEps = document.getElementById('global-include-eps').checked;
        const includeSingles = document.getElementById('global-include-singles').checked;
        const includeLive = document.getElementById('global-include-live').checked;
        const includeRemixes = document.getElementById('global-include-remixes').checked;
        const includeAcoustic = document.getElementById('global-include-acoustic').checked;
        const includeCompilations = document.getElementById('global-include-compilations').checked;
        const includeInstrumentals = document.getElementById('global-include-instrumentals').checked;
        const excludeTerms = (document.getElementById('global-exclude-terms').value || '').trim();

        if (globalOverrideEnabled && !includeAlbums && !includeEps && !includeSingles) {
            showToast('Please select at least one release type', 'error');
            return;
        }

        const saveBtn = document.getElementById('save-global-config-btn');
        if (saveBtn) {
            saveBtn.disabled = true;
            saveBtn.textContent = 'Saving...';
        }

        const response = await fetch('/api/watchlist/global-config', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                global_override_enabled: globalOverrideEnabled,
                include_albums: includeAlbums,
                include_eps: includeEps,
                include_singles: includeSingles,
                include_live: includeLive,
                include_remixes: includeRemixes,
                include_acoustic: includeAcoustic,
                include_compilations: includeCompilations,
                include_instrumentals: includeInstrumentals,
                exclude_terms: excludeTerms,
            })
        });

        const data = await response.json();

        if (data.success) {
            showToast('Global watchlist settings saved', 'success');
            closeWatchlistGlobalSettingsModal();

            // Refresh the watchlist modal to update button and banner
            const watchlistModal = document.getElementById('watchlist-modal');
            if (watchlistModal && watchlistModal.style.display === 'flex') {
                await showWatchlistModal();
            }
        } else {
            showToast(`Error: ${data.error}`, 'error');
        }

    } catch (error) {
        console.error('Error saving global config:', error);
        showToast(`Error: ${error.message}`, 'error');
    } finally {
        const saveBtn = document.getElementById('save-global-config-btn');
        if (saveBtn) {
            saveBtn.disabled = false;
            saveBtn.textContent = 'Save Global Settings';
        }
    }
}

/**
 * Save watchlist artist configuration
 * @param {string} artistId - Spotify artist ID
 */
async function saveWatchlistArtistConfig(artistId) {
    try {
        const includeAlbums = document.getElementById('config-include-albums').checked;
        const includeEps = document.getElementById('config-include-eps').checked;
        const includeSingles = document.getElementById('config-include-singles').checked;
        const includeLive = document.getElementById('config-include-live').checked;
        const includeRemixes = document.getElementById('config-include-remixes').checked;
        const includeAcoustic = document.getElementById('config-include-acoustic').checked;
        const includeCompilations = document.getElementById('config-include-compilations').checked;
        const includeInstrumentals = document.getElementById('config-include-instrumentals').checked;
        const lookbackDaysVal = document.getElementById('config-lookback-days').value;
        const lookbackDays = lookbackDaysVal !== '' ? parseInt(lookbackDaysVal) : null;

        // Validate at least one release type is selected
        if (!includeAlbums && !includeEps && !includeSingles) {
            showToast('Please select at least one release type', 'error');
            return;
        }

        // Disable save button
        const saveBtn = document.getElementById('save-artist-config-btn');
        if (saveBtn) {
            saveBtn.disabled = true;
            saveBtn.textContent = 'Saving...';
        }

        // Send update to backend
        const response = await fetch(`/api/watchlist/artist/${artistId}/config`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                include_albums: includeAlbums,
                include_eps: includeEps,
                include_singles: includeSingles,
                include_live: includeLive,
                include_remixes: includeRemixes,
                include_acoustic: includeAcoustic,
                include_compilations: includeCompilations,
                include_instrumentals: includeInstrumentals,
                lookback_days: lookbackDays,
            })
        });

        const data = await response.json();

        if (data.success) {
            showToast('Artist preferences saved successfully', 'success');
            closeWatchlistArtistConfigModal();

            // Refresh watchlist modal if it's open
            const watchlistModal = document.getElementById('watchlist-modal');
            if (watchlistModal && watchlistModal.style.display === 'flex') {
                await showWatchlistModal();
            }
        } else {
            showToast(`Error saving preferences: ${data.error}`, 'error');
        }

    } catch (error) {
        console.error('Error saving watchlist artist config:', error);
        showToast(`Error: ${error.message}`, 'error');
    } finally {
        // Re-enable save button
        const saveBtn = document.getElementById('save-artist-config-btn');
        if (saveBtn) {
            saveBtn.disabled = false;
            saveBtn.textContent = 'Save Preferences';
        }
    }
}

/**
 * Format large numbers with commas
 * @param {number} num - Number to format
 * @returns {string} Formatted number
 */
function formatNumber(num) {
    if (!num) return '0';
    return num.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",");
}

/**
 * Format last scan timestamp as relative time
 */
function formatRelativeScanTime(isoString) {
    if (!isoString) return 'Never scanned';
    const diff = Date.now() - new Date(isoString).getTime();
    const mins = Math.floor(diff / 60000);
    if (mins < 1) return 'Scanned just now';
    if (mins < 60) return `Scanned ${mins}m ago`;
    const hrs = Math.floor(mins / 60);
    if (hrs < 24) return `Scanned ${hrs}h ago`;
    const days = Math.floor(hrs / 24);
    if (days < 30) return `Scanned ${days}d ago`;
    const months = Math.floor(days / 30);
    return `Scanned ${months}mo ago`;
}

/**
 * Filter watchlist artists based on search input
 */
function filterWatchlistArtists() {
    const searchInput = document.getElementById('watchlist-search-input');
    const artistsList = document.getElementById('watchlist-artists-list');

    if (!searchInput || !artistsList) return;

    const searchTerm = searchInput.value.toLowerCase().trim();
    const artistItems = artistsList.querySelectorAll('.watchlist-artist-card');

    artistItems.forEach(item => {
        const artistName = item.getAttribute('data-artist-name');

        if (!searchTerm || artistName.includes(searchTerm)) {
            item.style.display = '';
        } else {
            item.style.display = 'none';
        }
    });

    // Refresh batch bar in case visible selection changed
    updateWatchlistBatchBar();
}

/**
 * Start watchlist scan
 */
async function cancelWatchlistScan() {
    try {
        const cancelBtn = document.getElementById('cancel-watchlist-scan-btn');
        if (cancelBtn) {
            cancelBtn.disabled = true;
            cancelBtn.textContent = 'Cancelling...';
        }

        const response = await fetch('/api/watchlist/scan/cancel', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' }
        });

        const data = await response.json();
        if (!data.success) {
            throw new Error(data.error || 'Failed to cancel scan');
        }

        showToast('Cancel request sent — scan will stop after current artist', 'info');

    } catch (error) {
        console.error('Error cancelling watchlist scan:', error);
        showToast(`Error cancelling scan: ${error.message}`, 'error');
        const cancelBtn = document.getElementById('cancel-watchlist-scan-btn');
        if (cancelBtn) {
            cancelBtn.disabled = false;
            cancelBtn.textContent = 'Cancel Scan';
        }
    }
}

async function startWatchlistScan() {
    try {
        const button = document.getElementById('scan-watchlist-btn');
        button.disabled = true;
        button.textContent = 'Starting scan...';
        button.classList.add('btn-processing');

        const response = await fetch('/api/watchlist/scan', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' }
        });

        const data = await response.json();
        if (!data.success) {
            throw new Error(data.error || 'Failed to start scan');
        }

        button.textContent = 'Scanning...';

        // Show cancel button
        const cancelBtn = document.getElementById('cancel-watchlist-scan-btn');
        if (cancelBtn) {
            cancelBtn.style.display = '';
            cancelBtn.disabled = false;
            cancelBtn.textContent = 'Cancel Scan';
        }

        // Show scan status
        const statusDiv = document.getElementById('watchlist-scan-status');
        if (statusDiv) {
            statusDiv.style.display = 'flex';
        }

        // Start polling for updates
        pollWatchlistScanStatus();

    } catch (error) {
        console.error('Error starting watchlist scan:', error);
        const button = document.getElementById('scan-watchlist-btn');
        button.disabled = false;
        button.textContent = 'Scan for New Releases';
        button.classList.remove('btn-processing');
        alert(`Error starting scan: ${error.message}`);
    }
}

/**
 * Poll watchlist scan status
 */
function handleWatchlistScanData(data) {
    const button = document.getElementById('scan-watchlist-btn');
    const liveActivity = document.getElementById('watchlist-live-activity');

    // Show/hide cancel button based on scan status
    const cancelBtn = document.getElementById('cancel-watchlist-scan-btn');
    if (cancelBtn) {
        cancelBtn.style.display = data.status === 'scanning' ? '' : 'none';
    }

    // Update live visual activity display
    if (liveActivity && data.status === 'scanning') {
        liveActivity.style.display = 'flex';

        // Update artist image and name
        const artistImg = document.getElementById('watchlist-artist-img');
        const artistName = document.getElementById('watchlist-artist-name');
        if (artistImg && data.current_artist_image_url) {
            artistImg.src = data.current_artist_image_url;
            artistImg.style.display = 'block';
        }
        if (artistName) {
            artistName.textContent = data.current_artist_name || 'Processing...';
        }

        // Update album image and name
        const albumImg = document.getElementById('watchlist-album-img');
        const albumName = document.getElementById('watchlist-album-name');
        if (albumImg && data.current_album_image_url) {
            albumImg.src = data.current_album_image_url;
            albumImg.style.display = 'block';
        } else if (albumImg) {
            albumImg.style.display = 'none';
        }
        if (albumName) {
            albumName.textContent = data.current_album || (data.current_phase === 'fetching_discography' ? 'Fetching releases...' : 'Processing...');
        }

        // Update current track
        const trackName = document.getElementById('watchlist-track-name');
        if (trackName) {
            trackName.textContent = data.current_track_name || (data.current_phase === 'fetching_discography' ? 'Fetching releases...' : 'Processing...');
        }

        // Update wishlist additions feed
        const additionsFeed = document.getElementById('watchlist-additions-feed');
        if (additionsFeed) {
            if (data.recent_wishlist_additions && data.recent_wishlist_additions.length > 0) {
                additionsFeed.innerHTML = data.recent_wishlist_additions.map(item => `
                    <div class="watchlist-live-addition-item">
                        <img src="${item.album_image_url || ''}" alt="" onerror="this.style.display='none';" />
                        <div class="watchlist-live-addition-item-info">
                            <div class="watchlist-live-addition-item-track">${item.track_name}</div>
                            <div class="watchlist-live-addition-item-artist">${item.artist_name}</div>
                        </div>
                    </div>
                `).join('');
            } else {
                additionsFeed.innerHTML = '<div class="watchlist-live-addition-empty">No tracks added yet...</div>';
            }
        }
    } else if (liveActivity && data.status !== 'scanning') {
        liveActivity.style.display = 'none';
    }

    if (data.status === 'completed') {
        if (button) {
            button.disabled = false;
            button.textContent = 'Scan for New Releases';
            button.classList.remove('btn-processing');
        }

        // Hide live activity
        if (liveActivity) {
            liveActivity.style.display = 'none';
        }

        // Show completion message in status div
        const statusDiv = document.getElementById('watchlist-scan-status');
        if (statusDiv && data.summary) {
            const newTracks = data.summary.new_tracks_found || 0;
            const addedTracks = data.summary.tracks_added_to_wishlist || 0;
            const totalArtists = data.summary.total_artists || 0;
            const successfulScans = data.summary.successful_scans || 0;

            let completionMessage = `Scan completed: ${successfulScans}/${totalArtists} artists scanned`;
            if (newTracks > 0) {
                completionMessage += `, found ${newTracks} new track${newTracks !== 1 ? 's' : ''}`;
                if (addedTracks > 0) {
                    completionMessage += `, added ${addedTracks} to wishlist`;
                }
            } else {
                completionMessage += ', no new tracks found';
            }

            // Update the scan status display with completion message and summary
            statusDiv.innerHTML = `
                <div class="watchlist-scan-completion">
                    <div class="watchlist-scan-completion-message">${completionMessage}</div>
                    <div style="font-size: 13px; opacity: 0.8;">
                        <span class="sync-stat">Artists: ${totalArtists}</span>
                        <span class="sync-separator"> • </span>
                        <span class="sync-stat">New tracks: ${newTracks}</span>
                        <span class="sync-separator"> • </span>
                        <span class="sync-stat">Added to wishlist: ${addedTracks}</span>
                    </div>
                </div>
            `;
        }

        // Update watchlist count
        updateWatchlistButtonCount();

        console.log('Watchlist scan completed:', data.summary);

    } else if (data.status === 'cancelled') {
        if (button) {
            button.disabled = false;
            button.textContent = 'Scan for New Releases';
            button.classList.remove('btn-processing');
        }

        // Hide cancel button
        const cancelBtn = document.getElementById('cancel-watchlist-scan-btn');
        if (cancelBtn) {
            cancelBtn.style.display = 'none';
            cancelBtn.disabled = false;
            cancelBtn.textContent = 'Cancel Scan';
        }

        // Hide live activity
        if (liveActivity) {
            liveActivity.style.display = 'none';
        }

        // Show cancellation message
        const statusDiv = document.getElementById('watchlist-scan-status');
        if (statusDiv && data.summary) {
            const scanned = data.summary.total_artists || 0;
            const newTracks = data.summary.new_tracks_found || 0;
            const addedTracks = data.summary.tracks_added_to_wishlist || 0;

            statusDiv.innerHTML = `
                <div class="watchlist-scan-completion">
                    <div class="watchlist-scan-completion-message">Scan cancelled after ${scanned} artist${scanned !== 1 ? 's' : ''}</div>
                    <div style="font-size: 13px; opacity: 0.8;">
                        <span class="sync-stat">Scanned: ${scanned}</span>
                        <span class="sync-separator"> &bull; </span>
                        <span class="sync-stat">New tracks: ${newTracks}</span>
                        <span class="sync-separator"> &bull; </span>
                        <span class="sync-stat">Added to wishlist: ${addedTracks}</span>
                    </div>
                </div>
            `;
        }

        // Update watchlist count
        updateWatchlistButtonCount();

        showToast('Watchlist scan cancelled', 'info');
        console.log('Watchlist scan cancelled:', data.summary);

    } else if (data.status === 'error') {
        if (button) {
            button.disabled = false;
            button.textContent = 'Scan for New Releases';
            button.classList.remove('btn-processing');
        }

        // Hide cancel button
        const cancelBtn = document.getElementById('cancel-watchlist-scan-btn');
        if (cancelBtn) {
            cancelBtn.style.display = 'none';
        }

        // Hide live activity
        if (liveActivity) {
            liveActivity.style.display = 'none';
        }

        console.error('Watchlist scan error:', data.error);
    }
}

async function pollWatchlistScanStatus() {
    if (socketConnected) return; // Phase 5: WS handles scan updates
    try {
        const response = await fetch('/api/watchlist/scan/status');
        const data = await response.json();

        if (data.success) {
            handleWatchlistScanData(data);
            if (data.status === 'completed' || data.status === 'error' || data.status === 'cancelled') {
                return; // Stop polling
            }
        }

        // Continue polling if still scanning
        if (data.success && data.status === 'scanning') {
            setTimeout(pollWatchlistScanStatus, 2000); // Poll every 2 seconds
        }

    } catch (error) {
        console.error('Error polling watchlist scan status:', error);
    }
}

/**
 * Update similar artists for discovery feature
 */
async function updateSimilarArtists() {
    try {
        const button = document.getElementById('update-similar-artists-btn');
        const scanButton = document.getElementById('scan-watchlist-btn');

        button.disabled = true;
        button.textContent = 'Updating...';
        button.classList.add('btn-processing');
        if (scanButton) scanButton.disabled = true;

        const response = await fetch('/api/watchlist/update-similar-artists', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' }
        });

        const data = await response.json();
        if (!data.success) {
            throw new Error(data.error || 'Failed to update similar artists');
        }

        showToast('Updating similar artists in background...', 'success');

        // Poll for completion
        pollSimilarArtistsUpdate();

    } catch (error) {
        console.error('Error updating similar artists:', error);
        const button = document.getElementById('update-similar-artists-btn');
        const scanButton = document.getElementById('scan-watchlist-btn');

        button.disabled = false;
        button.textContent = 'Update Similar Artists';
        button.classList.remove('btn-processing');
        if (scanButton) scanButton.disabled = false;

        showToast(`Error: ${error.message}`, 'error');
    }
}

/**
 * Poll similar artists update status
 */
async function pollSimilarArtistsUpdate() {
    try {
        const response = await fetch('/api/watchlist/similar-artists-status');
        const data = await response.json();

        if (data.success) {
            const button = document.getElementById('update-similar-artists-btn');
            const scanButton = document.getElementById('scan-watchlist-btn');

            if (data.status === 'completed') {
                if (button) {
                    button.disabled = false;
                    button.textContent = 'Update Similar Artists';
                    button.classList.remove('btn-processing');
                }
                if (scanButton) scanButton.disabled = false;

                showToast(`Updated similar artists for ${data.artists_processed || 0} artists!`, 'success');
                return; // Stop polling

            } else if (data.status === 'error') {
                if (button) {
                    button.disabled = false;
                    button.textContent = 'Update Similar Artists';
                    button.classList.remove('btn-processing');
                }
                if (scanButton) scanButton.disabled = false;

                showToast('Error updating similar artists', 'error');
                return; // Stop polling
            } else if (data.status === 'running') {
                // Update button text with progress
                if (button && data.current_artist) {
                    button.textContent = `Updating... (${data.artists_processed || 0}/${data.total_artists || 0})`;
                }
            }
        }

        // Continue polling if still running
        if (data.success && data.status === 'running') {
            setTimeout(pollSimilarArtistsUpdate, 1000); // Poll every 1 second
        }

    } catch (error) {
        console.error('Error polling similar artists update:', error);
        const button = document.getElementById('update-similar-artists-btn');
        const scanButton = document.getElementById('scan-watchlist-btn');

        if (button) {
            button.disabled = false;
            button.textContent = 'Update Similar Artists';
            button.classList.remove('btn-processing');
        }
        if (scanButton) scanButton.disabled = false;
    }
}

/**
 * Remove artist from watchlist via modal
 */
async function removeFromWatchlistModal(artistId, artistName) {
    try {
        const response = await fetch('/api/watchlist/remove', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ artist_id: artistId })
        });

        const data = await response.json();
        if (!data.success) {
            throw new Error(data.error || 'Failed to remove from watchlist');
        }

        console.log(`❌ Removed ${artistName} from watchlist`);

        // Close detail view if open
        closeWatchlistArtistDetailView();

        // Refresh the modal
        showWatchlistModal();

        // Update button count
        updateWatchlistButtonCount();

        // Update any visible artist cards
        updateArtistCardWatchlistStatus();

    } catch (error) {
        console.error('Error removing from watchlist:', error);
        alert(`Error removing ${artistName} from watchlist: ${error.message}`);
    }
}


/**
 * Get visible checked checkboxes (not hidden by search filter)
 */
function getVisibleCheckedWatchlist() {
    return Array.from(document.querySelectorAll('.watchlist-select-cb:checked')).filter(cb => {
        const item = cb.closest('.watchlist-artist-card');
        return item && item.style.display !== 'none';
    });
}

/**
 * Update the batch action bar based on checkbox selection
 */
function updateWatchlistBatchBar() {
    const checked = getVisibleCheckedWatchlist();
    const countEl = document.getElementById('watchlist-batch-count');
    const removeBtn = document.getElementById('watchlist-batch-remove-btn');
    const selectAllCb = document.getElementById('watchlist-select-all-cb');

    if (checked.length > 0) {
        countEl.textContent = `${checked.length} selected`;
        removeBtn.style.display = '';
    } else {
        countEl.textContent = '';
        removeBtn.style.display = 'none';
    }

    // Update select-all checkbox state
    if (selectAllCb) {
        const visible = Array.from(document.querySelectorAll('.watchlist-select-cb')).filter(cb => {
            const card = cb.closest('.watchlist-artist-card');
            return card && card.style.display !== 'none';
        });
        selectAllCb.checked = visible.length > 0 && checked.length === visible.length;
        selectAllCb.indeterminate = checked.length > 0 && checked.length < visible.length;
    }
}

function toggleWatchlistSelectAll(checked) {
    const checkboxes = document.querySelectorAll('.watchlist-select-cb');
    checkboxes.forEach(cb => {
        const card = cb.closest('.watchlist-artist-card');
        if (card && card.style.display !== 'none') {
            cb.checked = checked;
        }
    });
    updateWatchlistBatchBar();
}

/**
 * Batch remove selected artists from watchlist
 */
async function batchRemoveFromWatchlist() {
    const checked = getVisibleCheckedWatchlist();
    if (checked.length === 0) return;

    const count = checked.length;
    if (!await showConfirmDialog({ title: 'Remove Artists', message: `Remove ${count} artist${count !== 1 ? 's' : ''} from your watchlist?`, confirmText: 'Remove', destructive: true })) return;

    const artistIds = checked.map(cb => cb.getAttribute('data-artist-id'));

    try {
        const response = await fetch('/api/watchlist/remove-batch', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ artist_ids: artistIds })
        });

        const data = await response.json();
        if (!data.success) {
            throw new Error(data.error || 'Failed to remove artists');
        }

        console.log(`❌ Batch removed ${data.removed} artists from watchlist`);

        // Refresh the modal
        showWatchlistModal();

        // Update button count
        updateWatchlistButtonCount();

        // Update any visible artist cards
        updateArtistCardWatchlistStatus();

    } catch (error) {
        console.error('Error batch removing from watchlist:', error);
        alert(`Error removing artists: ${error.message}`);
    }
}

// --- Metadata Updater Functions ---

// Global state for metadata update polling
let metadataUpdatePolling = false;
let metadataUpdateInterval = null;

/**
 * Handle metadata update button click
 */
async function handleMetadataUpdateButtonClick() {
    const button = document.getElementById('metadata-update-button');
    const currentAction = button.textContent;

    if (currentAction === 'Begin Update') {
        // Get refresh interval from dropdown
        const refreshSelect = document.getElementById('metadata-refresh-interval');
        const refreshIntervalDays = refreshSelect.value !== undefined ? parseInt(refreshSelect.value) : 30;

        try {
            button.disabled = true;
            button.textContent = 'Starting...';

            const response = await fetch('/api/metadata/start', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ refresh_interval_days: refreshIntervalDays })
            });

            const data = await response.json();
            if (!data.success) {
                throw new Error(data.error || 'Failed to start metadata update');
            }

            showToast('Metadata update started!', 'success');

            // Start polling for status updates
            startMetadataUpdatePolling();

        } catch (error) {
            console.error('Error starting metadata update:', error);
            button.disabled = false;
            button.textContent = 'Begin Update';
            showToast(`Error: ${error.message}`, 'error');
        }
    } else {
        // Stop metadata update
        try {
            button.disabled = true;
            button.textContent = 'Stopping...';

            const response = await fetch('/api/metadata/stop', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' }
            });

            if (!response.ok) {
                throw new Error('Failed to stop metadata update');
            }

        } catch (error) {
            console.error('Error stopping metadata update:', error);
            button.disabled = false;
            button.textContent = 'Stop Update';
        }
    }
}

/**
 * Start polling for metadata update status
 */
function startMetadataUpdatePolling() {
    if (metadataUpdatePolling) return; // Already polling

    metadataUpdatePolling = true;
    metadataUpdateInterval = setInterval(checkMetadataUpdateStatus, 1000); // Poll every second

    // Also check immediately
    checkMetadataUpdateStatus();
}

/**
 * Stop polling for metadata update status
 */
function stopMetadataUpdatePolling() {
    metadataUpdatePolling = false;
    if (metadataUpdateInterval) {
        clearInterval(metadataUpdateInterval);
        metadataUpdateInterval = null;
    }
}

/**
 * Check current metadata update status and update UI
 */
async function checkMetadataUpdateStatus() {
    if (socketConnected) return; // WebSocket handles this
    try {
        const response = await fetch('/api/metadata/status');
        const data = await response.json();

        if (data.success && data.status) {
            updateMetadataProgressUI(data.status);

            // Stop polling if completed or error
            if (data.status.status === 'completed' || data.status.status === 'error') {
                stopMetadataUpdatePolling();
            }
        }

    } catch (error) {
        console.warn('Could not fetch metadata update status:', error);
    }
}

function updateMetadataStatusFromData(data) {
    if (!data.success || !data.status) return;
    const prev = _lastToolStatus['metadata'];
    _lastToolStatus['metadata'] = data.status.status;
    if (prev !== undefined && data.status.status === prev && data.status.status !== 'running' && data.status.status !== 'stopping') return;
    updateMetadataProgressUI(data.status);
    if (data.status.status === 'completed' || data.status.status === 'error') {
        stopMetadataUpdatePolling();
    }
}

/**
 * Update metadata progress UI elements
 */
function updateMetadataProgressUI(status) {
    const button = document.getElementById('metadata-update-button');
    const phaseLabel = document.getElementById('metadata-phase-label');
    const progressLabel = document.getElementById('metadata-progress-label');
    const progressBar = document.getElementById('metadata-progress-bar');
    const refreshSelect = document.getElementById('metadata-refresh-interval');

    if (!button || !phaseLabel || !progressLabel || !progressBar || !refreshSelect) return;

    if (status.status === 'running') {
        button.textContent = 'Stop Update';
        button.disabled = false;
        refreshSelect.disabled = true;

        // Update current artist display
        const currentArtist = status.current_artist || 'Processing...';
        phaseLabel.textContent = `Current Artist: ${currentArtist}`;

        // Update progress
        const processed = status.processed || 0;
        const total = status.total || 0;
        const percentage = status.percentage || 0;

        progressLabel.textContent = `${processed} / ${total} artists (${percentage.toFixed(1)}%)`;
        progressBar.style.width = `${percentage}%`;

    } else if (status.status === 'stopping') {
        button.textContent = 'Stopping...';
        button.disabled = true;
        phaseLabel.textContent = 'Current Artist: Stopping...';

    } else if (status.status === 'completed') {
        button.textContent = 'Begin Update';
        button.disabled = false;
        refreshSelect.disabled = false;

        phaseLabel.textContent = 'Current Artist: Completed';

        const processed = status.processed || 0;
        const successful = status.successful || 0;
        const failed = status.failed || 0;

        progressLabel.textContent = `Completed: ${processed} processed, ${successful} successful, ${failed} failed`;
        progressBar.style.width = '100%';

        showToast(`Metadata update completed: ${successful} artists updated, ${failed} failed`, 'success');

    } else if (status.status === 'error') {
        button.textContent = 'Begin Update';
        button.disabled = false;
        refreshSelect.disabled = false;

        phaseLabel.textContent = 'Current Artist: Error occurred';
        progressLabel.textContent = status.error || 'Unknown error';
        progressBar.style.width = '0%';

    } else {
        // Idle state
        button.textContent = 'Begin Update';
        button.disabled = false;
        refreshSelect.disabled = false;

        phaseLabel.textContent = 'Current Artist: Not running';
        progressLabel.textContent = '0 / 0 artists (0.0%)';
        progressBar.style.width = '0%';
    }
}

/**
 * Check active media server and hide metadata updater if not Plex
 */
async function checkAndHideMetadataUpdaterForNonPlex() {
    try {
        const response = await fetch('/api/active-media-server');
        const data = await response.json();

        if (data.success) {
            const metadataCard = document.getElementById('metadata-updater-card');
            if (metadataCard) {
                // Show metadata updater only for Plex and Jellyfin
                if (data.active_server === 'plex' || data.active_server === 'jellyfin') {
                    metadataCard.style.display = 'flex';
                    console.log(`Metadata updater shown: ${data.active_server} is active server`);

                    // Update the header text to reflect the current server
                    const headerElement = metadataCard.querySelector('.card-header h3');
                    if (headerElement) {
                        const serverDisplayName = data.active_server.charAt(0).toUpperCase() + data.active_server.slice(1);
                        headerElement.textContent = `${serverDisplayName} Metadata Updater`;
                    }

                    // Update the description based on the server type
                    const descElement = metadataCard.querySelector('.metadata-updater-description');
                    if (descElement) {
                        if (data.active_server === 'jellyfin') {
                            descElement.textContent = 'Download and upload high-quality artist images from Spotify to your Jellyfin server for artists without photos.';
                        } else {
                            descElement.textContent = 'Download and upload high-quality artist images from Spotify to your Plex server for artists without photos.';
                        }
                    }
                } else {
                    // Hide metadata updater for Navidrome
                    metadataCard.style.display = 'none';
                    console.log(`Metadata updater hidden: ${data.active_server} does not support image uploads`);
                }
            }
        }
    } catch (error) {
        console.warn('Could not check active media server for metadata updater visibility:', error);
    }
}

async function checkAndShowMediaScanForPlex() {
    /**
     * Show media scan tool only for Plex (Jellyfin/Navidrome auto-scan)
     */
    try {
        const response = await fetch('/api/active-media-server');
        const data = await response.json();

        if (data.success) {
            const mediaScanCard = document.getElementById('media-scan-card');
            if (mediaScanCard) {
                // Show media scan tool only for Plex
                if (data.active_server === 'plex') {
                    mediaScanCard.style.display = 'flex';
                    console.log('Media scan tool shown: Plex is active server');
                } else {
                    // Hide for Jellyfin/Navidrome (they auto-scan)
                    mediaScanCard.style.display = 'none';
                    console.log(`Media scan tool hidden: ${data.active_server} auto-scans`);
                }
            }
        }
    } catch (error) {
        console.warn('Could not check active media server for media scan visibility:', error);
    }
}

async function handleMediaScanButtonClick() {
    /**
     * Trigger a manual Plex media library scan
     */
    const button = document.getElementById('media-scan-button');
    const phaseLabel = document.getElementById('media-scan-phase-label');
    const progressBar = document.getElementById('media-scan-progress-bar');
    const progressLabel = document.getElementById('media-scan-progress-label');
    const statusValue = document.getElementById('media-scan-status');

    if (!button) return;

    try {
        // Disable button and update UI
        button.disabled = true;
        phaseLabel.textContent = 'Requesting scan...';
        progressBar.style.width = '30%';
        progressLabel.textContent = 'Sending scan request to Plex';
        statusValue.textContent = 'Scanning...';
        statusValue.style.color = 'rgb(var(--accent-rgb))';

        // Request scan (database update handled by system automation)
        const response = await fetch('/api/scan/request', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                reason: 'Manual scan triggered from dashboard'
            })
        });

        const result = await response.json();

        if (result.success) {
            // Get delay from API response (graceful fallback to 60 if not provided)
            const delaySeconds = (result.scan_info && result.scan_info.delay_seconds) || 60;
            let remainingSeconds = delaySeconds;
            let countdownInterval = null;
            let pollInterval = null;

            // Update last scan time
            const lastTimeEl = document.getElementById('media-scan-last-time');
            if (lastTimeEl) {
                const now = new Date();
                lastTimeEl.textContent = now.toLocaleTimeString();
            }

            // Start countdown timer (visual feedback during delay)
            phaseLabel.textContent = 'Scan scheduled...';
            progressBar.style.width = '0%';

            countdownInterval = setInterval(() => {
                remainingSeconds--;

                // Update progress bar (0% -> 100% over delay period)
                const progress = ((delaySeconds - remainingSeconds) / delaySeconds) * 100;
                progressBar.style.width = `${progress}%`;

                // Update progress label with countdown
                if (remainingSeconds > 0) {
                    progressLabel.textContent = `Starting scan in ${remainingSeconds}s...`;
                } else {
                    progressLabel.textContent = 'Scan starting now...';
                }

                // When countdown reaches 0, start polling
                if (remainingSeconds <= 0) {
                    clearInterval(countdownInterval);

                    // Transition to scanning phase
                    phaseLabel.textContent = 'Scan in progress...';
                    progressBar.style.width = '100%';
                    progressLabel.textContent = 'Media server is scanning library...';
                    showToast('📡 Media scan started', 'success', 3000);

                    // Start polling for scan completion (5 minutes = 150 polls × 2s)
                    let pollCount = 0;
                    const maxPolls = 150; // 5 minutes

                    pollInterval = setInterval(async () => {
                        if (socketConnected) return; // Phase 5: WS handles scan status
                        pollCount++;

                        if (pollCount > maxPolls) {
                            // Polling timeout after 5 minutes
                            clearInterval(pollInterval);
                            button.disabled = false;
                            phaseLabel.textContent = 'Scan completed';
                            progressBar.style.width = '0%';
                            progressLabel.textContent = 'Ready for next scan';
                            statusValue.textContent = 'Idle';
                            statusValue.style.color = '#b3b3b3';
                            showToast('✅ Media scan completed', 'success', 3000);
                            return;
                        }

                        try {
                            const statusResponse = await fetch('/api/scan/status');
                            const statusData = await statusResponse.json();

                            if (statusData.success && statusData.status) {
                                const status = statusData.status;

                                // Update status display
                                if (status.is_scanning) {
                                    phaseLabel.textContent = 'Media server scanning...';
                                    progressLabel.textContent = status.progress_message || 'Scan in progress';
                                } else if (status.status === 'idle') {
                                    // Scan completed
                                    clearInterval(pollInterval);
                                    button.disabled = false;
                                    phaseLabel.textContent = 'Scan completed successfully';
                                    progressBar.style.width = '0%';
                                    progressLabel.textContent = 'Ready for next scan';
                                    statusValue.textContent = 'Idle';
                                    statusValue.style.color = '#b3b3b3';
                                    showToast('✅ Media scan completed', 'success', 3000);
                                }
                            }
                        } catch (pollError) {
                            console.debug('Scan status poll error:', pollError);
                        }
                    }, 2000); // Poll every 2 seconds
                }
            }, 1000); // Update countdown every second

        } else {
            // Error occurred
            showToast(`❌ Scan request failed: ${result.error}`, 'error', 5000);
            button.disabled = false;
            phaseLabel.textContent = 'Scan failed';
            progressBar.style.width = '0%';
            progressLabel.textContent = result.error || 'Unknown error';
            statusValue.textContent = 'Error';
            statusValue.style.color = '#f44336';
        }

    } catch (error) {
        console.error('Error requesting media scan:', error);
        showToast('❌ Failed to request media scan', 'error', 3000);
        button.disabled = false;
        phaseLabel.textContent = 'Error';
        progressBar.style.width = '0%';
        progressLabel.textContent = error.message;
        statusValue.textContent = 'Error';
        statusValue.style.color = '#f44336';
    }
}

/**
 * Check for ongoing metadata update and restore state on page load
 */
async function checkAndRestoreMetadataUpdateState() {
    try {
        const response = await fetch('/api/metadata/status');
        const data = await response.json();

        if (data.success && data.status) {
            const status = data.status;

            // If metadata update is running, restore the UI state and start polling
            if (status.status === 'running') {
                console.log('Found ongoing metadata update, restoring state...');
                updateMetadataProgressUI(status);
                startMetadataUpdatePolling();
            } else if (status.status === 'completed' || status.status === 'error') {
                // Show final state but don't start polling
                updateMetadataProgressUI(status);
            }
        }
    } catch (error) {
        console.warn('Could not check metadata update state on page load:', error);
    }
}

// --- Live Log Viewer Functions ---

// Global state for log polling
let logPolling = false;
let logInterval = null;
let lastLogCount = 0;

/**
 * Initialize the live log viewer for sync page
 */
function initializeLiveLogViewer() {
    const logArea = document.getElementById('sync-log-area');
    if (!logArea) return;

    // Set initial content
    logArea.value = 'Loading activity feed...';

    // Start log polling
    startLogPolling();

    // Initial load
    loadLogs();
}

/**
 * Start polling for logs
 */
function startLogPolling() {
    if (logPolling) return; // Already polling

    logPolling = true;
    logInterval = setInterval(loadLogs, 3000); // Poll every 3 seconds
    console.log('📝 Started activity feed polling for sync page');
}

/**
 * Stop polling for logs
 */
function stopLogPolling() {
    logPolling = false;
    if (logInterval) {
        clearInterval(logInterval);
        logInterval = null;
        console.log('📝 Stopped log polling');
    }
}

/**
 * Load and display activity feed as logs
 */
async function loadLogs() {
    if (socketConnected) return; // WebSocket handles this
    try {
        const response = await fetch('/api/logs');
        const data = await response.json();
        updateLogsFromData(data);
    } catch (error) {
        console.warn('Could not load activity logs for sync page:', error);
        const logArea = document.getElementById('sync-log-area');
        if (logArea && (logArea.value === 'Loading logs...' || logArea.value === '')) {
            logArea.value = 'Error loading activity feed. Check console for details.';
        }
    }
}

function updateLogsFromData(data) {
    if (!data.logs || !Array.isArray(data.logs)) return;
    const logArea = document.getElementById('sync-log-area');
    if (!logArea) return;

    const logText = data.logs.join('\n');

    // Store current scroll state
    const wasAtTop = logArea.scrollTop <= 10;
    const wasUserScrolled = logArea.scrollTop < logArea.scrollHeight - logArea.clientHeight - 10;

    // Update content only if it has changed
    if (logArea.value !== logText) {
        logArea.value = logText;

        // Smart scrolling: stay at top for new entries, preserve user position if scrolled
        if (wasAtTop || !wasUserScrolled) {
            logArea.scrollTop = 0; // Stay at top since newest entries are now at top
        }
    }
}

/**
 * Stop log polling when leaving sync page
 */
function cleanupSyncPageLogs() {
    stopLogPolling();
}

// --- Global Cleanup on Page Unload ---
// Note: Automatic wishlist processing now runs server-side and continues even when browser is closed
// ===============================
// LIBRARY PAGE FUNCTIONALITY
// ===============================

// Library page state
const libraryPageState = {
    isInitialized: false,
    currentSearch: "",
    currentLetter: "all",
    currentPage: 1,
    limit: 75,
    debounceTimer: null,
    watchlistFilter: "all",
    sourceFilter: ""
};

function initializeLibraryPage() {
    console.log("🔧 Initializing Library page...");

    try {
        // Initialize search functionality
        initializeLibrarySearch();

        // Initialize watchlist filter
        initializeWatchlistFilter();

        // Initialize metadata source filter
        initializeSourceFilter();

        // Initialize alphabet selector
        initializeAlphabetSelector();

        // Initialize pagination
        initializeLibraryPagination();

        // Load initial data
        loadLibraryArtists();

        // Show download bubbles if any exist
        showLibraryDownloadsSection();

        libraryPageState.isInitialized = true;
        console.log("✅ Library page initialized successfully");

    } catch (error) {
        console.error("❌ Error initializing Library page:", error);
        showToast("Failed to initialize Library page", "error");
    }
}

function initializeLibrarySearch() {
    const searchInput = document.getElementById("library-search-input");
    if (!searchInput) return;

    searchInput.addEventListener("input", (e) => {
        const query = e.target.value.trim();

        // Clear existing debounce timer
        if (libraryPageState.debounceTimer) {
            clearTimeout(libraryPageState.debounceTimer);
        }

        // Debounce search requests
        libraryPageState.debounceTimer = setTimeout(() => {
            libraryPageState.currentSearch = query;
            libraryPageState.currentPage = 1; // Reset to first page
            loadLibraryArtists();
        }, 300);
    });

    // Clear search on Escape key
    searchInput.addEventListener("keydown", (e) => {
        if (e.key === "Escape") {
            searchInput.value = "";
            libraryPageState.currentSearch = "";
            libraryPageState.currentPage = 1;
            loadLibraryArtists();
        }
    });
}

function initializeWatchlistFilter() {
    const filterButtons = document.querySelectorAll(".watchlist-filter-btn");
    const watchAllBtn = document.getElementById("library-watchlist-all-btn");

    filterButtons.forEach(button => {
        button.addEventListener("click", () => {
            const filter = button.getAttribute("data-filter");

            // Update active state
            filterButtons.forEach(btn => btn.classList.remove("active"));
            button.classList.add("active");

            // Show/hide "Watch All Unwatched" button
            if (watchAllBtn) {
                if (filter === "unwatched") {
                    watchAllBtn.classList.remove("hidden");
                } else {
                    watchAllBtn.classList.add("hidden");
                }
            }

            // Update state and reload
            libraryPageState.watchlistFilter = filter;
            libraryPageState.currentPage = 1;
            loadLibraryArtists();
        });
    });
}

function initializeSourceFilter() {
    const select = document.getElementById('library-source-filter');
    if (!select) return;
    select.addEventListener('change', () => {
        libraryPageState.sourceFilter = select.value;
        libraryPageState.currentPage = 1;
        loadLibraryArtists();
    });
}

function initializeAlphabetSelector() {
    const alphabetButtons = document.querySelectorAll(".alphabet-btn");

    alphabetButtons.forEach(button => {
        button.addEventListener("click", () => {
            const letter = button.getAttribute("data-letter");

            // Update active state
            alphabetButtons.forEach(btn => btn.classList.remove("active"));
            button.classList.add("active");

            // Update state and load data
            libraryPageState.currentLetter = letter;
            libraryPageState.currentPage = 1; // Reset to first page
            loadLibraryArtists();
        });
    });
}

function initializeLibraryPagination() {
    const prevBtn = document.getElementById("prev-page-btn");
    const nextBtn = document.getElementById("next-page-btn");

    if (prevBtn) {
        prevBtn.addEventListener("click", () => {
            if (libraryPageState.currentPage > 1) {
                libraryPageState.currentPage--;
                loadLibraryArtists();
            }
        });
    }

    if (nextBtn) {
        nextBtn.addEventListener("click", () => {
            libraryPageState.currentPage++;
            loadLibraryArtists();
        });
    }
}

async function loadLibraryArtists() {
    try {
        // Show loading state
        showLibraryLoading(true);

        // Build query parameters
        const params = new URLSearchParams({
            search: libraryPageState.currentSearch,
            letter: libraryPageState.currentLetter,
            page: libraryPageState.currentPage,
            limit: libraryPageState.limit,
            watchlist: libraryPageState.watchlistFilter
        });
        if (libraryPageState.sourceFilter) params.set('source_filter', libraryPageState.sourceFilter);

        // Fetch artists from API
        const response = await fetch(`/api/library/artists?${params}`);
        const data = await response.json();

        if (!data.success) {
            throw new Error(data.error || "Failed to load artists");
        }

        // Update UI with artists
        displayLibraryArtists(data.artists);
        updateLibraryPagination(data.pagination);
        updateLibraryStats(data.pagination.total_count);

        // Hide loading state
        showLibraryLoading(false);

        // Show empty state if no artists
        if (data.artists.length === 0) {
            showLibraryEmpty(true);
        } else {
            showLibraryEmpty(false);
        }

    } catch (error) {
        console.error("❌ Error loading library artists:", error);
        showToast("Failed to load artists", "error");
        showLibraryLoading(false);
        showLibraryEmpty(true);
    }
}

function displayLibraryArtists(artists) {
    const grid = document.getElementById("library-artists-grid");
    if (!grid) return;

    // Build all cards as HTML string for single DOM write (much faster than createElement loop)
    grid.innerHTML = artists.map((artist, i) => buildLibraryArtistCardHTML(artist, i)).join('');

    // Attach click handlers via event delegation (single listener vs 75+ individual)
    grid.onclick = (e) => {
        // Ignore clicks on badge icons (they open external links / toggle watchlist)
        const badge = e.target.closest('.source-card-icon');
        if (badge) {
            e.stopPropagation();
            const url = badge.dataset.url;
            if (url) { window.open(url, '_blank'); return; }
            // Watchlist toggle
            if (badge.classList.contains('watch-card-icon') && badge.dataset.unwatched) {
                const card = badge.closest('.library-artist-card');
                if (card) {
                    const artistId = card.dataset.artistId;
                    const artistName = card.dataset.artistName;
                    const artist = artists.find(a => String(a.id) === artistId);
                    if (artist) toggleLibraryCardWatchlist(badge, artist);
                }
            }
            return;
        }
        const card = e.target.closest('.library-artist-card');
        if (card) {
            navigateToArtistDetail(card.dataset.artistId, card.dataset.artistName);
        }
    };
}

function buildLibraryArtistCardHTML(artist, index) {
    const _esc = (s) => (s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;');
    const delay = Math.min(index * 20, 600); // Cap at 600ms so last cards don't wait too long

    // Build badge icons
    const badges = [];
    if (artist.spotify_artist_id) badges.push({ logo: SPOTIFY_LOGO_URL, fb: 'SP', title: 'Spotify', url: `https://open.spotify.com/artist/${artist.spotify_artist_id}` });
    if (artist.musicbrainz_id) badges.push({ logo: MUSICBRAINZ_LOGO_URL, fb: 'MB', title: 'MusicBrainz', url: `https://musicbrainz.org/artist/${artist.musicbrainz_id}` });
    if (artist.deezer_id) badges.push({ logo: DEEZER_LOGO_URL, fb: 'Dz', title: 'Deezer', url: `https://www.deezer.com/artist/${artist.deezer_id}` });
    if (artist.audiodb_id) {
        const slug = artist.name ? artist.name.replace(/\s+/g, '-').replace(/[^a-zA-Z0-9-]/g, '') : '';
        badges.push({ logo: typeof getAudioDBLogoURL === 'function' ? getAudioDBLogoURL() : '', fb: 'ADB', title: 'AudioDB', url: `https://www.theaudiodb.com/artist/${artist.audiodb_id}-${slug}` });
    }
    if (artist.itunes_artist_id) badges.push({ logo: ITUNES_LOGO_URL, fb: 'IT', title: 'Apple Music', url: `https://music.apple.com/artist/${artist.itunes_artist_id}` });
    if (artist.lastfm_url) badges.push({ logo: LASTFM_LOGO_URL, fb: 'LFM', title: 'Last.fm', url: artist.lastfm_url });
    if (artist.genius_url) badges.push({ logo: GENIUS_LOGO_URL, fb: 'GEN', title: 'Genius', url: artist.genius_url });
    if (artist.tidal_id) badges.push({ logo: TIDAL_LOGO_URL, fb: 'TD', title: 'Tidal', url: `https://tidal.com/browse/artist/${artist.tidal_id}` });
    if (artist.qobuz_id) badges.push({ logo: QOBUZ_LOGO_URL, fb: 'Qz', title: 'Qobuz', url: `https://www.qobuz.com/artist/${artist.qobuz_id}` });
    if (artist.discogs_id) badges.push({ logo: DISCOGS_LOGO_URL, fb: 'DC', title: 'Discogs', url: `https://www.discogs.com/artist/${artist.discogs_id}` });
    if (artist.soul_id && !artist.soul_id.startsWith('soul_unnamed_')) badges.push({ logo: '/static/trans2.png', fb: 'SS', title: `SoulID: ${artist.soul_id}`, url: null });

    // Watchlist badge
    const hasActiveSourceId = currentMusicSourceName === 'iTunes'
        ? (artist.itunes_artist_id || artist.spotify_artist_id)
        : (artist.spotify_artist_id || artist.itunes_artist_id);
    let watchBadgeHTML = '';
    if (artist.is_watched) {
        watchBadgeHTML = `<div class="watch-card-icon watched source-card-icon" title="On your watchlist"><span class="watch-icon-emoji">👁️</span><span class="watch-icon-label">Watching</span></div>`;
    } else if (hasActiveSourceId) {
        watchBadgeHTML = `<div class="watch-card-icon source-card-icon" data-unwatched="1" title="Add to Watchlist" style="opacity:0.4"><span class="watch-icon-emoji">👁️</span><span class="watch-icon-label">Watch</span></div>`;
    }

    const maxPerColumn = 6;
    const needsOverflow = badges.length > maxPerColumn;
    const badgeIcon = (b) => `<div class="source-card-icon" title="${_esc(b.title)}" ${b.url ? `data-url="${_esc(b.url)}"` : ''}>${b.logo ? `<img src="${_esc(b.logo)}" style="width:16px;height:auto;display:block" onerror="this.parentNode.textContent='${b.fb}'">` : `<span style="font-size:9px;font-weight:700">${b.fb}</span>`}</div>`;

    let badgeContainerHTML = '';
    if (badges.length > 0 || watchBadgeHTML) {
        if (needsOverflow) {
            badgeContainerHTML = `<div class="card-badge-container">
                <div class="badge-overflow-column">${watchBadgeHTML}${badges.slice(maxPerColumn).map(badgeIcon).join('')}</div>
                <div class="badge-primary-column">${badges.slice(0, maxPerColumn).map(badgeIcon).join('')}</div>
            </div>`;
        } else {
            badgeContainerHTML = `<div class="card-badge-container">${badges.map(badgeIcon).join('')}${watchBadgeHTML}</div>`;
        }
    }

    // Image
    const hasImage = artist.image_url && artist.image_url.trim() !== '';
    const deezerFallback = artist.deezer_id ? `if(!this.dataset.triedDeezer){this.dataset.triedDeezer='true';this.src='https://api.deezer.com/artist/${artist.deezer_id}/image?size=big'}else{this.parentNode.innerHTML='<div class=\\'library-artist-image-fallback\\'>🎵</div>'}` : `this.parentNode.innerHTML='<div class=\\'library-artist-image-fallback\\'>🎵</div>'`;
    const imageHTML = hasImage
        ? `<div class="library-artist-image"><img src="${_esc(artist.image_url)}" alt="${_esc(artist.name)}" loading="lazy" onerror="${deezerFallback}"></div>`
        : `<div class="library-artist-image"><div class="library-artist-image-fallback">🎵</div></div>`;

    // Track stats
    const trackStat = artist.track_count > 0 ? `<span class="library-artist-stat">${artist.track_count} track${artist.track_count !== 1 ? 's' : ''}</span>` : '';

    return `<div class="library-artist-card" data-artist-id="${_esc(String(artist.id))}" data-artist-name="${_esc(artist.name)}" style="position:relative;animation:cardFadeIn 0.35s cubic-bezier(0.4,0,0.2,1) ${delay}ms both">
        ${badgeContainerHTML}
        ${imageHTML}
        <div class="library-artist-info">
            <h3 class="library-artist-name" title="${_esc(artist.name)}">${_esc(artist.name)}</h3>
            <div class="library-artist-stats">${trackStat}</div>
        </div>
    </div>`;
}

function updateLibraryPagination(pagination) {
    const prevBtn = document.getElementById("prev-page-btn");
    const nextBtn = document.getElementById("next-page-btn");
    const pageInfo = document.getElementById("page-info");
    const paginationContainer = document.getElementById("library-pagination");

    if (!paginationContainer) return;

    // Update button states
    if (prevBtn) {
        prevBtn.disabled = !pagination.has_prev;
    }

    if (nextBtn) {
        nextBtn.disabled = !pagination.has_next;
    }

    // Update page info
    if (pageInfo) {
        pageInfo.textContent = `Page ${pagination.page} of ${pagination.total_pages}`;
    }

    // Show/hide pagination based on total pages
    if (pagination.total_pages > 1) {
        paginationContainer.classList.remove("hidden");
    } else {
        paginationContainer.classList.add("hidden");
    }
}

function updateLibraryStats(totalCount) {
    const countElement = document.getElementById("library-artist-count");
    if (countElement) {
        countElement.textContent = totalCount;
    }
}

function showLibraryLoading(show) {
    const loadingElement = document.getElementById("library-loading");
    if (loadingElement) {
        if (show) {
            loadingElement.classList.remove("hidden");
        } else {
            loadingElement.classList.add("hidden");
        }
    }
}

function showLibraryEmpty(show) {
    const emptyElement = document.getElementById("library-empty");
    if (emptyElement) {
        if (show) {
            emptyElement.classList.remove("hidden");
        } else {
            emptyElement.classList.add("hidden");
        }
    }
}

async function openWatchAllUnwatchedModal() {
    if (document.getElementById('watch-all-modal-overlay')) return;

    const sourceIdField = currentMusicSourceName === 'iTunes' ? 'itunes_artist_id'
        : currentMusicSourceName === 'Deezer' ? 'deezer_id' : 'spotify_artist_id';
    const sourceName = currentMusicSourceName || 'Spotify';

    const overlay = document.createElement('div');
    overlay.id = 'watch-all-modal-overlay';
    overlay.className = 'modal-overlay';
    overlay.onclick = (e) => { if (e.target === overlay) closeWatchAllUnwatchedModal(); };

    overlay.innerHTML = `
        <div class="watch-all-modal">
            <div class="watch-all-header">
                <div class="watch-all-header-content">
                    <div class="watch-all-header-icon">&#128065;</div>
                    <div>
                        <h2 class="watch-all-title">Watch All Unwatched</h2>
                        <p class="watch-all-subtitle">Add unwatched artists with ${_esc(sourceName)} IDs to your watchlist</p>
                    </div>
                </div>
                <button class="watch-all-close" onclick="closeWatchAllUnwatchedModal()">&times;</button>
            </div>
            <div class="watch-all-body">
                <div class="watch-all-loading-state">
                    <div class="watch-all-loading-spinner"></div>
                    <div class="watch-all-loading-text">Loading unwatched artists...</div>
                    <div class="watch-all-loading-count" id="watch-all-load-count"></div>
                </div>
            </div>
            <div class="watch-all-footer">
                <button class="watch-all-btn watch-all-btn-cancel" onclick="closeWatchAllUnwatchedModal()">Cancel</button>
                <button class="watch-all-btn watch-all-btn-primary" id="watch-all-confirm-btn" disabled>Watch All</button>
            </div>
        </div>
    `;
    document.body.appendChild(overlay);

    // Fetch all unwatched artists paginated (SQLite variable limit safe)
    try {
        const eligible = [];
        const ineligible = [];
        let page = 1;
        const pageSize = 400;
        const countEl = document.getElementById('watch-all-load-count');

        while (true) {
            if (!document.getElementById('watch-all-modal-overlay')) return;
            if (countEl) countEl.textContent = `${eligible.length + ineligible.length} artists loaded...`;

            const params = new URLSearchParams({ search: '', letter: 'all', page, limit: pageSize, watchlist: 'unwatched' });
            const response = await fetch(`/api/library/artists?${params}`);
            const data = await response.json();
            if (!data.success) throw new Error(data.error || 'Failed to load artists');

            for (const a of (data.artists || [])) {
                if (a[sourceIdField]) eligible.push(a);
                else ineligible.push(a);
            }

            if (!data.pagination.has_next) break;
            page++;
        }

        _renderWatchAllModalContent(overlay, eligible, ineligible, sourceName);
    } catch (error) {
        console.error('Error loading unwatched artists:', error);
        const body = overlay.querySelector('.watch-all-body');
        if (body) body.innerHTML = `<div class="watch-all-empty-state"><div class="watch-all-empty-icon">&#9888;</div><div>Failed to load artists</div><a href="#" onclick="closeWatchAllUnwatchedModal(); openWatchAllUnwatchedModal(); return false;" class="watch-all-retry-link">Retry</a></div>`;
    }
}

function _renderWatchAllModalContent(overlay, eligible, ineligible, sourceName) {
    const body = overlay.querySelector('.watch-all-body');
    const confirmBtn = overlay.querySelector('#watch-all-confirm-btn');

    if (eligible.length === 0 && ineligible.length === 0) {
        body.innerHTML = '<div class="watch-all-empty-state"><div class="watch-all-empty-icon">&#127925;</div><div>No unwatched artists found</div></div>';
        return;
    }

    // Store data for search filtering
    overlay._watchAllEligible = eligible;
    overlay._watchAllIneligible = ineligible;

    let html = '';

    // Summary bar (sticky)
    html += '<div class="watch-all-stats">';
    html += `<div class="watch-all-stat-card eligible"><div class="watch-all-stat-value">${eligible.length}</div><div class="watch-all-stat-label">Ready to watch</div></div>`;
    html += `<div class="watch-all-stat-card ineligible"><div class="watch-all-stat-value">${ineligible.length}</div><div class="watch-all-stat-label">No ${_esc(sourceName)} ID</div></div>`;
    html += `<div class="watch-all-stat-card total"><div class="watch-all-stat-value">${eligible.length + ineligible.length}</div><div class="watch-all-stat-label">Total unwatched</div></div>`;
    html += '</div>';

    // Search filter
    if (eligible.length > 10) {
        html += '<div class="watch-all-search-wrap"><input type="text" class="watch-all-search" id="watch-all-search" placeholder="Search artists..." oninput="_filterWatchAllList(this.value)"></div>';
    }

    // Eligible grid
    if (eligible.length > 0) {
        html += '<div class="watch-all-section-label">Artists to be watched</div>';
        html += '<div class="watch-all-grid" id="watch-all-eligible-grid">';
        html += _buildWatchAllRows(eligible, false);
        html += '</div>';
    }

    // Ineligible section
    if (ineligible.length > 0) {
        html += `<div class="watch-all-ineligible">
            <div class="watch-all-ineligible-header" onclick="this.parentElement.classList.toggle('expanded')">
                <div class="watch-all-ineligible-label">
                    <span class="watch-all-ineligible-icon">&#9888;</span>
                    <span>${ineligible.length} artist${ineligible.length !== 1 ? 's' : ''} without ${_esc(sourceName)} ID</span>
                </div>
                <span class="watch-all-chevron">&#9660;</span>
            </div>
            <div class="watch-all-ineligible-body">
                <div class="watch-all-ineligible-hint">These artists haven't been matched to ${_esc(sourceName)} yet. The background enrichment worker will match them over time.</div>
                <div class="watch-all-grid" id="watch-all-ineligible-grid">${_buildWatchAllRows(ineligible, true)}</div>
            </div>
        </div>`;
    }

    if (eligible.length === 0) {
        html += `<div class="watch-all-empty-state"><div class="watch-all-empty-icon">&#128268;</div><div>None of your unwatched artists have a ${_esc(sourceName)} ID yet</div><div class="watch-all-empty-hint">The background enrichment worker will match them over time.</div></div>`;
    }

    body.innerHTML = html;

    if (eligible.length > 0 && confirmBtn) {
        confirmBtn.textContent = `Watch All (${eligible.length})`;
        confirmBtn.disabled = false;
        confirmBtn.onclick = () => _confirmWatchAllUnwatched(overlay, eligible.length);
    }
}

function _buildWatchAllRows(artists, dimmed) {
    let html = '';
    for (const a of artists) {
        const img = a.image_url
            ? `<img src="${_esc(a.image_url)}" alt="" onerror="this.style.display='none'; this.nextElementSibling.style.display='flex'" loading="lazy"><div class="watch-all-cell-placeholder" style="display:none">&#127925;</div>`
            : `<div class="watch-all-cell-placeholder">&#127925;</div>`;
        html += `<div class="watch-all-cell${dimmed ? ' dimmed' : ''}" data-name="${_esc(a.name.toLowerCase())}">
            <div class="watch-all-cell-img">${img}</div>
            <div class="watch-all-cell-name" title="${_esc(a.name)}">${_esc(a.name)}</div>
            <div class="watch-all-cell-meta">${a.track_count || 0} tracks</div>
        </div>`;
    }
    return html;
}

function _filterWatchAllList(query) {
    const q = query.toLowerCase().trim();
    document.querySelectorAll('#watch-all-eligible-grid .watch-all-cell').forEach(cell => {
        cell.style.display = !q || cell.dataset.name.includes(q) ? '' : 'none';
    });
}

async function _confirmWatchAllUnwatched(overlay, expectedCount) {
    const confirmBtn = overlay.querySelector('#watch-all-confirm-btn');
    const cancelBtn = overlay.querySelector('.watch-all-btn-cancel');
    if (confirmBtn) { confirmBtn.disabled = true; confirmBtn.textContent = 'Adding...'; }
    if (cancelBtn) cancelBtn.disabled = true;

    try {
        const response = await fetch('/api/library/watchlist-all-unwatched', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' }
        });
        const data = await response.json();

        if (data.success) {
            const body = overlay.querySelector('.watch-all-body');
            body.innerHTML = `<div class="watch-all-results">
                <div class="watch-all-results-icon">&#10003;</div>
                <div class="watch-all-results-title">Added ${data.added} artist${data.added !== 1 ? 's' : ''} to watchlist</div>
                ${data.skipped_already > 0 ? `<div class="watch-all-results-detail">${data.skipped_already} already watched</div>` : ''}
                ${data.skipped_no_id > 0 ? `<div class="watch-all-results-detail">${data.skipped_no_id} skipped (no external ID)</div>` : ''}
            </div>`;

            if (confirmBtn) confirmBtn.style.display = 'none';
            if (cancelBtn) { cancelBtn.disabled = false; cancelBtn.textContent = 'Close'; }
            overlay.dataset.needsRefresh = 'true';
        } else {
            throw new Error(data.error || 'Failed to add artists');
        }
    } catch (error) {
        console.error('Error in watch all:', error);
        if (confirmBtn) { confirmBtn.disabled = false; confirmBtn.textContent = `Watch All (${expectedCount})`; }
        if (cancelBtn) cancelBtn.disabled = false;
        showToast('Failed to add artists to watchlist', 'error');
    }
}

function closeWatchAllUnwatchedModal() {
    const overlay = document.getElementById('watch-all-modal-overlay');
    if (!overlay) return;
    const needsRefresh = overlay.dataset.needsRefresh === 'true';
    overlay.remove();
    if (needsRefresh) loadLibraryArtists();
}

async function toggleLibraryCardWatchlist(btn, artist) {
    if (btn.disabled) return;
    btn.disabled = true;

    // Support both badge-style (.watch-icon-label) and button-style (.watchlist-text)
    const label = btn.querySelector('.watch-icon-label') || btn.querySelector('.watchlist-text');
    const isWatching = btn.classList.contains('watched') || btn.classList.contains('watching');

    if (label) label.textContent = '...';

    try {
        // Use the ID matching the active metadata source
        const artistId = currentMusicSourceName === 'iTunes'
            ? (artist.itunes_artist_id || artist.spotify_artist_id)
            : (artist.spotify_artist_id || artist.itunes_artist_id);
        if (!artistId) throw new Error('No iTunes or Spotify ID available for this artist');

        if (isWatching) {
            const response = await fetch('/api/watchlist/remove', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ artist_id: artistId })
            });
            const data = await response.json();
            if (!data.success) throw new Error(data.error);

            btn.classList.remove('watched', 'watching');
            btn.style.opacity = '0.4';
            btn.title = 'Add to Watchlist';
            if (label) label.textContent = 'Watch';
            showToast(`Removed ${artist.name} from watchlist`, 'success');
        } else {
            const response = await fetch('/api/watchlist/add', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ artist_id: artistId, artist_name: artist.name })
            });
            const data = await response.json();
            if (!data.success) throw new Error(data.error);

            btn.classList.add('watched');
            btn.style.opacity = '';
            btn.title = 'Remove from Watchlist';
            if (label) label.textContent = 'Watching';
            showToast(`Added ${artist.name} to watchlist`, 'success');
        }

        if (typeof updateWatchlistCount === 'function') {
            updateWatchlistCount();
        }
    } catch (error) {
        console.error('Error toggling library card watchlist:', error);
        if (label) label.textContent = isWatching ? 'Watching' : 'Watch';
        showToast(`Error: ${error.message}`, 'error');
    } finally {
        btn.disabled = false;
    }
}

