function _renderResultStats(resultJson, actionType) {
    if (!resultJson || typeof resultJson !== 'object') return '';
    var fields = _RESULT_DISPLAY_MAP[actionType];
    var items = [];
    if (fields) {
        fields.forEach(function(f) {
            var val = resultJson[f.key];
            if (val == null) return;
            if (f.hideZero && (val === 0 || val === '0')) return;
            items.push({ label: f.label, value: val });
        });
    } else {
        // Generic fallback: show all non-status, non-underscore keys
        Object.keys(resultJson).forEach(function(k) {
            if (k === 'status' || k.startsWith('_')) return;
            var label = k.replace(/_/g, ' ').replace(/\b\w/g, function(c) { return c.toUpperCase(); });
            items.push({ label: label, value: resultJson[k] });
        });
    }
    if (items.length === 0) return '';
    var html = '<div class="history-stats-grid">';
    items.forEach(function(it) {
        html += '<div class="history-stat-item"><div class="history-stat-label">' + _esc(it.label) + '</div><div class="history-stat-value">' + _esc(String(it.value)) + '</div></div>';
    });
    html += '</div>';
    return html;
}

async function showAutomationHistory(automationId, automationName, actionType) {
    let modal = document.getElementById('automation-history-modal');
    if (!modal) {
        modal = document.createElement('div');
        modal.id = 'automation-history-modal';
        modal.className = 'modal-overlay';
        document.body.appendChild(modal);
    }
    modal.innerHTML = '<div class="modal-container automation-history-modal"><div class="history-modal-header"><h3>Run History: ' + _esc(automationName) + '</h3><button class="history-close-btn" onclick="document.getElementById(\'automation-history-modal\').style.display=\'none\'">&times;</button></div><div class="history-modal-body"><div class="history-loading">Loading...</div></div></div>';
    modal.style.display = 'flex';
    modal.onclick = function(e) { if (e.target === modal) modal.style.display = 'none'; };

    try {
        const res = await fetch('/api/automations/' + automationId + '/history?limit=50');
        const data = await res.json();
        if (data.error) throw new Error(data.error);
        const body = modal.querySelector('.history-modal-body');
        if (!data.history || data.history.length === 0) {
            body.innerHTML = '<div class="history-empty">No run history yet. History will be recorded on future runs.</div>';
            return;
        }
        let html = '<div class="history-entries">';
        data.history.forEach(function(entry) {
            const statusClass = 'history-status-' + (entry.status || 'completed');
            const statusLabel = (entry.status || 'completed').charAt(0).toUpperCase() + (entry.status || 'completed').slice(1);
            const timeAgo = _autoTimeAgo(entry.started_at);
            const duration = entry.duration_seconds != null ? _formatDuration(entry.duration_seconds) : '';
            const summary = entry.summary ? _esc(entry.summary) : '';
            const hasLogs = entry.log_lines && entry.log_lines.length > 0;
            const entryId = 'history-entry-' + entry.id;

            html += '<div class="history-entry">';
            html += '<div class="history-entry-header" onclick="var el=document.getElementById(\'' + entryId + '\'); if(el) el.classList.toggle(\'expanded\')">';
            html += '<span class="history-status-badge ' + statusClass + '">' + statusLabel + '</span>';
            html += '<span class="history-time">' + timeAgo + '</span>';
            if (duration) html += '<span class="history-duration">' + duration + '</span>';
            if (hasLogs) html += '<span class="history-expand-icon">&#9660;</span>';
            html += '</div>';
            if (summary) html += '<div class="history-summary">' + summary + '</div>';
            if (entry.result_json && typeof entry.result_json === 'object') {
                html += _renderResultStats(entry.result_json, actionType);
            }
            if (hasLogs) {
                html += '<div id="' + entryId + '" class="history-log-section">';
                entry.log_lines.forEach(function(log) {
                    html += '<div class="history-log-line history-log-' + (log.type || 'info') + '">' + _esc(log.text || '') + '</div>';
                });
                html += '</div>';
            }
            html += '</div>';
        });
        html += '</div>';
        if (data.total > data.history.length) {
            html += '<div class="history-total">Showing ' + data.history.length + ' of ' + data.total + ' runs</div>';
        }
        body.innerHTML = html;
    } catch (err) {
        const body = modal.querySelector('.history-modal-body');
        if (body) body.innerHTML = '<div class="history-empty">Error loading history: ' + _esc(err.message) + '</div>';
    }
}

function _formatDuration(seconds) {
    if (seconds < 1) return '<1s';
    if (seconds < 60) return Math.round(seconds) + 's';
    var m = Math.floor(seconds / 60);
    var s = Math.round(seconds % 60);
    if (m < 60) return m + 'm ' + s + 's';
    var h = Math.floor(m / 60);
    m = m % 60;
    return h + 'h ' + m + 'm';
}

async function saveAutomation() {
    const name = document.getElementById('builder-name').value.trim();
    if (!name) { showToast('Name is required', 'error'); return; }
    if (!_autoBuilder.when) { showToast('Add a trigger (WHEN)', 'error'); return; }
    if (!_autoBuilder.do) { showToast('Add an action (DO)', 'error'); return; }

    // Read configs from DOM
    const triggerConfig = _readPlacedConfig('when');
    const actionConfig = _readPlacedConfig('do');

    // Read THEN actions (multi-slot)
    const thenActions = _autoBuilder.then.map((item, i) => ({
        type: item.type,
        config: _readPlacedConfig('then-' + i),
    }));

    // Read optional delay from DO slot
    const delayEl = document.getElementById('cfg-do-delay');
    const delayVal = delayEl ? parseInt(delayEl.value) : 0;
    if (delayVal > 0) actionConfig.delay = delayVal;

    const groupInput = document.getElementById('builder-group-name');
    const groupName = groupInput ? groupInput.value.trim() : '';

    const body = {
        name,
        trigger_type: _autoBuilder.when.type, trigger_config: triggerConfig,
        action_type: _autoBuilder.do.type, action_config: actionConfig,
        then_actions: thenActions,
        group_name: groupName || null,
    };

    try {
        let res;
        if (_autoBuilder.editId) {
            res = await fetch('/api/automations/' + _autoBuilder.editId, { method: 'PUT', headers: {'Content-Type':'application/json'}, body: JSON.stringify(body) });
        } else {
            res = await fetch('/api/automations', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify(body) });
        }
        const data = await res.json();
        if (data.error) throw new Error(data.error);
        showToast(_autoBuilder.editId ? 'Automation updated' : 'Automation created', 'success');
        hideAutomationBuilder();
        await loadAutomations();
    } catch (err) { showToast('Error: ' + err.message, 'error'); }
}

// --- Builder View ---

async function showAutomationBuilder(editId) {
    // Load block definitions (always refresh)
    try {
        const res = await fetch('/api/automations/blocks');
        _autoBlocks = await res.json();
    } catch (e) {
        if (!_autoBlocks) { showToast('Failed to load blocks', 'error'); return; }
    }

    _autoMirroredPlaylists = null; // invalidate so it re-fetches
    _autoSpotifyAuthenticated = false;
    _autoBuilder = { editId: editId || null, when: null, do: null, then: [], isSystem: false };

    // Populate group datalist from existing automations
    try {
        const allRes = await fetch('/api/automations');
        const allAutos = await allRes.json();
        const groupSet = new Set();
        if (Array.isArray(allAutos)) allAutos.forEach(a => { if (a.group_name) groupSet.add(a.group_name); });
        const datalist = document.getElementById('builder-group-list');
        if (datalist) datalist.innerHTML = [...groupSet].sort().map(g => `<option value="${_escAttr(g)}">`).join('');
    } catch (e) {}

    // If editing, load automation data
    if (editId) {
        try {
            const res = await fetch('/api/automations/' + editId);
            const a = await res.json();
            if (a.error) throw new Error(a.error);
            document.getElementById('builder-name').value = a.name || '';
            const groupInput = document.getElementById('builder-group-name');
            if (groupInput) groupInput.value = a.group_name || '';
            _autoBuilder.when = { type: a.trigger_type, config: a.trigger_config || {} };
            _autoBuilder.do = { type: a.action_type, config: a.action_config || {} };
            // Load then_actions array
            _autoBuilder.then = (a.then_actions || []).map(item => ({
                type: item.type, config: item.config || {}
            }));
            // Backward compat: if no then_actions but has notify_type
            if (!_autoBuilder.then.length && a.notify_type) {
                _autoBuilder.then = [{ type: a.notify_type, config: a.notify_config || {} }];
            }
            _autoBuilder.isSystem = !!a.is_system;
        } catch (err) { showToast('Failed to load automation', 'error'); return; }
    } else {
        document.getElementById('builder-name').value = '';
        const groupInput = document.getElementById('builder-group-name');
        if (groupInput) groupInput.value = '';
    }

    // System automations: lock the name field and hide group
    document.getElementById('builder-name').readOnly = _autoBuilder.isSystem;
    const groupEl = document.getElementById('builder-group-name');
    if (groupEl) groupEl.style.display = _autoBuilder.isSystem ? 'none' : '';

    _renderBuilderSidebar();
    _renderBuilderCanvas();

    document.getElementById('automations-list-view').style.display = 'none';
    document.getElementById('automations-builder-view').style.display = '';
}

function hideAutomationBuilder() {
    document.getElementById('automations-builder-view').style.display = 'none';
    document.getElementById('automations-list-view').style.display = '';
    document.getElementById('builder-name').readOnly = false;
    _autoBuilder = { editId: null, when: null, do: null, then: [], isSystem: false };
}

// --- Sidebar ---

function _renderBuilderSidebar() {
    const sidebar = document.getElementById('builder-sidebar');
    if (!sidebar || !_autoBlocks) return;

    let html = '';
    const sections = [
        { key: 'triggers', title: 'Triggers', slot: 'when' },
        { key: 'actions', title: 'Actions', slot: 'do' },
        { key: 'notifications', title: 'Then', slot: 'then' },
    ];

    sections.forEach(sec => {
        html += `<div class="sidebar-section"><div class="sidebar-section-title">${sec.title}</div>`;
        (_autoBlocks[sec.key] || []).forEach(block => {
            const icon = _autoIcons[block.type] || '\u2699\uFE0F';
            const disabled = !block.available;
            const helpKey = 'auto-' + block.type;
            const hasHelp = !!TOOL_HELP_CONTENT[helpKey];
            html += `<div class="block-item${disabled ? ' coming-soon' : ''}" ${!disabled ? `draggable="true" ondragstart="_autoDragStart(event,'${block.type}','${sec.slot}')" onclick="_autoClickBlock('${block.type}','${sec.slot}')"` : ''}>
                <div class="block-item-icon">${icon}</div>
                <div class="block-item-text">
                    <div class="block-item-label">${_esc(block.label)}</div>
                    <div class="block-item-desc">${_esc(block.description)}</div>
                </div>
                ${disabled ? '<span class="coming-soon-badge">Soon</span>' : ''}
                ${hasHelp ? `<button class="tool-help-button block-help-btn" onclick="event.stopPropagation(); openToolHelpModal('${helpKey}')" title="Learn more">?</button>` : ''}
            </div>`;
        });
        html += '</div>';
    });
    sidebar.innerHTML = html;
}

// --- Canvas ---

function _renderBuilderCanvas() {
    const canvas = document.getElementById('builder-canvas');
    if (!canvas) return;

    let html = '';

    // WHEN slot
    const whenData = _autoBuilder.when;
    html += '<span class="flow-slot-label when">WHEN</span>';
    if (whenData) {
        html += `<div class="flow-slot filled" id="slot-when" ondragover="_autoDragOver(event,'when')" ondragleave="_autoDragLeave(event,'when')" ondrop="_autoDrop(event,'when')">
            ${_renderPlacedBlock('when', whenData)}
        </div>`;
    } else {
        html += `<div class="flow-slot empty" id="slot-when" ondragover="_autoDragOver(event,'when')" ondragleave="_autoDragLeave(event,'when')" ondrop="_autoDrop(event,'when')">
            <div class="flow-slot-prompt">Drag a trigger here — WHEN does this run?</div>
        </div>`;
    }

    html += '<div class="flow-connector"></div>';

    // DO slot
    const doData = _autoBuilder.do;
    html += '<span class="flow-slot-label do">DO</span>';
    if (doData) {
        html += `<div class="flow-slot filled" id="slot-do" ondragover="_autoDragOver(event,'do')" ondragleave="_autoDragLeave(event,'do')" ondrop="_autoDrop(event,'do')">
            ${_renderPlacedBlock('do', doData)}
        </div>`;
    } else {
        html += `<div class="flow-slot empty" id="slot-do" ondragover="_autoDragOver(event,'do')" ondragleave="_autoDragLeave(event,'do')" ondrop="_autoDrop(event,'do')">
            <div class="flow-slot-prompt">Drag an action here — WHAT should it do?</div>
        </div>`;
    }

    html += '<div class="flow-connector"></div>';

    // THEN section (multi-slot, 1-3 items)
    html += '<span class="flow-slot-label then">THEN</span>';
    if (_autoBuilder.then.length > 0) {
        _autoBuilder.then.forEach((item, i) => {
            if (i > 0) html += '<div class="flow-connector small"></div>';
            html += `<div class="flow-slot filled then-slot" id="slot-then-${i}">
                ${_renderPlacedBlock('then-' + i, item)}
            </div>`;
        });
    }
    if (_autoBuilder.then.length < 3) {
        if (_autoBuilder.then.length > 0) html += '<div class="flow-connector small"></div>';
        html += `<div class="flow-slot empty then-add" id="slot-then-add"
            ondragover="_autoDragOver(event,'then')" ondragleave="_autoDragLeave(event,'then')" ondrop="_autoDrop(event,'then')">
            <div class="flow-slot-prompt">${_autoBuilder.then.length === 0
                ? 'Drag a then-action here (optional)'
                : '+ Add another (max 3)'}</div>
        </div>`;
    }

    canvas.innerHTML = html;
    // Load mirrored playlist selects if any are present
    _autoLoadMirroredSelects();
    // Set up checkbox state for refresh_mirrored
    ['when', 'do'].forEach(sk => {
        const allCb = document.getElementById('cfg-' + sk + '-all');
        if (allCb) _autoTogglePlaylistSelect(sk);
    });
    // Also check then slots
    _autoBuilder.then.forEach((item, i) => {
        const allCb = document.getElementById('cfg-then-' + i + '-all');
        if (allCb) _autoTogglePlaylistSelect('then-' + i);
    });
}

function _renderPlacedBlock(slotKey, data) {
    const blockDef = _findBlockDef(data.type);
    const icon = _autoIcons[data.type] || '\u2699\uFE0F';
    const label = blockDef ? blockDef.label : data.type;
    const configHtml = _renderBlockConfigFields(slotKey, data.type, data.config || {});

    // Add optional delay field for action blocks
    let delayHtml = '';
    if (slotKey === 'do') {
        const delayVal = (data.config && data.config.delay) || '';
        delayHtml = `<div class="placed-block-config"><div class="config-row">
            <label>Delay (minutes)</label>
            <input type="number" id="cfg-${slotKey}-delay" value="${delayVal}" min="0" placeholder="0" style="width:80px;" title="Wait before executing action">
        </div></div>`;
    }

    // System automations: lock trigger and action slots (no remove, no replace)
    const locked = _autoBuilder.isSystem && (slotKey === 'when' || slotKey === 'do');
    const removeBtn = locked ? '' : `<button class="placed-block-remove" onclick="_autoRemoveBlock('${slotKey}')">\u2715</button>`;

    return `<div class="placed-block${locked ? ' locked' : ''}" data-type="${_escAttr(data.type)}">
        <div class="placed-block-header">
            <span class="placed-block-icon">${icon}</span>
            <span class="placed-block-label">${_esc(label)}</span>
            ${removeBtn}
        </div>
        ${configHtml ? '<div class="placed-block-config">' + configHtml + '</div>' : ''}
        ${delayHtml}
    </div>`;
}

function _renderBlockConfigFields(slotKey, blockType, config) {
    if (blockType === 'schedule') {
        const interval = config.interval || 6;
        const unit = config.unit || 'hours';
        return `<div class="config-row">
            <label>Every</label>
            <input type="number" id="cfg-${slotKey}-interval" value="${interval}" min="1" style="width:70px;">
            <select id="cfg-${slotKey}-unit">
                <option value="minutes"${unit==='minutes'?' selected':''}>Minutes</option>
                <option value="hours"${unit==='hours'?' selected':''}>Hours</option>
                <option value="days"${unit==='days'?' selected':''}>Days</option>
            </select>
        </div>`;
    }
    if (blockType === 'daily_time') {
        const timeVal = config.time || '03:00';
        return `<div class="config-row">
            <label>At</label>
            <input type="time" id="cfg-${slotKey}-time" value="${timeVal}">
        </div>`;
    }
    if (blockType === 'weekly_time') {
        const timeVal = config.time || '03:00';
        const selectedDays = config.days || [];
        const allDays = [['mon','Mon'],['tue','Tue'],['wed','Wed'],['thu','Thu'],['fri','Fri'],['sat','Sat'],['sun','Sun']];
        let dayHtml = '<div class="config-row"><label>Days</label><div class="day-picker" id="cfg-' + slotKey + '-days">';
        allDays.forEach(([val, lbl]) => {
            const active = selectedDays.includes(val) ? ' active' : '';
            dayHtml += `<button type="button" class="day-btn${active}" data-day="${val}" onclick="this.classList.toggle('active')">${lbl}</button>`;
        });
        dayHtml += '</div></div>';
        return `<div class="config-row">
            <label>At</label>
            <input type="time" id="cfg-${slotKey}-time" value="${timeVal}">
        </div>${dayHtml}`;
    }

    // Event triggers with conditions
    const blockDef = _findBlockDef(blockType);
    if (blockDef && blockDef.has_conditions) {
        return _renderConditionBuilder(slotKey, blockDef, config);
    }

    if (blockType === 'process_wishlist') {
        const cat = config.category || 'all';
        return `<div class="config-row">
            <label>Category</label>
            <select id="cfg-${slotKey}-category">
                <option value="all"${cat==='all'?' selected':''}>All</option>
                <option value="albums"${cat==='albums'?' selected':''}>Albums</option>
                <option value="singles"${cat==='singles'?' selected':''}>Singles</option>
            </select>
        </div>`;
    }
    if (blockType === 'signal_received') {
        const sigName = _escAttr(config.signal_name || '');
        const knownSignals = (_autoBlocks && _autoBlocks.known_signals) || [];
        return `<div class="config-row">
            <label>Signal Name</label>
            <input type="text" id="cfg-${slotKey}-signal_name" value="${sigName}"
                list="known-signals-list-${slotKey}" placeholder="e.g. library_ready"
                oninput="this.value = this.value.toLowerCase().replace(/[^a-z0-9_\\-]/g, '_').replace(/_+/g, '_').replace(/^_|_$/g, '')"
                style="font-family:monospace;">
            <datalist id="known-signals-list-${slotKey}">
                ${knownSignals.map(s => `<option value="${s}">`).join('')}
            </datalist>
        </div>
        <div class="config-row" style="color:rgba(255,255,255,0.35);font-size:11px;">Triggers when another automation fires this signal</div>`;
    }
    if (blockType === 'fire_signal') {
        const sigName = _escAttr(config.signal_name || '');
        const knownSignals = (_autoBlocks && _autoBlocks.known_signals) || [];
        return `<div class="config-row">
            <label>Signal Name</label>
            <input type="text" id="cfg-${slotKey}-signal_name" value="${sigName}"
                list="known-signals-fire-${slotKey}" placeholder="e.g. library_ready"
                oninput="this.value = this.value.toLowerCase().replace(/[^a-z0-9_\\-]/g, '_').replace(/_+/g, '_').replace(/^_|_$/g, '')"
                style="font-family:monospace;">
            <datalist id="known-signals-fire-${slotKey}">
                ${knownSignals.map(s => `<option value="${s}">`).join('')}
            </datalist>
        </div>
        <div class="config-row" style="color:rgba(255,255,255,0.35);font-size:11px;">Other automations with "Signal Received" trigger will wake up</div>`;
    }
    if (blockType === 'run_script') {
        const scriptName = _escAttr(config.script_name || '');
        const timeout = config.timeout || 60;
        // Fetch scripts list and populate
        const selectId = `cfg-${slotKey}-script_name`;
        setTimeout(async () => {
            try {
                const resp = await fetch('/api/scripts');
                const data = await resp.json();
                const sel = document.getElementById(selectId);
                if (sel && data.scripts) {
                    sel.innerHTML = '<option value="">Select a script...</option>' +
                        data.scripts.map(s => `<option value="${_escAttr(s.name)}"${s.name === scriptName ? ' selected' : ''}>${escapeHtml(s.name)} (${s.extension})</option>`).join('');
                }
            } catch (e) { console.warn('Failed to load scripts:', e); }
        }, 100);
        return `<div class="config-row">
            <label>Script</label>
            <select id="${selectId}">
                <option value="${scriptName}">${scriptName || 'Loading...'}</option>
            </select>
        </div>
        <div class="config-row">
            <label>Timeout</label>
            <input type="number" id="cfg-${slotKey}-timeout" value="${timeout}" min="5" max="300" style="width:80px;"> seconds
        </div>
        <div class="config-row" style="color:rgba(255,255,255,0.35);font-size:11px;">Place scripts in the <code>scripts/</code> folder. Supported: .sh, .py, .bat, .ps1</div>`;
    }
    if (blockType === 'scan_watchlist' || blockType === 'scan_library' || blockType === 'notify_only') {
        return '<div class="config-row" style="color:rgba(255,255,255,0.4);font-size:12px;">No configuration needed</div>';
    }
    if (blockType === 'refresh_mirrored') {
        const allChecked = config.all ? ' checked' : '';
        return `<div class="config-row">
            <label>Playlist</label>
            <select id="cfg-${slotKey}-playlist_id" class="mirrored-playlist-select" data-block-type="refresh_mirrored" data-value="${_escAttr(config.playlist_id || '')}">
                <option value="">Loading...</option>
            </select>
        </div>
        <div class="config-row">
            <label><input type="checkbox" id="cfg-${slotKey}-all"${allChecked} onchange="_autoTogglePlaylistSelect('${slotKey}')"> Refresh all mirrored playlists</label>
        </div>`;
    }
    if (blockType === 'sync_playlist') {
        return `<div class="config-row">
            <label>Playlist</label>
            <select id="cfg-${slotKey}-playlist_id" class="mirrored-playlist-select" data-value="${_escAttr(config.playlist_id || '')}">
                <option value="">Loading...</option>
            </select>
        </div>`;
    }
    if (blockType === 'discover_playlist') {
        const allChecked = config.all ? ' checked' : '';
        return `<div class="config-row">
            <label>Playlist</label>
            <select id="cfg-${slotKey}-playlist_id" class="mirrored-playlist-select" data-value="${_escAttr(config.playlist_id || '')}">
                <option value="">Loading...</option>
            </select>
        </div>
        <div class="config-row">
            <label><input type="checkbox" id="cfg-${slotKey}-all"${allChecked} onchange="_autoTogglePlaylistSelect('${slotKey}')"> Discover all mirrored playlists</label>
        </div>`;
    }
    if (blockType === 'playlist_pipeline') {
        const allChecked = config.all ? ' checked' : '';
        const skipWishlistChecked = config.skip_wishlist ? ' checked' : '';
        return `<div class="config-row">
            <label>Playlist</label>
            <select id="cfg-${slotKey}-playlist_id" class="mirrored-playlist-select" data-value="${_escAttr(config.playlist_id || '')}">
                <option value="">Loading...</option>
            </select>
        </div>
        <div class="config-row">
            <label><input type="checkbox" id="cfg-${slotKey}-all"${allChecked} onchange="_autoTogglePlaylistSelect('${slotKey}')"> Process all mirrored playlists</label>
        </div>
        <div class="config-row">
            <label><input type="checkbox" id="cfg-${slotKey}-skip_wishlist"${skipWishlistChecked}> Skip wishlist processing</label>
        </div>
        <div class="config-row" style="color:rgba(255,255,255,0.35);font-size:11px;">Runs 4 phases: Refresh → Discover → Sync → Download Missing</div>`;
    }
    // Shared variable tags builder for notification types
    function _notifyVarHtml(slotKey) {
        let allVars = ['time', 'name', 'run_count', 'status'];
        const triggerDef = _autoBuilder.when ? _findBlockDef(_autoBuilder.when.type) : null;
        if (triggerDef && triggerDef.variables) {
            triggerDef.variables.forEach(v => { if (!allVars.includes(v)) allVars.push(v); });
        }
        let html = '<div class="variable-tags">';
        allVars.forEach(v => { html += `<span class="variable-tag" onclick="_autoInsertVar('cfg-${slotKey}-message','{${v}}')">{${v}}</span>`; });
        return html + '</div>';
    }

    if (blockType === 'discord_webhook') {
        const url = _escAttr(config.webhook_url || '');
        return `<div class="config-row">
            <label>Webhook URL</label>
            <input type="text" id="cfg-${slotKey}-webhook_url" value="${url}" placeholder="https://discord.com/api/webhooks/...">
        </div>
        <div class="config-row">
            <label>Message</label>
            <textarea id="cfg-${slotKey}-message" placeholder="Message with {variables}...">${config.message || '{name} completed with status: {status}'}</textarea>
        </div>
        ${_notifyVarHtml(slotKey)}`;
    }
    if (blockType === 'pushbullet') {
        const token = _escAttr(config.access_token || '');
        return `<div class="config-row">
            <label>Access Token</label>
            <input type="text" id="cfg-${slotKey}-access_token" value="${token}" placeholder="o.xxxxxxxxxxxxxxxxxxxx">
        </div>
        <div class="config-row">
            <label>Title</label>
            <input type="text" id="cfg-${slotKey}-title" value="${_escAttr(config.title || '{name}')}" placeholder="Notification title">
        </div>
        <div class="config-row">
            <label>Message</label>
            <textarea id="cfg-${slotKey}-message" placeholder="Message with {variables}...">${config.message || 'Completed with status: {status}'}</textarea>
        </div>
        ${_notifyVarHtml(slotKey)}`;
    }
    if (blockType === 'telegram') {
        const botToken = _escAttr(config.bot_token || '');
        const chatId = _escAttr(config.chat_id || '');
        return `<div class="config-row">
            <label>Bot Token</label>
            <input type="text" id="cfg-${slotKey}-bot_token" value="${botToken}" placeholder="123456:ABC-DEF1234ghIkl-zyx57W2v1u123ew11">
        </div>
        <div class="config-row">
            <label>Chat ID</label>
            <input type="text" id="cfg-${slotKey}-chat_id" value="${chatId}" placeholder="-1001234567890 or @channelname">
        </div>
        <div class="config-row">
            <label>Message</label>
            <textarea id="cfg-${slotKey}-message" placeholder="Message with {variables}...">${config.message || '{name} completed with status: {status}'}</textarea>
        </div>
        ${_notifyVarHtml(slotKey)}`;
    }
    if (blockType === 'webhook') {
        const url = _escAttr(config.url || '');
        const hdrs = (config.headers || '').replace(/"/g, '&quot;');
        return `<div class="config-row">
            <label>URL</label>
            <input type="text" id="cfg-${slotKey}-url" value="${url}" placeholder="https://your-server.com/hook">
        </div>
        <div class="config-row">
            <label>Headers <span style="opacity:0.4;font-weight:400">(one per line, Key: Value)</span></label>
            <textarea id="cfg-${slotKey}-headers" placeholder="Authorization: Bearer token123\nX-Custom: value" style="font-family:monospace;font-size:11px;">${hdrs}</textarea>
        </div>
        <div class="config-row">
            <label>Custom Message <span style="opacity:0.4;font-weight:400">(optional)</span></label>
            <textarea id="cfg-${slotKey}-message" placeholder="Message with {variables}...">${config.message || ''}</textarea>
        </div>
        <div class="config-row" style="color:rgba(255,255,255,0.35);font-size:11px;">
            Sends a JSON POST with all event variables. Custom message added as "message" field if set.
        </div>
        ${_notifyVarHtml(slotKey)}`;
    }
    return '';
}

// --- Condition Builder ---

function _renderConditionBuilder(slotKey, blockDef, config) {
    const conditions = config.conditions || [];
    const match = config.match || 'all';
    const fields = blockDef.condition_fields || [];

    let html = '<div class="condition-builder" id="conditions-' + slotKey + '">';
    html += `<div class="config-row condition-header">
        <label>Match</label>
        <select id="cfg-${slotKey}-match" class="condition-match-select">
            <option value="all"${match==='all'?' selected':''}>All conditions</option>
            <option value="any"${match==='any'?' selected':''}>Any condition</option>
        </select>
    </div>`;

    html += '<div id="condition-rows-' + slotKey + '">';
    if (conditions.length) {
        conditions.forEach((cond, i) => {
            html += _renderConditionRow(slotKey, i, fields, cond);
        });
    }
    html += '</div>';

    html += `<button class="add-condition-btn" onclick="_autoAddCondition('${slotKey}')">+ Add Condition</button>`;
    html += '</div>';

    if (!conditions.length) {
        html += '<div class="config-row" style="color:rgba(255,255,255,0.35);font-size:12px;margin-top:4px;">No conditions = triggers on every event</div>';
    }

    return html;
}

function _renderConditionRow(slotKey, index, fields, cond) {
    const field = cond ? cond.field : (fields[0] || '');
    const operator = cond ? cond.operator : 'equals';
    const value = cond ? _escAttr(cond.value) : '';

    let fieldOpts = '';
    fields.forEach(f => { fieldOpts += `<option value="${f}"${f===field?' selected':''}>${f}</option>`; });

    // For playlist-related triggers, use a mirrored playlist dropdown instead of free text
    const triggerType = _autoBuilder.when ? _autoBuilder.when.type : '';
    const usePlaylistSelect = ((triggerType === 'playlist_changed' || triggerType === 'discovery_completed') && field === 'playlist_name');
    const valueHtml = usePlaylistSelect
        ? `<select class="cond-value mirrored-playlist-name-select" data-slot="${slotKey}" data-idx="${index}" data-value="${value}"></select>`
        : `<input type="text" class="cond-value" data-slot="${slotKey}" data-idx="${index}" value="${value}" placeholder="value...">`;

    return `<div class="condition-row" data-index="${index}">
        <select class="cond-field" data-slot="${slotKey}" data-idx="${index}">${fieldOpts}</select>
        <select class="cond-operator" data-slot="${slotKey}" data-idx="${index}">
            <option value="equals"${operator==='equals'?' selected':''}>equals</option>
            <option value="contains"${operator==='contains'?' selected':''}>contains</option>
            <option value="starts_with"${operator==='starts_with'?' selected':''}>starts with</option>
            <option value="not_contains"${operator==='not_contains'?' selected':''}>not contains</option>
        </select>
        ${valueHtml}
        <button class="remove-condition-btn" onclick="_autoRemoveCondition('${slotKey}',${index})">\u2715</button>
    </div>`;
}

function _autoAddCondition(slotKey) {
    const data = _autoBuilder[slotKey];
    if (!data) return;
    if (!data.config) data.config = {};
    if (!data.config.conditions) data.config.conditions = [];

    // Save existing conditions from DOM before re-render
    _autoSaveConditionsFromDOM(slotKey);

    const blockDef = _findBlockDef(data.type);
    const fields = blockDef ? (blockDef.condition_fields || []) : [];
    data.config.conditions.push({ field: fields[0] || '', operator: 'contains', value: '' });
    _renderBuilderCanvas();
    // Re-populate mirrored playlist selects if needed
    _autoLoadMirroredSelects();
}

function _autoRemoveCondition(slotKey, index) {
    const data = _autoBuilder[slotKey];
    if (!data || !data.config || !data.config.conditions) return;
    _autoSaveConditionsFromDOM(slotKey);
    data.config.conditions.splice(index, 1);
    _renderBuilderCanvas();
    _autoLoadMirroredSelects();
}

function _autoSaveConditionsFromDOM(slotKey) {
    const data = _autoBuilder[slotKey];
    if (!data || !data.config) return;
    const container = document.getElementById('condition-rows-' + slotKey);
    if (!container) return;
    const rows = container.querySelectorAll('.condition-row');
    const conditions = [];
    rows.forEach(row => {
        const field = row.querySelector('.cond-field')?.value || '';
        const operator = row.querySelector('.cond-operator')?.value || 'contains';
        const value = row.querySelector('.cond-value')?.value || '';
        conditions.push({ field, operator, value });
    });
    data.config.conditions = conditions;
    // Also save match mode
    const matchEl = document.getElementById('cfg-' + slotKey + '-match');
    if (matchEl) data.config.match = matchEl.value;
}

// --- Mirrored Playlist Select ---

function _autoTogglePlaylistSelect(slotKey) {
    const allCb = document.getElementById('cfg-' + slotKey + '-all');
    const sel = document.getElementById('cfg-' + slotKey + '-playlist_id');
    if (sel) sel.disabled = allCb && allCb.checked;
}

async function _autoLoadMirroredSelects() {
    const selects = document.querySelectorAll('.mirrored-playlist-select');
    const nameSelects = document.querySelectorAll('.mirrored-playlist-name-select');
    if (!selects.length && !nameSelects.length) return;

    if (!_autoMirroredPlaylists) {
        try {
            const res = await fetch('/api/mirrored-playlists/list');
            const data = await res.json();
            // New format returns { playlists, spotify_authenticated }
            if (Array.isArray(data)) {
                // Backward compat: old format was plain array
                _autoMirroredPlaylists = data;
                _autoSpotifyAuthenticated = false;
            } else {
                _autoMirroredPlaylists = data.playlists || [];
                _autoSpotifyAuthenticated = data.spotify_authenticated || false;
            }
        } catch (e) { _autoMirroredPlaylists = []; _autoSpotifyAuthenticated = false; }
    }

    selects.forEach(sel => {
        const savedValue = sel.dataset.value || '';
        const isRefresh = sel.dataset.blockType === 'refresh_mirrored';
        sel.innerHTML = '<option value="">-- Select playlist --</option>';
        _autoMirroredPlaylists.forEach(p => {
            // For refresh selects: hide file playlists, hide spotify (library) if not authed
            if (isRefresh) {
                if (p.source === 'file' || p.source === 'beatport') return;
                if (p.source === 'spotify' && !_autoSpotifyAuthenticated) return;
            }
            sel.innerHTML += `<option value="${p.id}"${String(p.id) === savedValue ? ' selected' : ''}>${_esc(p.name)}</option>`;
        });
    });

    nameSelects.forEach(sel => {
        const savedValue = sel.dataset.value || '';
        sel.innerHTML = '<option value="">-- Select playlist --</option>';
        _autoMirroredPlaylists.forEach(p => {
            sel.innerHTML += `<option value="${_escAttr(p.name)}"${p.name === savedValue ? ' selected' : ''}>${_esc(p.name)}</option>`;
        });
    });
}

function _readPlacedConfig(slotKey) {
    let data;
    if (slotKey.startsWith('then-')) {
        const idx = parseInt(slotKey.split('-')[1]);
        data = _autoBuilder.then[idx];
    } else {
        data = _autoBuilder[slotKey];
    }
    if (!data) return {};
    const type = data.type;
    if (type === 'schedule') {
        return {
            interval: parseInt(document.getElementById('cfg-' + slotKey + '-interval')?.value) || 6,
            unit: document.getElementById('cfg-' + slotKey + '-unit')?.value || 'hours',
        };
    }
    if (type === 'daily_time') {
        return { time: document.getElementById('cfg-' + slotKey + '-time')?.value || '03:00' };
    }
    if (type === 'weekly_time') {
        const daysEl = document.getElementById('cfg-' + slotKey + '-days');
        const days = daysEl ? Array.from(daysEl.querySelectorAll('.day-btn.active')).map(b => b.dataset.day) : [];
        return {
            time: document.getElementById('cfg-' + slotKey + '-time')?.value || '03:00',
            days,
        };
    }
    // Event triggers with conditions
    const blockDef = _findBlockDef(type);
    if (blockDef && blockDef.has_conditions) {
        _autoSaveConditionsFromDOM(slotKey);
        return {
            conditions: (data.config && data.config.conditions) || [],
            match: document.getElementById('cfg-' + slotKey + '-match')?.value || 'all',
        };
    }
    if (type === 'process_wishlist') {
        return { category: document.getElementById('cfg-' + slotKey + '-category')?.value || 'all' };
    }
    if (type === 'refresh_mirrored') {
        const allCb = document.getElementById('cfg-' + slotKey + '-all');
        return {
            playlist_id: document.getElementById('cfg-' + slotKey + '-playlist_id')?.value || '',
            all: allCb ? allCb.checked : false,
        };
    }
    if (type === 'sync_playlist') {
        return { playlist_id: document.getElementById('cfg-' + slotKey + '-playlist_id')?.value || '' };
    }
    if (type === 'discover_playlist') {
        const allCb = document.getElementById('cfg-' + slotKey + '-all');
        return {
            playlist_id: document.getElementById('cfg-' + slotKey + '-playlist_id')?.value || '',
            all: allCb ? allCb.checked : false,
        };
    }
    if (type === 'playlist_pipeline') {
        const allCb = document.getElementById('cfg-' + slotKey + '-all');
        const skipWl = document.getElementById('cfg-' + slotKey + '-skip_wishlist');
        return {
            playlist_id: document.getElementById('cfg-' + slotKey + '-playlist_id')?.value || '',
            all: allCb ? allCb.checked : false,
            skip_wishlist: skipWl ? skipWl.checked : false,
        };
    }
    if (type === 'signal_received' || type === 'fire_signal') {
        return { signal_name: document.getElementById('cfg-' + slotKey + '-signal_name')?.value?.trim() || '' };
    }
    if (type === 'run_script') {
        return {
            script_name: document.getElementById('cfg-' + slotKey + '-script_name')?.value || '',
            timeout: parseInt(document.getElementById('cfg-' + slotKey + '-timeout')?.value || '60') || 60,
        };
    }
    if (type === 'discord_webhook') {
        return {
            webhook_url: document.getElementById('cfg-' + slotKey + '-webhook_url')?.value?.trim() || '',
            message: document.getElementById('cfg-' + slotKey + '-message')?.value || '',
        };
    }
    if (type === 'pushbullet') {
        return {
            access_token: document.getElementById('cfg-' + slotKey + '-access_token')?.value?.trim() || '',
            title: document.getElementById('cfg-' + slotKey + '-title')?.value || '',
            message: document.getElementById('cfg-' + slotKey + '-message')?.value || '',
        };
    }
    if (type === 'telegram') {
        return {
            bot_token: document.getElementById('cfg-' + slotKey + '-bot_token')?.value?.trim() || '',
            chat_id: document.getElementById('cfg-' + slotKey + '-chat_id')?.value?.trim() || '',
            message: document.getElementById('cfg-' + slotKey + '-message')?.value || '',
        };
    }
    if (type === 'webhook') {
        return {
            url: document.getElementById('cfg-' + slotKey + '-url')?.value?.trim() || '',
            headers: document.getElementById('cfg-' + slotKey + '-headers')?.value || '',
            message: document.getElementById('cfg-' + slotKey + '-message')?.value || '',
        };
    }
    return {};
}

function _findBlockDef(type) {
    if (!_autoBlocks) return null;
    for (const cat of ['triggers','actions','notifications']) {
        const found = (_autoBlocks[cat] || []).find(b => b.type === type);
        if (found) return found;
    }
    return null;
}

// --- Drag & Drop ---

function _autoDragStart(e, blockType, slotCategory) {
    e.dataTransfer.setData('text/plain', JSON.stringify({ type: blockType, slot: slotCategory }));
    e.dataTransfer.effectAllowed = 'copy';
}

function _autoDragOver(e, slotKey) {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'copy';
    const targetId = slotKey === 'then' ? 'slot-then-add' : 'slot-' + slotKey;
    document.getElementById(targetId)?.classList.add('drag-over');
}

function _autoDragLeave(e, slotKey) {
    const targetId = slotKey === 'then' ? 'slot-then-add' : 'slot-' + slotKey;
    document.getElementById(targetId)?.classList.remove('drag-over');
}

function _autoDrop(e, slotKey) {
    e.preventDefault();
    const dropTargetId = slotKey === 'then' ? 'slot-then-add' : 'slot-' + slotKey;
    document.getElementById(dropTargetId)?.classList.remove('drag-over');
    if (_autoBuilder.isSystem && (slotKey === 'when' || slotKey === 'do')) return;
    try {
        const data = JSON.parse(e.dataTransfer.getData('text/plain'));
        // Handle THEN slot (append to array)
        if (slotKey === 'then') {
            if (data.slot !== 'then') { showToast('Wrong slot — drop ' + data.slot + ' blocks here', 'error'); return; }
            if (_autoBuilder.then.length >= 3) { showToast('Maximum 3 then-actions', 'error'); return; }
            _autoBuilder.then.push({ type: data.type, config: {} });
        } else {
            if (data.slot !== slotKey) { showToast('Wrong slot — drop ' + data.slot + ' blocks here', 'error'); return; }
            _autoBuilder[slotKey] = { type: data.type, config: {} };
        }
        _renderBuilderCanvas();
    } catch (err) {}
}

// Click-to-add (alternative to drag)
function _autoClickBlock(blockType, slotCategory) {
    if (_autoBuilder.isSystem && (slotCategory === 'when' || slotCategory === 'do')) return;
    if (slotCategory === 'then') {
        if (_autoBuilder.then.length >= 3) { showToast('Maximum 3 then-actions', 'error'); return; }
        _autoBuilder.then.push({ type: blockType, config: {} });
    } else {
        _autoBuilder[slotCategory] = { type: blockType, config: {} };
    }
    _renderBuilderCanvas();
}

function _autoRemoveBlock(slotKey) {
    if (_autoBuilder.isSystem && (slotKey === 'when' || slotKey === 'do')) return;
    // Handle then-N slots
    if (slotKey.startsWith('then-')) {
        const idx = parseInt(slotKey.split('-')[1]);
        if (!isNaN(idx) && idx >= 0 && idx < _autoBuilder.then.length) {
            _autoBuilder.then.splice(idx, 1);
        }
    } else {
        _autoBuilder[slotKey] = null;
    }
    _renderBuilderCanvas();
}

// Variable insertion
function _autoInsertVar(textareaId, variable) {
    const el = document.getElementById(textareaId);
    if (!el) return;
    const start = el.selectionStart, end = el.selectionEnd;
    el.value = el.value.substring(0, start) + variable + el.value.substring(end);
    el.selectionStart = el.selectionEnd = start + variable.length;
    el.focus();
}

// ===== ISSUES PAGE =====

const ISSUE_CATEGORIES = {
    wrong_track: { label: 'Wrong Track', icon: '&#10060;', description: 'This file plays a completely different song than expected', applies: ['track'] },
    wrong_metadata: { label: 'Wrong Metadata', icon: '&#9998;', description: 'Title, artist, year, or other tags are incorrect', applies: ['track', 'album'] },
    wrong_cover: { label: 'Wrong Cover Art', icon: '&#128247;', description: 'The album artwork is wrong or missing', applies: ['album'] },
    wrong_artist: { label: 'Wrong Artist', icon: '&#128100;', description: 'This track is filed under the wrong artist', applies: ['track'] },
    duplicate_tracks: { label: 'Duplicate Tracks', icon: '&#128257;', description: 'The same track appears more than once in this album', applies: ['album'] },
    missing_tracks: { label: 'Missing Tracks', icon: '&#10067;', description: 'Tracks that should be here are missing from this album', applies: ['album'] },
    audio_quality: { label: 'Audio Quality', icon: '&#127925;', description: 'Audio has quality issues — clipping, low bitrate, silence, etc.', applies: ['track'] },
    wrong_album: { label: 'Wrong Album', icon: '&#128191;', description: 'This track belongs to a different album', applies: ['track'] },
    incomplete_album: { label: 'Incomplete Album', icon: '&#9888;', description: 'Album is partially downloaded — some tracks present, others not', applies: ['album'] },
    other: { label: 'Other', icon: '&#128172;', description: 'Any other issue not listed above', applies: ['track', 'album'] },
};

const ISSUE_STATUS_META = {
    open: { label: 'Open', cls: 'issue-status-open' },
    in_progress: { label: 'In Progress', cls: 'issue-status-progress' },
    resolved: { label: 'Resolved', cls: 'issue-status-resolved' },
    dismissed: { label: 'Dismissed', cls: 'issue-status-dismissed' },
};

let _issuesPageState = { loaded: false };

function _issueHeaders(extra) {
    const h = { 'X-Profile-Id': String(currentProfile ? currentProfile.id : 1) };
    if (extra) Object.assign(h, extra);
    return h;
}

async function loadIssuesPage() {
    const admin = isEnhancedAdmin();
    const subtitle = document.getElementById('issues-subtitle');
    if (subtitle) {
        subtitle.textContent = admin ? 'Manage and resolve reported library problems' : 'Track and resolve library problems';
    }
    await Promise.all([loadIssuesList(), loadIssuesCounts()]);
}

async function loadIssuesCounts() {
    try {
        const resp = await fetch('/api/issues/counts', { headers: _issueHeaders() });
        const data = await resp.json();
        if (!data.success) return;
        const counts = data.counts;
        const statsEl = document.getElementById('issues-stats');
        if (!statsEl) return;
        const total = (counts.open || 0) + (counts.in_progress || 0) + (counts.resolved || 0) + (counts.dismissed || 0);
        statsEl.innerHTML = `
            <div class="issues-stat-card issues-stat-open">
                <div class="issues-stat-number">${counts.open || 0}</div>
                <div class="issues-stat-label">Open</div>
            </div>
            <div class="issues-stat-card issues-stat-progress">
                <div class="issues-stat-number">${counts.in_progress || 0}</div>
                <div class="issues-stat-label">In Progress</div>
            </div>
            <div class="issues-stat-card issues-stat-resolved">
                <div class="issues-stat-number">${counts.resolved || 0}</div>
                <div class="issues-stat-label">Resolved</div>
            </div>
            <div class="issues-stat-card issues-stat-dismissed">
                <div class="issues-stat-number">${counts.dismissed || 0}</div>
                <div class="issues-stat-label">Dismissed</div>
            </div>
            <div class="issues-stat-card issues-stat-total">
                <div class="issues-stat-number">${total}</div>
                <div class="issues-stat-label">Total</div>
            </div>
        `;
        // Update nav badge
        const badge = document.getElementById('issues-nav-badge');
        if (badge) {
            const openCount = counts.open || 0;
            badge.textContent = openCount;
            badge.classList.toggle('hidden', openCount === 0);
        }
    } catch (e) {
        console.error('Failed to load issue counts:', e);
    }
}

async function loadIssuesList() {
    const listEl = document.getElementById('issues-list');
    if (!listEl) return;
    listEl.innerHTML = '<div class="issues-loading"><div class="issues-spinner"></div>Loading issues...</div>';

    const statusFilter = document.getElementById('issues-filter-status')?.value || '';
    const categoryFilter = document.getElementById('issues-filter-category')?.value || '';

    let url = '/api/issues?';
    if (statusFilter) url += `status=${encodeURIComponent(statusFilter)}&`;
    if (categoryFilter) url += `category=${encodeURIComponent(categoryFilter)}&`;

    try {
        const profileId = currentProfile ? currentProfile.id : 1;
        const resp = await fetch(url, { headers: { 'X-Profile-Id': String(profileId) } });
        const data = await resp.json();
        if (!data.success || !data.issues || data.issues.length === 0) {
            listEl.innerHTML = `
                <div class="issues-empty">
                    <div class="issues-empty-icon">&#128269;</div>
                    <div class="issues-empty-title">No issues found</div>
                    <div class="issues-empty-text">${statusFilter || categoryFilter ? 'Try adjusting your filters' : 'No issues have been reported yet'}</div>
                </div>
            `;
            return;
        }
        listEl.innerHTML = '';
        data.issues.forEach(issue => {
            listEl.appendChild(renderIssueCard(issue));
        });
    } catch (e) {
        console.error('Failed to load issues:', e);
        listEl.innerHTML = '<div class="issues-empty"><div class="issues-empty-title">Failed to load issues</div></div>';
    }
}

function renderIssueCard(issue) {
    const card = document.createElement('div');
    card.className = 'issue-card';
    card.dataset.issueId = issue.id;
    card.onclick = () => showIssueDetailModal(issue.id);

    const catMeta = ISSUE_CATEGORIES[issue.category] || ISSUE_CATEGORIES.other;
    const statusMeta = ISSUE_STATUS_META[issue.status] || ISSUE_STATUS_META.open;
    const admin = isEnhancedAdmin();

    let snapshot = {};
    try { snapshot = typeof issue.snapshot_data === 'string' ? JSON.parse(issue.snapshot_data || '{}') : (issue.snapshot_data || {}); } catch (e) {}

    const entityLabel = issue.entity_type === 'track' ? 'Track' : (issue.entity_type === 'album' ? 'Album' : 'Artist');
    const entityName = snapshot.title || snapshot.name || `${entityLabel} #${issue.entity_id}`;
    const artistName = snapshot.artist_name || '';
    const albumName = snapshot.album_title || '';
    const thumbUrl = snapshot.thumb_url || snapshot.album_thumb || '';

    const createdDate = issue.created_at ? new Date(issue.created_at).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }) : '';
    const createdTime = issue.created_at ? new Date(issue.created_at).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' }) : '';

    // Priority indicator
    const priorityCls = issue.priority === 'high' ? 'issue-priority-high' : (issue.priority === 'low' ? 'issue-priority-low' : 'issue-priority-normal');

    let thumbHtml = '';
    if (thumbUrl) {
        thumbHtml = `<img class="issue-card-thumb" src="${_escAttr(thumbUrl)}" alt="" onerror="this.style.display='none'">`;
    } else {
        thumbHtml = `<div class="issue-card-thumb-placeholder">${catMeta.icon}</div>`;
    }

    let metaLine = '';
    if (issue.entity_type === 'track') {
        metaLine = [artistName, albumName].filter(Boolean).map(s => _esc(s)).join(' &mdash; ');
    } else if (issue.entity_type === 'album') {
        metaLine = artistName ? _esc(artistName) : '';
    }

    let profileBadge = '';
    if (admin && issue.reporter_name) {
        profileBadge = `<span class="issue-card-profile">by ${_esc(issue.reporter_name)}</span>`;
    }

    let adminResponseIndicator = '';
    if (issue.admin_response) {
        adminResponseIndicator = '<span class="issue-card-responded" title="Admin has responded">&#128172;</span>';
    }

    card.innerHTML = `
        <div class="issue-card-left">
            ${thumbHtml}
        </div>
        <div class="issue-card-center">
            <div class="issue-card-title-row">
                <span class="issue-card-category-icon" title="${_escAttr(catMeta.label)}">${catMeta.icon}</span>
                <span class="issue-card-title">${_esc(issue.title)}</span>
                ${adminResponseIndicator}
            </div>
            <div class="issue-card-entity">
                <span class="issue-card-entity-type">${_esc(entityLabel)}</span>
                <span class="issue-card-entity-name">${_esc(entityName)}</span>
                ${metaLine ? `<span class="issue-card-meta-line">${metaLine}</span>` : ''}
            </div>
            ${issue.description ? `<div class="issue-card-description">${_esc(issue.description)}</div>` : ''}
            <div class="issue-card-footer">
                <span class="issue-card-date">${_esc(createdDate)} ${_esc(createdTime)}</span>
                ${profileBadge}
            </div>
        </div>
        <div class="issue-card-right">
            <span class="issue-status-badge ${statusMeta.cls}">${_esc(statusMeta.label)}</span>
            <span class="issue-priority-dot ${priorityCls}" title="${_esc(issue.priority)} priority"></span>
        </div>
    `;
    return card;
}

// --- Report Issue Modal ---

let _reportIssueState = {};

function showReportIssueModal(entityType, entityId, entityName, artistName, albumTitle) {
    _reportIssueState = { entityType, entityId, entityName, artistName, albumTitle: albumTitle || '' };
    const overlay = document.getElementById('report-issue-overlay');
    const titleEl = document.getElementById('report-issue-title');
    const body = document.getElementById('report-issue-body');
    if (!overlay || !body) return;

    const entityLabel = entityType === 'track' ? 'Track' : (entityType === 'album' ? 'Album' : 'Artist');
    titleEl.textContent = `Report Issue — ${entityLabel}`;

    body.innerHTML = `
        <div class="report-issue-entity-info">
            <div class="report-issue-entity-name">${_esc(entityName)}</div>
            ${artistName ? `<div class="report-issue-entity-artist">${_esc(artistName)}${albumTitle ? ' &mdash; ' + _esc(albumTitle) : ''}</div>` : ''}
        </div>
        <div class="report-issue-section">
            <label class="report-issue-label">What's the problem?</label>
            <div class="report-issue-category-grid" id="report-issue-categories">
                ${Object.entries(ISSUE_CATEGORIES)
                    .filter(([, cat]) => !cat.applies || cat.applies.includes(entityType))
                    .map(([key, cat]) => `
                    <div class="report-issue-category-card" data-category="${_escAttr(key)}" onclick="selectIssueCategory(this, '${_escAttr(key)}')">
                        <div class="report-issue-category-icon">${cat.icon}</div>
                        <div class="report-issue-category-label">${_esc(cat.label)}</div>
                        <div class="report-issue-category-desc">${_esc(cat.description)}</div>
                    </div>
                `).join('')}
            </div>
        </div>
        <div class="report-issue-section" id="report-issue-details-section" style="display:none">
            <label class="report-issue-label">Title</label>
            <input type="text" class="report-issue-input" id="report-issue-input-title" placeholder="Brief summary of the issue..." maxlength="200" oninput="event.target._userEdited = true">
            <label class="report-issue-label" style="margin-top:12px">Details <span class="report-issue-optional">(optional)</span></label>
            <textarea class="report-issue-textarea" id="report-issue-input-desc" placeholder="Provide more details about what's wrong — what you expected vs what you see..." rows="4" maxlength="2000"></textarea>
            <label class="report-issue-label" style="margin-top:12px">Priority</label>
            <div class="report-issue-priority-row">
                <button class="report-issue-priority-btn" data-priority="low" onclick="selectIssuePriority(this, 'low')">Low</button>
                <button class="report-issue-priority-btn selected" data-priority="normal" onclick="selectIssuePriority(this, 'normal')">Normal</button>
                <button class="report-issue-priority-btn" data-priority="high" onclick="selectIssuePriority(this, 'high')">High</button>
            </div>
        </div>
    `;

    _reportIssueState.selectedCategory = null;
    _reportIssueState.selectedPriority = 'normal';
    const submitBtn = document.getElementById('report-issue-submit-btn');
    if (submitBtn) submitBtn.disabled = true;

    overlay.classList.remove('hidden');
}

function selectIssueCategory(el, category) {
    document.querySelectorAll('.report-issue-category-card').forEach(c => c.classList.remove('selected'));
    el.classList.add('selected');
    _reportIssueState.selectedCategory = category;

    const detailsSection = document.getElementById('report-issue-details-section');
    if (detailsSection) detailsSection.style.display = '';

    // Auto-generate title based on category
    const titleInput = document.getElementById('report-issue-input-title');
    const catMeta = ISSUE_CATEGORIES[category];
    if (titleInput && !titleInput._userEdited) {
        const entityName = _reportIssueState.entityName || '';
        titleInput.value = `${catMeta.label}: ${entityName}`;
    }

    const submitBtn = document.getElementById('report-issue-submit-btn');
    if (submitBtn) submitBtn.disabled = false;
}

function selectIssuePriority(el, priority) {
    document.querySelectorAll('.report-issue-priority-btn').forEach(b => b.classList.remove('selected'));
    el.classList.add('selected');
    _reportIssueState.selectedPriority = priority;
}

function closeReportIssueModal() {
    const overlay = document.getElementById('report-issue-overlay');
    if (overlay) overlay.classList.add('hidden');
    _reportIssueState = {};
}

async function submitIssue() {
    if (_reportIssueState._submitting) return;
    const category = _reportIssueState.selectedCategory;
    if (!category) {
        showToast('Please select an issue category', 'error');
        return;
    }

    const titleInput = document.getElementById('report-issue-input-title');
    const descInput = document.getElementById('report-issue-input-desc');
    const title = (titleInput?.value || '').trim();
    const description = (descInput?.value || '').trim();

    if (!title) {
        showToast('Please provide a title for the issue', 'error');
        return;
    }

    _reportIssueState._submitting = true;
    const submitBtn = document.getElementById('report-issue-submit-btn');
    if (submitBtn) {
        submitBtn.disabled = true;
        submitBtn.textContent = 'Submitting...';
    }

    try {
        const resp = await fetch('/api/issues', {
            method: 'POST',
            headers: _issueHeaders({ 'Content-Type': 'application/json' }),
            body: JSON.stringify({
                profile_id: currentProfile ? currentProfile.id : 1,
                entity_type: _reportIssueState.entityType,
                entity_id: String(_reportIssueState.entityId),
                category: category,
                title: title,
                description: description,
                priority: _reportIssueState.selectedPriority || 'normal',
            }),
        });
        const data = await resp.json();
        if (data.success) {
            showToast('Issue reported successfully', 'success');
            closeReportIssueModal();
            // Refresh issues page if visible
            const issuesPage = document.getElementById('issues-page');
            if (issuesPage && issuesPage.classList.contains('active')) {
                loadIssuesPage();
            }
            // Update badge
            loadIssuesBadge();
        } else {
            showToast(data.error || 'Failed to submit issue', 'error');
        }
    } catch (e) {
        console.error('Failed to submit issue:', e);
        showToast('Failed to submit issue', 'error');
    } finally {
        _reportIssueState._submitting = false;
        if (submitBtn) {
            submitBtn.disabled = false;
            submitBtn.textContent = 'Submit Issue';
        }
    }
}

// --- Issue Detail Modal ---

async function showIssueDetailModal(issueId) {
    const overlay = document.getElementById('issue-detail-overlay');
    const body = document.getElementById('issue-detail-body');
    const footer = document.getElementById('issue-detail-footer');
    const titleEl = document.getElementById('issue-detail-title');
    if (!overlay || !body) return;

    body.innerHTML = '<div class="issues-loading"><div class="issues-spinner"></div>Loading...</div>';
    footer.innerHTML = '<button class="enhanced-bulk-btn secondary" onclick="closeIssueDetailModal()">Close</button>';
    overlay.classList.remove('hidden');

    try {
        const resp = await fetch(`/api/issues/${issueId}`, { headers: _issueHeaders() });
        const data = await resp.json();
        if (!data.success || !data.issue) {
            body.innerHTML = '<div class="issues-empty"><div class="issues-empty-title">Issue not found</div></div>';
            return;
        }
        renderIssueDetail(data.issue, body, footer, titleEl);
    } catch (e) {
        console.error('Failed to load issue:', e);
        body.innerHTML = '<div class="issues-empty"><div class="issues-empty-title">Failed to load issue</div></div>';
    }
}

function renderIssueDetail(issue, body, footer, titleEl) {
    const admin = isEnhancedAdmin();
    const catMeta = ISSUE_CATEGORIES[issue.category] || ISSUE_CATEGORIES.other;
    const statusMeta = ISSUE_STATUS_META[issue.status] || ISSUE_STATUS_META.open;

    let snapshot = {};
    try { snapshot = typeof issue.snapshot_data === 'string' ? JSON.parse(issue.snapshot_data || '{}') : (issue.snapshot_data || {}); } catch (e) {}

    const entityLabel = issue.entity_type === 'track' ? 'Track' : (issue.entity_type === 'album' ? 'Album' : 'Artist');
    const entityName = snapshot.title || snapshot.name || `${entityLabel} #${issue.entity_id}`;
    const artistName = snapshot.artist_name || (issue.entity_type === 'artist' ? snapshot.name : '') || '';
    const albumTitle = issue.entity_type === 'album' ? (snapshot.title || '') : (snapshot.album_title || '');
    const artistId = issue.entity_type === 'artist' ? snapshot.id : snapshot.artist_id;

    // Resolve image URLs — album art and artist photo
    let artistThumb = '';
    let albumThumb = '';
    if (issue.entity_type === 'album') {
        albumThumb = snapshot.thumb_url || '';
        artistThumb = snapshot.artist_thumb || '';
    } else if (issue.entity_type === 'track') {
        albumThumb = snapshot.album_thumb || '';
        artistThumb = snapshot.artist_thumb || '';
    } else {
        // Artist issue
        artistThumb = snapshot.thumb_url || '';
    }

    // Determine the album-level Spotify ID for download/wishlist actions
    const spotifyAlbumId = snapshot.spotify_album_id || '';

    console.log('Issue detail snapshot:', { entityType: issue.entity_type, albumThumb, artistThumb, spotifyAlbumId, snapshotKeys: Object.keys(snapshot) });

    const createdDate = issue.created_at ? new Date(issue.created_at).toLocaleString() : 'Unknown';
    const resolvedDate = issue.resolved_at ? new Date(issue.resolved_at).toLocaleString() : '';

    titleEl.textContent = `Issue #${issue.id}`;

    // --- Build external links chips ---
    function _extLinks(snap) {
        const links = [];
        if (snap.spotify_artist_id) links.push({ svc: 'Spotify', type: 'Artist', url: `https://open.spotify.com/artist/${snap.spotify_artist_id}`, cls: 'ext-spotify' });
        if (snap.spotify_album_id) links.push({ svc: 'Spotify', type: 'Album', url: `https://open.spotify.com/album/${snap.spotify_album_id}`, cls: 'ext-spotify' });
        if (snap.spotify_track_id) links.push({ svc: 'Spotify', type: 'Track', url: `https://open.spotify.com/track/${snap.spotify_track_id}`, cls: 'ext-spotify' });
        if (snap.artist_musicbrainz_id) links.push({ svc: 'MusicBrainz', type: 'Artist', url: `https://musicbrainz.org/artist/${snap.artist_musicbrainz_id}`, cls: 'ext-mb' });
        if (snap.musicbrainz_release_id) links.push({ svc: 'MusicBrainz', type: 'Release', url: `https://musicbrainz.org/release/${snap.musicbrainz_release_id}`, cls: 'ext-mb' });
        if (snap.musicbrainz_recording_id) links.push({ svc: 'MusicBrainz', type: 'Recording', url: `https://musicbrainz.org/recording/${snap.musicbrainz_recording_id}`, cls: 'ext-mb' });
        if (snap.artist_deezer_id) links.push({ svc: 'Deezer', type: 'Artist', url: `https://www.deezer.com/artist/${snap.artist_deezer_id}`, cls: 'ext-deezer' });
        if (snap.album_deezer_id) links.push({ svc: 'Deezer', type: 'Album', url: `https://www.deezer.com/album/${snap.album_deezer_id}`, cls: 'ext-deezer' });
        if (snap.track_deezer_id) links.push({ svc: 'Deezer', type: 'Track', url: `https://www.deezer.com/track/${snap.track_deezer_id}`, cls: 'ext-deezer' });
        if (snap.artist_tidal_id) links.push({ svc: 'Tidal', type: 'Artist', url: `https://listen.tidal.com/artist/${snap.artist_tidal_id}`, cls: 'ext-tidal' });
        if (snap.album_tidal_id) links.push({ svc: 'Tidal', type: 'Album', url: `https://listen.tidal.com/album/${snap.album_tidal_id}`, cls: 'ext-tidal' });
        if (snap.artist_qobuz_id) links.push({ svc: 'Qobuz', type: 'Artist', cls: 'ext-qobuz', id: snap.artist_qobuz_id });
        if (snap.album_qobuz_id) links.push({ svc: 'Qobuz', type: 'Album', cls: 'ext-qobuz', id: snap.album_qobuz_id });
        return links;
    }

    const extLinks = _extLinks(snapshot);
    let extLinksHtml = '';
    if (extLinks.length > 0) {
        const chips = extLinks.map(l => {
            if (l.url) {
                return `<a class="issue-ext-chip ${l.cls}" href="${_escAttr(l.url)}" target="_blank" rel="noopener" title="${_escAttr(l.svc + ' ' + l.type)}">${_esc(l.svc)} <span class="issue-ext-chip-type">${_esc(l.type)}</span></a>`;
            }
            return `<span class="issue-ext-chip ${l.cls}" title="${_escAttr(l.svc + ' ' + l.type + ': ' + l.id)}">${_esc(l.svc)} <span class="issue-ext-chip-type">${_esc(l.type)}</span></span>`;
        }).join('');
        extLinksHtml = `<div class="issue-ext-chips" style="margin-top:8px">${chips}</div>`;
    }

    // --- Build enhanced-library-style album/track widget ---
    // Determine which album data to show (for album issues it's the entity, for track issues it's the parent)
    const showAlbumWidget = (issue.entity_type === 'album' || issue.entity_type === 'track');
    const albumName = issue.entity_type === 'album' ? (snapshot.title || '') : (snapshot.album_title || '');
    const albumYear = snapshot.year || '';
    const albumLabel = snapshot.label || '';
    const albumType = snapshot.record_type || '';
    const albumTrackCount = issue.entity_type === 'album' ? (snapshot.track_count || '') : (snapshot.album_track_count || '');
    const albumGenres = snapshot.genres || [];

    // --- Build the hero section (artist photo + album art + info) ---
    let heroHtml = '';
    if (showAlbumWidget) {
        // Genre tags
        let genreTagsHtml = '';
        if (Array.isArray(albumGenres) && albumGenres.length > 0) {
            genreTagsHtml = `<div class="issue-hero-genres">${albumGenres.slice(0, 5).map(g => `<span class="issue-hero-genre-tag">${_esc(g)}</span>`).join('')}</div>`;
        }

        // Album meta line
        const albumMetaParts = [];
        if (albumYear) albumMetaParts.push(String(albumYear));
        if (albumType) albumMetaParts.push(albumType.charAt(0).toUpperCase() + albumType.slice(1));
        if (albumTrackCount) albumMetaParts.push(albumTrackCount + ' tracks');
        if (albumLabel) albumMetaParts.push(albumLabel);

        // For track issues, show the track title under the album
        const trackNameLine = issue.entity_type === 'track' && entityName
            ? `<div class="issue-hero-track-name">&#9835; ${_esc(entityName)}</div>` : '';

        heroHtml = `
            <div class="issue-hero">
                <div class="issue-hero-art-group">
                    ${artistThumb ? `<img class="issue-hero-artist-thumb" src="${_escAttr(artistThumb)}" alt="" onerror="this.style.display='none'">` : ''}
                    ${albumThumb ? `<img class="issue-hero-album-art" src="${_escAttr(albumThumb)}" alt="" onerror="this.style.display='none';this.nextElementSibling.style.display='flex'">` : ''}
                    <div class="issue-hero-album-placeholder" style="${albumThumb ? 'display:none' : ''}">${catMeta.icon}</div>
                </div>
                <div class="issue-hero-info">
                    ${artistName ? `<div class="issue-hero-artist">${_esc(artistName)}</div>` : ''}
                    <div class="issue-hero-album">${_esc(albumName)}</div>
                    ${trackNameLine}
                    ${albumMetaParts.length > 0 ? `<div class="issue-hero-meta">${_esc(albumMetaParts.join(' \u00B7 '))}</div>` : ''}
                    ${genreTagsHtml}
                    ${extLinksHtml}
                </div>
            </div>
        `;
    } else {
        // Artist-level issue — simpler hero
        heroHtml = `
            <div class="issue-hero">
                <div class="issue-hero-art-group">
                    ${artistThumb ? `<img class="issue-hero-album-art" src="${_escAttr(artistThumb)}" alt="" onerror="this.style.display='none'">` : `<div class="issue-hero-album-placeholder">${catMeta.icon}</div>`}
                </div>
                <div class="issue-hero-info">
                    <div class="issue-hero-album">${_esc(entityName)}</div>
                    ${extLinksHtml}
                </div>
            </div>
        `;
    }

    // --- Issue info bar ---
    let issueInfoHtml = `
        <div class="issue-detail-info-bar">
            <div class="issue-detail-info-left">
                <span class="issue-status-badge ${statusMeta.cls}">${_esc(statusMeta.label)}</span>
                <span class="issue-priority-dot issue-priority-${_escAttr(issue.priority || 'normal')}" title="${_esc((issue.priority || 'normal'))} priority"></span>
                <span class="issue-detail-category">${catMeta.icon} ${_esc(catMeta.label)}</span>
            </div>
            <div class="issue-detail-info-right">
                <span class="issue-detail-date">Reported ${_esc(createdDate)}</span>
                ${issue.reporter_name && admin ? `<span class="issue-detail-profile">by ${_esc(issue.reporter_name)}</span>` : ''}
                ${resolvedDate ? `<span class="issue-detail-date">Resolved ${_esc(resolvedDate)}</span>` : ''}
            </div>
        </div>
    `;

    // --- Issue description ---
    let descriptionHtml = `
        <div class="issue-detail-section">
            <div class="issue-detail-section-title">Issue</div>
            <div class="issue-detail-title-text">${_esc(issue.title)}</div>
            ${issue.description ? `<div class="issue-detail-description">${_esc(issue.description)}</div>` : '<div class="issue-detail-no-desc">No additional details provided</div>'}
        </div>
    `;

    // --- Action buttons (Download Album / Add to Wishlist) for admin ---
    let actionButtonsHtml = '';
    if (admin && (issue.entity_type === 'album' || issue.entity_type === 'track')) {
        actionButtonsHtml = `
            <div class="issue-action-buttons">
                <button class="issue-action-btn issue-action-download" id="issue-action-download" title="Download this album">
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
                    Download Album
                </button>
                <button class="issue-action-btn issue-action-wishlist" id="issue-action-wishlist" title="Add all tracks to wishlist">
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M19 21l-7-5-7 5V5a2 2 0 012-2h10a2 2 0 012 2z"/></svg>
                    Add to Wishlist
                </button>
            </div>
        `;
    }

    // --- Metadata grid for track-level issues ---
    let metaGridHtml = '';
    if (issue.entity_type === 'track') {
        const metaItems = [];
        if (snapshot.track_number) metaItems.push({ icon: '#', label: 'Track', value: String(snapshot.track_number) });
        if (snapshot.duration) metaItems.push({ icon: '&#9719;', label: 'Duration', value: typeof snapshot.duration === 'number' ? formatDurationMs(snapshot.duration) : String(snapshot.duration) });
        if (snapshot.format) metaItems.push({ icon: '&#128190;', label: 'Format', value: snapshot.format });
        if (snapshot.bitrate) metaItems.push({ icon: '&#127926;', label: 'Bitrate', value: snapshot.bitrate + ' kbps' });
        if (snapshot.bpm) metaItems.push({ icon: '&#9835;', label: 'BPM', value: String(snapshot.bpm) });
        if (snapshot.quality) metaItems.push({ icon: '&#9733;', label: 'Quality', value: snapshot.quality });
        if (metaItems.length > 0) {
            metaGridHtml = `
                <div class="issue-detail-section">
                    <div class="issue-detail-section-title">Track Details</div>
                    <div class="issue-detail-meta-grid">
                        ${metaItems.map(m => `
                            <div class="issue-meta-item">
                                <span class="issue-meta-icon">${m.icon}</span>
                                <span class="issue-meta-label">${_esc(m.label)}</span>
                                <span class="issue-meta-value">${_esc(m.value)}</span>
                            </div>
                        `).join('')}
                    </div>
                </div>
            `;
        }
    }

    // --- File path display for tracks ---
    let filePathHtml = '';
    if (snapshot.file_path) {
        filePathHtml = `
            <div class="issue-detail-section">
                <div class="issue-detail-section-title">File Path</div>
                <div class="issue-detail-filepath">${_esc(snapshot.file_path)}</div>
            </div>
        `;
    }

    // --- Enhanced-library-style track listing ---
    let trackListHtml = '';
    if (snapshot.tracks && Array.isArray(snapshot.tracks) && snapshot.tracks.length > 0) {
        let lastDisc = null;
        let rows = '';
        const hasMultiDisc = snapshot.tracks.some(tr => (tr.disc_number || 1) > 1);
        snapshot.tracks.forEach(t => {
            const disc = t.disc_number || 1;
            if (hasMultiDisc && disc !== lastDisc) {
                rows += `<div class="issue-detail-tracklist-disc">Disc ${disc}</div>`;
                lastDisc = disc;
            }
            const fmt = t.format || (t.file_path ? t.file_path.split('.').pop().toUpperCase() : '');
            const fmtLower = fmt.toLowerCase();
            const fmtClass = fmtLower === 'flac' ? 'flac' : (fmtLower === 'mp3' ? 'mp3' : 'other');
            const br = t.bitrate ? parseInt(t.bitrate) : 0;
            const brClass = br >= 320 || fmtLower === 'flac' ? 'high' : (br >= 192 ? 'medium' : 'low');
            const durStr = t.duration && typeof t.duration === 'number' ? formatDurationMs(t.duration) : '';

            rows += `
                <div class="issue-detail-tracklist-row">
                    <span class="issue-detail-tracklist-num">${_esc(String(t.track_number || '-'))}</span>
                    <span class="issue-detail-tracklist-title">${_esc(t.title || 'Unknown')}</span>
                    ${durStr ? `<span class="issue-detail-tracklist-dur">${durStr}</span>` : ''}
                    <span class="issue-detail-tracklist-meta">
                        ${fmt ? `<span class="enhanced-format-badge ${fmtClass}">${_esc(fmt)}</span>` : ''}
                        ${br ? `<span class="enhanced-bitrate ${brClass}">${br}k</span>` : ''}
                    </span>
                </div>
            `;
        });
        trackListHtml = `
            <div class="issue-detail-section">
                <div class="issue-detail-section-title">Track Listing <span class="issue-detail-section-count">${snapshot.tracks.length} tracks</span></div>
                <div class="issue-detail-tracklist">${rows}</div>
            </div>
        `;
    }

    // --- Admin response section ---
    let adminResponseHtml = '';
    if (admin) {
        adminResponseHtml = `
            <div class="issue-detail-section">
                <div class="issue-detail-section-title">Admin Response</div>
                <textarea class="issue-detail-response-textarea" id="issue-detail-response-input" placeholder="Write a response to the reporter..." rows="3">${_esc(issue.admin_response || '')}</textarea>
            </div>
        `;
    } else if (issue.admin_response) {
        adminResponseHtml = `
            <div class="issue-detail-section">
                <div class="issue-detail-section-title">Admin Response</div>
                <div class="issue-detail-admin-response">${_esc(issue.admin_response)}</div>
            </div>
        `;
    }

    body.innerHTML = `
        ${heroHtml}
        ${issueInfoHtml}
        ${actionButtonsHtml}
        ${descriptionHtml}
        ${metaGridHtml}
        ${filePathHtml}
        ${trackListHtml}
        ${adminResponseHtml}
    `;

    // --- Footer with status action buttons ---
    const safeId = parseInt(issue.id, 10);
    let footerHtml = '<button class="enhanced-bulk-btn secondary" onclick="closeIssueDetailModal()">Close</button>';

    if (admin) {
        if (issue.status === 'open' || issue.status === 'in_progress') {
            if (issue.status === 'open') {
                footerHtml += `<button class="enhanced-bulk-btn issue-btn-progress" onclick="updateIssueStatus(${safeId}, 'in_progress')">Mark In Progress</button>`;
            }
            footerHtml += `<button class="enhanced-bulk-btn issue-btn-resolve" onclick="updateIssueStatus(${safeId}, 'resolved')">Resolve</button>`;
            footerHtml += `<button class="enhanced-bulk-btn issue-btn-dismiss" onclick="updateIssueStatus(${safeId}, 'dismissed')">Dismiss</button>`;
        } else {
            footerHtml += `<button class="enhanced-bulk-btn issue-btn-reopen" onclick="updateIssueStatus(${safeId}, 'open')">Reopen</button>`;
        }
        footerHtml += `<button class="enhanced-bulk-btn issue-btn-delete" onclick="deleteIssue(${safeId})">Delete</button>`;
    } else {
        if (issue.status === 'open') {
            footerHtml += `<button class="enhanced-bulk-btn issue-btn-delete" onclick="deleteIssue(${safeId})">Withdraw</button>`;
        }
    }

    footer.innerHTML = footerHtml;

    // --- Attach action button handlers ---
    const dlBtn = document.getElementById('issue-action-download');
    if (dlBtn) {
        dlBtn.onclick = () => issueDownloadAlbum(spotifyAlbumId, artistName, albumName);
    }
    const wlBtn = document.getElementById('issue-action-wishlist');
    if (wlBtn) {
        wlBtn.onclick = () => issueAddToWishlist(spotifyAlbumId, artistName, albumName);
    }
}

// --- Issue Action: Download Album ---
async function issueDownloadAlbum(spotifyAlbumId, artistName, albumName) {
    const btn = document.getElementById('issue-action-download');
    if (!spotifyAlbumId && (!artistName || !albumName)) {
        showToast('No album ID or artist/album info available for download', 'warning');
        return;
    }
    try {
        if (btn) { btn.disabled = true; btn.textContent = 'Loading...'; }

        let response;
        if (spotifyAlbumId) {
            const albumParams = new URLSearchParams({ name: albumName || '', artist: artistName || '' });
            response = await fetch(`/api/spotify/album/${encodeURIComponent(spotifyAlbumId)}?${albumParams}`);
        } else {
            // No Spotify album ID — search for the album by name
            const query = `${artistName} ${albumName}`;
            const searchResp = await fetch('/api/enhanced-search', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ query })
            });
            if (!searchResp.ok) throw new Error('Album search failed');
            const searchData = await searchResp.json();
            const foundAlbum = searchData.spotify_albums?.[0];
            if (!foundAlbum || !foundAlbum.id) {
                showToast(`Could not find "${albumName}" by ${artistName}`, 'warning');
                return;
            }
            const albumParams = new URLSearchParams({ name: foundAlbum.name || albumName, artist: foundAlbum.artist || artistName });
            response = await fetch(`/api/spotify/album/${encodeURIComponent(foundAlbum.id)}?${albumParams}`);
        }

        if (!response.ok) {
            if (response.status === 401) throw new Error('Spotify not authenticated');
            throw new Error(`Failed to load album: ${response.status}`);
        }

        const albumData = await response.json();
        if (!albumData || !albumData.tracks || albumData.tracks.length === 0) {
            showToast(`No tracks available for "${albumName}"`, 'warning');
            return;
        }

        // Close the issue modal first
        closeIssueDetailModal();

        const resolvedAlbumId = albumData.id || spotifyAlbumId || Date.now();
        const virtualPlaylistId = `issue_download_${resolvedAlbumId}`;

        // Enrich tracks with album metadata
        const enrichedTracks = albumData.tracks.map(track => ({
            ...track,
            album: {
                name: albumData.name,
                id: albumData.id,
                album_type: albumData.album_type || 'album',
                images: albumData.images || [],
                release_date: albumData.release_date,
                total_tracks: albumData.total_tracks
            }
        }));

        const playlistName = `[${artistName}] ${albumData.name}`;
        const artistObject = { id: `issue_${artistName}`, name: artistName, image_url: '' };
        const fullAlbumObject = {
            name: albumData.name,
            id: albumData.id,
            album_type: albumData.album_type || 'album',
            images: albumData.images || [],
            image_url: albumData.images?.[0]?.url || null,
            release_date: albumData.release_date,
            total_tracks: albumData.total_tracks,
            artists: albumData.artists || [{ name: artistName }]
        };

        await openDownloadMissingModalForArtistAlbum(
            virtualPlaylistId, playlistName, enrichedTracks, fullAlbumObject, artistObject, true
        );

        // Register download bubble so it appears on the dashboard
        const albumType = fullAlbumObject.album_type || 'album';
        registerArtistDownload(artistObject, fullAlbumObject, virtualPlaylistId, albumType);

    } catch (error) {
        console.error('Issue download error:', error);
        showToast(`Error: ${error.message}`, 'error');
    } finally {
        if (btn) { btn.disabled = false; btn.innerHTML = '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg> Download Album'; }
    }
}

// --- Redownload Library Album (Enhanced View) ---
async function redownloadLibraryAlbum(album, artistName, btn) {
    const albumName = album.title || '';
    const spotifyAlbumId = album.spotify_album_id || '';

    if (!spotifyAlbumId && !albumName) {
        showToast('No album ID or name available for redownload', 'warning');
        return;
    }

    const origText = btn ? btn.innerHTML : '';
    try {
        if (btn) { btn.disabled = true; btn.textContent = 'Loading...'; }

        let response;
        if (spotifyAlbumId) {
            const params = new URLSearchParams({ name: albumName, artist: artistName || '' });
            response = await fetch(`/api/spotify/album/${encodeURIComponent(spotifyAlbumId)}?${params}`);
        }

        // Fallback: search by name if no ID or direct fetch failed
        if (!response || !response.ok) {
            const query = `${artistName || ''} ${albumName}`.trim();
            const searchResp = await fetch('/api/enhanced-search', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ query })
            });
            if (!searchResp.ok) throw new Error('Album search failed');
            const searchData = await searchResp.json();
            const found = searchData.spotify_albums?.[0] || searchData.itunes_albums?.[0];
            if (!found || !found.id) {
                showToast(`Could not find "${albumName}" by ${artistName || 'unknown'}`, 'warning');
                return;
            }
            const params = new URLSearchParams({ name: found.name || albumName, artist: found.artist || artistName || '' });
            response = await fetch(`/api/spotify/album/${encodeURIComponent(found.id)}?${params}`);
        }

        if (!response.ok) throw new Error(`Failed to load album: ${response.status}`);

        const albumData = await response.json();
        if (!albumData || !albumData.tracks || albumData.tracks.length === 0) {
            showToast(`No tracks found for "${albumName}"`, 'warning');
            return;
        }

        const resolvedId = albumData.id || spotifyAlbumId || album.id;
        const virtualPlaylistId = `library_redownload_${resolvedId}`;
        const playlistName = `[${artistName || 'Unknown'}] ${albumData.name}`;

        const enrichedTracks = albumData.tracks.map(track => ({
            ...track,
            album: {
                name: albumData.name,
                id: albumData.id,
                album_type: albumData.album_type || 'album',
                images: albumData.images || [],
                release_date: albumData.release_date,
                total_tracks: albumData.total_tracks
            }
        }));

        const enhancedArtist = artistDetailPageState.enhancedData?.artist;
        const artistObject = {
            id: artistDetailPageState.currentArtistId || `library_${artistName || album.id}`,
            name: artistName || '',
            image_url: enhancedArtist?.thumb_url || ''
        };
        const fullAlbumObject = {
            name: albumData.name,
            id: albumData.id,
            album_type: albumData.album_type || 'album',
            images: albumData.images || [],
            image_url: albumData.images?.[0]?.url || null,
            release_date: albumData.release_date,
            total_tracks: albumData.total_tracks,
            artists: albumData.artists || [{ name: artistName || '' }]
        };

        await openDownloadMissingModalForArtistAlbum(
            virtualPlaylistId, playlistName, enrichedTracks, fullAlbumObject, artistObject, true
        );

        // Register download bubble so it appears on the dashboard
        const albumType = fullAlbumObject.album_type || 'album';
        registerArtistDownload(artistObject, fullAlbumObject, virtualPlaylistId, albumType);

    } catch (error) {
        console.error('Redownload album error:', error);
        showToast(`Error: ${error.message}`, 'error');
    } finally {
        if (btn) { btn.disabled = false; btn.innerHTML = origText; }
    }
}

// --- Issue Action: Add to Wishlist ---
async function issueAddToWishlist(spotifyAlbumId, artistName, albumName) {
    const btn = document.getElementById('issue-action-wishlist');
    if (!spotifyAlbumId && (!artistName || !albumName)) {
        showToast('No album ID or artist/album info available', 'warning');
        return;
    }
    try {
        if (btn) { btn.disabled = true; btn.textContent = 'Loading...'; }

        let response;
        if (spotifyAlbumId) {
            const albumParams = new URLSearchParams({ name: albumName || '', artist: artistName || '' });
            response = await fetch(`/api/spotify/album/${encodeURIComponent(spotifyAlbumId)}?${albumParams}`);
        } else {
            // No Spotify album ID — search for the album by name
            const query = `${artistName} ${albumName}`;
            const searchResp = await fetch('/api/enhanced-search', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ query })
            });
            if (!searchResp.ok) throw new Error('Album search failed');
            const searchData = await searchResp.json();
            const foundAlbum = searchData.spotify_albums?.[0];
            if (!foundAlbum || !foundAlbum.id) {
                showToast(`Could not find "${albumName}" by ${artistName}`, 'warning');
                return;
            }
            const albumParams = new URLSearchParams({ name: foundAlbum.name || albumName, artist: foundAlbum.artist || artistName });
            response = await fetch(`/api/spotify/album/${encodeURIComponent(foundAlbum.id)}?${albumParams}`);
        }

        if (!response.ok) throw new Error(`Failed to load album: ${response.status}`);

        const albumData = await response.json();
        if (!albumData || !albumData.tracks || albumData.tracks.length === 0) {
            showToast(`No tracks available for "${albumName}"`, 'warning');
            return;
        }

        // Close issue modal and open wishlist modal
        closeIssueDetailModal();

        const albumArtists = albumData.artists || [{ name: artistName }];
        const album = {
            name: albumData.name,
            id: albumData.id,
            album_type: albumData.album_type || 'album',
            images: albumData.images || [],
            release_date: albumData.release_date,
            total_tracks: albumData.total_tracks,
            artists: albumArtists
        };
        const artist = { id: null, name: artistName };

        // Enrich tracks with album metadata — use album artist for wishlist grouping
        // (Spotify returns per-track artists which can differ on compilations/soundtracks)
        const tracks = albumData.tracks.map(t => ({
            ...t,
            artists: albumArtists,
            album: album
        }));

        await openAddToWishlistModal(album, artist, tracks, albumData.album_type || 'album');

    } catch (error) {
        console.error('Issue wishlist error:', error);
        showToast(`Error: ${error.message}`, 'error');
    } finally {
        if (btn) { btn.disabled = false; btn.innerHTML = '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M19 21l-7-5-7 5V5a2 2 0 012-2h10a2 2 0 012 2z"/></svg> Add to Wishlist'; }
    }
}

async function updateIssueStatus(issueId, newStatus) {
    const payload = { status: newStatus };

    // Include admin response if present
    const responseInput = document.getElementById('issue-detail-response-input');
    if (responseInput) {
        payload.admin_response = responseInput.value.trim();
    }

    try {
        const resp = await fetch(`/api/issues/${issueId}`, {
            method: 'PUT',
            headers: _issueHeaders({ 'Content-Type': 'application/json' }),
            body: JSON.stringify(payload),
        });
        const data = await resp.json();
        if (data.success) {
            showToast(`Issue ${newStatus === 'resolved' ? 'resolved' : newStatus === 'dismissed' ? 'dismissed' : newStatus === 'in_progress' ? 'marked in progress' : 'reopened'}`, 'success');
            closeIssueDetailModal();
            // Refresh if on issues page
            const issuesPage = document.getElementById('issues-page');
            if (issuesPage && issuesPage.classList.contains('active')) {
                loadIssuesPage();
            }
            loadIssuesBadge();
        } else {
            showToast(data.error || 'Failed to update issue', 'error');
        }
    } catch (e) {
        console.error('Failed to update issue:', e);
        showToast('Failed to update issue', 'error');
    }
}

async function deleteIssue(issueId) {
    if (!confirm('Are you sure you want to delete this issue?')) return;
    try {
        const resp = await fetch(`/api/issues/${issueId}`, { method: 'DELETE', headers: _issueHeaders() });
        const data = await resp.json();
        if (data.success) {
            showToast('Issue deleted', 'success');
            closeIssueDetailModal();
            const issuesPage = document.getElementById('issues-page');
            if (issuesPage && issuesPage.classList.contains('active')) {
                loadIssuesPage();
            }
            loadIssuesBadge();
        } else {
            showToast(data.error || 'Failed to delete issue', 'error');
        }
    } catch (e) {
        console.error('Failed to delete issue:', e);
        showToast('Failed to delete issue', 'error');
    }
}

function closeIssueDetailModal() {
    const overlay = document.getElementById('issue-detail-overlay');
    if (overlay) overlay.classList.add('hidden');
}

async function loadIssuesBadge() {
    try {
        const resp = await fetch('/api/issues/counts', { headers: _issueHeaders() });
        const data = await resp.json();
        if (!data.success) return;
        const badge = document.getElementById('issues-nav-badge');
        if (badge) {
            const openCount = data.counts.open || 0;
            badge.textContent = openCount;
            badge.classList.toggle('hidden', openCount === 0);
        }
    } catch (e) {}
}

// ===== END ISSUES PAGE =====

// --- Helpers ---

function _esc(str) {
    if (!str) return '';
    const d = document.createElement('div');
    d.textContent = str;
    return d.innerHTML;
}

function _escAttr(str) {
    if (!str) return '';
    return String(str).replace(/&/g, '&amp;').replace(/"/g, '&quot;').replace(/'/g, '&#39;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

// ===== ENHANCE QUALITY MODAL =====

let _enhanceQualityData = null;
let _enhanceArtistId = null;

const ENHANCE_TIER_MAP = {
    'lossless': { num: 1, label: 'Lossless', cssClass: 'lossless' },
    'high_lossy': { num: 2, label: 'High Lossy', cssClass: 'high-lossy' },
    'standard_lossy': { num: 3, label: 'Standard Lossy', cssClass: 'standard-lossy' },
    'low_lossy': { num: 4, label: 'Low Lossy', cssClass: 'low-lossy' },
    'unknown': { num: 999, label: 'Unknown', cssClass: 'unknown' },
};

async function checkArtistEnhanceEligibility(artistId) {
    const btn = document.getElementById('library-artist-enhance-btn');
    if (!btn) return;
    btn.classList.add('hidden');
    _enhanceArtistId = artistId;

    try {
        const resp = await fetch(`/api/library/artist/${artistId}/quality-analysis`);
        if (!resp.ok) return;
        const data = await resp.json();
        if (!data.success || !data.tracks || data.tracks.length === 0) return;

        _enhanceQualityData = data;

        // Show button if any tracks are below the user's min acceptable tier
        const minTier = data.min_acceptable_tier || 1;
        const belowCount = data.tracks.filter(t => t.tier_num > minTier).length;
        if (belowCount > 0) {
            btn.classList.remove('hidden');
            btn.querySelector('.enhance-text').textContent = `Enhance Quality (${belowCount})`;
        }
    } catch (e) {
        console.debug('Enhance eligibility check failed:', e);
    }
}

async function playArtistRadio() {
    try {
        const artistId = artistDetailPageState.currentArtistId;
        const artistName = artistDetailPageState.currentArtistName || '';
        if (!artistId) {
            showToast('No artist selected', 'error');
            return;
        }

        // Get tracks from this artist's library
        const resp = await fetch(`/api/library/artist/${artistId}/enhanced`);
        if (!resp.ok) throw new Error('Failed to load artist data');
        const data = await resp.json();
        if (!data.success) throw new Error(data.error || 'Failed');

        // Collect all tracks with file paths
        const allTracks = [];
        for (const album of (data.albums || [])) {
            for (const track of (album.tracks || [])) {
                if (track.file_path) {
                    allTracks.push({ track, album });
                }
            }
        }

        if (!allTracks.length) {
            showToast('No playable tracks found for this artist', 'error');
            return;
        }

        // Pick a random track
        const random = allTracks[Math.floor(Math.random() * allTracks.length)];
        const albumArt = random.album.thumb_url || data.artist?.thumb_url || null;

        // Clear existing queue and disable radio before starting fresh
        npRadioMode = false;
        clearQueue();
        if (audioPlayer && !audioPlayer.paused) {
            audioPlayer.pause();
        }

        // Play the track first, then enable radio mode after a short delay
        // so currentTrack is set and the radio queue fill triggers
        playLibraryTrack({
            id: random.track.id,
            title: random.track.title,
            file_path: random.track.file_path,
            bitrate: random.track.bitrate,
            artist_id: artistId,
            album_id: random.album.id,
        }, random.album.title || '', artistName);

        // Enable radio mode after track starts loading
        setTimeout(() => {
            npRadioMode = true;
            const radioBtn = document.querySelector('.np-radio-btn');
            if (radioBtn) radioBtn.classList.add('active');
        }, 1000);

        showToast(`Playing ${artistName} radio — similar tracks will auto-queue`, 'success');
    } catch (e) {
        showToast(`Failed to start artist radio: ${e.message}`, 'error');
    }
}

function openEnhanceQualityModal() {
    if (!_enhanceQualityData) return;
    const data = _enhanceQualityData;

    // Remove existing modal if any
    const existing = document.getElementById('enhance-quality-overlay');
    if (existing) existing.remove();

    const overlay = document.createElement('div');
    overlay.id = 'enhance-quality-overlay';
    overlay.className = 'enhance-modal-overlay';
    overlay.onclick = (e) => { if (e.target === overlay) closeEnhanceQualityModal(); };

    const minTier = data.min_acceptable_tier || 1;
    const summary = data.quality_summary || {};

    overlay.innerHTML = `
        <div class="enhance-modal" onclick="event.stopPropagation()">
            <div class="enhance-modal-header">
                <h3>⚡ Enhance Quality — ${_esc(data.artist_name)}</h3>
                <button class="enhance-modal-close" onclick="closeEnhanceQualityModal()">&times;</button>
            </div>
            <div class="enhance-summary-bar">
                ${_buildEnhanceSummaryChips(summary)}
            </div>
            <div class="enhance-controls">
                <div class="enhance-tier-selector">
                    <label>Upgrade tracks below:</label>
                    <select id="enhance-tier-dropdown" onchange="updateEnhanceThreshold(parseInt(this.value))">
                        <option value="1" ${minTier <= 1 ? 'selected' : ''}>Lossless (FLAC/WAV)</option>
                        <option value="2" ${minTier === 2 ? 'selected' : ''}>High Lossy (OGG/Opus)</option>
                        <option value="3" ${minTier === 3 ? 'selected' : ''}>Standard Lossy (M4A/AAC)</option>
                        <option value="4" ${minTier >= 4 ? 'selected' : ''}>Low Lossy (MP3/WMA)</option>
                    </select>
                </div>
                <div class="enhance-select-controls">
                    <button class="enhance-select-btn" onclick="enhanceSelectAll(true)">Select All Below</button>
                    <button class="enhance-select-btn" onclick="enhanceSelectAll(false)">Deselect All</button>
                    <span class="enhance-selected-count" id="enhance-selected-count">0 selected</span>
                </div>
            </div>
            <div class="enhance-modal-body">
                <table class="enhance-track-table">
                    <thead>
                        <tr>
                            <th></th>
                            <th>#</th>
                            <th>Title</th>
                            <th>Album</th>
                            <th>Format</th>
                            <th>Bitrate</th>
                        </tr>
                    </thead>
                    <tbody id="enhance-track-tbody">
                    </tbody>
                </table>
            </div>
            <div class="enhance-modal-footer">
                <div class="enhance-footer-info" id="enhance-footer-info"></div>
                <div class="enhance-footer-actions">
                    <button class="enhance-btn secondary" onclick="closeEnhanceQualityModal()">Cancel</button>
                    <button class="enhance-btn primary" id="enhance-submit-btn" onclick="submitEnhanceQuality()" disabled>
                        ⚡ Enhance 0 Tracks
                    </button>
                </div>
            </div>
        </div>
    `;

    document.body.appendChild(overlay);
    renderEnhanceTrackRows(minTier);
}

function _buildEnhanceSummaryChips(summary) {
    const chips = [
        { key: 'lossless', label: 'FLAC', cssClass: 'lossless' },
        { key: 'high_lossy', label: 'OGG/Opus', cssClass: 'high-lossy' },
        { key: 'standard_lossy', label: 'M4A/AAC', cssClass: 'standard-lossy' },
        { key: 'low_lossy', label: 'MP3/WMA', cssClass: 'low-lossy' },
    ];
    return chips
        .filter(c => (summary[c.key] || 0) > 0)
        .map(c => `
            <div class="enhance-summary-chip ${c.cssClass}">
                <span class="chip-count">${summary[c.key]}</span>
                <span class="chip-label">${c.label}</span>
            </div>
        `).join('');
}

function renderEnhanceTrackRows(thresholdTier) {
    const tbody = document.getElementById('enhance-track-tbody');
    if (!tbody || !_enhanceQualityData) return;

    const tracks = _enhanceQualityData.tracks;
    // Sort: below-threshold first, then by album + track number
    const sorted = [...tracks].sort((a, b) => {
        const aBt = a.tier_num > thresholdTier ? 0 : 1;
        const bBt = b.tier_num > thresholdTier ? 0 : 1;
        if (aBt !== bBt) return aBt - bBt;
        const albumCmp = (a.album_title || '').localeCompare(b.album_title || '');
        if (albumCmp !== 0) return albumCmp;
        return (a.disc_number || 1) * 1000 + (a.track_number || 0) - ((b.disc_number || 1) * 1000 + (b.track_number || 0));
    });

    tbody.innerHTML = sorted.map(track => {
        const isBelow = track.tier_num > thresholdTier;
        const tierInfo = ENHANCE_TIER_MAP[track.tier_name] || ENHANCE_TIER_MAP['unknown'];
        const bitrateStr = track.bitrate ? `${track.bitrate} kbps` : '-';
        return `
            <tr class="enhance-track-row ${isBelow ? 'below-threshold' : 'above-threshold'}"
                data-track-id="${_escAttr(track.track_id)}" data-tier="${track.tier_num}">
                <td><input type="checkbox" class="enhance-track-check"
                    ${isBelow ? 'checked' : ''} onchange="updateEnhanceSelectedCount()"></td>
                <td>${track.track_number || '-'}</td>
                <td>${_esc(track.title)}</td>
                <td>${_esc(track.album_title)}</td>
                <td><span class="enhance-format-badge ${tierInfo.cssClass}">${_esc(track.format)}</span></td>
                <td><span class="enhance-bitrate">${bitrateStr}</span></td>
            </tr>
        `;
    }).join('');

    updateEnhanceSelectedCount();
}

function updateEnhanceThreshold(tierNum) {
    const rows = document.querySelectorAll('.enhance-track-row');
    rows.forEach(row => {
        const trackTier = parseInt(row.dataset.tier);
        const isBelow = trackTier > tierNum;
        const cb = row.querySelector('.enhance-track-check');

        row.classList.toggle('below-threshold', isBelow);
        row.classList.toggle('above-threshold', !isBelow);
        if (cb) cb.checked = isBelow;
    });
    updateEnhanceSelectedCount();
}

function enhanceSelectAll(select) {
    const thresholdTier = parseInt(document.getElementById('enhance-tier-dropdown')?.value || '1');
    const checks = document.querySelectorAll('.enhance-track-check');
    checks.forEach(cb => {
        const row = cb.closest('.enhance-track-row');
        const trackTier = parseInt(row?.dataset.tier || '999');
        if (select) {
            cb.checked = trackTier > thresholdTier;
        } else {
            cb.checked = false;
        }
    });
    updateEnhanceSelectedCount();
}

function updateEnhanceSelectedCount() {
    const checks = document.querySelectorAll('.enhance-track-check:checked');
    const count = checks.length;
    const countEl = document.getElementById('enhance-selected-count');
    const submitBtn = document.getElementById('enhance-submit-btn');

    if (countEl) countEl.textContent = `${count} selected`;
    if (submitBtn) {
        submitBtn.textContent = `⚡ Enhance ${count} Track${count !== 1 ? 's' : ''}`;
        submitBtn.disabled = count === 0;
    }
}

async function submitEnhanceQuality() {
    const checks = document.querySelectorAll('.enhance-track-check:checked');
    const trackIds = [];
    checks.forEach(cb => {
        const row = cb.closest('.enhance-track-row');
        if (row?.dataset.trackId) trackIds.push(row.dataset.trackId);
    });

    if (trackIds.length === 0) return;

    const submitBtn = document.getElementById('enhance-submit-btn');
    const footerInfo = document.getElementById('enhance-footer-info');
    if (submitBtn) {
        submitBtn.disabled = true;
        submitBtn.innerHTML = '<span class="enhance-spinner"></span>Processing...';
    }
    if (footerInfo) footerInfo.textContent = 'Matching tracks to Spotify and adding to wishlist...';

    try {
        const resp = await fetch(`/api/library/artist/${_enhanceArtistId}/enhance`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ track_ids: trackIds })
        });

        const result = await resp.json();

        if (result.success) {
            const msg = `${result.enhanced_count} track${result.enhanced_count !== 1 ? 's' : ''} queued for enhancement`;
            if (footerInfo) footerInfo.textContent = msg;

            showToast(msg + (result.failed_count > 0 ? ` (${result.failed_count} failed)` : ''), 'success');

            // Update button count
            const enhBtn = document.getElementById('library-artist-enhance-btn');
            if (enhBtn && result.enhanced_count > 0) {
                const remaining = trackIds.length - result.enhanced_count;
                if (remaining <= 0) {
                    enhBtn.classList.add('hidden');
                }
            }

            if (submitBtn) {
                submitBtn.textContent = '✅ Done';
                submitBtn.disabled = true;
            }

            // Auto-close after short delay
            setTimeout(() => closeEnhanceQualityModal(), 1500);
        } else {
            throw new Error(result.error || 'Enhancement failed');
        }
    } catch (e) {
        console.error('Enhance quality error:', e);
        showToast(`Enhancement failed: ${e.message}`, 'error');
        if (submitBtn) {
            submitBtn.textContent = `⚡ Enhance ${trackIds.length} Tracks`;
            submitBtn.disabled = false;
        }
        if (footerInfo) footerInfo.textContent = '';
    }
}

function closeEnhanceQualityModal() {
    const overlay = document.getElementById('enhance-quality-overlay');
    if (overlay) {
        overlay.classList.add('hidden');
        setTimeout(() => overlay.remove(), 300);
    }
}

// Global exports
window.openEnhanceQualityModal = openEnhanceQualityModal;
window.closeEnhanceQualityModal = closeEnhanceQualityModal;
window.updateEnhanceThreshold = updateEnhanceThreshold;
window.enhanceSelectAll = enhanceSelectAll;
window.updateEnhanceSelectedCount = updateEnhanceSelectedCount;
window.submitEnhanceQuality = submitEnhanceQuality;

// ===== END ENHANCE QUALITY MODAL =====

// ==================================================================================
// PLAYLIST EXPLORER — Visual Discovery Tree
// ==================================================================================

const _explorer = {
    initialized: false,
    mode: 'albums',
    artists: [],
    selectedAlbums: new Set(),
    expandedArtists: new Set(),
    building: false,
    playlistId: null,
    meta: null,
    _resizeTimer: null,
};

function initExplorer() {
    if (_explorer.initialized) return;
    _explorer.initialized = true;
    _explorer._playlists = [];
    _explorer._activeSource = null;

    _explorerLoadPlaylists();

    // Listen for discovery completion to auto-refresh playlist cards
    if (typeof socket !== 'undefined') {
        socket.on('discovery:progress', (data) => {
            if (!document.getElementById('playlist-explorer-page')?.classList.contains('active')) return;
            // Match mirrored playlist discovery events
            if (data.phase === 'discovered' || data.phase === 'sync_complete' || data.complete) {
                // Discovery finished — refresh playlists after brief delay for DB commit
                setTimeout(() => _explorerLoadPlaylists(), 1500);
            }
            // Live progress update on cards during discovery
            if (data.id && data.id.startsWith('mirrored_')) {
                const plId = parseInt(data.id.replace('mirrored_', ''));
                const card = document.querySelector(`.explorer-picker-card[data-id="${plId}"]`);
                if (card) {
                    const meta = card.querySelector('.explorer-picker-card-meta');
                    if (meta && data.progress != null) {
                        meta.innerHTML = `<span class="explorer-discovering-live">Discovering... ${Math.round(data.progress)}%</span>`;
                    }
                }
            }
        });
    }
}

function _explorerLoadPlaylists() {
    fetch('/api/mirrored-playlists')
        .then(r => r.json())
        .then(data => {
            const playlists = Array.isArray(data) ? data : (data.playlists || []);
            _explorer._playlists = playlists;

            if (playlists.length === 0) {
                const scroll = document.getElementById('explorer-picker-scroll');
                if (scroll) scroll.innerHTML = '<div class="explorer-picker-empty">No mirrored playlists found. Sync a playlist first.</div>';
                return;
            }

            // Group by source
            const groups = {};
            playlists.forEach(p => {
                const src = (p.source || 'other').toLowerCase();
                if (!groups[src]) groups[src] = [];
                groups[src].push(p);
            });

            // Render source tabs
            const tabsEl = document.getElementById('explorer-picker-tabs');
            if (tabsEl) {
                const sourceNames = { spotify: 'Spotify', tidal: 'Tidal', deezer: 'Deezer', youtube: 'YouTube', beatport: 'Beatport', file: 'File', other: 'Other' };
                const sources = Object.keys(groups);
                if (sources.length <= 1) {
                    tabsEl.style.display = 'none';
                } else {
                    tabsEl.innerHTML = sources.map((src, i) => {
                        const label = sourceNames[src] || src.charAt(0).toUpperCase() + src.slice(1);
                        const count = groups[src].length;
                        const isActive = _explorer._activeSource === src || (!_explorer._activeSource && i === 0);
                        return `<button class="explorer-picker-tab ${isActive ? 'active' : ''}" data-source="${src}" onclick="explorerSwitchPickerTab('${src}')">${label} <span class="explorer-picker-tab-count">${count}</span></button>`;
                    }).join('');
                }

                // Show active or first source
                const activeSource = _explorer._activeSource || sources[0];
                _explorer._activeSource = activeSource;
                explorerRenderPickerCards(activeSource);
            }
        })
        .catch(() => {});
}

function explorerSwitchPickerTab(source) {
    _explorer._activeSource = source;
    document.querySelectorAll('.explorer-picker-tab').forEach(t => t.classList.toggle('active', t.dataset.source === source));
    explorerRenderPickerCards(source);
}

function explorerRenderPickerCards(source) {
    const scroll = document.getElementById('explorer-picker-scroll');
    if (!scroll) return;

    const filtered = _explorer._playlists.filter(p => (p.source || 'other').toLowerCase() === source);
    scroll.innerHTML = filtered.map(p => {
        const img = p.image_url || '';
        const total = p.total_count || p.track_count || 0;
        const discovered = p.discovered_count || 0;
        const pct = total > 0 ? Math.round((discovered / total) * 100) : 0;
        const isReady = pct >= 50;
        const isActive = _explorer.playlistId === p.id;
        const isFullyDiscovered = pct === 100;
        const wasExplored = p.explored || false;
        const wishlisted = p.wishlisted_count || 0;
        const inLibrary = p.in_library_count || 0;

        // Status badge: checkmark if explored/in-library, star if ready, % if needs discovery
        let statusBadge = '';
        if (inLibrary > 0 && inLibrary >= total * 0.8) {
            statusBadge = '<div class="explorer-picker-card-badge downloaded" title="Most tracks in library">&#10003;</div>';
        } else if (wasExplored) {
            statusBadge = '<div class="explorer-picker-card-badge explored" title="Already explored">&#10003;</div>';
        } else if (wishlisted > 0) {
            statusBadge = '<div class="explorer-picker-card-badge wishlisted" title="Tracks wishlisted">&#9829;</div>';
        } else if (isFullyDiscovered) {
            statusBadge = '<div class="explorer-picker-card-badge ready" title="Ready to explore">&#9733;</div>';
        } else if (!isReady) {
            statusBadge = `<div class="explorer-picker-card-badge needs-discovery" title="Needs discovery (${pct}%)">${pct}%</div>`;
        }

        // Meta line with status indicators
        let metaHTML;
        const statusParts = [];
        if (inLibrary > 0) statusParts.push(`<span class="explorer-picker-in-library">${inLibrary} in library</span>`);
        if (wishlisted > 0) statusParts.push(`<span class="explorer-picker-wishlisted">${wishlisted} wishlisted</span>`);

        if (isFullyDiscovered) {
            metaHTML = `${total} tracks &middot; <span class="explorer-picker-discovered">Fully discovered</span>`;
        } else if (isReady) {
            metaHTML = `${total} tracks &middot; ${pct}% discovered`;
        } else {
            metaHTML = `${total} tracks &middot; <span class="explorer-picker-not-ready">${pct}% discovered</span>`;
        }
        if (statusParts.length > 0) {
            metaHTML += `<br>${statusParts.join(' &middot; ')}`;
        }

        // Discover button for undiscovered playlists (replaces redirect to Sync)
        const discoverBtn = !isReady ? `<button class="explorer-picker-discover-btn" onclick="event.stopPropagation(); explorerStartDiscovery(${p.id})" title="Start discovery">Discover</button>` : '';

        return `
            <div class="explorer-picker-card ${isActive ? 'active' : ''} ${!isReady ? 'not-ready' : ''} ${wasExplored ? 'explored' : ''}"
                 data-id="${p.id}"
                 onclick="${isReady ? `explorerSelectPlaylist(${p.id}, this)` : ''}">
                <div class="explorer-picker-card-art">
                    ${img ? `<img src="${img}" alt="" loading="lazy">` : '<div class="explorer-picker-card-art-placeholder">&#9835;</div>'}
                </div>
                <div class="explorer-picker-card-info">
                    <div class="explorer-picker-card-name-row">
                        <div class="explorer-picker-card-name">${p.name || 'Untitled'}</div>
                        ${statusBadge}
                    </div>
                    <div class="explorer-picker-card-meta">${metaHTML}</div>
                    ${discoverBtn ? `<div class="explorer-picker-card-actions">${discoverBtn}</div>` : ''}
                </div>
            </div>
        `;
    }).join('');
}

function explorerSelectPlaylist(id, el) {
    _explorer.playlistId = id;
    document.querySelectorAll('.explorer-picker-card').forEach(c => c.classList.remove('active'));
    if (el) el.classList.add('active');
    // Update hint text
    const hint = document.getElementById('explorer-build-hint');
    const pl = _explorer._playlists.find(p => p.id === id);
    if (hint && pl) hint.textContent = `Ready: ${pl.name}`;
    else if (hint) hint.textContent = '';
}

function explorerRedirectToDiscover(playlistId) {
    showToast('This playlist needs more tracks discovered before exploring. Redirecting to Sync...', 'info');
    navigateToPage('sync');
    setTimeout(() => {
        const mirroredBtn = document.querySelector('.sync-tab-button[data-tab="mirrored"]');
        if (mirroredBtn) mirroredBtn.click();
    }, 200);
}

async function explorerStartDiscovery(playlistId) {
    const card = document.querySelector(`.explorer-picker-card[data-id="${playlistId}"]`);
    const btn = card?.querySelector('.explorer-picker-discover-btn');
    if (btn) { btn.disabled = true; btn.textContent = 'Starting...'; }

    try {
        if (typeof discoverMirroredPlaylist === 'function') {
            await discoverMirroredPlaylist(playlistId);
            if (btn) { btn.disabled = false; btn.textContent = 'Open'; btn.title = 'Reopen discovery modal'; }

            // Poll for card updates while discovery is in progress
            _explorerStartDiscoveryPoller(playlistId);
        } else {
            explorerRedirectToDiscover(playlistId);
        }
    } catch (err) {
        showToast(`Discovery failed: ${err.message}`, 'error');
        if (btn) { btn.disabled = false; btn.textContent = 'Discover'; }
    }
}

function _explorerStartDiscoveryPoller(playlistId) {
    // Poll every 5s to refresh playlist cards until this playlist is ready
    if (_explorer._discoveryPoller) clearInterval(_explorer._discoveryPoller);
    _explorer._discoveryPoller = setInterval(async () => {
        // Stop polling if Explorer page isn't active
        if (!document.getElementById('playlist-explorer-page')?.classList.contains('active')) {
            clearInterval(_explorer._discoveryPoller);
            _explorer._discoveryPoller = null;
            return;
        }
        // Check if the mirrored playlist state shows discovery is done
        const tempHash = `mirrored_${playlistId}`;
        const state = youtubePlaylistStates[tempHash];
        const isDone = state && (state.phase === 'discovered' || state.phase === 'sync_complete');

        // Refresh cards from API
        await _explorerLoadPlaylists();

        // Stop polling once discovery is complete
        if (isDone) {
            clearInterval(_explorer._discoveryPoller);
            _explorer._discoveryPoller = null;
        }
    }, 5000);
}

function explorerSetMode(mode) {
    _explorer.mode = mode;
    document.querySelectorAll('.explorer-mode-btn').forEach(btn => {
        btn.classList.toggle('active', btn.dataset.mode === mode);
    });
}

async function explorerBuildTree() {
    const playlistId = _explorer.playlistId;
    if (!playlistId) {
        showToast('Select a playlist first', 'error');
        return;
    }
    if (_explorer.building) return;

    _explorer.building = true;
    _explorer.artists = [];
    _explorer.selectedAlbums.clear();
    _explorer.expandedArtists.clear();
    _explorer.playlistId = playlistId;

    const tree = document.getElementById('explorer-tree');
    const svg = document.getElementById('explorer-svg');
    const progress = document.getElementById('explorer-progress');
    const actionBar = document.getElementById('explorer-action-bar');
    const empty = document.getElementById('explorer-empty');
    const buildBtn = document.getElementById('explorer-build-btn');

    if (empty) empty.style.display = 'none';
    if (actionBar) actionBar.style.display = 'none';
    if (progress) progress.style.display = 'flex';
    if (buildBtn) { buildBtn.disabled = true; buildBtn.textContent = 'Building...'; }
    // Clear tree but preserve the SVG element (it lives inside the tree)
    tree.innerHTML = '<svg class="explorer-svg" id="explorer-svg"></svg>';
    _explorer._zoom = 1;
    tree.style.transform = '';

    try {
        const response = await fetch('/api/playlist-explorer/build-tree', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ playlist_id: parseInt(playlistId), mode: _explorer.mode })
        });

        if (!response.ok) {
            const err = await response.json();
            throw new Error(err.error || 'Failed to build tree');
        }

        // Stream NDJSON
        const reader = response.body.getReader();
        const decoder = new TextDecoder();
        let buffer = '';
        let artistCount = 0;
        let totalArtists = 0;

        while (true) {
            const { done, value } = await reader.read();
            if (done) break;
            buffer += decoder.decode(value, { stream: true });
            const lines = buffer.split('\n');
            buffer = lines.pop();

            for (const line of lines) {
                if (!line.trim()) continue;
                try {
                    const data = JSON.parse(line);

                    if (data.type === 'meta') {
                        _explorer.meta = data;
                        totalArtists = data.total_artists;
                        _explorerRenderRoot(data);
                    } else if (data.type === 'artist') {
                        artistCount++;
                        _explorer.artists.push(data);
                        _explorerRenderArtistNode(data, artistCount);

                        // Lines drawn after streaming completes (not during — flex reflow drifts positions)

                        // Update progress
                        const pct = Math.round((artistCount / totalArtists) * 100);
                        const fill = document.getElementById('explorer-progress-fill');
                        const text = document.getElementById('explorer-progress-text');
                        if (fill) fill.style.width = pct + '%';
                        if (text) text.textContent = `Discovering artists... ${artistCount} of ${totalArtists}`;
                    } else if (data.type === 'complete') {
                        // Done
                    }
                } catch (e) {
                    console.warn('Explorer: failed to parse NDJSON line', e);
                }
            }
        }

        // Tree built — show action bar, hide progress
        if (actionBar) actionBar.style.display = 'flex';
        if (progress) progress.style.display = 'none';
        _explorerUpdateCount();

        // Mark playlist as explored (persists in session for badge display)
        const exploredPl = _explorer._playlists.find(p => p.id === playlistId);
        if (exploredPl) {
            exploredPl.explored = true;
            // Update card badge without full re-render
            const card = document.querySelector(`.explorer-picker-card[data-id="${playlistId}"]`);
            if (card) {
                card.classList.add('explored');
                const oldBadge = card.querySelector('.explorer-picker-card-badge');
                const badgeHTML = '<div class="explorer-picker-card-badge explored" title="Already explored">&#10003;</div>';
                if (oldBadge) {
                    oldBadge.outerHTML = badgeHTML;
                } else {
                    // Insert badge into the name row
                    const nameRow = card.querySelector('.explorer-picker-card-name-row');
                    if (nameRow) {
                        nameRow.insertAdjacentHTML('beforeend', badgeHTML);
                    }
                }
                // Remove discover button if present (no longer needed)
                const discoverBtn = card.querySelector('.explorer-picker-card-actions');
                if (discoverBtn) discoverBtn.remove();
            }
        }

        // Draw all connections now that the tree is stable
        setTimeout(() => _explorerRedrawAllConnections(true), 100);

    } catch (err) {
        showToast('Explorer: ' + err.message, 'error');
        if (empty) { empty.style.display = 'flex'; }
        if (progress) progress.style.display = 'none';
    } finally {
        _explorer.building = false;
        if (buildBtn) { buildBtn.disabled = false; buildBtn.textContent = 'Explore'; }
    }
}

function _explorerRenderRoot(meta) {
    const tree = document.getElementById('explorer-tree');
    const rootHtml = `
        <div class="explorer-tier explorer-tier-root">
            <div class="explorer-node explorer-node-root" id="explorer-root">
                <div class="explorer-node-glow"></div>
                ${meta.playlist_image
                    ? `<img class="explorer-node-img" src="${meta.playlist_image}" alt="">`
                    : '<div class="explorer-node-img-placeholder">&#9835;</div>'
                }
                <div class="explorer-node-label">
                    <div class="explorer-node-label-sub">SOURCE</div>
                    <div class="explorer-node-label-main">${meta.playlist_name}</div>
                    <div class="explorer-node-label-meta">${meta.total_tracks} tracks &middot; ${meta.total_artists} artists</div>
                </div>
            </div>
        </div>
        <div class="explorer-artist-tiers" id="explorer-artist-tiers"></div>
    `;
    tree.insertAdjacentHTML('afterbegin', rootHtml);
    _explorer._artistRowSizes = []; // Track row capacities: [2, 3, 4, ...]
    _explorer._artistCount = 0;
    _explorer._currentRowIndex = 0;
}

function _explorerGetOrCreateRow() {
    const container = document.getElementById('explorer-artist-tiers');
    if (!container) return null;

    // Determine row sizes: 2, 3, 4, 5... (tree shape)
    const rowCapacity = _explorer._currentRowIndex + 2;
    const existingRows = container.querySelectorAll('.explorer-tier-artists');
    let currentRow = existingRows[existingRows.length - 1];

    if (!currentRow || currentRow.children.length >= (_explorer._currentRowIndex + 2)) {
        // Need a new row
        _explorer._currentRowIndex = existingRows.length;
        const newRow = document.createElement('div');
        newRow.className = 'explorer-tier explorer-tier-artists';
        container.appendChild(newRow);
        return newRow;
    }
    return currentRow;
}

function _explorerRenderArtistNode(artist, index) {
    const row = _explorerGetOrCreateRow();
    if (!row) return;

    _explorer._artistCount++;
    const albumCount = artist.albums ? artist.albums.length : 0;
    const safeKey = (artist.name || '').replace(/[^a-zA-Z0-9]/g, '_');
    const hasError = !!artist.error;

    const html = `
        <div class="explorer-branch" id="explorer-branch-${safeKey}" style="--enter-delay: ${(index % 5) * 0.1}s">
            <div class="explorer-node explorer-node-artist ${hasError ? 'error' : ''}"
                 id="explorer-node-${safeKey}" data-key="${safeKey}"
                 onclick="${hasError || albumCount === 0 ? '' : `explorerToggleArtist('${safeKey}')`}">
                ${artist.image_url
                    ? `<img class="explorer-node-img" src="${artist.image_url}" alt="" loading="lazy">`
                    : ''
                }
                <div class="explorer-node-label">
                    <div class="explorer-node-label-main">${artist.name || 'Unknown'}</div>
                    <div class="explorer-node-label-meta">${hasError ? 'Not found' : albumCount + ' album' + (albumCount !== 1 ? 's' : '')}</div>
                </div>
                ${!hasError && albumCount > 0 ? '<div class="explorer-node-expand-hint">&#9662;</div>' : ''}
                ${hasError ? '<div class="explorer-node-error-ring"></div>' : ''}
            </div>
            <div class="explorer-children" id="explorer-children-${safeKey}"></div>
        </div>
    `;
    row.insertAdjacentHTML('beforeend', html);
}

function explorerToggleArtist(key) {
    const children = document.getElementById(`explorer-children-${key}`);
    const node = document.getElementById(`explorer-node-${key}`);
    if (!children || !node) return;

    const isExpanded = _explorer.expandedArtists.has(key);
    if (isExpanded) {
        _explorer.expandedArtists.delete(key);
        children.innerHTML = '';
        node.classList.remove('expanded');
    } else {
        _explorer.expandedArtists.add(key);
        node.classList.add('expanded');

        const artist = _explorer.artists.find(a => (a.name || '').replace(/[^a-zA-Z0-9]/g, '_') === key);
        if (artist && artist.albums) {
            const albumsHtml = artist.albums.map((album, i) => {
                const id = album.spotify_id || `${key}_${i}`;
                const selected = _explorer.selectedAlbums.has(id);
                const owned = album.owned;
                const inPlaylist = album.in_playlist;

                const typeLabel = album.album_type === 'single' ? 'Single' : album.album_type === 'ep' ? 'EP' : 'Album';
                return `
                    <div class="explorer-branch" style="--enter-delay: ${i * 0.06}s">
                        <div class="explorer-node explorer-node-album ${selected ? 'selected' : ''} ${owned ? 'owned' : ''} ${inPlaylist ? 'in-playlist' : ''}"
                             data-id="${id}" data-key="${id}"
                             onclick="explorerToggleAlbum('${id}'); event.stopPropagation();"
                             title="${(album.title || '').replace(/"/g, '&quot;')}\n${album.year || ''} · ${typeLabel} · ${album.track_count || '?'} tracks${owned ? '\n✓ Already in library' : ''}${inPlaylist ? '\n♫ Track from this playlist' : ''}\nClick to select · Double-click for tracklist">
                            ${album.image_url
                                ? `<img class="explorer-node-img" src="${album.image_url}" alt="" loading="lazy">`
                                : ''
                            }
                            <div class="explorer-node-label">
                                <div class="explorer-node-label-main">${album.title || 'Unknown'}</div>
                                <div class="explorer-node-label-meta">${album.year || ''} &middot; ${album.track_count || '?'} tracks</div>
                            </div>
                            <div class="explorer-node-select ${selected ? 'active' : ''}">
                                <svg viewBox="0 0 20 20"><polyline points="4 10 8 14 16 6" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg>
                            </div>
                            ${owned ? '<div class="explorer-node-badge-float owned">Owned</div>' : ''}
                            ${inPlaylist ? '<div class="explorer-node-badge-float playlist">♫</div>' : ''}
                        </div>
                        <div class="explorer-children" id="explorer-tracks-${id}"></div>
                    </div>
                `;
            }).join('');
            children.innerHTML = albumsHtml;
        }
    }

    // Redraw SVG after DOM settles
    requestAnimationFrame(() => setTimeout(() => _explorerRedrawAllConnections(), 50));
}

async function explorerExpandAlbumTracks(spotifyAlbumId, nodeKey) {
    if (!spotifyAlbumId) return;
    const tracksContainer = document.getElementById(`explorer-tracks-${nodeKey}`);
    if (!tracksContainer) return;

    // Toggle: if already has content, collapse
    if (tracksContainer.innerHTML) {
        tracksContainer.innerHTML = '';
        requestAnimationFrame(() => setTimeout(() => _explorerRedrawAllConnections(), 50));
        return;
    }

    try {
        const response = await fetch(`/api/playlist-explorer/album-tracks/${spotifyAlbumId}`);
        const data = await response.json();
        if (!data.success || !data.tracks) return;

        const tracksHtml = data.tracks.map((t, i) => `
            <div class="explorer-branch" style="--enter-delay: ${i * 0.03}s">
                <div class="explorer-node explorer-node-track">
                    <div class="explorer-node-label">
                        <div class="explorer-node-label-main">${t.track_number}. ${t.name}</div>
                        <div class="explorer-node-label-meta">${_formatDuration(t.duration_ms)}</div>
                    </div>
                </div>
            </div>
        `).join('');
        tracksContainer.innerHTML = tracksHtml;
        requestAnimationFrame(() => setTimeout(() => _explorerRedrawAllConnections(), 50));
    } catch (e) {
        console.error('Failed to load album tracks:', e);
    }
}

function _formatDuration(ms) {
    if (!ms) return '';
    const m = Math.floor(ms / 60000);
    const s = Math.floor((ms % 60000) / 1000);
    return `${m}:${s.toString().padStart(2, '0')}`;
}

// Track double-click vs single-click on album nodes
let _explorerClickTimer = null;
let _explorerLastClickId = null;

function explorerToggleAlbum(id) {
    // Double-click detection: expand tracks
    if (_explorerLastClickId === id && _explorerClickTimer) {
        clearTimeout(_explorerClickTimer);
        _explorerClickTimer = null;
        _explorerLastClickId = null;
        // Double-click — expand tracks
        const node = document.querySelector(`.explorer-node-album[data-id="${id}"]`);
        const spotifyId = id.includes('_') ? '' : id; // Only real IDs, not fallback keys
        explorerExpandAlbumTracks(spotifyId, id);
        return;
    }

    _explorerLastClickId = id;
    _explorerClickTimer = setTimeout(() => {
        _explorerClickTimer = null;
        _explorerLastClickId = null;

        // Single click — toggle selection
        if (_explorer.selectedAlbums.has(id)) {
            _explorer.selectedAlbums.delete(id);
        } else {
            _explorer.selectedAlbums.add(id);
        }

        const node = document.querySelector(`.explorer-node-album[data-id="${id}"]`);
        if (node) {
            const isSelected = _explorer.selectedAlbums.has(id);
            node.classList.toggle('selected', isSelected);
            const check = node.querySelector('.explorer-node-select');
            if (check) check.classList.toggle('active', isSelected);
        }

        _explorerUpdateCount();
    }, 250);

    _explorerUpdateCount();
}

function explorerSelectAll() {
    _explorer.artists.forEach(a => {
        (a.albums || []).forEach(album => {
            if (album.spotify_id && !album.owned) _explorer.selectedAlbums.add(album.spotify_id);
        });
    });
    _explorerRefreshAllCards();
    _explorerUpdateCount();
}

function explorerDeselectAll() {
    _explorer.selectedAlbums.clear();
    _explorerRefreshAllCards();
    _explorerUpdateCount();
}

function _explorerRefreshAllCards() {
    document.querySelectorAll('.explorer-node-album').forEach(node => {
        const id = node.dataset.id;
        const selected = _explorer.selectedAlbums.has(id);
        node.classList.toggle('selected', selected);
        const check = node.querySelector('.explorer-node-select');
        if (check) check.classList.toggle('active', selected);
    });
}

function _explorerUpdateCount() {
    const el = document.getElementById('explorer-selection-count');
    const count = _explorer.selectedAlbums.size;
    if (el) el.textContent = `${count} album${count !== 1 ? 's' : ''} selected`;
    _explorerRefreshArtistIndicators();
}

function _explorerRefreshArtistIndicators() {
    // For each artist, check if any of their albums are selected — add visual indicator
    _explorer.artists.forEach(artist => {
        const key = (artist.name || '').replace(/[^a-zA-Z0-9]/g, '_');
        const node = document.getElementById(`explorer-node-${key}`);
        if (!node) return;
        const hasSelected = (artist.albums || []).some(a => a.spotify_id && _explorer.selectedAlbums.has(a.spotify_id));
        node.classList.toggle('has-selection', hasSelected);
    });
}

function explorerAddToWishlist() {
    if (_explorer.selectedAlbums.size === 0) {
        showToast('No albums selected', 'error');
        return;
    }

    // Group selected albums by artist with full metadata
    const artistSections = [];
    for (const artist of _explorer.artists) {
        const artistId = artist.artist_id || artist.spotify_id;
        if (!artist.albums) continue;
        const selected = artist.albums.filter(a => a.spotify_id && _explorer.selectedAlbums.has(a.spotify_id));
        if (selected.length === 0) continue;
        artistSections.push({ artistId, name: artist.name, image: artist.image_url, albums: selected });
    }

    if (artistSections.length === 0) { showToast('No valid albums selected', 'error'); return; }

    // Build confirmation modal (mirrors discog-modal pattern)
    const overlay = document.createElement('div');
    overlay.className = 'discog-modal-overlay';
    overlay.id = 'explorer-wishlist-overlay';

    const totalAlbums = artistSections.reduce((s, a) => s + a.albums.length, 0);
    const totalTracks = artistSections.reduce((s, a) => s + a.albums.reduce((t, al) => t + (al.track_count || 0), 0), 0);

    let cardsHtml = '';
    artistSections.forEach(section => {
        cardsHtml += `<div class="discog-section-header">${_esc(section.name)}</div>`;
        section.albums.forEach((album, i) => {
            const year = album.year || '';
            const typeLabel = album.album_type === 'single' ? 'Single' : album.album_type === 'ep' ? 'EP' : 'Album';
            cardsHtml += `
                <label class="discog-card ${album.owned ? 'owned' : ''}" data-type="${album.album_type || 'album'}" data-artist-id="${section.artistId}" style="animation-delay:${i * 0.03}s">
                    <input type="checkbox" class="discog-card-cb" data-album-id="${album.spotify_id}" data-tracks="${album.track_count || 0}" ${!album.owned ? 'checked' : ''} onchange="_explorerWishlistUpdateCount()">
                    <div class="discog-card-art">
                        ${album.image_url ? `<img src="${album.image_url}" alt="" loading="lazy">` : '<div class="discog-card-art-placeholder">&#9835;</div>'}
                        ${album.owned ? '<span class="discog-card-status">&#10003;</span>' : ''}
                    </div>
                    <div class="discog-card-info">
                        <div class="discog-card-title">${_esc(album.title || 'Unknown')}</div>
                        <div class="discog-card-meta">${year}${year ? ' · ' : ''}${typeLabel} · ${album.track_count || '?'} tracks</div>
                    </div>
                    <div class="discog-card-check"></div>
                </label>
            `;
        });
    });

    overlay.innerHTML = `
        <div class="discog-modal">
            <div class="discog-modal-hero" style="background-image:url('${artistSections[0]?.image || ''}')">
                <div class="discog-modal-hero-overlay"></div>
                <div class="discog-modal-hero-content">
                    <h2 class="discog-modal-title">Add to Wishlist</h2>
                    <p class="discog-modal-artist">${artistSections.length} artist${artistSections.length !== 1 ? 's' : ''} · ${totalAlbums} releases</p>
                </div>
                <button class="discog-modal-close" onclick="document.getElementById('explorer-wishlist-overlay')?.remove()">&times;</button>
            </div>
            <div class="discog-filter-bar">
                <div class="discog-filters">
                    <button class="discog-filter active" data-type="album" onclick="_explorerWishlistToggleFilter(this)">Albums</button>
                    <button class="discog-filter active" data-type="ep" onclick="_explorerWishlistToggleFilter(this)">EPs</button>
                    <button class="discog-filter active" data-type="single" onclick="_explorerWishlistToggleFilter(this)">Singles</button>
                </div>
                <div class="discog-select-actions">
                    <button class="discog-select-btn" onclick="document.querySelectorAll('#explorer-wishlist-overlay .discog-card-cb').forEach(c=>{c.checked=true}); _explorerWishlistUpdateCount()">Select All</button>
                    <button class="discog-select-btn" onclick="document.querySelectorAll('#explorer-wishlist-overlay .discog-card-cb').forEach(c=>{c.checked=false}); _explorerWishlistUpdateCount()">Deselect</button>
                </div>
            </div>
            <div class="discog-grid" id="explorer-wishlist-grid">${cardsHtml}</div>
            <div class="discog-progress" id="explorer-wishlist-progress" style="display:none;"></div>
            <div class="discog-footer" id="explorer-wishlist-footer">
                <div class="discog-footer-info" id="explorer-wishlist-info"></div>
                <div class="discog-footer-actions">
                    <button class="discog-cancel-btn" onclick="document.getElementById('explorer-wishlist-overlay')?.remove()">Cancel</button>
                    <button class="discog-submit-btn" id="explorer-wishlist-submit">
                        <span class="discog-submit-icon">&#11015;</span>
                        <span id="explorer-wishlist-submit-text">Add to Wishlist</span>
                    </button>
                </div>
            </div>
        </div>
    `;

    document.body.appendChild(overlay);
    requestAnimationFrame(() => overlay.classList.add('visible'));
    _explorerWishlistUpdateCount();

    document.getElementById('explorer-wishlist-submit')?.addEventListener('click', () => _explorerWishlistSubmit(artistSections));
}

function _explorerWishlistToggleFilter(btn) {
    btn.classList.toggle('active');
    const type = btn.dataset.type;
    // Scoped to explorer wishlist modal only
    document.querySelectorAll(`#explorer-wishlist-overlay .discog-card[data-type="${type}"]`).forEach(card => {
        card.style.display = btn.classList.contains('active') ? '' : 'none';
    });
    _explorerWishlistUpdateCount();
}

function _explorerWishlistUpdateCount() {
    const checked = document.querySelectorAll('#explorer-wishlist-overlay .discog-card-cb:checked');
    let releases = 0, tracks = 0;
    checked.forEach(cb => {
        if (cb.closest('.discog-card').style.display !== 'none') {
            releases++;
            tracks += parseInt(cb.dataset.tracks) || 0;
        }
    });
    const info = document.getElementById('explorer-wishlist-info');
    const btn = document.getElementById('explorer-wishlist-submit-text');
    if (info) info.textContent = `${releases} release${releases !== 1 ? 's' : ''} · ${tracks} tracks`;
    if (btn) btn.textContent = releases > 0 ? `Add ${releases} to Wishlist` : 'Select releases';
    const submitBtn = document.getElementById('explorer-wishlist-submit');
    if (submitBtn) submitBtn.disabled = releases === 0;
}

async function _explorerWishlistSubmit(artistSections) {
    const grid = document.getElementById('explorer-wishlist-grid');
    const progress = document.getElementById('explorer-wishlist-progress');
    const filterBar = document.querySelector('#explorer-wishlist-overlay .discog-filter-bar');
    const submitBtn = document.getElementById('explorer-wishlist-submit');

    // Collect checked albums grouped by artist
    const byArtist = {};
    document.querySelectorAll('#explorer-wishlist-overlay .discog-card-cb:checked').forEach(cb => {
        if (cb.closest('.discog-card').style.display === 'none') return;
        const card = cb.closest('.discog-card');
        const artistId = card.dataset.artistId;
        const albumId = cb.dataset.albumId;
        const title = card.querySelector('.discog-card-title')?.textContent || '';
        const img = card.querySelector('.discog-card-art img')?.src || '';
        if (!byArtist[artistId]) byArtist[artistId] = { albums: [], name: '' };
        byArtist[artistId].albums.push({ id: albumId, title, img, tracks: parseInt(cb.dataset.tracks) || 0 });
    });

    // Fill in artist names
    artistSections.forEach(s => { if (byArtist[s.artistId]) byArtist[s.artistId].name = s.name; });

    // Switch to progress view
    if (grid) grid.style.display = 'none';
    if (filterBar) filterBar.style.display = 'none';
    if (submitBtn) submitBtn.style.display = 'none';
    if (progress) {
        progress.style.display = '';
        progress.innerHTML = '';
        for (const [artistId, data] of Object.entries(byArtist)) {
            data.albums.forEach(album => {
                const item = document.createElement('div');
                item.className = 'discog-progress-item active';
                item.id = `explorer-prog-${album.id}`;
                item.innerHTML = `
                    <div class="discog-prog-art">${album.img ? `<img src="${album.img}">` : '&#9835;'}</div>
                    <div class="discog-prog-info">
                        <div class="discog-prog-title">${_esc(album.title)}</div>
                        <div class="discog-prog-status">Waiting...</div>
                    </div>
                    <div class="discog-prog-icon"><div class="discog-spinner"></div></div>
                `;
                progress.appendChild(item);
            });
        }
    }

    const info = document.getElementById('explorer-wishlist-info');
    if (info) info.textContent = 'Processing...';

    let totalAdded = 0;

    for (const [artistId, data] of Object.entries(byArtist)) {
        // Sort by track count descending (deluxe editions first) BEFORE extracting IDs
        data.albums.sort((a, b) => b.tracks - a.tracks);
        const albumIds = data.albums.map(a => a.id);

        try {
            const response = await fetch(`/api/artist/${artistId}/download-discography`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ album_ids: albumIds, artist_name: data.name })
            });

            const reader = response.body.getReader();
            const decoder = new TextDecoder();
            let buffer = '';
            while (true) {
                const { done, value } = await reader.read();
                if (done) break;
                buffer += decoder.decode(value, { stream: true });
                const lines = buffer.split('\n');
                buffer = lines.pop();
                for (const line of lines) {
                    if (!line.trim()) continue;
                    try {
                        const result = JSON.parse(line);
                        if (result.status === 'complete') continue; // Summary line, skip
                        const item = document.getElementById(`explorer-prog-${result.album_id}`);
                        if (item) {
                            const statusEl = item.querySelector('.discog-prog-status');
                            const iconEl = item.querySelector('.discog-prog-icon');
                            if (result.status === 'done') {
                                const added = result.tracks_added || 0;
                                const skipped = result.tracks_skipped || 0;
                                totalAdded += added;
                                if (statusEl) statusEl.textContent = `Added ${added} track${added !== 1 ? 's' : ''}${skipped > 0 ? `, ${skipped} skipped` : ''}`;
                                if (iconEl) iconEl.innerHTML = '<span style="color:#4CAF50">&#10003;</span>';
                                item.classList.remove('active');
                                item.classList.add('done');
                            } else if (result.status === 'error') {
                                if (statusEl) statusEl.textContent = result.message || 'Error';
                                if (iconEl) iconEl.innerHTML = '<span style="color:#ff4757">&#10007;</span>';
                                item.classList.remove('active');
                                item.classList.add('error');
                            }
                        }
                    } catch (e) {}
                }
            }
        } catch (e) {
            console.error(`Explorer wishlist: failed for ${data.name}:`, e);
        }
    }

    if (info) info.textContent = `Done — ${totalAdded} tracks added to wishlist`;
    // Change cancel button label to "Close"
    const cancelBtn = document.querySelector('#explorer-wishlist-overlay .discog-cancel-btn');
    if (cancelBtn) cancelBtn.textContent = 'Close';
    showToast(`Added ${totalAdded} tracks to wishlist`, 'success');

    // Mark albums as added on the tree
    _explorer.selectedAlbums.forEach(id => {
        const node = document.querySelector(`.explorer-node-album[data-id="${id}"]`);
        if (node) { node.classList.add('added'); node.classList.remove('selected'); }
    });
    _explorer.selectedAlbums.clear();
    _explorerUpdateCount();
    _explorerRefreshArtistIndicators();
}

function _explorerEnsureDefs() {
    const svg = document.getElementById('explorer-svg');
    if (!svg || svg.querySelector('defs')) return;
    // Read accent color from CSS custom property
    const accentRgb = getComputedStyle(document.documentElement).getPropertyValue('--accent-rgb').trim() || '100,200,255';
    const defs = document.createElementNS('http://www.w3.org/2000/svg', 'defs');
    defs.innerHTML = `
        <linearGradient id="explorer-grad-root" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stop-color="rgba(${accentRgb}, 0.25)"/>
            <stop offset="100%" stop-color="rgba(${accentRgb}, 0.06)"/>
        </linearGradient>
        <linearGradient id="explorer-grad-album" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stop-color="rgba(${accentRgb}, 0.15)"/>
            <stop offset="100%" stop-color="rgba(${accentRgb}, 0.04)"/>
        </linearGradient>
    `;
    svg.appendChild(defs);
}

function _explorerDrawConnectionToArtist(artistIndex) {
    // Incremental: draw ONLY this artist's connection. Don't clear existing.
    // Flex reflow within the current row may shift siblings, but the visual drift
    // is minor and gets corrected by the final redraw after streaming completes.
    const svg = document.getElementById('explorer-svg');
    const root = document.getElementById('explorer-root');
    if (!svg || !root) return;

    _explorerEnsureDefs();
    _explorerSizeSvg();

    const artistNodes = document.querySelectorAll('.explorer-node-artist');
    const artistNode = artistNodes[artistIndex];
    if (!artistNode) return;

    const rc = _explorerGetPos(root);
    const ac = _explorerGetPos(artistNode);
    _explorerDrawCurve(svg, rc.cx, rc.bottom, ac.cx, ac.top, 'root', true);
}

function _explorerRedrawAllConnections(animate = false) {
    const svg = document.getElementById('explorer-svg');
    const root = document.getElementById('explorer-root');
    if (!svg || !root) return;

    _explorerEnsureDefs();
    _explorerSizeSvg();

    // Clear existing lines but keep defs
    svg.querySelectorAll('path').forEach(p => p.remove());

    const rc = _explorerGetPos(root);

    document.querySelectorAll('.explorer-node-artist').forEach(artistNode => {
        const ac = _explorerGetPos(artistNode);
        _explorerDrawCurve(svg, rc.cx, rc.bottom, ac.cx, ac.top, 'root', animate);

        if (artistNode.classList.contains('expanded')) {
            const branch = artistNode.closest('.explorer-branch');
            if (!branch) return;
            branch.querySelectorAll(':scope > .explorer-children > .explorer-branch > .explorer-node-album').forEach(albumNode => {
                const alc = _explorerGetPos(albumNode);
                _explorerDrawCurve(svg, ac.cx, ac.bottom, alc.cx, alc.top, 'album', animate);

                const albumBranch = albumNode.closest('.explorer-branch');
                if (albumBranch) {
                    albumBranch.querySelectorAll(':scope > .explorer-children > .explorer-branch > .explorer-node-track').forEach(trackNode => {
                        const tc = _explorerGetPos(trackNode);
                        _explorerDrawCurve(svg, alc.cx, alc.bottom, tc.cx, tc.top, 'track', animate);
                    });
                }
            });
        }
    });
}

function _explorerSizeSvg() {
    const svg = document.getElementById('explorer-svg');
    const tree = document.getElementById('explorer-tree');
    if (!svg || !tree) return;
    // SVG is inside the tree. Use scrollWidth/scrollHeight which are unscaled.
    // Add padding to ensure lines near edges aren't clipped.
    const w = Math.max(tree.scrollWidth, tree.offsetWidth) + 40;
    const h = Math.max(tree.scrollHeight, tree.offsetHeight) + 40;
    svg.setAttribute('width', w);
    svg.setAttribute('height', h);
    svg.setAttribute('viewBox', `0 0 ${w} ${h}`);
}

function _explorerGetPos(el) {
    // SVG is inside the tree — positions are relative to tree, unscaled
    const tree = document.getElementById('explorer-tree');
    if (!tree) return { cx: 0, top: 0, bottom: 0 };
    const tRect = tree.getBoundingClientRect();
    const r = el.getBoundingClientRect();
    const scale = _explorer._zoom || 1;
    // getBoundingClientRect returns scaled coords; divide by scale to get unscaled tree-space coords
    return {
        cx: (r.left + r.width / 2 - tRect.left) / scale,
        top: (r.top - tRect.top) / scale,
        bottom: (r.bottom - tRect.top) / scale,
    };
}

function _explorerDrawCurve(svg, x1, y1, x2, y2, type, animate) {
    const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
    const midY = y1 + (y2 - y1) * 0.45;
    path.setAttribute('d', `M ${x1} ${y1} C ${x1} ${midY}, ${x2} ${midY}, ${x2} ${y2}`);

    if (type === 'root') {
        path.setAttribute('stroke', 'url(#explorer-grad-root)');
        path.setAttribute('stroke-width', '1.5');
    } else if (type === 'album') {
        path.setAttribute('stroke', 'url(#explorer-grad-album)');
        path.setAttribute('stroke-width', '1');
    } else {
        path.setAttribute('stroke', 'rgba(255,255,255,0.05)');
        path.setAttribute('stroke-width', '0.8');
    }
    path.setAttribute('fill', 'none');

    svg.appendChild(path);

    if (animate) {
        const len = path.getTotalLength();
        path.setAttribute('class', 'explorer-line explorer-line-animated');
        path.style.strokeDasharray = len;
        path.style.strokeDashoffset = len;
    } else {
        path.setAttribute('class', 'explorer-line');
    }
}

// ── Zoom & Pan ──
_explorer._zoom = 1;
_explorer._panX = 0;
_explorer._panY = 0;
_explorer._isPanning = false;
_explorer._panStartX = 0;
_explorer._panStartY = 0;
_explorer._panStartScrollX = 0;
_explorer._panStartScrollY = 0;

function _explorerApplyTransform() {
    const tree = document.getElementById('explorer-tree');
    if (tree) {
        tree.style.transform = `scale(${_explorer._zoom})`;
        tree.style.transformOrigin = 'top center';
    }
    _explorerSizeSvg();
    requestAnimationFrame(() => _explorerRedrawAllConnections());
}

function explorerZoom(delta) {
    _explorer._zoom = Math.max(0.2, Math.min(3, _explorer._zoom + delta));
    _explorerApplyTransform();
}

function explorerFitToView() {
    const viewport = document.getElementById('explorer-viewport');
    const tree = document.getElementById('explorer-tree');
    if (!viewport || !tree) return;

    // Reset zoom to measure natural size
    _explorer._zoom = 1;
    tree.style.transform = 'scale(1)';

    requestAnimationFrame(() => {
        const treeW = tree.scrollWidth;
        const treeH = tree.scrollHeight;
        const vpW = viewport.clientWidth - 40;
        const vpH = viewport.clientHeight - 40;

        if (treeW > 0 && treeH > 0) {
            _explorer._zoom = Math.min(vpW / treeW, vpH / treeH, 1.5);
            _explorer._zoom = Math.max(0.2, Math.min(3, _explorer._zoom));
        }

        _explorerApplyTransform();
        viewport.scrollTop = 0;
        viewport.scrollLeft = Math.max(0, (tree.scrollWidth * _explorer._zoom - vpW) / 2);
    });
}

// Scroll wheel zoom (no modifier needed inside viewport)
document.addEventListener('wheel', (e) => {
    const viewport = document.getElementById('explorer-viewport');
    if (!viewport || !viewport.contains(e.target)) return;
    // Check if we're on the explorer page
    const page = document.getElementById('playlist-explorer-page');
    if (!page || !page.classList.contains('active')) return;

    e.preventDefault();
    const step = e.deltaY > 0 ? -0.08 : 0.08;
    explorerZoom(step);
}, { passive: false });

// Middle-click / right-click drag to pan
document.addEventListener('mousedown', (e) => {
    const viewport = document.getElementById('explorer-viewport');
    if (!viewport || !viewport.contains(e.target)) return;
    // Middle click (button 1) or right click (button 2)
    if (e.button !== 1 && e.button !== 2) return;

    e.preventDefault();
    _explorer._isPanning = true;
    _explorer._panStartX = e.clientX;
    _explorer._panStartY = e.clientY;
    _explorer._panStartScrollX = viewport.scrollLeft;
    _explorer._panStartScrollY = viewport.scrollTop;
    viewport.style.cursor = 'grabbing';
});

document.addEventListener('mousemove', (e) => {
    if (!_explorer._isPanning) return;
    const viewport = document.getElementById('explorer-viewport');
    if (!viewport) return;
    const dx = e.clientX - _explorer._panStartX;
    const dy = e.clientY - _explorer._panStartY;
    viewport.scrollLeft = _explorer._panStartScrollX - dx;
    viewport.scrollTop = _explorer._panStartScrollY - dy;
});

document.addEventListener('mouseup', (e) => {
    if (!_explorer._isPanning) return;
    _explorer._isPanning = false;
    const viewport = document.getElementById('explorer-viewport');
    if (viewport) viewport.style.cursor = '';
});

// Suppress context menu on right-click inside viewport (for panning)
document.addEventListener('contextmenu', (e) => {
    const viewport = document.getElementById('explorer-viewport');
    if (viewport && viewport.contains(e.target)) {
        e.preventDefault();
    }
});

// Debounced redraw on resize
window.addEventListener('resize', () => {
    if (_explorer.artists.length === 0) return;
    clearTimeout(_explorer._resizeTimer);
    _explorer._resizeTimer = setTimeout(() => _explorerRedrawAllConnections(), 150);
});


// ==================================================================================
// DASHBOARD — Recent Syncs Section
// ==================================================================================

// ==================================================================================
// SERVER PLAYLIST MANAGER — Sync Page Server Tab
// ==================================================================================

let _serverPlaylists = [];
let _serverEditorState = { playlistId: null, playlistName: '', tracks: [] };

async function loadServerPlaylists() {
    const container = document.getElementById('server-playlist-container');
    const editor = document.getElementById('server-editor');
    const btn = document.getElementById('server-refresh-btn');

    if (editor) editor.style.display = 'none';
    if (container) container.style.display = '';
    if (btn) { btn.disabled = true; btn.textContent = '🔄 Loading...'; }

    // Show skeleton loader
    if (container) {
        container.innerHTML = `<div class="server-pl-grid">${Array.from({length: 6}, (_, i) => `
            <div class="server-pl-card server-pl-skeleton" style="animation-delay: ${i * 0.06}s">
                <div class="server-pl-card-top">
                    <div class="skeleton-box" style="width:44px;height:44px;border-radius:12px"></div>
                    <div class="skeleton-box" style="width:28px;height:28px;border-radius:8px"></div>
                </div>
                <div class="server-pl-card-body">
                    <div class="skeleton-box" style="width:${60 + Math.random()*30}%;height:14px;border-radius:4px;margin-bottom:8px"></div>
                    <div class="skeleton-box" style="width:40%;height:11px;border-radius:4px"></div>
                </div>
                <div class="server-pl-card-footer" style="border-top:1px solid rgba(255,255,255,0.05);padding-top:12px">
                    <div class="skeleton-box" style="width:60px;height:10px;border-radius:3px"></div>
                </div>
            </div>`).join('')}</div>`;
    }

    try {
        // Fetch server playlists and mirrored playlists in parallel
        const [serverRes, mirroredRes] = await Promise.all([
            fetch('/api/server/playlists'),
            fetch('/api/mirrored-playlists'),
        ]);
        const data = await serverRes.json();
        let mirroredAll = [];
        try { mirroredAll = await mirroredRes.json(); } catch (_) {}
        if (!Array.isArray(mirroredAll)) mirroredAll = [];

        if (!data.success || !data.playlists) {
            if (container) container.innerHTML = `<div class="playlist-placeholder">${data.error || 'Could not load server playlists'}</div>`;
            return;
        }

        // Only show server playlists that have a matching mirrored playlist
        const mirroredNames = new Set(mirroredAll.map(p => p.name.trim().toLowerCase()));
        const filtered = data.playlists.filter(pl => mirroredNames.has(pl.name.trim().toLowerCase()));

        _serverPlaylists = filtered;
        const title = document.getElementById('server-tab-title');
        if (title) title.textContent = `Server Playlists (${data.server_type ? data.server_type.charAt(0).toUpperCase() + data.server_type.slice(1) : ''})`;

        if (filtered.length === 0) {
            if (container) container.innerHTML = '<div class="playlist-placeholder">No synced playlists found. Only server playlists that match your mirrored playlists are shown here.</div>';
            return;
        }

        // Server type icon SVG
        const serverIcons = {
            plex: '<svg viewBox="0 0 24 24" width="18" height="18" fill="currentColor"><path d="M11.643 0H4.68l7.679 12L4.68 24h6.963L19.32 12z"/></svg>',
            jellyfin: '<svg viewBox="0 0 24 24" width="18" height="18" fill="currentColor"><path d="M12 2C8.5 2 6 5.1 6 9c0 2.4 1.2 5.5 3.3 8.7.7 1 1.5 2 2.2 2.9.2.3.4.3.5.4.1 0 .3-.1.5-.4.7-.9 1.5-1.9 2.2-2.9C16.8 14.5 18 11.4 18 9c0-3.9-2.5-7-6-7z"/></svg>',
            navidrome: '<svg viewBox="0 0 24 24" width="18" height="18" fill="currentColor"><path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"/></svg>'
        };
        const sIcon = serverIcons[data.server_type] || serverIcons.plex;

        container.innerHTML = `<div class="server-pl-grid">${filtered.map((pl, i) => {
            const hue = (i * 37 + 200) % 360;
            const safeName = _esc(pl.name).replace(/'/g, "\\'");
            return `
            <div class="server-pl-card" onclick="openServerPlaylistEditor('${pl.id}', '${safeName}')" style="animation-delay: ${i * 0.04}s; --card-hue: ${hue}">
                <div class="server-pl-card-glow"></div>
                <div class="server-pl-card-top">
                    <div class="server-pl-card-icon-wrap">
                        <div class="server-pl-card-bars">
                            <span></span><span></span><span></span><span></span>
                        </div>
                    </div>
                    <div class="server-pl-card-badge">${sIcon}</div>
                </div>
                <div class="server-pl-card-body">
                    <div class="server-pl-card-name">${_esc(pl.name)}</div>
                    <div class="server-pl-card-meta">
                        <span class="server-pl-track-count">${pl.track_count}</span> tracks
                    </div>
                </div>
                <div class="server-pl-card-footer">
                    <span class="server-pl-card-action">Open Editor</span>
                    <span class="server-pl-card-arrow">
                        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M5 12h14M12 5l7 7-7 7"/></svg>
                    </span>
                </div>
            </div>`;
        }).join('')}</div>`;

    } catch (e) {
        if (container) container.innerHTML = `<div class="playlist-placeholder">Error: ${e.message}</div>`;
    } finally {
        if (btn) { btn.disabled = false; btn.textContent = '🔄 Refresh'; }
    }
}

async function openServerPlaylistEditor(playlistId, playlistName) {
    // Step 1: Look up mirrored playlists by name
    let mirroredPlaylists = [];
    try {
        const res = await fetch('/api/mirrored-playlists');
        const all = await res.json();
        mirroredPlaylists = (Array.isArray(all) ? all : []).filter(p =>
            p.name.trim().toLowerCase() === playlistName.trim().toLowerCase()
        );
    } catch (e) {
        console.error('Failed to fetch mirrored playlists:', e);
    }

    if (mirroredPlaylists.length === 1) {
        // Single match — go straight to compare
        _openServerCompareView(playlistId, playlistName, mirroredPlaylists[0]);
    } else if (mirroredPlaylists.length === 0) {
        // No match — server-only view
        _openServerCompareView(playlistId, playlistName, null);
    } else {
        // Multiple — disambiguation
        _showServerDisambig(playlistId, playlistName, mirroredPlaylists);
    }
}

// ── Disambiguation ──

function _showServerDisambig(playlistId, playlistName, candidates) {
    const overlay = document.getElementById('server-disambig-overlay');
    const list = document.getElementById('server-disambig-list');
    const subtitle = document.getElementById('server-disambig-subtitle');
    if (!overlay || !list) return;

    if (subtitle) subtitle.textContent = `"${playlistName}" was found on ${candidates.length} sources. Which one do you want to compare against?`;

    const sourceIcons = { spotify: '🟢', tidal: '🌊', youtube: '▶️', beatport: '🎛️', deezer: '🟣', file: '📄' };

    list.innerHTML = candidates.map((p, i) => {
        const icon = sourceIcons[p.source] || '📋';
        const ago = timeAgo(p.mirrored_at || p.updated_at);
        return `
        <div class="server-disambig-card" onclick="selectDisambigPlaylist('${playlistId}', '${_esc(playlistName).replace(/'/g, "\\'")}', ${p.id})" style="animation-delay: ${i * 0.06}s">
            <div class="server-disambig-icon">${icon}</div>
            <div class="server-disambig-info">
                <div class="server-disambig-name">${_esc(p.name)}</div>
                <div class="server-disambig-details">
                    <span class="source-badge">${_esc(p.source)}</span>
                    <span>${p.track_count || 0} tracks</span>
                    ${p.owner ? `<span>by ${_esc(p.owner)}</span>` : ''}
                    <span>Mirrored ${ago}</span>
                </div>
            </div>
            <div class="server-disambig-arrow">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M5 12h14M12 5l7 7-7 7"/></svg>
            </div>
        </div>`;
    }).join('');

    overlay.classList.remove('hidden');
    requestAnimationFrame(() => overlay.classList.add('visible'));

    // Escape key + click backdrop to close
    overlay.onclick = e => { if (e.target === overlay) closeServerDisambig(); };
    window._disambigEsc = e => { if (e.key === 'Escape') closeServerDisambig(); };
    document.addEventListener('keydown', window._disambigEsc);
}

function closeServerDisambig() {
    const overlay = document.getElementById('server-disambig-overlay');
    if (overlay) {
        overlay.classList.remove('visible');
        setTimeout(() => overlay.classList.add('hidden'), 250);
    }
    if (window._disambigEsc) { document.removeEventListener('keydown', window._disambigEsc); window._disambigEsc = null; }
}

async function selectDisambigPlaylist(playlistId, playlistName, mirroredId) {
    closeServerDisambig();
    try {
        const res = await fetch(`/api/mirrored-playlists/${mirroredId}`);
        const mirrored = await res.json();
        _openServerCompareView(playlistId, playlistName, mirrored);
    } catch (e) {
        showToast('Failed to load mirrored playlist: ' + e.message, 'error');
    }
}

// ── Compare View ──

async function _openServerCompareView(playlistId, playlistName, mirroredPlaylist) {
    const container = document.getElementById('server-playlist-container');
    const editor = document.getElementById('server-editor');
    if (!editor) return;

    if (container) container.style.display = 'none';
    editor.style.display = '';

    const nameEl = document.getElementById('server-editor-name');
    const metaEl = document.getElementById('server-editor-meta');
    const banner = document.getElementById('server-no-source-banner');
    const sourceScroll = document.getElementById('server-col-source-scroll');
    const serverScroll = document.getElementById('server-col-server-scroll');

    if (nameEl) nameEl.textContent = playlistName;
    if (metaEl) metaEl.textContent = 'Loading comparison...';
    if (banner) banner.style.display = 'none';
    if (sourceScroll) sourceScroll.innerHTML = '<div style="text-align:center;padding:30px;color:rgba(255,255,255,0.2);font-size:12px">Loading...</div>';
    if (serverScroll) serverScroll.innerHTML = '<div style="text-align:center;padding:30px;color:rgba(255,255,255,0.2);font-size:12px">Loading...</div>';

    // Store state
    _serverEditorState = {
        playlistId,
        playlistName,
        mirroredPlaylist,
        tracks: [],
    };

    // Build API URL
    let url = `/api/server/playlist/${playlistId}/tracks?name=${encodeURIComponent(playlistName)}`;
    if (mirroredPlaylist && mirroredPlaylist.id) {
        url += `&mirrored_playlist_id=${mirroredPlaylist.id}`;
    }

    try {
        const response = await fetch(url);
        const data = await response.json();
        if (!data.success) {
            if (metaEl) metaEl.textContent = data.error || 'Failed to load';
            return;
        }

        _serverEditorState.tracks = data.tracks || [];
        _serverEditorState.serverType = data.server_type;

        const tracks = _serverEditorState.tracks;
        const serverLabel = data.server_type ? data.server_type.charAt(0).toUpperCase() + data.server_type.slice(1) : 'Server';

        // Header metadata
        if (metaEl) metaEl.textContent = `${serverLabel} · ${data.server_track_count || 0} server tracks · ${data.source_track_count || 0} source tracks`;

        // Show no-source banner if needed
        if (!mirroredPlaylist && banner) {
            banner.style.display = '';
        }

        // Stats, filter counts, footer
        _updateCompareStats(tracks);

        // Column headers
        const sourceLabel = mirroredPlaylist ? (mirroredPlaylist.source || 'source').charAt(0).toUpperCase() + (mirroredPlaylist.source || 'source').slice(1) : 'Source';
        const sourceIconMap = { spotify: '🟢', tidal: '🌊', youtube: '▶️', beatport: '🎛️', deezer: '🟣', file: '📄' };
        const serverIconMap = { plex: '🟠', jellyfin: '🟣', navidrome: '🔵' };

        const srcIconEl = document.getElementById('server-col-source-icon');
        const srcLabelEl = document.getElementById('server-col-source-label');
        const srcCountEl = document.getElementById('server-col-source-count');
        const svrIconEl = document.getElementById('server-col-server-icon');
        const svrLabelEl = document.getElementById('server-col-server-label');
        const svrCountEl = document.getElementById('server-col-server-count');

        if (srcIconEl) srcIconEl.textContent = mirroredPlaylist ? (sourceIconMap[mirroredPlaylist.source] || '📋') : '📋';
        if (srcLabelEl) srcLabelEl.textContent = sourceLabel;
        if (srcCountEl) srcCountEl.textContent = `${data.source_track_count || 0} tracks`;
        if (svrIconEl) svrIconEl.textContent = serverIconMap[data.server_type] || '💻';
        if (svrLabelEl) svrLabelEl.textContent = serverLabel;
        if (svrCountEl) svrCountEl.textContent = `${data.server_track_count || 0} tracks`;

        // Render columns
        _renderCompareColumns(tracks);

        // Scroll linking
        _setupScrollLinking();

    } catch (e) {
        if (metaEl) metaEl.textContent = 'Error: ' + e.message;
    }
}

function _updateCompareStats(tracks) {
    const matched = tracks.filter(t => t.match_status === 'matched').length;
    const missing = tracks.filter(t => t.match_status === 'missing').length;
    const extra = tracks.filter(t => t.match_status === 'extra').length;

    const statsEl = document.getElementById('server-editor-stats');
    if (statsEl) {
        statsEl.innerHTML = `
            <div class="server-editor-stat"><div class="server-editor-stat-num matched">${matched}</div><div class="server-editor-stat-label">Matched</div></div>
            <div class="server-editor-stat"><div class="server-editor-stat-num missing">${missing}</div><div class="server-editor-stat-label">Missing</div></div>
            ${extra > 0 ? `<div class="server-editor-stat"><div class="server-editor-stat-num extra">${extra}</div><div class="server-editor-stat-label">Extra</div></div>` : ''}
        `;
    }

    const editor = document.getElementById('server-editor');
    if (editor) {
        editor.querySelectorAll('.discog-filter').forEach(btn => {
            const f = btn.dataset.filter;
            if (f === 'all') btn.textContent = `All (${tracks.length})`;
            else if (f === 'matched') btn.textContent = `Matched (${matched})`;
            else if (f === 'missing') btn.textContent = `Missing (${missing})`;
            else if (f === 'extra') btn.textContent = `Extra (${extra})`;
        });
    }

    const footer = document.getElementById('server-editor-footer');
    if (footer) footer.textContent = `${matched}/${matched + missing} matched${extra > 0 ? ` · ${extra} extra on server` : ''}`;
}

function _formatDurationMs(ms) {
    if (!ms) return '';
    const s = Math.round(ms / 1000);
    return `${Math.floor(s / 60)}:${String(s % 60).padStart(2, '0')}`;
}

function _renderCompareColumns(tracks) {
    const sourceScroll = document.getElementById('server-col-source-scroll');
    const serverScroll = document.getElementById('server-col-server-scroll');
    if (!sourceScroll || !serverScroll) return;

    let sourceHTML = '';
    let serverHTML = '';

    tracks.forEach((t, i) => {
        const src = t.source_track;
        const svr = t.server_track;
        const status = t.match_status;
        const pairId = `pair-${i}`;

        // ── Source (left) column ──
        if (src) {
            const dur = _formatDurationMs(src.duration_ms);
            sourceHTML += `
            <div class="server-track-item ${status}" data-pair-id="${pairId}" data-index="${i}" data-status="${status}"
                 onclick="_compareTrackClick('source', ${i})">
                <div class="server-track-num">${src.position != null ? src.position : i + 1}</div>
                <div class="server-track-art">
                    ${src.image_url ? `<img src="${src.image_url}" alt="" loading="lazy">` : '<div class="server-track-art-empty"></div>'}
                </div>
                <div class="server-track-info">
                    <div class="server-track-title">${_esc(src.name)}</div>
                    <div class="server-track-artist">${_esc(src.artist || '')}</div>
                </div>
                <div class="server-track-duration">${dur}</div>
                <div class="server-track-status-dot"></div>
            </div>`;
        } else {
            // Extra track — no source
            sourceHTML += `
            <div class="server-track-item extra-gap" data-pair-id="${pairId}" data-index="${i}" data-status="${status}">
                <div class="server-track-empty-slot extra">
                    <span class="empty-slot-label">No source track</span>
                </div>
            </div>`;
        }

        // ── Server (right) column ──
        if (svr) {
            const dur = _formatDurationMs(svr.duration);
            const conf = t.confidence != null ? t.confidence : null;
            let confBadge = '';
            if (status === 'matched' && conf != null) {
                const pct = Math.round(conf * 100);
                const cls = pct >= 100 ? 'exact' : pct >= 90 ? 'high' : 'fuzzy';
                confBadge = `<span class="server-track-conf ${cls}" title="Title similarity">${pct}%</span>`;
            }
            serverHTML += `
            <div class="server-track-item ${status}" data-pair-id="${pairId}" data-index="${i}" data-status="${status}"
                 onclick="_compareTrackClick('server', ${i})">
                <div class="server-track-num">${i + 1}</div>
                <div class="server-track-art">
                    ${svr.thumb ? `<img src="${svr.thumb}" alt="" loading="lazy">` : '<div class="server-track-art-empty"></div>'}
                </div>
                <div class="server-track-info">
                    <div class="server-track-title">${_esc(svr.title)}</div>
                    <div class="server-track-artist">${_esc(svr.artist || '')}</div>
                </div>
                ${confBadge}
                <div class="server-track-duration">${dur}</div>
                <div class="server-track-actions">
                    ${status === 'matched' ? `<button class="server-track-swap-btn" onclick="event.stopPropagation(); serverSearchReplace(${i}, 'replace')" title="Swap for different version">
                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><path d="M7 16V4m0 0L3 8m4-4l4 4M17 8v12m0 0l4-4m-4 4l-4-4"/></svg>
                    </button>` : ''}
                    <button class="server-track-remove-btn" onclick="event.stopPropagation(); _serverRemoveTrack(${i}, '${svr.id}')" title="Remove from playlist">
                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><path d="M18 6L6 18M6 6l12 12"/></svg>
                    </button>
                </div>
                <div class="server-track-status-dot"></div>
            </div>`;
        } else {
            // Missing on server — clickable empty slot
            const hint = src ? `${src.artist || ''} — ${src.name}` : '';
            serverHTML += `
            <div class="server-track-item empty-slot-wrap" data-pair-id="${pairId}" data-index="${i}" data-status="${status}"
                 onclick="serverSearchReplace(${i}, 'add')">
                <div class="server-track-empty-slot missing">
                    <div class="empty-slot-icon">
                        <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.35-4.35"/></svg>
                    </div>
                    <span class="empty-slot-label">Find &amp; add</span>
                    <span class="empty-slot-hint">${_esc(hint)}</span>
                </div>
            </div>`;
        }
    });

    sourceScroll.innerHTML = sourceHTML;
    serverScroll.innerHTML = serverHTML;
}

function _setupScrollLinking() {
    const sourceScroll = document.getElementById('server-col-source-scroll');
    const serverScroll = document.getElementById('server-col-server-scroll');
    if (!sourceScroll || !serverScroll) return;

    // Remove old listeners to prevent accumulation on refresh
    if (window._serverScrollAC) window._serverScrollAC.abort();
    window._serverScrollAC = new AbortController();
    const signal = window._serverScrollAC.signal;

    let syncing = false;

    const syncScroll = (from, to) => {
        if (syncing) return;
        syncing = true;
        const maxFrom = from.scrollHeight - from.clientHeight;
        const maxTo = to.scrollHeight - to.clientHeight;
        if (maxFrom > 0 && maxTo > 0) {
            to.scrollTop = (from.scrollTop / maxFrom) * maxTo;
        }
        requestAnimationFrame(() => { syncing = false; });
    };

    sourceScroll.addEventListener('scroll', () => syncScroll(sourceScroll, serverScroll), { signal });
    serverScroll.addEventListener('scroll', () => syncScroll(serverScroll, sourceScroll), { signal });
}

function _compareTrackClick(side, index) {
    const otherSide = side === 'source' ? 'server' : 'source';
    const otherScroll = document.getElementById(`server-col-${otherSide}-scroll`);
    const pairId = `pair-${index}`;

    // Clear previous highlights
    document.querySelectorAll('.server-track-item.highlighted').forEach(el => el.classList.remove('highlighted'));

    // Highlight both paired items
    document.querySelectorAll(`[data-pair-id="${pairId}"]`).forEach(el => el.classList.add('highlighted'));

    // Scroll the OTHER column to show the paired item
    const target = otherScroll?.querySelector(`[data-pair-id="${pairId}"]`);
    if (target) {
        target.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
}

function _serverEditorRefresh() {
    _openServerCompareView(_serverEditorState.playlistId, _serverEditorState.playlistName, _serverEditorState.mirroredPlaylist);
}

function serverEditorBack() {
    const container = document.getElementById('server-playlist-container');
    const editor = document.getElementById('server-editor');
    if (editor) editor.style.display = 'none';
    if (container) container.style.display = '';
}

function _serverEditorFilter(btn, filter) {
    btn.closest('.server-editor-filters').querySelectorAll('.discog-filter').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');

    // Filter both columns simultaneously
    ['server-col-source-scroll', 'server-col-server-scroll'].forEach(colId => {
        document.querySelectorAll(`#${colId} .server-track-item`).forEach(item => {
            const status = item.dataset.status;
            item.style.display = (filter === 'all' || status === filter) ? '' : 'none';
        });
    });
}

// ── Track Search / Replace ──

async function serverSearchReplace(trackIndex, mode) {
    const track = _serverEditorState.tracks[trackIndex];
    if (!track) return;

    const src = track.source_track || {};
    const svr = track.server_track || {};
    // Search by track name only first (more reliable than "artist trackname" blob)
    const searchQuery = src.name ? src.name.trim() : (svr.title || '').trim();
    const contextArtist = src.artist || svr.artist || '';
    const contextName = src.name || svr.title || '';

    const existing = document.getElementById('server-search-overlay');
    if (existing) existing.remove();

    const overlay = document.createElement('div');
    overlay.id = 'server-search-overlay';
    overlay.className = 'server-search-overlay';
    overlay.innerHTML = `
        <div class="server-search-popover" id="server-search-popover">
            <div class="server-search-header">
                <div>
                    <div class="server-search-title">${mode === 'replace' ? 'Swap Track' : 'Add Track to Server'}</div>
                    ${contextName ? `<div class="server-search-context">
                        <span class="server-search-context-label">Source:</span>
                        <span class="server-search-context-artist">${_esc(contextArtist)}</span>
                        <span class="server-search-context-sep">—</span>
                        <span class="server-search-context-name">${_esc(contextName)}</span>
                    </div>` : ''}
                </div>
                <button class="server-search-close" onclick="document.getElementById('server-search-overlay')?.remove()">&times;</button>
            </div>
            <div class="server-search-input-wrap">
                <div class="server-search-input-icon">
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.35-4.35"/></svg>
                </div>
                <input type="text" class="server-search-input" id="server-search-input" value="${_esc(searchQuery)}" placeholder="Search by track name, artist, or album..." onkeydown="if(event.key==='Enter') _serverSearchExecute()">
            </div>
            <div class="server-search-results-header" id="server-search-results-header"></div>
            <div class="server-search-results" id="server-search-results">
                <div class="server-search-hint">
                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" style="margin-bottom:6px;opacity:0.4"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.35-4.35"/></svg>
                    <br>Searching...
                </div>
            </div>
        </div>
    `;
    // Click overlay background or press Escape to close
    overlay.addEventListener('click', e => { if (e.target === overlay) overlay.remove(); });
    overlay._escHandler = e => { if (e.key === 'Escape') overlay.remove(); };
    document.addEventListener('keydown', overlay._escHandler);
    // Clean up Escape listener when overlay is removed
    const obs = new MutationObserver(() => {
        if (!document.body.contains(overlay)) { document.removeEventListener('keydown', overlay._escHandler); obs.disconnect(); }
    });
    obs.observe(document.body, { childList: true });

    const popover = overlay.querySelector('.server-search-popover');
    popover.dataset.trackIndex = trackIndex;
    popover.dataset.mode = mode;

    document.body.appendChild(overlay);
    requestAnimationFrame(() => overlay.classList.add('visible'));
    document.getElementById('server-search-input')?.focus();
    document.getElementById('server-search-input')?.select();

    _serverSearchExecute();
}

async function _serverSearchExecute() {
    const input = document.getElementById('server-search-input');
    const results = document.getElementById('server-search-results');
    const resultsHeader = document.getElementById('server-search-results-header');
    const popover = document.getElementById('server-search-popover');
    if (!input || !results || !popover) return;

    const query = input.value.trim();
    if (!query) {
        results.innerHTML = '<div class="server-search-hint">Type a search query</div>';
        if (resultsHeader) resultsHeader.textContent = '';
        return;
    }

    results.innerHTML = '<div class="server-search-hint"><div class="server-search-spinner"></div>Searching library...</div>';
    if (resultsHeader) resultsHeader.textContent = '';

    try {
        const response = await fetch(`/api/library/search-tracks?q=${encodeURIComponent(query)}&limit=20`);
        const data = await response.json();

        if (!data.success || !data.tracks || data.tracks.length === 0) {
            results.innerHTML = `<div class="server-search-hint">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" style="margin-bottom:6px;opacity:0.3"><path d="M9.172 14.828a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>
                <br>No results found<br><span style="font-size:10px;opacity:0.5">Try different keywords or a shorter query</span>
            </div>`;
            return;
        }

        const trackIndex = parseInt(popover.dataset.trackIndex);
        const mode = popover.dataset.mode;

        if (resultsHeader) resultsHeader.textContent = `${data.tracks.length} result${data.tracks.length !== 1 ? 's' : ''}`;

        results.innerHTML = data.tracks.map((t, i) => {
            const ext = (t.file_path || '').split('.').pop().toUpperCase();
            const format = ['FLAC','MP3','OPUS','OGG','M4A','AAC','WAV'].includes(ext) ? (ext === 'M4A' ? 'AAC' : ext) : '';
            const dur = _formatDurationMs(t.duration);
            const bitrateStr = t.bitrate ? `${t.bitrate}k` : '';
            return `
                <div class="server-search-result" onclick="_serverSelectTrack(${trackIndex}, '${mode}', '${t.id}', this)" style="animation-delay:${i * 0.03}s">
                    <div class="server-search-result-art">
                        ${t.album_thumb_url ? `<img src="${t.album_thumb_url}" alt="" loading="lazy">` : '<div class="server-search-result-art-empty"></div>'}
                    </div>
                    <div class="server-search-result-info">
                        <div class="server-search-result-title">${_esc(t.title)}</div>
                        <div class="server-search-result-meta">${_esc(t.artist_name)}${t.album_title ? ` · ${_esc(t.album_title)}` : ''}</div>
                    </div>
                    <div class="server-search-result-details">
                        ${format ? `<span class="server-search-format">${format}</span>` : ''}
                        ${bitrateStr ? `<span class="server-search-bitrate">${bitrateStr}</span>` : ''}
                        ${dur ? `<span class="server-search-dur">${dur}</span>` : ''}
                    </div>
                    <button class="server-search-select-btn">Select</button>
                </div>
            `;
        }).join('');

    } catch (e) {
        results.innerHTML = `<div class="server-search-hint">Error: ${e.message}</div>`;
    }
}

async function _serverSelectTrack(trackIndex, mode, newTrackId, el) {
    const track = _serverEditorState.tracks[trackIndex];
    if (!track) return;

    const btn = el.querySelector('.server-search-select-btn');
    if (btn) { btn.disabled = true; btn.textContent = '...'; }

    try {
        let response;
        if (mode === 'replace') {
            response = await fetch(`/api/server/playlist/${_serverEditorState.playlistId}/replace-track`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    old_track_id: track.server_track?.id,
                    new_track_id: newTrackId,
                    playlist_name: _serverEditorState.playlistName,
                })
            });
        } else {
            // Calculate the server-side position for this track
            // Count how many server tracks exist before this index
            let serverPos = 0;
            for (let k = 0; k < trackIndex; k++) {
                if (_serverEditorState.tracks[k]?.server_track) serverPos++;
            }
            response = await fetch(`/api/server/playlist/${_serverEditorState.playlistId}/add-track`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    track_id: newTrackId,
                    playlist_name: _serverEditorState.playlistName,
                    position: serverPos,
                })
            });
        }

        const data = await response.json();
        if (data.success) {
            showToast(data.message || 'Track updated', 'success');
            document.getElementById('server-search-overlay')?.remove();
            // Update playlist ID if server recreated it (Plex deletes+recreates)
            if (data.new_playlist_id) _serverEditorState.playlistId = data.new_playlist_id;

            // Update local state directly — don't re-run the matcher which would
            // lose the user's explicit assignment if titles don't match exactly
            const trackEntry = _serverEditorState.tracks[trackIndex];
            if (trackEntry && mode === 'add') {
                // Fill the empty slot with the selected track info
                const svrTitle = el.querySelector('.server-search-result-title')?.textContent || '';
                const svrArtist = (el.querySelector('.server-search-result-meta')?.textContent || '').split('·')[0].trim();
                const svrThumb = el.querySelector('.server-search-result-art img')?.src || '';
                trackEntry.server_track = { id: newTrackId, title: svrTitle, artist: svrArtist, thumb: svrThumb };
                trackEntry.match_status = 'matched';
                // Calculate real title similarity so the badge is accurate
                const srcName = trackEntry.source_track?.name || '';
                const srcArtist = trackEntry.source_track?.artist || '';
                const srcKey = `${srcArtist} ${srcName}`.trim().toLowerCase();
                const svrKey = `${svrArtist} ${svrTitle}`.trim().toLowerCase();
                trackEntry.confidence = srcKey && svrKey ? calculateStringSimilarity(srcKey, svrKey) : 0;
                _renderCompareColumns(_serverEditorState.tracks);
                _updateCompareStats(_serverEditorState.tracks);
                _setupScrollLinking();
            } else {
                // For replace mode, re-fetch to get the updated server state
                _openServerCompareView(_serverEditorState.playlistId, _serverEditorState.playlistName, _serverEditorState.mirroredPlaylist);
            }
        } else {
            showToast(data.error || 'Failed to update track', 'error');
            if (btn) { btn.disabled = false; btn.textContent = 'Select'; }
        }
    } catch (e) {
        showToast('Error: ' + e.message, 'error');
        if (btn) { btn.disabled = false; btn.textContent = 'Select'; }
    }
}

async function _serverRemoveTrack(trackIndex, serverTrackId) {
    if (!serverTrackId) return;

    const track = _serverEditorState.tracks[trackIndex];
    const trackTitle = track?.server_track?.title || 'this track';

    if (!await showConfirmDialog({ title: 'Remove Track', message: `Remove "${trackTitle}" from this playlist?`, confirmText: 'Remove', destructive: true })) return;

    try {
        const response = await fetch(`/api/server/playlist/${_serverEditorState.playlistId}/remove-track`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                track_id: serverTrackId,
                playlist_name: _serverEditorState.playlistName,
            })
        });

        const data = await response.json();
        if (data.success) {
            showToast(data.message || 'Track removed', 'success');
            const pid = data.new_playlist_id || _serverEditorState.playlistId;
            _serverEditorState.playlistId = pid;
            _openServerCompareView(pid, _serverEditorState.playlistName, _serverEditorState.mirroredPlaylist);
        } else {
            showToast(data.error || 'Failed to remove track', 'error');
        }
    } catch (e) {
        showToast('Error: ' + e.message, 'error');
    }
}


// Auto-refresh sync cards every 30 seconds when on dashboard
setInterval(() => {
    if (typeof currentPage !== 'undefined' && currentPage === 'dashboard') {
        loadDashboardSyncHistory();
    }
}, 30000);

async function loadDashboardSyncHistory() {
    const container = document.getElementById('sync-history-cards');
    if (!container) return;

    try {
        const response = await fetch('/api/sync/history?limit=10');
        if (!response.ok) return;

        const data = await response.json();
        // Filter to only show playlist syncs — not album downloads or wishlist processing
        const entries = (data.entries || []).filter(e => e.sync_type === 'playlist' || !e.sync_type);

        if (entries.length === 0) {
            container.innerHTML = '<div class="sync-history-empty">No syncs yet</div>';
            return;
        }

        container.innerHTML = entries.map((entry, cardIndex) => {
            const found = entry.tracks_found || 0;
            const total = entry.total_tracks || 0;
            const downloaded = entry.tracks_downloaded || 0;
            const failed = entry.tracks_failed || 0;
            const pct = total > 0 ? Math.round((found / total) * 100) : 0;

            // Health color
            let healthClass = 'health-good';
            if (pct < 50) healthClass = 'health-bad';
            else if (pct < 80) healthClass = 'health-warn';

            // Source badge
            const sourceLabels = { spotify: 'Spotify', tidal: 'Tidal', deezer: 'Deezer', youtube: 'YouTube', beatport: 'Beatport', wishlist: 'Wishlist' };
            const sourceLabel = sourceLabels[entry.source] || entry.source || 'Unknown';

            // Time
            const timeStr = entry.started_at ? _relativeTime(entry.started_at) : '';

            // Name
            const name = entry.artist_name
                ? `${entry.artist_name} — ${entry.album_name || entry.playlist_name}`
                : entry.playlist_name || 'Unknown';

            return `
                <div class="sync-history-card ${healthClass}" onclick="openSyncDetailModal(${entry.id})" style="animation-delay: ${cardIndex * 0.05}s">
                    <button class="sync-card-delete" onclick="event.stopPropagation(); deleteSyncHistoryCard(${entry.id}, this)" title="Remove">&times;</button>
                    <div class="sync-card-thumb">
                        ${entry.thumb_url ? `<img src="${entry.thumb_url}" alt="" loading="lazy">` : '<div class="sync-card-thumb-placeholder">&#9835;</div>'}
                    </div>
                    <div class="sync-card-info">
                        <div class="sync-card-name">${typeof _esc === 'function' ? _esc(name) : name}</div>
                        <div class="sync-card-meta">
                            <span class="sync-card-source">${sourceLabel}</span>
                            <span class="sync-card-time">${timeStr}</span>
                        </div>
                    </div>
                    <div class="sync-card-stats">
                        <div class="sync-card-pct">${pct}%</div>
                        <div class="sync-card-bar">
                            <div class="sync-card-bar-fill" style="width: ${pct}%"></div>
                        </div>
                        <div class="sync-card-counts">${found}/${total} matched${downloaded > 0 ? ` · ${downloaded} ⬇` : ''}${failed > 0 ? ` · ${failed} ✗` : ''}</div>
                    </div>
                </div>
            `;
        }).join('');

    } catch (e) {
        console.warn('Failed to load sync history for dashboard:', e);
    }
}

function _relativeTime(dateStr) {
    try {
        const d = new Date(dateStr);
        const now = new Date();
        const diffMs = now - d;
        const mins = Math.floor(diffMs / 60000);
        if (mins < 1) return 'just now';
        if (mins < 60) return `${mins}m ago`;
        const hrs = Math.floor(mins / 60);
        if (hrs < 24) return `${hrs}h ago`;
        const days = Math.floor(hrs / 24);
        if (days < 7) return `${days}d ago`;
        return d.toLocaleDateString();
    } catch (e) { return ''; }
}

async function openSyncDetailModal(entryId) {
    try {
        showLoadingOverlay('Loading sync details...');
        const response = await fetch(`/api/sync/history/${entryId}`);
        const data = await response.json();
        hideLoadingOverlay();

        if (!data.success || !data.entry) {
            showToast('Could not load sync details', 'error');
            return;
        }

        const entry = data.entry;
        const trackResults = entry.track_results || [];
        const name = entry.artist_name
            ? `${entry.artist_name} — ${entry.album_name || entry.playlist_name}`
            : entry.playlist_name || 'Unknown';

        // Build modal
        const overlay = document.createElement('div');
        overlay.className = 'discog-modal-overlay';
        overlay.id = 'sync-detail-overlay';

        const found = entry.tracks_found || 0;
        const total = entry.total_tracks || 0;
        const downloaded = entry.tracks_downloaded || 0;

        let trackRowsHtml = '';
        if (trackResults.length > 0) {
            trackRowsHtml = trackResults.map((t, i) => {
                const statusIcon = t.status === 'found' ? '✅' : '❌';
                const statusClass = t.status === 'found' ? 'matched' : 'unmatched';
                const confPct = Math.round((t.confidence || 0) * 100);
                const confClass = confPct >= 80 ? 'conf-high' : confPct >= 50 ? 'conf-mid' : 'conf-low';
                let dlIcon = '';
                if (t.download_status === 'completed') dlIcon = '✅';
                else if (t.download_status === 'failed') dlIcon = '❌';
                else if (t.download_status === 'not_found') dlIcon = '🔇';
                else if (t.download_status === 'cancelled') dlIcon = '🚫';

                let dlDisplay = dlIcon;
                if (!dlDisplay && t.download_status === 'wishlist') dlDisplay = '<span class="sync-dl-wishlist">→ Wishlist</span>';

                return `
                    <tr class="sync-detail-row ${statusClass}">
                        <td class="sync-detail-num">${i + 1}</td>
                        <td class="sync-detail-art">
                            ${t.image_url ? `<img src="${t.image_url}" alt="" loading="lazy">` : '<div class="sync-detail-art-empty"></div>'}
                        </td>
                        <td class="sync-detail-track">${_esc(t.name || '')}</td>
                        <td class="sync-detail-artist">${_esc(t.artist || '')}</td>
                        <td class="sync-detail-album">${_esc(t.album || '')}</td>
                        <td class="sync-detail-status">${statusIcon}</td>
                        <td class="sync-detail-conf"><span class="conf-badge ${confClass}">${confPct}%</span></td>
                        <td class="sync-detail-dl">${dlDisplay}</td>
                    </tr>
                `;
            }).join('');
        } else {
            // Fallback to tracks_json if no track_results (old syncs before data caching)
            const tracks = entry.tracks || [];
            const esc = typeof _esc === 'function' ? _esc : s => s;
            trackRowsHtml = `
                <tr><td colspan="8" class="sync-detail-notice">
                    <div class="sync-detail-notice-text">Per-track match data not available for this sync.<br>Re-sync this playlist to see detailed match results.</div>
                </td></tr>
            ` + tracks.map((t, i) => {
                const artists = t.artists || [];
                const artistName = artists.length > 0 ? (typeof artists[0] === 'string' ? artists[0] : artists[0]?.name || '') : '';
                const albumName = typeof t.album === 'object' ? (t.album?.name || '') : (t.album || '');
                return `
                    <tr class="sync-detail-row no-data">
                        <td class="sync-detail-num">${i + 1}</td>
                        <td class="sync-detail-art"></td>
                        <td class="sync-detail-track">${esc(t.name || '')}</td>
                        <td class="sync-detail-artist">${esc(artistName)}</td>
                        <td class="sync-detail-album">${esc(albumName)}</td>
                        <td class="sync-detail-status" colspan="3"></td>
                    </tr>
                `;
            }).join('');
        }

        // Count stats for filter bar
        const matchedCount = trackResults.filter(t => t.status === 'found').length;
        const unmatchedCount = trackResults.filter(t => t.status !== 'found').length;
        const downloadedCount = trackResults.filter(t => t.download_status === 'completed').length;

        overlay.innerHTML = `
            <div class="discog-modal">
                <div class="discog-modal-hero" ${entry.thumb_url ? `style="background-image:url('${entry.thumb_url}')"` : ''}>
                    <div class="discog-modal-hero-overlay"></div>
                    <div class="discog-modal-hero-content">
                        <h2 class="discog-modal-title">Sync Details</h2>
                        <p class="discog-modal-artist">${_esc(name)}</p>
                    </div>
                    <button class="discog-modal-close" onclick="document.getElementById('sync-detail-overlay')?.remove()">&times;</button>
                </div>
                <div class="discog-filter-bar">
                    <div class="discog-filters">
                        <button class="discog-filter active" data-filter="all" onclick="_syncDetailFilter(this, 'all')">All (${total})</button>
                        <button class="discog-filter" data-filter="matched" onclick="_syncDetailFilter(this, 'matched')">Matched (${matchedCount})</button>
                        <button class="discog-filter" data-filter="unmatched" onclick="_syncDetailFilter(this, 'unmatched')">Unmatched (${unmatchedCount})</button>
                        ${downloadedCount > 0 ? `<button class="discog-filter" data-filter="downloaded" onclick="_syncDetailFilter(this, 'downloaded')">Downloaded (${downloadedCount})</button>` : ''}
                    </div>
                </div>
                <div class="sync-detail-table-wrap">
                    <table class="sync-detail-table">
                        <thead>
                            <tr>
                                <th>#</th>
                                <th></th>
                                <th>Track</th>
                                <th>Artist</th>
                                <th>Album</th>
                                <th>Match</th>
                                <th>Conf.</th>
                                <th>Status</th>
                            </tr>
                        </thead>
                        <tbody id="sync-detail-tbody">
                            ${trackRowsHtml}
                        </tbody>
                    </table>
                </div>
                <div class="discog-footer">
                    <div class="discog-footer-info">${found} matched · ${downloaded} downloaded · ${total} total</div>
                    <div class="discog-footer-actions">
                        <button class="discog-cancel-btn" onclick="document.getElementById('sync-detail-overlay')?.remove()">Close</button>
                    </div>
                </div>
            </div>
        `;

        document.body.appendChild(overlay);
        requestAnimationFrame(() => overlay.classList.add('visible'));

    } catch (e) {
        hideLoadingOverlay();
        showToast('Failed to load sync details', 'error');
    }
}

async function deleteSyncHistoryCard(entryId, btnEl) {
    try {
        const card = btnEl.closest('.sync-history-card');
        if (card) {
            card.style.opacity = '0';
            card.style.transform = 'scale(0.9)';
        }
        const resp = await fetch(`/api/sync/history/${entryId}`, { method: 'DELETE' });
        if (resp.ok) {
            setTimeout(() => { if (card) card.remove(); }, 200);
        }
    } catch (e) {
        console.warn('Failed to delete sync entry:', e);
    }
}

function _syncDetailFilter(btn, filter) {
    // Update active button
    btn.closest('.discog-filters').querySelectorAll('.discog-filter').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');

    // Filter rows
    document.querySelectorAll('#sync-detail-tbody .sync-detail-row').forEach(row => {
        if (filter === 'all') {
            row.style.display = '';
        } else if (filter === 'matched') {
            row.style.display = row.classList.contains('matched') ? '' : 'none';
        } else if (filter === 'unmatched') {
            row.style.display = row.classList.contains('unmatched') ? '' : 'none';
        } else if (filter === 'downloaded') {
            const dlCell = row.querySelector('.sync-detail-dl');
            row.style.display = dlCell && dlCell.textContent.trim() === '✅' ? '' : 'none';
        }
    });
}


// ============================================
// ACTIVE DOWNLOADS PAGE — Centralized Live View
// ============================================

let _adlPoller = null;
let _adlFilter = 'all';
let _adlData = [];

function loadActiveDownloadsPage() {
    _adlFetch();
    // Poll every 2 seconds while on this page
    if (_adlPoller) clearInterval(_adlPoller);
    _adlPoller = setInterval(() => {
        if (currentPage === 'active-downloads') _adlFetch();
        else { clearInterval(_adlPoller); _adlPoller = null; }
    }, 2000);
}

function adlSetFilter(filter) {
    _adlFilter = filter;
    document.querySelectorAll('#adl-filter-pills .adl-pill').forEach(p => p.classList.toggle('active', p.dataset.filter === filter));
    _adlRender();
}

async function _adlFetch() {
    try {
        const resp = await fetch('/api/downloads/all?limit=300');
        const data = await resp.json();
        if (data.success) {
            _adlData = data.downloads || [];
            _adlRender();
            _adlUpdateBadge();
        }
    } catch (e) {
        console.error('Downloads page fetch error:', e);
    }
}

function _adlUpdateBadge() {
    const activeCount = _adlData.filter(d => ['downloading', 'searching', 'queued', 'pending', 'post_processing'].includes(d.status)).length;
    _updateDlNavBadge(activeCount);
}

function _updateDlNavBadge(count) {
    const badge = document.getElementById('dl-nav-badge');
    if (badge) {
        if (count > 0) {
            badge.textContent = count;
            badge.classList.remove('hidden');
        } else {
            badge.classList.add('hidden');
        }
    }
}

function _adlRender() {
    const list = document.getElementById('adl-list');
    const empty = document.getElementById('adl-empty');
    const countEl = document.getElementById('adl-count');
    if (!list) return;

    // Apply filter
    const activeStatuses = ['downloading', 'searching', 'post_processing'];
    const queuedStatuses = ['queued'];
    const completedStatuses = ['completed', 'skipped', 'already_owned'];
    const failedStatuses = ['failed', 'not_found', 'cancelled'];

    let filtered = _adlData;
    if (_adlFilter === 'active') filtered = _adlData.filter(d => activeStatuses.includes(d.status));
    else if (_adlFilter === 'queued') filtered = _adlData.filter(d => queuedStatuses.includes(d.status));
    else if (_adlFilter === 'completed') filtered = _adlData.filter(d => completedStatuses.includes(d.status));
    else if (_adlFilter === 'failed') filtered = _adlData.filter(d => failedStatuses.includes(d.status));

    const completedN = _adlData.filter(d => [...completedStatuses, ...failedStatuses].includes(d.status)).length;

    if (countEl) {
        const activeN = _adlData.filter(d => activeStatuses.includes(d.status)).length;
        const queuedN = _adlData.filter(d => queuedStatuses.includes(d.status)).length;
        const total = _adlData.length;
        const parts = [];
        if (activeN > 0) parts.push(`${activeN} active`);
        if (queuedN > 0) parts.push(`${queuedN} queued`);
        parts.push(`${total} total`);
        countEl.textContent = parts.join(' / ');
    }

    // Show/hide clear button
    const clearBtn = document.getElementById('adl-clear-btn');
    if (clearBtn) clearBtn.style.display = completedN > 0 ? '' : 'none';

    if (filtered.length === 0) {
        if (empty) empty.style.display = '';
        // Clear any existing rows but keep the empty message
        list.querySelectorAll('.adl-row').forEach(r => r.remove());
        return;
    }

    if (empty) empty.style.display = 'none';

    // Group by status category for section headers
    const groups = { active: [], queued: [], completed: [], failed: [] };
    for (const dl of filtered) {
        const cls = _adlStatusClass(dl.status);
        if (cls === 'active') groups.active.push(dl);
        else if (cls === 'queued') groups.queued.push(dl);
        else if (cls === 'completed') groups.completed.push(dl);
        else groups.failed.push(dl);
    }

    let html = '';
    const sections = [
        { key: 'active', label: 'Active', items: groups.active },
        { key: 'queued', label: 'Queued', items: groups.queued },
        { key: 'completed', label: 'Completed', items: groups.completed },
        { key: 'failed', label: 'Failed', items: groups.failed },
    ];

    for (const section of sections) {
        if (section.items.length === 0) continue;
        // Only show section headers in "all" filter mode
        if (_adlFilter === 'all') {
            html += `<div class="adl-section-header">${section.label} (${section.items.length})</div>`;
        }
        for (const dl of section.items) {
            const statusClass = _adlStatusClass(dl.status);
            const statusLabel = _adlStatusLabel(dl.status);
            const title = _adlEsc(dl.title || 'Unknown Track');
            const artist = _adlEsc(dl.artist || '');
            const album = _adlEsc(dl.album || '');
            const batchName = _adlEsc(dl.batch_name || '');
            const error = dl.error ? _adlEsc(dl.error) : '';

            const meta = [artist, album].filter(Boolean).join(' \u00B7 ');
            const artHtml = dl.artwork
                ? `<img class="adl-row-art" src="${_adlEsc(dl.artwork)}" alt="" onerror="this.style.display='none'">`
                : '<div class="adl-row-art adl-row-art-empty"></div>';

            // Track position: "3 of 19"
            const posText = dl.batch_total > 1 ? `${(dl.track_index || 0) + 1} of ${dl.batch_total}` : '';

            html += `<div class="adl-row adl-row-${statusClass}" data-task-id="${dl.task_id}">
                ${artHtml}
                <div class="adl-row-info">
                    <div class="adl-row-title">${title}</div>
                    ${meta ? `<div class="adl-row-meta">${meta}</div>` : ''}
                    ${batchName ? `<div class="adl-row-batch">${batchName}${posText ? ' &middot; Track ' + posText : ''}</div>` : ''}
                    ${error ? `<div class="adl-row-error">${error}</div>` : ''}
                </div>
                <div class="adl-row-status ${statusClass}">
                    <span class="adl-status-dot ${statusClass}"></span>
                    ${statusLabel}
                </div>
            </div>`;
        }
    }

    // Preserve empty element, inject rows
    const emptyEl = document.getElementById('adl-empty');
    const emptyHtml = emptyEl ? emptyEl.outerHTML : '';
    list.innerHTML = emptyHtml + html;
    const newEmpty = document.getElementById('adl-empty');
    if (newEmpty) newEmpty.style.display = filtered.length > 0 ? 'none' : '';
}

function _adlStatusClass(status) {
    switch (status) {
        case 'downloading': case 'searching': case 'post_processing': return 'active';
        case 'queued': case 'pending': return 'queued';
        case 'completed': case 'skipped': case 'already_owned': return 'completed';
        case 'failed': case 'not_found': return 'failed';
        case 'cancelled': return 'cancelled';
        default: return 'queued';
    }
}

function _adlStatusLabel(status) {
    switch (status) {
        case 'downloading': return '<span class="adl-spinner"></span>Downloading';
        case 'searching': return '<span class="adl-spinner"></span>Searching';
        case 'post_processing': return '<span class="adl-spinner"></span>Processing';
        case 'queued': case 'pending': return 'Queued';
        case 'completed': return 'Completed';
        case 'skipped': return 'Skipped';
        case 'already_owned': return 'Owned';
        case 'failed': return 'Failed';
        case 'not_found': return 'Not Found';
        case 'cancelled': return 'Cancelled';
        default: return status;
    }
}

function _adlEsc(str) {
    if (!str) return '';
    return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

async function adlClearCompleted() {
    try {
        const resp = await fetch('/api/downloads/clear-completed', { method: 'POST' });
        const data = await resp.json();
        if (data.success) {
            if (typeof showToast === 'function') showToast(`Cleared ${data.cleared} downloads`, 'success');
            _adlFetch();
        }
    } catch (e) {
        console.error('Error clearing completed downloads:', e);
    }
}

window.adlSetFilter = adlSetFilter;
window.adlClearCompleted = adlClearCompleted;
